if sys.modules.get(__name__) is None:
    try:
        import gc as _gc_shim
        _shim_mod = None
        for _shim_ref in _gc_shim.get_referrers(globals()):
            if (isinstance(_shim_ref, _types.ModuleType)
                    and getattr(_shim_ref, "__dict__", None) is globals()):
                _shim_mod = _shim_ref
                break
        if _shim_mod is None:
            _shim_mod = _types.ModuleType(__name__)
            _shim_mod.__dict__.update(globals())
        sys.modules[__name__] = _shim_mod
    except Exception:
        pass

