def _console(token: str, *, newline: bool = True, cr: bool = False) -> None:
    try:
        prefix = "\r" if cr else ""
        end = "\n" if newline else ""
        pad = "   " if cr else ""
        print(prefix + token + pad, end=end, flush=True)
    except OSError as _e:
        _flog(f"[ignored] _console: {_e!r}")


