def _term_open_tty():
    try:
        if os.name == "nt":
            fin = open("CONIN$", "rb", buffering=0)
            fout = open("CONOUT$", "wb", buffering=0)
        else:
            fd = os.open("/dev/tty", os.O_RDWR)
            fin = fout = os.fdopen(fd, "r+b", buffering=0)
        return fin, fout
    except Exception:
        return None, None


def _term_probe_widths(chars, timeout=0.30):
    fin, fout = _term_open_tty()
    if fin is None:
        return None
    restore = None
    try:
        if os.name == "nt":
            import ctypes, msvcrt

            class _COORD(ctypes.Structure):
                _fields_ = [("X", ctypes.c_short), ("Y", ctypes.c_short)]

            class _CSBI(ctypes.Structure):
                _fields_ = [("dwSize", _COORD), ("dwCursorPosition", _COORD),
                            ("wAttributes", ctypes.c_ushort),
                            ("srWindow", ctypes.c_short * 4),
                            ("dwMaximumWindowSize", _COORD)]

            k32 = ctypes.windll.kernel32
            hout = msvcrt.get_osfhandle(fout.fileno())
            csbi = _CSBI()
            if not k32.GetConsoleScreenBufferInfo(hout, ctypes.byref(csbi)):
                return None

            def _wc(s):
                _n = ctypes.c_uint(0)
                return bool(k32.WriteConsoleW(hout, s, len(s),
                                              ctypes.byref(_n), None))

            res = {}
            for ch in chars:
                if not _wc("\r"):
                    return None
                if not k32.GetConsoleScreenBufferInfo(hout, ctypes.byref(csbi)):
                    return None
                _x0 = csbi.dwCursorPosition.X
                if not _wc(ch):
                    return None
                if not k32.GetConsoleScreenBufferInfo(hout, ctypes.byref(csbi)):
                    return None
                col = csbi.dwCursorPosition.X - _x0
                _wc("\r        \r")
                if col < 1 or col > 4:
                    if 0xE000 <= ord(ch) <= 0xF8FF:
                        continue
                    return None
                res[ch] = col
            return res
        else:
            import termios, tty
            restore = termios.tcgetattr(fin.fileno())
            tty.setcbreak(fin.fileno())

        res = {}
        for ch in chars:
            fout.write(b"\r" + ch.encode("utf-8") + b"\x1b[6n")
            buf = b""
            t0 = time.time()
            col = None
            while time.time() - t0 < timeout:
                import select
                r, _, _ = select.select([fin.fileno()], [], [], timeout)
                if not r:
                    break
                buf += os.read(fin.fileno(), 64)
                m = re.search(rb"\x1b\[(\d+);(\d+)R", buf)
                if m:
                    col = int(m.group(2)) - 1
                    break
            fout.write(b"\r\x1b[K")
            if col is None or col < 1 or col > 4:
                if 0xE000 <= ord(ch) <= 0xF8FF:
                    continue
                return None
            res[ch] = col
        return res
    except Exception:
        return None
    finally:
        try:
            if restore is not None:
                import termios
                termios.tcsetattr(fin.fileno(), termios.TCSADRAIN, restore)
            if fin is not None:
                fin.close()
                if fout is not fin and fout is not None:
                    fout.close()
        except Exception as _e:
            _flog(f"[ignored] _term_probe_widths: {_e!r}")


_SR_MEASURED_W = {}
_SR_FLIP_DECIDED = None
_SR_PROBE_NOTE = ""

_term_size_cache = (0.0, 120, 40)


def _term_size():
    global _term_size_cache
    _now = time.monotonic()
    if _now - _term_size_cache[0] < 0.5:
        return _term_size_cache[1], _term_size_cache[2]
    try:
        import shutil
        _ts = shutil.get_terminal_size((120, 40))
        _c, _r = max(20, _ts.columns), max(10, _ts.lines)
    except Exception:
        _c, _r = 120, 40
    _term_size_cache = (_now, _c, _r)
    return _c, _r

_SR_PROBE_CHARS = ["歩", chr(0xE000), chr(0xE010), chr(0xE020),
                   "▲", "▽", "■", "□", "─",
                   "₁", "₂", "₃", "→", "═", "…", "○", "※"]


def _sr_configure_render(force=False):
    global _SR_FLIP_DECIDED, _SR_PROBE_NOTE
    if _SR_FLIP_DECIDED is not None and not force:
        return
    if force:
        _SR_MEASURED_W.clear()
        _sr_cw_cache.clear()
        _sr_vis_cache.clear()
        _SR_PROBE_NOTE = ""
    ev = os.environ.get("LIVE_FLIP_FONT", "")
    if ev in ("0", "false", "no", "off"):
        _SR_FLIP_DECIDED = False
        return
    if os.environ.get("LIVE_FLIP_FONT_FORCE", "") in ("1", "true", "yes", "on"):
        _SR_FLIP_DECIDED = True
        _SR_PROBE_NOTE = "flip=FORCE (実測スキップ)"
        return
    w = _term_probe_widths(_SR_PROBE_CHARS)
    if w is None:
        _SR_FLIP_DECIDED = False
        _SR_PROBE_NOTE = ("端末プローブ不能 (CSI 6n 無応答/非TTY/GetConsoleMode 失敗) "
                          "→ v表記へ降格 (強制するなら LIVE_FLIP_FONT_FORCE=1)")
        _flog("[width-probe] probe returned None — flip disabled. %s" % _SR_PROBE_NOTE)
        return
    _SR_MEASURED_W.update(w)
    base = w.get("歩", 2)
    _pua_chars = (chr(0xE000), chr(0xE010), chr(0xE020))
    _pua_widths = {hex(ord(c)): w.get(c) for c in _pua_chars}
    _pua_missing = [k for k, v in _pua_widths.items() if v is None]
    pua_ok = all(w.get(c) == base == 2 for c in _pua_chars)
    if pua_ok and os.environ.get("WT_SESSION"):
        try:
            _msg5 = _flip_setup_windows_terminal(_BASE_DIR)
            if _msg5:
                _flog("[flip-auto][self-heal] %s" % _msg5)
        except Exception as _fse:
            _flog("[flip-auto][self-heal] failed (ignored): %r" % _fse)
    _SR_FLIP_DECIDED = bool(pua_ok)
    if not pua_ok:
        if _pua_missing:
            _SR_PROBE_NOTE = ("PUA 未実測 %s (フォント未適用で描画不能) → v表記へ降格。"
                              "端末フォントが PyfamateFlip になっているか確認 "
                              "(WT: 設定 → プロファイル → フォント / "
                              "強制するなら LIVE_FLIP_FONT_FORCE=1)"
                              % _pua_missing)
        else:
            _SR_PROBE_NOTE = ("PUA 実測幅 %s (基準 歩=%d) → 反転フォント未適用/幅1端末と"
                              "判断し v表記へ降格"
                              % (_pua_widths, base))
    _flog("[width-probe] measured=%s flip=%s %s"
          % ({(hex(ord(c)) if ord(c) >= 0xE000 else c): v for c, v in w.items()},
             _SR_FLIP_DECIDED, _SR_PROBE_NOTE))


