_SR_JA_PIECE = {"P": "歩", "L": "香", "N": "桂", "S": "銀", "G": "金", "B": "角", "R": "飛", "K": "玉",
                "+P": "と", "+L": "杏", "+N": "圭", "+S": "全", "+B": "馬", "+R": "龍"}


_sr_cw_cache: dict[str, int] = {}


def _sr_cw(ch: str) -> int:
    r = _sr_cw_cache.get(ch)
    if r is not None:
        return r
    w = _SR_MEASURED_W.get(ch)
    if w is not None:
        _sr_cw_cache[ch] = w
        return w
    cp = ord(ch)
    if 0xE000 <= cp <= 0xE02F:
        w = _SR_MEASURED_W.get("歩", 2)
        _sr_cw_cache[ch] = w
        return w
    if ch in _SR_WIDE_MARK:
        w = _SR_MEASURED_W.get("▲", 2)
        _sr_cw_cache[ch] = w
        return w
    ea = unicodedata.east_asian_width(ch)
    if ea in ("W", "F"):
        _sr_cw_cache[ch] = 2
        return 2
    if ea == "A":
        w = _SR_MEASURED_W.get("■", 1)
        _sr_cw_cache[ch] = w
        return w
    _sr_cw_cache[ch] = 1
    return 1


_sr_vis_cache: dict[str, int] = {}


def _sr_vis(s: str) -> int:
    r = _sr_vis_cache.get(s)
    if r is not None:
        return r
    r = sum(_sr_cw(c) for c in s)
    if len(_sr_vis_cache) >= 256:
        try:
            _sr_vis_cache.pop(next(iter(_sr_vis_cache)))
        except StopIteration as _e:
            _flog(f"[ignored] _sr_vis: {_e!r}")
    _sr_vis_cache[s] = r
    return r


def _sr_pad(s: str, width: int) -> str:
    return s + " " * max(0, width - _sr_vis(s))


def _sr_key(pc) -> str:
    if not pc:
        return ""
    base = pc.lstrip("+").upper()
    return ("+" + base) if pc.startswith("+") else base


def _sr_cell(pc) -> str:
    if _sr_flip_font_active():
        if not pc:
            return _SR_EMPTY
        _k = _sr_key(pc)
        glyph = _SR_KANJI.get(_k)
        if glyph is None:
            return _SR_EMPTY
        if pc.lstrip("+")[:1].islower():
            return _SR_ROT_PUA.get(_k, glyph)
        return _SR_SENTE_PUA.get(_k, glyph)
    if not pc:
        return " " + _SR_EMPTY
    glyph = _SR_KANJI.get(_sr_key(pc))
    if glyph is None:
        return " " + _SR_EMPTY
    return ("v" if pc.lstrip("+")[:1].islower() else " ") + glyph


def _sr_hand_pieces(hand: dict) -> list:
    out = []
    for p in _SR_HAND_ORDER:
        n = hand.get(p, 0)
        if n <= 0:
            continue
        out.append(_SR_HAND_KANJI[p])
        if n >= 2:
            out.extend(list(_SR_CNT[min(n, 9)]))
    return out if out else ["な", "し"]


def _sr_eval_bar(sente_wr: float, n: int = 10) -> str:
    if not isinstance(sente_wr, (int, float)):
        return "□" * n
    frac = _clamp01((float(sente_wr) - 45.0) / 10.0)
    filled = int(frac * n + 0.5)
    return "□" * (n - filled) + "■" * filled


def _sr_fmt_clock(ms) -> str:
    if ms is None:
        return ""
    try:
        s = max(0, int(ms)) // 1000
    except Exception:
        return ""
    if s >= 3600:
        return "%d:%02d:%02d" % (s // 3600, (s % 3600) // 60, s % 60)
    return "%d:%02d" % (s // 60, s % 60)


_sr_ja_empty_seen = set()

def _sr_usi_to_ja(board, usi: str) -> str:
    try:
        if not usi or usi in ("resign", "win"):
            return usi or ""
        if "*" in usi:
            _pc, _sq = usi.split("*", 1)
            _tc, _tr = board._to_rc(_sq)
            return _SR_JA_FILE[_tc - 1] + _SR_RANKS[_tr - 1] + _SR_JA_PIECE[_pc.upper()] + "打"
        _promote = usi.endswith("+")
        _body = usi.rstrip("+")
        if len(_body) != 4:
            return usi
        _fc, _fr = board._to_rc(_body[0:2])
        _tc, _tr = board._to_rc(_body[2:4])
        _pc = board.board.get((_fc, _fr), "")
        if not _pc:
            _pc_to = board.board.get((_tc, _tr), "")
            if _pc_to:
                _pc = _pc_to.lstrip("+") if _promote else _pc_to
            if not _pc:
                try:
                    _sfen_snap = board.sfen()
                except Exception:
                    _sfen_snap = "(sfen error)"
                _dedup_key = (usi, _sfen_snap)
                if (_dedup_key not in _sr_ja_empty_seen
                        and len(_sr_ja_empty_seen) < 30):
                    _sr_ja_empty_seen.add(_dedup_key)
                    import traceback as _tb_mod
                    _near = {(c, r): board.board.get((c, r), "")
                             for c in range(_fc - 1, _fc + 2) for r in range(_fr - 1, _fr + 2)
                             if 1 <= c <= 9 and 1 <= r <= 9}
                    _flog("[SR-JA] piece=EMPTY for %s: from=(%d,%d) to=(%d,%d) "
                          "pc_to=%r side=%s near=%s sfen=%s\n%s"
                          % (usi, _fc, _fr, _tc, _tr,
                             _pc_to, getattr(board, "side", "?"),
                             _near, _sfen_snap,
                             "".join(_tb_mod.format_stack()[-6:])))
                    if len(_sr_ja_empty_seen) == 30:
                        _flog("[SR-JA] piece=EMPTY が 30 件到達 — 以降のダンプは抑止")
                return usi
        _key = ("+" + _pc.lstrip("+").upper()) if _pc.startswith("+") else _pc.upper()
        _piece_ja = _SR_JA_PIECE.get(_key, "")
        if not _piece_ja:
            return usi
        return (_SR_JA_FILE[_tc - 1] + _SR_RANKS[_tr - 1]
                + _piece_ja + ("成" if _promote else ""))
    except Exception:
        return usi


def _sr_render_board(board, *, move_no=None, last_move="", winrate=None, mark=None,
                     bar_len=10, sente_time="", gote_time="",
                     start_label="", header="") -> str:
    grid = getattr(board, "board", {})
    side = getattr(board, "side", "b")
    sente_hand = getattr(board, "sente_hand", {})
    gote_hand = getattr(board, "gote_hand", {})

    _gh = _sr_hand_pieces(gote_hand); _sh = _sr_hand_pieces(sente_hand)
    _flip_on = _sr_flip_font_active()
    left = _gh + ["▽"]
    right = ["▲"] + _sh

    _cw = _SR_CW if _flip_on else _SR_CW3
    _files = _SR_FILES if _flip_on else _SR_FILES3
    center = [_sr_pad(_files, _cw)]
    for r in range(1, 10):
        row = "".join(_sr_cell(grid.get((c, r))) for c in range(9, 0, -1))
        center.append(_sr_pad(row + _SR_RANKS[r - 1], _cw))
    nb = len(center)
    _right_top = max(1, nb - len(right))
    total = max(nb, 1 + len(left), _right_top + len(right))

    _lw = max(_SR_LW, _sr_vis(gote_time) + 1) if gote_time else _SR_LW

    out = []
    global _SR_PROBE_NOTE
    if _SR_PROBE_NOTE:
        out.append("[表示] " + _SR_PROBE_NOTE)
        _SR_PROBE_NOTE = ""
    if header:
        out.extend(header.splitlines())
        if winrate is not None:
            sp = int(round(winrate))
            out.append(f"{100 - sp}% {_sr_eval_bar(winrate, bar_len)} {sp}%")
    else:
        if mark is None:
            mark = "△" if side == "b" else "▲"
        if move_no is None:
            ply = getattr(board, "ply", None)
            move_no = (ply - 1) if isinstance(ply, int) else 0
        if move_no and move_no > 0:
            out.append(f"{move_no}手目{mark}{last_move}まで")
        else:
            out.append(start_label)
        if winrate is not None:
            sp = int(round(winrate))
            out.append(f"{100 - sp}% {_sr_eval_bar(winrate, bar_len)} {sp}%")

    for i in range(total):
        cl = center[i] if 0 <= i < nb else _sr_pad("", _cw)
        if i == 0:
            if sente_time or gote_time:
                line = (_sr_pad(gote_time, _lw) + _files
                        + ((" " + sente_time) if sente_time else ""))
            else:
                line = _sr_pad("", _lw) + cl
        else:
            lc = left[i - 1] if 0 <= i - 1 < len(left) else ""
            _ri = i - _right_top
            rc = right[_ri] if 0 <= _ri < len(right) else ""
            line = _sr_pad(lc, _lw) + cl + (("  " + rc) if rc else "")
        out.append(line.rstrip())

    return "\n".join(out)


_EASY_DROP_CP = 100
_SR_WR_SLOPE = 0.0049


def _sr_meta_line(rec):
    return ""


def _sr_yose_meter(rec, b=None):
    _sc = rec.get("nnue_score_cp")
    _atk, _def = 0, 0

    if rec.get("mate_detected"):
        if isinstance(_sc, (int, float)) and _sc < 0:
            _def = 5
        else:
            _atk = 5

    if isinstance(rec.get("pv_mate_step"), int):
        if isinstance(_sc, (int, float)) and _sc < 0:
            _def = max(_def, 4)
        else:
            _atk = max(_atk, 4)

    _tek = rec.get("zyfamate_tesuki_n")
    if isinstance(_tek, int):
        if _tek == 0:
            _def = max(_def, 5)
        elif _tek == 1:
            _def = max(_def, 3)
        elif _tek == 2:
            _def = max(_def, 2)
        elif _tek == 3:
            _def = max(_def, 1)

    if rec.get("zyfamate_tsumero_hit"):
        _def = max(_def, 3)

    if rec.get("tonshi_guard_refuted"):
        _def = max(_def, 3)
    elif rec.get("tonshi_guard_fired"):
        _def = max(_def, 2)

    if isinstance(_sc, (int, float)):
        if _sc >= _MATE_CP:
            _atk = max(_atk, 4)
        elif _sc >= 5000:
            _atk = max(_atk, 2)
        elif _sc >= 2000:
            _atk = max(_atk, 1)
        if _sc <= -_MATE_CP:
            _def = max(_def, 4)
        elif _sc <= -5000:
            _def = max(_def, 2)
        elif _sc <= -2000:
            _def = max(_def, 1)

    if b is not None:
        try:
            _side = getattr(b, "side", "b")
            _opp = "w" if _side == "b" else "b"
            _sp = b._king_zone_pressure(_side)
            _op = b._king_zone_pressure(_opp)
            if _sp >= 6:
                _def = max(_def, 2)
            elif _sp >= 4:
                _def = max(_def, 1)
            if _op >= 6:
                _atk = max(_atk, 2)
            elif _op >= 4:
                _atk = max(_atk, 1)
        except Exception as _e:
            _flog(f"[ignored] _sr_yose_meter: {_e!r}")

    if _atk == 0 and _def == 0:
        return ""
    return (" 寄せ 敵玉" + _sr_segbar(_atk, cap=5) + " 自玉" + _sr_segbar(_def, cap=5))


def _sr_segbar(n, cap=8, width=5):
    if not isinstance(n, (int, float)) or cap <= 0:
        return "□" * width
    f = _clamp(int(round((n / float(cap)) * width)), 0, width)
    return "■" * f + "□" * (width - f)


def _sr_csm_line(rec):
    return ""


_sr_pv_ja_cache = {}
_sr_pv_ja_cache_order = []
_sr_pv_ja_cache_lock = threading.Lock()
_sr_pv_ja_CACHE_MAX = 32


def _sr_pv_ja(b, pv, n=999):
    if not pv:
        return []
    _seq = pv if isinstance(pv, list) else str(pv).split()
    _bserial = getattr(b, "_pv_ja_serial", None) if b is not None else None
    if _bserial is None and b is not None:
        try:
            _bserial = id(b)
        except Exception as _e:
            _flog(f"[ignored] _sr_pv_ja: {_e!r}")
    _cache_key = (_bserial, tuple(_seq[:n]), n) if _bserial is not None else None
    if _cache_key is not None:
        with _sr_pv_ja_cache_lock:
            _hit = _sr_pv_ja_cache.get(_cache_key)
            if _hit is not None:
                return _hit
    try:
        _sb = b.clone() if b is not None else None
    except Exception:
        _sb = None
    _acc = []
    for _mv in _seq[:n]:
        if not _mv or _mv in ("resign", "win"):
            break
        if _sb is not None:
            try:
                if not _bestmove_is_for_board(_mv, _sb):
                    break
            except Exception:
                break
        _j = _sr_usi_to_ja(_sb, _mv) if _sb is not None else _mv
        if _j == _mv:
            break
        _mk = ("▲" if getattr(_sb, "side", "b") == "b" else "△") if _sb is not None else ""
        _acc.append(_mk + _j)
        if _sb is not None:
            try:
                _sb.apply_usi(_mv)
            except Exception:
                _sb = None
    if _cache_key is not None:
        with _sr_pv_ja_cache_lock:
            _sr_pv_ja_cache[_cache_key] = _acc
            _sr_pv_ja_cache_order.append(_cache_key)
            while len(_sr_pv_ja_cache_order) > _sr_pv_ja_CACHE_MAX:
                _old = _sr_pv_ja_cache_order.pop(0)
                _sr_pv_ja_cache.pop(_old, None)
    return _acc


def _sv_leaf_winrate(sb):
    if not globals().get("_LIVE_PV_LEAF_MODEL_WR", False):
        return None
    try:
        r = _sv_infer_get().infer_board(sb)
        if r and "gp" in r:
            _gp_xchk_report(sb, r["gp"])
        return r["value"] * 100.0 if r else None
    except Exception:
        return None


def _model_wr_for_position(position_cmd):
    try:
        b = _board_for_position(position_cmd)
        r = _sv_infer_get().infer_board(b)
        if not r:
            return None
        v = r["value"]
        return v if getattr(b, "side", "b") == "b" else 1.0 - v
    except Exception:
        return None


_GP_XCHK_LAST = [0.0]


def _gp_xchk_report(board, model_gp, thresh=0.20, min_interval_s=30.0):
    if not _GP_XCHK_ENABLE:
        return
    now = time.time()
    if now - _GP_XCHK_LAST[0] < min_interval_s:
        return
    try:
        eng_gp = _game_phase_value_state(board)
    except Exception:
        return
    if abs(eng_gp - model_gp) >= thresh:
        _GP_XCHK_LAST[0] = now
        try:
            _flog(f"[GP-XCHK] 乖離 {abs(eng_gp - model_gp):.3f}: "
                  f"engine={eng_gp:.3f} model={model_gp:.3f} "
                  f"sfen={str(board.sfen()).strip()}")
        except Exception as _xe:
            _flog(f"[ignored] _gp_xchk_report: {_xe!r}")


_LIVE_PV_LEAF_MIN_S = 0.1


def _sr_render_pv_leaf(pos, pv, board=None):
    if not pos or not pv:
        return ""
    _seq = pv if isinstance(pv, list) else str(pv).split()
    try:
        _sb = board.clone() if board is not None else _board_for_position(pos).clone()
    except Exception:
        return ""
    _n = 0
    _last = ""
    for _mv in _seq:
        if not _mv or _mv in ("resign", "win"):
            break
        try:
            if not _bestmove_is_for_board(_mv, _sb):
                break
            _mk = "▲" if getattr(_sb, "side", "b") == "b" else "△"
            _j = _sr_usi_to_ja(_sb, _mv)
            if _j == _mv:
                break
            _sb.apply_usi(_mv)
        except Exception:
            break
        _last = _mk + _j
        _n += 1
    if _n == 0:
        return ""
    _hdr = "%d手先 %sまで" % (_n, _last)
    _win_rate = _sv_leaf_winrate(_sb)
    try:
        return _sr_render_board(_sb, header=_hdr, winrate=_win_rate)
    except Exception:
        return ""


def _sr_hjoin(left: str, right: str, gap: int = 2, align: str = "top") -> str:
    _ll = left.split("\n")
    _rl = right.split("\n")
    _w = max((_sr_vis(_l) for _l in _ll), default=0) + gap
    _n = max(len(_ll), len(_rl))
    if align == "bottom":
        _ll = [""] * (_n - len(_ll)) + _ll
        _rl = [""] * (_n - len(_rl)) + _rl
    else:
        _ll += [""] * (_n - len(_ll))
        _rl += [""] * (_n - len(_rl))
    return "\n".join((_sr_pad(_a, _w) + _b) if _b else _a
                     for _a, _b in zip(_ll, _rl))


def _sr_dl_wr(rec):
    sc = rec.get("dl_top_score")
    if not isinstance(sc, (int, float)):
        pol = rec.get("dl_display_policy")
        try:
            if pol and isinstance(pol[0][1], (int, float)):
                sc = pol[0][1]
        except (IndexError, TypeError):
            sc = None
    if isinstance(sc, (int, float)) and abs(sc) < _MATE_CP:
        return _cp_to_winrate(sc, _SR_WR_SLOPE)
    return None


def _sr_augment_arbiter(rec, status, voices):
    _p = rec.get("arb_p_pairwise")
    if _p is None:
        return status, voices
    if rec.get("arb_abstained"):
        _mv = "(棄権: %s)" % (rec.get("nnue_bestmove") or "")
    else:
        _mv = rec.get("council_winner")
    voices = list(voices) + [("裁定", _mv, _p if isinstance(_p, (int, float)) else None)]
    if rec.get("council_source") == "sv_arbiter":
        status = "裁定"
    return status, voices


def _sr_status_voices(rec, mode):
    src = rec.get("source")
    voices = []
    _wr_nnue = None
    if isinstance(rec.get("nnue_score_cp"), (int, float)):
        _wr_nnue = _cp_to_winrate(rec["nnue_score_cp"], _SR_WR_SLOPE)
    if src == "selfplay":
        status = "合議中" if rec.get("dl_used") else "探索中"
        final = rec.get("council_winner")
        if rec.get("nnue_bestmove"):
            voices.append(("NNUE", rec.get("nnue_bestmove"), _wr_nnue))
        if rec.get("dl_top_move"):
            voices.append(("DL₁", rec.get("dl_top_move"), _sr_dl_wr(rec)))
        status, voices = _sr_augment_arbiter(rec, status, voices)
        return status, final, voices
    ph = (mode == "ponderhit") or (rec.get("handler") == "ponderhit")
    if ph:
        status = "Ponderヒット"
        final = rec.get("council_winner")
        if rec.get("nnue_bestmove"):
            voices.append(("NNUE", rec.get("nnue_bestmove"), _wr_nnue))
        if rec.get("dl_top_move"):
            voices.append(("DL₁", rec.get("dl_top_move"), _sr_dl_wr(rec)))
    elif src == "book":
        status = "定跡"
        final = rec.get("council_winner")
    else:
        status = "合議中" if rec.get("dl_used") else "探索中"
        final = rec.get("council_winner")
        voices.append(("NNUE", rec.get("nnue_bestmove"), _wr_nnue))
        if rec.get("dl_top_move"):
            voices.append(("DL₁", rec.get("dl_top_move"), _sr_dl_wr(rec)))
        elif rec.get("dl_used"):
            _gap_mv = rec.get("dl_1_gap_top_move")
            if _gap_mv:
                voices.append(("DL₁", "(棄権: %s)" % _gap_mv, _sr_dl_wr(rec)))
            else:
                voices.append(("DL₁", "(棄権)", None))
    status, voices = _sr_augment_arbiter(rec, status, voices)
    return status, final, voices


def _sr_status_badges(rec):
    b = []
    if rec.get("tonshi_guard_refuted"):
        b.append("頓死回避")
    if rec.get("game_phase_surge"):
        b.append("進行急変")
    return ("  " + " ".join(b)) if b else ""


def _sr_gp_suffix(gp, dgp, zenrei=None):
    parts = []
    if isinstance(gp, (int, float)):
        parts.append("GP%.2f" % gp)
    if isinstance(dgp, (int, float)) and abs(dgp) >= 0.005:
        parts.append("%+.2f" % dgp)
    if zenrei:
        parts.append(str(zenrei))
    return (" " + " ".join(parts)) if parts else ""

def _sr_pv_fold(out, pvlist, label, tail="", annot=""):
    _first = " %s " % label
    _cont = " " * _sr_vis(_first)
    _nlines = 0
    for _pi in range(0, len(pvlist), 6):
        _nlines += 1
        if _SR_PV_FOLD_MAX is not None and _nlines > _SR_PV_FOLD_MAX:
            if out:
                out[-1] += " …"
            break
        _line = (_first if _pi == 0 else _cont) + " ".join(pvlist[_pi:_pi + 6])
        if _pi == 0 and (tail or annot):
            _line += tail + (("  " + annot) if annot else "")
        out.append(_line)

def _sr_clip(line: str, cols: int) -> str:
    if len(line) * 2 < cols:
        return line
    _budget = cols - 3
    w = 0
    for i, ch in enumerate(line):
        _cw = _sr_cw(ch)
        if w + _cw > _budget:
            return line[:i] + "…"
        w += _cw
    return line




def _sr_pred_ease_lines(rec, b, policy, ja, multi_engine=True):
    out = []
    if not policy:
        return out
    gp = rec.get("game_phase") if isinstance(rec, dict) else None
    _pred, _pred_gpd, _cands = None, None, []
    if b is not None:
        try:
            _gp0 = _game_phase_value_state(b)
        except Exception:
            _gp0 = None
        for _r, (mv, _sc) in enumerate(policy):
            if not mv or mv in ("resign", "win"):
                continue
            _d = None
            try:
                _cb = b.clone(); _cb.apply_usi(mv)
                if _gp0 is not None:
                    _d = _game_phase_value_state(_cb) - _gp0
            except Exception:
                _d = None
            _cands.append((_r, mv, _sc if isinstance(_sc, (int, float)) else None, _d))
        if _cands and multi_engine:
            def _mm(vals):
                _vv = [v for v in vals if isinstance(v, (int, float))]
                _lo = min(_vv) if _vv else 0.0
                return _lo, ((max(_vv) - _lo) if _vv else 0.0) or 1.0
            _slo, _srg = _mm([c[2] for c in _cands])
            _dlo, _drg = _mm([c[3] for c in _cands])
            _nmax = max(1, len(policy) - 1)
            _ph = gp if isinstance(gp, (int, float)) else (_gp0 if _gp0 is not None else 0.5)
            if _ph >= 0.66:    _w = (0.75, 0.10, 0.15)
            elif _ph >= 0.33:  _w = (0.60, 0.25, 0.15)
            else:              _w = (0.45, 0.40, 0.15)
            _bs = None
            for (_r, mv, _sc, _d) in _cands:
                _sn = ((_sc - _slo) / _srg) if isinstance(_sc, (int, float)) else 0.0
                _dn = ((_d - _dlo) / _drg) if isinstance(_d, (int, float)) else 0.0
                _rn = (_nmax - _r) / _nmax
                _s = _w[0] * _sn + _w[1] * _dn + _w[2] * _rn
                if _bs is None or _s > _bs:
                    _bs, _pred, _pred_gpd = _s, mv, _d
    if _pred:
        _pl = " 予想最善手 " + ja(_pred)
        if isinstance(_pred_gpd, (int, float)) and abs(_pred_gpd) >= 0.005:
            _pl += "(GP%+.2f)" % _pred_gpd
        out.append(_pl)
    _wrs = [(_cp_to_winrate(c[2], _SR_WR_SLOPE), c)
            for c in _cands if isinstance(c[2], (int, float))]
    if len(_wrs) >= 2:
        _wrs.sort(key=lambda t: -t[0])
        _shp = rec.get("sharpness") if isinstance(rec, dict) else None
        if _shp is not None and _shp >= 0.65:
            _ease_lbl = "難所"
        elif _shp is not None and _shp <= 0.30:
            _ease_lbl = "明確"
        else:
            _ease_lbl = "標準"
        _best_cp = _wrs[0][1][2]
        _elig = [c for (_w2, c) in _wrs if c[2] >= _best_cp - _EASY_DROP_CP]
        if _ease_lbl in ("明確", "難所") or len(_elig) < 2:
            _move = _wrs[0][1][1]
        else:
            _move = min(_elig, key=lambda c: (abs(c[3]) if isinstance(c[3], (int, float)) else 1.0,
                                              -c[2]))[1]
        out.append(" 指しやすさ %s %s" % (ja(_move), _ease_lbl))
    elif _wrs:
        out.append(" 指しやすさ " + ja(_wrs[0][1][1]) + " 一本道")
    return out


def _sr_multipv_lines(policy, ja):
    out = []
    if not policy:
        return out
    _circ = "①②③④⑤⑥⑦⑧⑨⑩"
    _best_sc = None
    try:
        _b0 = policy[0][1]
        if isinstance(_b0, (int, float)) and abs(_b0) < _MATE_CP:
            _best_sc = _b0
    except (IndexError, TypeError):
        _best_sc = None
    _rows = []
    for _i, (mv, sc) in enumerate(policy):
        if _i == 0:
            continue
        if not mv or mv in ("resign", "win"):
            continue
        if len(_rows) >= _SR_MULTIPV_MAX:
            break
        _n = _circ[_i] if _i < len(_circ) else ("%2d." % (_i + 1))
        if isinstance(sc, (int, float)):
            if sc >= _MATE_CP:
                _scs = "詰"
            elif sc <= -_MATE_CP:
                _scs = "被詰"
            elif _best_sc is not None:
                _dpt = int(round((_cp_to_winrate(sc, _SR_WR_SLOPE)
                                  - _cp_to_winrate(_best_sc, _SR_WR_SLOPE)) * 100))
                _scs = ("%+d%%" % _dpt) if _dpt != 0 else ""
            else:
                _scs = "%d%%" % int(round(_cp_to_winrate(sc, _SR_WR_SLOPE) * 100))
        else:
            _scs = ""
        _rows.append(" " + _sr_pad(_n, 3) + " " + _sr_pad(ja(mv), 12) + _scs)
    if _rows:
        out.append(" MultiPV")
        out.extend(_rows)
    return out


def _sr_linger_split(hold_rec, hold_pos, hold_policy, cur_side=None):
    try:
        b = _board_for_position(hold_pos)
    except Exception:
        b = None
    _smk = ("▲" if getattr(b, "side", "b") == "b" else "△") if b is not None else ""
    _wr_flip = (cur_side is not None and b is not None
                and getattr(b, "side", "b") != cur_side)

    def _ja(mv):
        if not mv or mv in ("resign", "win"):
            return mv or "—"
        if b is not None and not _bestmove_is_for_board(mv, b):
            return mv
        return _smk + (_sr_usi_to_ja(b, mv) if b is not None else mv)

    _rec = hold_rec if isinstance(hold_rec, dict) else {}
    head = []
    _dmv = _rec.get("dl_top_move")
    if (_dmv and isinstance(_dmv, str) and not _dmv.startswith("(")
            and b is not None and not _bestmove_is_for_board(_dmv, b)):
        _dmv = None
    if _dmv and isinstance(_dmv, str) and not _dmv.startswith("("):
        _dwr = _sr_dl_wr(_rec)
        if _wr_flip and isinstance(_dwr, (int, float)):
            _dwr = 1.0 - _dwr
        _w = ("%3.0f%%" % (_dwr * 100)) if isinstance(_dwr, (int, float)) else ""
        head.append(" " + _sr_pad("DL₁", 5) + _sr_pad(_ja(_dmv), 11) + _w)
    head.extend(_sr_pred_ease_lines(_rec, b, hold_policy, _ja, multi_engine=True))
    return head, _sr_multipv_lines(hold_policy, _ja)


def _sr_linger_lines(hold_rec, hold_pos, hold_policy):
    _h, _m = _sr_linger_split(hold_rec, hold_pos, hold_policy)
    return _h + _m




def _sr_render_think(rec, pos, policy=None, pv=None, clock=None,
                     zenrei=None, dgp_ema=None,
                     gp_ema=None, mode=None, hold=None) -> str:
    _ = clock
    try:
        b = _board_for_position(pos)
    except Exception:
        b = None

    _smk = ("▲" if getattr(b, "side", "b") == "b" else "△") if b is not None else ""
    def _ja(mv):
        if not mv or mv in ("resign", "win"):
            return mv or "—"
        if b is not None and not _bestmove_is_for_board(mv, b):
            return mv
        return _smk + (_sr_usi_to_ja(b, mv) if b is not None else mv)

    def _fmt_wr(v):
        return ("%3.0f%%" % (v * 100)) if isinstance(v, (int, float)) else ""

    _mode = ("ponderhit" if (mode == "ponderhit"
                             or (isinstance(rec, dict) and rec.get("handler") == "ponderhit"))
             else None)
    _hold_head, _hold_mpv = [], []
    if hold is not None and not policy:
        try:
            _hold_head, _hold_mpv = _sr_linger_split(
                hold[0], hold[1], hold[2],
                cur_side=(getattr(b, "side", "b") if b is not None else None))
        except Exception as _e:
            _flog(f"[ignored] _sr_render_think: {_e!r}")

    status, final, voices = _sr_status_voices(rec, _mode)
    _gp_st = rec.get("game_phase") if isinstance(rec, dict) else None
    if _gp_st is None and isinstance(gp_ema, (int, float)):
        _gp_st = gp_ema
    _gpd_disp = dgp_ema if isinstance(dgp_ema, (int, float)) else rec.get("game_phase_delta")
    out = ["─" * _SR_RULE, " " + status + _sr_gp_suffix(_gp_st, _gpd_disp, zenrei) + _sr_status_badges(rec)]
    for lbl, mv, w in voices:
        if not mv:
            continue
        if isinstance(mv, str) and mv.startswith("(棄権: ") and mv.endswith(")"):
            _disp = "(棄権: %s)" % _ja(mv[len("(棄権: "):-1])
        elif isinstance(mv, str) and mv.startswith("(棄権"):
            _disp = mv
        else:
            _disp = _ja(mv)
        out.append(" " + _sr_pad(lbl, 5) + _sr_pad(_disp, 11) + _fmt_wr(w))
    if isinstance(rec, dict) and rec.get("arb_p_pairwise") is not None:
        _ap = rec.get("arb_p_pairwise")
        _al = " 裁定 P=%s Tier=%s" % (_fmt_wr(_ap), rec.get("arb_tier") or "?")
        if rec.get("arb_abstained"):
            _al += " 棄権"
        _tau = rec.get("arb_tau_eff")
        if isinstance(_tau, (int, float)):
            _al += " τ=%.2f" % _tau
        out.append(_al)
        _qn, _qd = rec.get("arb_q_nnue"), rec.get("arb_q_dl")
        if isinstance(_qn, (int, float)) or isinstance(_qd, (int, float)):
            out.append("  q(NNUE)=%s q(DL₁)=%s" % (_fmt_wr(_qn), _fmt_wr(_qd)))
    out.extend(_hold_head)
    out.extend(_sr_pred_ease_lines(rec, b, policy, _ja, multi_engine=True))
    _sc = rec.get("nnue_score_cp")
    _is_mate = bool(rec.get("mate_detected")) or (isinstance(_sc, (int, float)) and abs(_sc) >= _MATE_CP)
    _pvmoves = _sr_pv_ja(b, pv)
    _lbl = ("被詰" if (_is_mate and isinstance(_sc, (int, float)) and _sc < 0) else ("詰" if _is_mate else "ツリー"))
    _annot = ""
    if _pvmoves:
        _mt = (" %s手" % rec.get("pv_mate_step")) if (_is_mate and rec.get("pv_mate_step")) else ""
        _sr_pv_fold(out, _pvmoves, _lbl, tail=_mt, annot=_annot)
    elif _is_mate:
        _msm = rec.get("mate_solver_move")
        out.append((" %s " % _lbl)
                   + ((("%s手" % rec.get("pv_mate_step")) if rec.get("pv_mate_step") else "あり")
                      + ((" " + _ja(_msm)) if _msm else "")))
    elif final:
        out.append(" ツリー " + _ja(final)
                   + (("  (%s/詰めろ圏)" % ("勝勢" if _sc > 0 else "劣勢"))
                      if isinstance(_sc, (int, float)) and abs(_sc) >= 2000 else "")
                   + (("  " + _annot) if _annot else ""))
    if b is not None:
        _os = getattr(b, "side", "b")
        _kpos = b._king_pos(_os)
        _king_in = _kpos is not None and b._in_promotion_zone(_os, _kpos[1])
        if _king_in or rec.get("nyugyoku"):
            _opts, _oin = b.nyugyoku_score(_os)
            _need = 28 if _os == "b" else 27
            _decl = "宣言可!" if b.can_declare_win(_os) else ("宣言まで+%d点" % max(0, _need - _opts))
            out.append(" 入玉 自%d点 在域%d %s" % (_opts, _oin, _decl))
    _mm = _sr_yose_meter(rec, b)
    if _mm:
        out.append(_mm)
    _csm = _sr_csm_line(rec)
    if _csm:
        out.append(_csm)
    _meta = _sr_meta_line(rec)
    if _meta:
        out.append(" " + _meta)
    _mpv = _sr_multipv_lines(policy, _ja)
    out.extend(_mpv if _mpv else _hold_mpv)
    return "\n".join(out)


def _init_windows_console() -> None:
    if os.name != "nt":
        return
    try:
        import ctypes
        k = ctypes.windll.kernel32
        k.SetConsoleOutputCP(65001)
        try:
            k.SetConsoleCP(65001)
        except Exception as _e:
            _flog(f"[ignored] _init_windows_console: {_e!r}")
        for _hid in (-11, -12):
            h = k.GetStdHandle(_hid)
            if h and h != -1:
                mode = ctypes.c_uint(0)
                if k.GetConsoleMode(h, ctypes.byref(mode)):
                    k.SetConsoleMode(h, mode.value | 0x0004 | 0x0001)
    except Exception as _e:
        _flog(f"[ignored] _init_windows_console: {_e!r}")


os.environ.setdefault("PIP_DISABLE_PIP_VERSION_CHECK", "1")
os.environ.setdefault("PIP_NO_PYTHON_VERSION_WARNING", "1")


def _py_bootstrap_msg(msg):
    _flog("[py-bootstrap] " + msg)
    try:
        print("info string [setup] " + msg, flush=True)
    except OSError as _e:
        _flog(f"[ignored] _py_bootstrap_msg: {_e!r}")


def _run_pip_logged(cmd, timeout=3600, tag="pip", heartbeat_sec=15):
    import time as _time

    cmd = [c for c in cmd if c not in ("-q", "--quiet")]

    _flog(f"[{tag}] 実行開始: {' '.join(cmd)}")
    t0 = _time.monotonic()
    tail = []
    try:
        proc = subprocess.Popen(
            cmd, stdout=subprocess.PIPE, stderr=subprocess.STDOUT,
            text=True, bufsize=1, universal_newlines=True)
    except Exception as e:
        _flog(f"[{tag}] 起動失敗: {e!r}")
        return False, tail

    last_line_ts = _time.monotonic()
    last_heartbeat_ts = last_line_ts

    def _reader():
        nonlocal last_line_ts
        try:
            for line in proc.stdout:
                line = line.rstrip("\n")
                if line.strip():
                    _flog(f"[{tag}] {line}")
                    tail.append(line)
                    if len(tail) > 40:
                        del tail[0]
                last_line_ts = _time.monotonic()
        except Exception as e:
            _flog(f"[{tag}] 出力読み取り中にエラー: {e!r}")

    reader_thread = _spawn(f'{tag}-reader', _reader, start_now=False)
    reader_thread.start()

    while True:
        try:
            proc.wait(timeout=1)
            break
        except subprocess.TimeoutExpired:
            now = _time.monotonic()
            if now - t0 > timeout:
                _flog(f"[{tag}] タイムアウト ({timeout}s) — プロセスを終了します")
                try:
                    proc.kill()
                except Exception as _e:
                    _flog(f"[ignored] _run_pip_logged: {_e!r}")
                try:
                    proc.wait(timeout=5)
                except Exception as _e:
                    _flog(f"[ignored] _run_pip_logged: {_e!r}")
                reader_thread.join(timeout=5)
                _flog(f"[{tag}] 中断 (経過 {now - t0:.0f}s)")
                return False, tail
            if now - last_heartbeat_ts >= heartbeat_sec:
                idle = now - last_line_ts
                _flog(f"[{tag}] 実行中… (経過 {now - t0:.0f}s / "
                      f"出力なし {idle:.0f}s — ダウンロード/展開中で無出力の"
                      f"区間は正常なことがあります)")
                last_heartbeat_ts = now

    reader_thread.join(timeout=5)
    elapsed = _time.monotonic() - t0
    ok = proc.returncode == 0
    _flog(f"[{tag}] 終了: returncode={proc.returncode} 経過={elapsed:.0f}s "
          f"({'成功' if ok else '失敗'})")
    return ok, tail


def _auto_install_ok():
    return False


def _find_system_python():
    import shutil
    import glob as _g
    cands = []
    envp = os.environ.get("PYFAMATE_PYTHON", "").strip().strip('"')
    if envp:
        cands.append([envp])
    for cmd in ("python", "python3"):
        p = shutil.which(cmd)
        if p:
            cands.append([p])
    if shutil.which("py"):
        cands.append([shutil.which("py"), "-3"])
    for pat in (os.path.expandvars(r"%LOCALAPPDATA%\Programs\Python\Python3*\python.exe"),
                r"C:\Python3*\python.exe",
                r"C:\Program Files\Python3*\python.exe",
                os.path.expanduser(r"~\miniconda3\python.exe"),
                os.path.expanduser(r"~\anaconda3\python.exe"),
                r"C:\ProgramData\miniconda3\python.exe",
                r"C:\ProgramData\anaconda3\python.exe",
                os.path.expanduser(r"~\scoop\apps\python*\current\python.exe"),
                os.path.expanduser(r"~\.pyenv\pyenv-win\versions\3*\python.exe")):
        cands.extend([x] for x in sorted(_g.glob(pat), reverse=True))
    for c in cands:
        try:
            r = subprocess.run(
                c + ["-c", "import sys; "
                     "print(sys.executable if sys.version_info >= (3, 9) else '')"],
                capture_output=True, text=True, timeout=15)
            exe = (r.stdout or "").strip().splitlines()[-1] if r.returncode == 0 else ""
            if exe and os.path.exists(exe):
                return [exe]
        except Exception:
            continue
    return None


def _ensure_system_python():
    pycmd = _find_system_python()
    if pycmd:
        return pycmd
    import shutil
    if not _auto_install_ok():
        _py_bootstrap_msg("Python が見つかりません (PYFAMATE_NO_AUTO_INSTALL=1 のため"
                          "自動導入はしません。PYFAMATE_PYTHON でパス指定できます)")
        return None
    if os.name == "nt" and shutil.which("winget"):
        _py_bootstrap_msg("Python が見つかりません — winget で自動インストール中… (数分かかります)")
        try:
            subprocess.check_call(
                ["winget", "install", "-e", "--id", "Python.Python.3.12",
                 "--silent", "--accept-source-agreements",
                 "--accept-package-agreements"],
                timeout=1200)
        except Exception as e:
            _flog(f"[py-bootstrap] winget failed: {e!r}")
        pycmd = _find_system_python()
        if pycmd:
            _py_bootstrap_msg("Python の自動インストールに成功しました")
            return pycmd
    _py_bootstrap_msg("Python を用意できませんでした。https://www.python.org/downloads/ から"
                      "インストールして (Add to PATH にチェック)、再度お試しください")
    return None


def _pip_cmd(pycmd):
    import shutil

    def _has_pip():
        try:
            return subprocess.run(pycmd + ["-m", "pip", "--version"],
                                  stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL,
                                  timeout=30).returncode == 0
        except Exception:
            return False
    if _has_pip():
        return pycmd + ["-m", "pip", "install", "-q"]
    uv = shutil.which("uv")
    if uv:
        _py_bootstrap_msg("pip 未導入 — 既存の uv を利用します")
        return [uv, "pip", "install", "-q", "--python", pycmd[0]]
    if not _auto_install_ok():
        _py_bootstrap_msg("pip/uv とも見つかりません (PYFAMATE_NO_AUTO_INSTALL=1 のため"
                          "自動導入はしません)")
        return None
    _py_bootstrap_msg("pip 未導入 — ensurepip で導入中…")
    try:
        subprocess.check_call(pycmd + ["-m", "ensurepip", "--upgrade", "--default-pip"],
                              stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL,
                              timeout=300)
    except Exception as e:
        _flog(f"[py-bootstrap] ensurepip failed: {e!r}")
    if _has_pip():
        return pycmd + ["-m", "pip", "install", "-q"]
    _py_bootstrap_msg("ensurepip 不可 — get-pip.py を取得して導入中…")
    try:
        import urllib.request
        import tempfile
        fp = os.path.join(tempfile.gettempdir(), "get-pip.py")
        _flog("[get-pip] ダウンロード開始: https://bootstrap.pypa.io/get-pip.py")
        urllib.request.urlretrieve("https://bootstrap.pypa.io/get-pip.py", fp)
        _flog(f"[get-pip] ダウンロード完了: {fp}")
        _ok, _tail = _run_pip_logged(pycmd + [fp], timeout=600, tag="get-pip")
        if not _ok:
            tail_preview = " | ".join(_tail[-5:]) if _tail else "(出力なし)"
            _flog(f"[get-pip] インストール失敗。末尾ログ: {tail_preview}")
    except Exception as e:
        _flog(f"[py-bootstrap] get-pip failed: {e!r}")
    if _has_pip():
        return pycmd + ["-m", "pip", "install", "-q"]
    _py_bootstrap_msg("pip を導入できませんでした (ネットワーク/権限をご確認ください)")
    return None


def _pip_install(packages):
    if not packages:
        return True
    packages = list(packages)
    import shutil
    if _IS_FROZEN:
        pycmd = _ensure_system_python()
        if not pycmd:
            return False
    else:
        pycmd = [sys.executable]
    pipcmd = _pip_cmd(pycmd)
    if not pipcmd:
        return False
    extra = []
    if (any(str(p).startswith("torch") for p in packages)
            and shutil.which("nvidia-smi")):
        extra = ["--index-url", "https://download.pytorch.org/whl/cu126"]
    _py_bootstrap_msg("パッケージ導入中: " + " ".join(packages) +
                      (" (CUDA index 指定あり)" if extra else "") +
                      " — 進捗は diagnosis.txt の [pip-install] に記録されます")
    _ok, _tail = _run_pip_logged(pipcmd + packages + extra, timeout=3600,
                                 tag="pip-install")
    if not _ok:
        tail_preview = " | ".join(_tail[-5:]) if _tail else "(出力なし)"
        _flog(f"[pip-install] 失敗。末尾ログ: {tail_preview}")
        return False
    if _IS_FROZEN:
        try:
            r = subprocess.run(
                pycmd + ["-c", "import sys; print('\\n'.join(sys.path))"],
                capture_output=True, text=True, timeout=10)
            for line in (r.stdout or "").strip().splitlines():
                if line and line not in sys.path:
                    sys.path.insert(0, line)
        except Exception as _e:
            _flog(f"[ignored] _pip_install: {_e!r}")
    return True


_FLIP_AUTO_DONE = False


def _flip_installed_font_path() -> str:
    name = _FLIP_FONT_NAME + ".ttf"
    if os.name == "nt":
        return os.path.join(os.environ.get("LOCALAPPDATA", ""), "Microsoft", "Windows", "Fonts", name)
    if sys.platform == "darwin":
        return os.path.join(os.path.expanduser("~"), "Library", "Fonts", name)
    return os.path.join(os.path.expanduser("~"), ".local", "share", "fonts", name)


def _flip_ensure_installed() -> None:
    global _FLIP_AUTO_DONE
    if _FLIP_AUTO_DONE:
        return
    _FLIP_AUTO_DONE = True
    _flip_env = os.environ.get("LIVE_FLIP_FONT_AUTO", "").strip().lower()
    if _flip_env in ("0", "false", "no", "off"):
        return
    if not _flip_env and not _auto_install_ok():
        _flog("[flip-auto] PYFAMATE_NO_AUTO_INSTALL=1 のためフォント自動導入をスキップ"
              " (LIVE_FLIP_FONT_AUTO=1 で個別に許可可能)")
        return

    def _note(msg):
        _flog("[flip-auto] " + msg)

    def _activate_user_machine_native():
        if os.name != "nt":
            return
        try:
            _flip_set_user_env_live_flip_font()
        except Exception as e:
            _flog(f"[flip-auto] HKCU\\Environment 設定失敗 (非致命): {e!r}")
        try:
            _flip_register_console_face()
        except Exception as e:
            _flog(f"[flip-auto] HKCU\\Console 登録失敗 (非致命): {e!r}")

    def _font_needs_rebuild(path):
        try:
            from fontTools.ttLib import TTFont as _TF
            _f = _TF(path)
            _cm = _f.getBestCmap()
            _f.close()
            return 0xE000 not in _cm
        except Exception:
            return True

    def _work():
        try:
            engine_dir = os.path.dirname(os.path.abspath(__file__))
            try:
                _legacy_marker = os.path.join(_BASE_DIR, ".fonttools_installed")
                if os.path.exists(_legacy_marker):
                    os.remove(_legacy_marker)
                    _note(".fonttools_installed (旧マーカー) を掃除 — 以後生成しません")
            except Exception as _e:
                _flog(f"[ignored] _flip_ensure_installed/_work: {_e!r}")

            def _ft_import_ok():
                try:
                    import fontTools
                    return True
                except Exception:
                    return False

            _ft_ok = _ft_import_ok()
            if not _ft_ok and _IS_FROZEN:
                try:
                    _sys_py = _find_system_python()
                    if _sys_py:
                        _r = subprocess.run(
                            _sys_py + ["-c", "import sys; print('\\n'.join(sys.path))"],
                            capture_output=True, text=True, timeout=10)
                        for _ln in (_r.stdout or "").strip().splitlines():
                            if _ln and _ln not in sys.path:
                                sys.path.append(_ln)
                except Exception as _e:
                    _flog(f"[ignored] _flip_ensure_installed/_work: {_e!r}")
                _ft_ok = _ft_import_ok()
            if not _ft_ok and os.path.exists(_flip_installed_font_path()):
                _note("fontTools import 不可 (フォント導入済み) — pip 再実行はスキップし"
                      "既存フォントをそのまま使用します。")
                if os.name == "nt":
                    _note(_flip_setup_windows_terminal(engine_dir))
                    _activate_user_machine_native()
                elif sys.platform.startswith("linux"):
                    _note(_flip_setup_fontconfig_fallback())
                return
            if not _ft_ok:
                _note("fontTools 未導入 — 自動インストール中…")
                if not _pip_install(["fonttools"]):
                    _note("fontTools の自動インストールに失敗。"
                          "フォント未導入のため生成もできません。")
                    return
                if not _ft_import_ok():
                    _note("fontTools のインストール後もインポート不可。")
                    return

            if os.path.exists(_flip_installed_font_path()):
                if not _font_needs_rebuild(_flip_installed_font_path()):
                    _flog("[flip-auto] 導入済 (PUA OK): %s" % _flip_installed_font_path())
                    if os.name == "nt":
                        _note(_flip_setup_windows_terminal(engine_dir))
                        _activate_user_machine_native()
                    elif sys.platform.startswith("linux"):
                        _note(_flip_setup_fontconfig_fallback())
                    return
                _note("[flip-auto] 旧 cmap (U+F900) 検出 — PUA (U+E000) へ再生成")
            if not _flip_find_cjk_font():
                _note("システムに CJK フォント(メイリオ/Noto/IPA 等)が見つからず生成不可。")
                return
            out = os.path.join(engine_dir, "_fontcheck", _FLIP_FONT_NAME + ".ttf")
            os.makedirs(os.path.dirname(out), exist_ok=True)
            _flip_build_font(out, mode="plain")
            _note(_flip_install_font(out))
            if os.name == "nt":
                _note(_flip_setup_windows_terminal(engine_dir))
                _activate_user_machine_native()
                _note("反転フォントを自動導入。Pyfamate が自プロセス・WT・HKCU を全自動設定。"
                      "次回起動から反転表示。")
            else:
                _note("反転フォントを自動導入。Linux は fontconfig フォールバックで自動適用 "
                      "(新しい端末ウィンドウから)。mac は端末フォントを %s に手動設定。"
                      "反映確認: `flip-font --check`。" % _FLIP_FONT_NAME)
        except Exception as e:
            _emsg = repr(e)
            _known_quiet = (
                "glyphDataFormat" in _emsg
                or "cu2qu" in _emsg
                or "cubic Bezier" in _emsg
            )
            if _known_quiet:
                _note("[flip-auto] 既知の font 変換制約でスキップ (対局には無影響)")
            else:
                _note("スキップ (例外): %r" % e)

    _spawn('flip-auto', _work)



def _tr_field_meta(carry=False, pos_bound=False, emergency_keep=True):
    return {"carry": carry, "pos_bound": pos_bound, "emergency_keep": emergency_keep}


@dataclasses.dataclass
class ThinkRec:
    council_winner:       "str | None" = dataclasses.field(default=None,
        metadata=_tr_field_meta(carry=False, pos_bound=True, emergency_keep=False))
    nnue_bestmove:        "str | None" = dataclasses.field(default=None,
        metadata=_tr_field_meta(carry=False, pos_bound=True, emergency_keep=False))
    dl_top_move:          "str | None" = dataclasses.field(default=None,
        metadata=_tr_field_meta(carry=True,  pos_bound=True))
    dl_1_gap_top_move:    "str | None" = dataclasses.field(default=None,
        metadata=_tr_field_meta(carry=True,  pos_bound=True))
    dl_top_score:         "float | None" = dataclasses.field(default=None,
        metadata=_tr_field_meta(carry=True))
    dl_display_policy:    "list | None" = dataclasses.field(default=None,
        metadata=_tr_field_meta(carry=True,  pos_bound=True))
    dl_used:              "bool | None" = dataclasses.field(default=None,
        metadata=_tr_field_meta(carry=True))
    nyugyoku:             "bool | None" = dataclasses.field(default=None,
        metadata=_tr_field_meta(carry=True))
    nnue_score_cp:        "float | None" = dataclasses.field(default=None,
        metadata=_tr_field_meta(carry=True))
    game_phase:           "float | None" = dataclasses.field(default=None,
        metadata=_tr_field_meta(carry=True))
    game_phase_delta:     "float | None" = dataclasses.field(default=None,
        metadata=_tr_field_meta(carry=True))
    sharpness:            "float | None" = dataclasses.field(default=None,
        metadata=_tr_field_meta(carry=True))
    mate_detected:        "bool | None" = dataclasses.field(default=None,
        metadata=_tr_field_meta(carry=True))
    pv_mate_step:         "int | None" = dataclasses.field(default=None,
        metadata=_tr_field_meta(carry=True))
    mate_solver_move:     "str | None" = dataclasses.field(default=None,
        metadata=_tr_field_meta(carry=True,  pos_bound=True))
    zyfamate_tesuki_n:    "int | None" = dataclasses.field(default=None,
        metadata=_tr_field_meta(carry=True))
    zyfamate_tsumero_hit: "bool | None" = dataclasses.field(default=None,
        metadata=_tr_field_meta(carry=True))
    tonshi_guard_refuted: "bool | None" = dataclasses.field(default=None,
        metadata=_tr_field_meta(carry=True))
    tonshi_guard_fired:   "bool | None" = dataclasses.field(default=None,
        metadata=_tr_field_meta(carry=True))
    game_phase_surge:     "bool | None" = dataclasses.field(default=None,
        metadata=_tr_field_meta(carry=True))
    source:               "str | None" = dataclasses.field(default=None,
        metadata=_tr_field_meta(carry=False, emergency_keep=False))
    _orig_source:         "str | None" = dataclasses.field(default=None,
        metadata=_tr_field_meta(carry=True))
    handler:              "str | None" = dataclasses.field(default=None,
        metadata=_tr_field_meta(carry=True))
    ply:                  "int | None" = dataclasses.field(default=None,
        metadata=_tr_field_meta(carry=False, emergency_keep=False))
    elapsed_ms:           "float | None" = dataclasses.field(default=None,
        metadata=_tr_field_meta(carry=False, emergency_keep=False))
    depth_quality:        "float | None" = dataclasses.field(default=None,
        metadata=_tr_field_meta(carry=True))
    confidence_dq:        "float | None" = dataclasses.field(default=None,
        metadata=_tr_field_meta(carry=True))
    confidence:           "float | None" = dataclasses.field(default=None,
        metadata=_tr_field_meta(carry=True))
    momentum:             "float | None" = dataclasses.field(default=None,
        metadata=_tr_field_meta(carry=True))
    nnue_depth:           "int | None" = dataclasses.field(default=None,
        metadata=_tr_field_meta(carry=True))
    regime_label:         "str | None" = dataclasses.field(default=None,
        metadata=_tr_field_meta(carry=True))
    regime_conviction:    "float | None" = dataclasses.field(default=None,
        metadata=_tr_field_meta(carry=True))

    _extra: dict = dataclasses.field(default_factory=dict,
        metadata=_tr_field_meta(carry=False, emergency_keep=True))

    _DOTTED_TO_ATTR = {}
    _ATTR_TO_DOTTED = {}

    @classmethod
    def _declared_attrs(cls):
        _da = getattr(cls, "_DECLARED_ATTRS_CACHE", None)
        if _da is None:
            _da = set(f.name for f in dataclasses.fields(cls) if f.name != "_extra")
            cls._DECLARED_ATTRS_CACHE = _da
        return _da

    @classmethod
    def from_dict(cls, d):
        if d is None:
            return None
        if isinstance(d, cls):
            return d
        if not isinstance(d, dict):
            return None
        attrs = cls._declared_attrs()
        kw = {}
        extra = {}
        for _k, _v in d.items():
            if _k in cls._DOTTED_TO_ATTR:
                kw[cls._DOTTED_TO_ATTR[_k]] = _v
            elif _k in attrs:
                kw[_k] = _v
            else:
                extra[_k] = _v
        rec = cls(**kw)
        if extra:
            rec._extra = extra
        return rec

    def to_dict(self):
        d = {}
        for _f in dataclasses.fields(self):
            if _f.name == "_extra":
                continue
            _v = getattr(self, _f.name)
            if _v is None:
                continue
            _k = self._ATTR_TO_DOTTED.get(_f.name, _f.name)
            d[_k] = _v
        if self._extra:
            for _k, _v in self._extra.items():
                if _v is not None and _k not in d:
                    d[_k] = _v
        return d

    def get(self, key, default=None):
        if key in self._DOTTED_TO_ATTR:
            _v = getattr(self, self._DOTTED_TO_ATTR[key], None)
            return _v if _v is not None else default
        if key in self._declared_attrs():
            _v = getattr(self, key, None)
            return _v if _v is not None else default
        return self._extra.get(key, default) if self._extra else default

    def __getitem__(self, key):
        _v = self.get(key)
        if _v is None and (not self._extra or key not in self._extra):
            raise KeyError(key)
        return _v

    def __setitem__(self, key, value):
        if key in self._DOTTED_TO_ATTR:
            setattr(self, self._DOTTED_TO_ATTR[key], value)
            return
        if key in self._declared_attrs():
            setattr(self, key, value)
        else:
            self._extra[key] = value

    def __contains__(self, key):
        return self.get(key) is not None or (self._extra and key in self._extra)

    def setdefault(self, key, default=None):
        _v = self.get(key)
        if _v is None:
            self[key] = default
            return default
        return _v

    def keys(self):
        _seen = set()
        for _f in dataclasses.fields(self):
            if _f.name == "_extra":
                continue
            if getattr(self, _f.name) is not None:
                _k = self._ATTR_TO_DOTTED.get(_f.name, _f.name)
                _seen.add(_k)
                yield _k
        if self._extra:
            for _k in self._extra:
                if _k not in _seen and self._extra[_k] is not None:
                    yield _k

    def carry_from(self, prev, same_pos):
        if prev is None:
            return
        if isinstance(prev, dict):
            prev = type(self).from_dict(prev)
        if prev is None:
            return
        for _f in dataclasses.fields(self):
            if _f.name == "_extra":
                continue
            _m = _f.metadata
            if not _m.get("carry"):
                continue
            if (not same_pos) and _m.get("pos_bound"):
                continue
            if getattr(self, _f.name) is None:
                _pv = getattr(prev, _f.name)
                if _pv is not None:
                    setattr(self, _f.name, _pv)
        if same_pos and prev._extra:
            for _k, _v in prev._extra.items():
                if _v is not None and self._extra.get(_k) is None:
                    self._extra[_k] = _v

    def carry_emergency_from(self, prev):
        if prev is None:
            return
        if isinstance(prev, dict):
            prev = type(self).from_dict(prev)
        if prev is None:
            return
        for _f in dataclasses.fields(self):
            if _f.name == "_extra":
                continue
            if not _f.metadata.get("emergency_keep", True):
                continue
            if getattr(self, _f.name) is None:
                _pv = getattr(prev, _f.name)
                if _pv is not None:
                    setattr(self, _f.name, _pv)
        if prev._extra:
            for _k, _v in prev._extra.items():
                if _v is not None and self._extra.get(_k) is None:
                    self._extra[_k] = _v



class _LiveState:
    LIVE_EMPTY  = "LIVE_EMPTY"
    LIVE_ACTIVE = "LIVE_ACTIVE"
    SETTLED     = "SETTLED"
    LINGER      = "LINGER"



class _LiveFeed:
    __slots__ = ("_pos", "_board", "_mode", "_source", "_fresh_pv",
                 "_last_emit", "_pos_hash8", "_throttle_s")

    def __init__(self, pos, board, mode, source):
        self._pos = pos
        try:
            self._board = board.clone() if board is not None else None
        except Exception as _e:
            _flog(f"[ignored] _LiveFeed.__init__ clone: {_e!r}")
            self._board = board
        self._mode = mode
        self._source = source
        self._fresh_pv = False
        self._last_emit = 0.0
        self._throttle_s = 0.2 if mode == "selfplay" else 0.0
        try:
            self._pos_hash8 = hashlib.md5(
                (pos or "").encode()).hexdigest()[:8] if pos else None
        except Exception:
            self._pos_hash8 = None

    def paint_placeholder(self, rec_seed=None, mode=None):
        if not _LIVE._ready():
            return
        prev_think = _LIVE._think
        prev = prev_think[0] if prev_think is not None else None
        if isinstance(rec_seed, ThinkRec):
            rec = rec_seed
        else:
            rec = ThinkRec.from_dict(rec_seed) if rec_seed else ThinkRec()
        rec.carry_from(prev, same_pos=False)
        _LIVE.set_think(rec, self._pos, None, live=True, mode=mode)

    def on_nnue(self, pv, score_cp):
        if not _LIVE._ready():
            return
        _now = time.perf_counter()
        if self._throttle_s > 0 and (_now - self._last_emit) < self._throttle_s:
            return
        walked_pv = None
        if pv:
            walked_pv = self._walk_pv(pv)
            if walked_pv is None:
                return
            self._fresh_pv = True
        elif not self._fresh_pv:
            return
        try:
            _LIVE.update_think_pv(pv=walked_pv, score_cp=score_cp, pos=self._pos)
            self._last_emit = _now
        except Exception as _e:
            _flog(f"[ignored] _LiveFeed.on_nnue: {_e!r}")

    def on_dl(self, policy):
        if not _LIVE._ready() or not policy:
            return
        if self._board is not None:
            policy = [(m, s) for (m, s) in policy
                      if _bestmove_is_for_board(m, self._board)] or None
        if policy:
            try:
                _LIVE.update_think_pv(policy=policy, pos=self._pos)
            except Exception as _e:
                _flog(f"[ignored] _LiveFeed.on_dl: {_e!r}")

    def settle(self, rec, *, pv=None, policy=None, clock=None, mode=None):
        if not _LIVE._ready():
            return
        walked_pv = self._walk_pv(pv) if pv else None
        walked_policy = policy
        if policy and self._board is not None:
            walked_policy = [(m, s) for (m, s) in policy
                             if _bestmove_is_for_board(m, self._board)] or None
        try:
            _LIVE.set_think(rec, self._pos, walked_policy, walked_pv, clock,
                            mode=mode, live=False)
        except Exception as _e:
            _flog(f"[ignored] _LiveFeed.settle: {_e!r}")

    def _walk_pv(self, pv):
        if not pv:
            return None
        if self._board is None:
            return list(pv) if not isinstance(pv, list) else pv
        n_ok = 0
        try:
            wb = self._board.clone()
            for mv in pv:
                if mv in ("resign", "win") or not _bestmove_is_for_board(mv, wb):
                    break
                wb.apply_usi(mv)
                n_ok += 1
        except Exception as _e:
            _flog(f"[ignored] _LiveFeed._walk_pv: {_e!r}")
            return None
        if n_ok == 0:
            return None
        return pv[:n_ok] if n_ok < len(pv) else (list(pv) if not isinstance(pv, list) else pv)


class _LiveConsole:
    __slots__ = ("_lines", "_enabled", "_think", "_zenrei", "_mode",
                 "_gp_ema", "_dgp_ema", "_dyn_cp", "_dyn_cp_pos", "_tall",
                 "_think_live", "_last_rich_panel",
                 "_render_lock", "_clk_evt", "_clk_th",
                 "_clk_board", "_clk_kw", "_clk_sente_ms", "_clk_gote_ms",
                 "_clk_active_sente", "_clk_t0",
                 "_last_board", "_last_kw", "_last_redraw_t",
                 "_leaf_key", "_leaf_text", "_leaf_t",
                 "_last_winrate", "_think_hold",
                 "_prev_lns", "_render_dirty", "_render_th",
                 "_live_sources")

    _RESET_SLOTS = (
        ("_lines",           0),
        ("_prev_lns",        None),
        ("_think",           None),
        ("_dyn_cp",          None),
        ("_dyn_cp_pos",      None),
        ("_think_live",      False),
        ("_last_rich_panel", None),
        ("_zenrei",          None),
        ("_mode",            None),
        ("_gp_ema",          None),
        ("_dgp_ema",         None),
        ("_last_board",      None),
        ("_last_kw",         dict),
        ("_leaf_key",        None),
        ("_leaf_text",       None),
        ("_leaf_t",          0.0),
        ("_last_winrate",    None),
        ("_think_hold",      None),
    )
    _RESET_EXEMPT = (
        ("_enabled",         "isatty 判定結果 (プロセス寿命固定)"),
        ("_tall",            "[SCROLL-OK] 次描画の _blit で無条件再計算"),
        ("_last_redraw_t",   "[throttle] 次 show() で time.monotonic() が上書き"),
        ("_render_lock",     "threading.Lock 本体 (リセット中の with 節が保持中)"),
        ("_render_th",       "[B-1] render daemon (プロセス寿命)"),
        ("_render_dirty",    "[B-1] Event オブジェクト継続使用 (clear() で内部状態のみ quiesce)"),
        ("_live_sources",    "[WO-6a] engine list (プロセス寿命 — 局跨ぎで永続)"),
        ("_clk_kw",          "_stop_clock 後は _clock_tick が回らないため stale 化しない"),
        ("_clk_sente_ms",    "同上"),
        ("_clk_gote_ms",     "同上"),
        ("_clk_active_sente","同上"),
        ("_clk_t0",          "同上"),
        ("_clk_evt",         "_stop_clock() が evt.set() 後 None 化"),
        ("_clk_th",          "_stop_clock() が join 後 None 化"),
        ("_clk_board",       "_stop_clock() が None 化"),
    )

    def _classify_state(self):
        if self._think is None:
            return _LiveState.LIVE_EMPTY
        if self._think_hold is not None:
            return _LiveState.LINGER
        if self._think_live:
            return _LiveState.LIVE_ACTIVE
        return _LiveState.SETTLED

    def _transition(self, event, **kw):
        if event == "SET_THINK":
            self._transition_set_think(**kw)
        elif event == "UPDATE_PV":
            self._transition_update_pv(**kw)
        elif event == "RESET":
            self._transition_reset()

    def _transition_set_think(self, rec, pos, policy, pv, clock, mode, live):
        self._dyn_cp = None
        self._dyn_cp_pos = None

        if isinstance(rec, ThinkRec):
            rec_tr = rec
        else:
            rec_tr = ThinkRec.from_dict(rec) if rec else ThinkRec()

        prev_think = self._think
        prev_rec = prev_think[0] if prev_think is not None else None
        prev_pos = prev_think[1] if prev_think is not None else None
        prev_policy = prev_think[2] if prev_think is not None else None

        if not policy and prev_policy and prev_pos == pos:
            policy = prev_policy

        if prev_pos == pos and prev_rec is not None:
            if rec_tr.source == "emergency":
                rec_tr.carry_emergency_from(prev_rec)
                if not policy and prev_policy:
                    policy = prev_policy
            else:
                rec_tr.carry_from(prev_rec, same_pos=True)

        if prev_pos != pos and prev_think is not None and prev_rec is not None:
            _has_dl_voice = prev_rec.get("dl_top_move")
            if prev_policy or _has_dl_voice:
                self._think_hold = (prev_rec, prev_pos, prev_policy,
                                    time.monotonic())

        self._think = (rec_tr, pos, policy, pv, clock)
        self._think_live = bool(live)
        self._mode = mode

        _gp = rec_tr.get("game_phase")
        if isinstance(_gp, (int, float)):
            self._gp_ema = (_gp if self._gp_ema is None
                            else (0.4 * _gp + 0.6 * self._gp_ema))
        _dg = rec_tr.get("game_phase_delta")
        if isinstance(_dg, (int, float)):
            self._dgp_ema = (_dg if self._dgp_ema is None
                             else (0.4 * _dg + 0.6 * self._dgp_ema))

    def _transition_update_pv(self, pv, score_cp, policy, pos):
        cur = self._think
        cur_pos = cur[1] if cur is not None else None
        if pos is None:
            pos = cur_pos

        if cur is None or cur_pos != pos:
            if cur is not None:
                cur_rec = cur[0]
                cur_pol = cur[2]
                _has_dl = (cur_rec is not None
                           and cur_rec.get("dl_top_move"))
                if cur_pol or _has_dl:
                    self._think_hold = (cur_rec, cur_pos, cur_pol,
                                        time.monotonic())
            rec_tr = ThinkRec()
            _pol, _pv, _clk = None, None, None
        else:
            if isinstance(cur[0], ThinkRec):
                rec_tr = cur[0]
            else:
                rec_tr = ThinkRec.from_dict(cur[0]) or ThinkRec()
            _pol, _pv, _clk = cur[2], cur[3], cur[4]

        if score_cp is not None:
            rec_tr.nnue_score_cp = score_cp
            self._dyn_cp = score_cp
            self._dyn_cp_pos = pos
        if pv:
            _pv = pv
            rec_tr.nnue_bestmove = pv[0]
        if policy:
            _pol = policy
            rec_tr.dl_used = True
            if policy[0] and policy[0][0] not in (None, "resign", "win"):
                rec_tr.dl_top_move = policy[0][0]
                _sc0 = policy[0][1]
                if isinstance(_sc0, (int, float)) and abs(_sc0) < _MATE_CP:
                    rec_tr.dl_top_score = _sc0
            self._think_hold = None

        self._think = (rec_tr, pos, _pol, _pv, _clk)
        self._think_live = not (_pv or _pol)

    def _transition_reset(self):
        for _slot, _val in self._RESET_SLOTS:
            setattr(self, _slot, _val() if callable(_val) else _val)
        self._render_dirty.clear()

    def __init__(self):
        self._lines = 0
        self._prev_lns = None
        self._enabled = None
        self._think = None
        self._zenrei = None
        self._mode = None
        self._gp_ema = None
        self._dgp_ema = None
        self._dyn_cp = None
        self._dyn_cp_pos = None
        self._think_live = False
        self._last_rich_panel = None
        self._tall = False
        self._render_lock = threading.Lock()
        self._render_dirty = threading.Event()
        self._render_th = None
        self._clk_evt = None
        self._clk_th = None
        self._clk_board = None
        self._clk_kw = None
        self._clk_sente_ms = None
        self._clk_gote_ms = None
        self._clk_active_sente = None
        self._clk_t0 = None
        self._last_board = None
        self._last_kw = None
        self._last_redraw_t = 0.0
        self._leaf_key = None
        self._leaf_text = None
        self._leaf_t = 0.0
        self._last_winrate = None
        self._think_hold = None
        self._live_sources = []

    def _ready(self) -> bool:
        if self._enabled is None:
            try:
                self._enabled = bool(sys.stdout.isatty())
            except Exception:
                self._enabled = False
            if self._enabled:
                _init_windows_console()
                _flip_ensure_installed()
        return self._enabled

    def _live_register(self, eng) -> None:
        if eng not in self._live_sources:
            self._live_sources.append(eng)
        self._ensure_render_thread()

    def set_think(self, rec, pos, policy=None, pv=None, clock=None, mode=None,
                  live=False) -> None:
        if not self._ready():
            return
        with self._render_lock:
            self._transition("SET_THINK", rec=rec, pos=pos, policy=policy,
                             pv=pv, clock=clock, mode=mode, live=live)

    def set_zenrei(self, text) -> None:
        with self._render_lock:
            self._zenrei = text

    def clear_ponder(self) -> None:
        with self._render_lock:
            self._dyn_cp = None
            self._dyn_cp_pos = None

    def update_think_pv(self, pv=None, score_cp=None, policy=None, pos=None) -> None:
        if not self._ready():
            return
        with self._render_lock:
            self._transition("UPDATE_PV", pv=pv, score_cp=score_cp,
                             policy=policy, pos=pos)
        self._throttled_redraw()

    def _throttled_redraw(self) -> None:
        self._ensure_render_thread()
        self._render_dirty.set()

    def _redraw(self) -> None:
        if self._last_board is None:
            return
        self._ensure_render_thread()
        self._render_dirty.set()


    def _ensure_render_thread(self) -> None:
        if self._render_th is not None:
            return
        with self._render_lock:
            if self._render_th is not None:
                return
            t = _spawn('live-render', self._render_loop, start_now=False)
            self._render_th = t
            t.start()

    def _render_loop(self) -> None:
        while True:
            self._render_dirty.wait(timeout=0.2)
            self._render_dirty.clear()
            for _eng in list(self._live_sources):
                _slot = _eng._live_scored_latest
                if _slot is not None:
                    _eng._live_scored_latest = None
                    _cb = _eng._live_info_cb
                    if _cb is not None:
                        try:
                            _cb(_slot)
                        except Exception as _e:
                            _flog(f"[ignored] _render_loop: {_e!r}")
            if self._last_board is None:
                continue
            if time.monotonic() - self._last_redraw_t < 0.05:
                continue
            try:
                self.show(self._last_board, **self._last_kw)
            except Exception as _e:
                _flog(f"[ignored] _render_loop: {_e!r}")


    def _compose(self, board, **kw):
        _compose_t0 = time.perf_counter()
        self._last_board = board
        self._last_kw = kw
        if isinstance(self._dyn_cp, (int, float)) and self._dyn_cp_pos:
            try:
                _win_rate = _cp_to_winrate(self._dyn_cp, _SR_WR_SLOPE)
                if getattr(_board_for_position(self._dyn_cp_pos), "side", "b") == "w":
                    _win_rate = 1.0 - _win_rate
                kw = dict(kw)
                kw["winrate"] = _win_rate * 100.0
            except Exception as _e:
                _flog(f"[ignored] _compose: {_e!r}")
        if kw.get("winrate") is not None:
            self._last_winrate = kw["winrate"]
        elif self._last_winrate is not None:
            kw = dict(kw)
            kw["winrate"] = self._last_winrate
        text = _sr_render_board(board, **kw)
        _think_disp = self._think
        if _think_disp is not None:
            if self._think_live and self._last_rich_panel is not None:
                _panel = self._last_rich_panel
            else:
                _hold = self._think_hold
                _hold_arg = None
                if (_hold is not None and not _think_disp[2]
                        and _hold[1] != _think_disp[1]):
                    _hold_rec = _hold[0]
                    if isinstance(_hold_rec, ThinkRec):
                        _hold_rec = _hold_rec.to_dict()
                    _hold_arg = (_hold_rec, _hold[1], _hold[2])
                _disp_rec = _think_disp[0]
                if isinstance(_disp_rec, ThinkRec):
                    _disp_rec = _disp_rec.to_dict()
                _panel = _sr_render_think(
                    _disp_rec, _think_disp[1], _think_disp[2],
                    _think_disp[3], _think_disp[4],
                    zenrei=self._zenrei, dgp_ema=self._dgp_ema,
                    gp_ema=self._gp_ema, mode=self._mode, hold=_hold_arg)
                if not self._think_live:
                    self._last_rich_panel = _panel
            if _LIVE_PV_LEAF_ENABLE:
                try:
                    _lpos, _lpv = _think_disp[1], _think_disp[3]
                    if _lpv:
                        _lkey = (_lpos, tuple(_lpv) if isinstance(_lpv, list)
                                 else str(_lpv))
                        _lnow = time.monotonic()
                        if (_lkey != self._leaf_key
                                and _lnow - self._leaf_t >= _LIVE_PV_LEAF_MIN_S):
                            self._leaf_text = _sr_render_pv_leaf(_lpos, _lpv)
                            self._leaf_key = _lkey
                            self._leaf_t = _lnow
                    if self._leaf_text:
                        _need_w = (max((_sr_vis(_l) for _l in text.split("\n")),
                                       default=0)
                                   + 2 + max((_sr_vis(_l) for _l in
                                              self._leaf_text.split("\n")),
                                             default=0))
                        _lcols, _ = _term_size()
                        if _need_w < _lcols:
                            text = _sr_hjoin(text, self._leaf_text, align="bottom")
                except Exception as _e:
                    _flog(f"[ignored] _compose: {_e!r}")
            text += "\n" + _panel
        _compose_ms = (time.perf_counter() - _compose_t0) * 1000
        if _compose_ms > 5.0:
            _dlog(f"[P-2] _compose {_compose_ms:.1f}ms")
        return text

    def safe_print(self, msg):
        with self._render_lock:
            try:
                if self._lines > 0:
                    sys.stdout.write(f"\x1b[{self._lines}A\x1b[J")
                sys.stdout.write(str(msg) + "\n")
                sys.stdout.flush()
                self._lines = 0
                self._prev_lns = None
            except OSError as _e:
                _flog(f"[ignored] safe_print: {_e!r}")

    def _blit(self, text) -> None:
        with self._render_lock:
            try:
                _cols, _rows = _term_size()
                _lns = [_sr_clip(_ln, _cols) for _ln in text.split("\n")]
                if _cfg_bool("Live_Frame_Clamp", True) and len(_lns) > _rows - 1:
                    _now_cl = time.monotonic()
                    if _now_cl - _clamp_log_t[0] >= 10.0:
                        _clamp_log_t[0] = _now_cl
                        _flog("[FRAME-CLAMP] %d lines > term rows-1=%d — tail cut"
                              % (len(_lns), _rows - 1))
                    _lns = _lns[:_rows - 1]
                _prev = self._prev_lns
                if (_prev is not None and len(_prev) == len(_lns)
                        and self._lines == len(_prev)):
                    buf_parts = []
                    buf_parts.append(f"\x1b[{self._lines}A")
                    for _di, (_ol, _nl) in enumerate(zip(_prev, _lns)):
                        if _ol == _nl:
                            buf_parts.append("\n")
                        else:
                            buf_parts.append(f"\x1b[K{_nl}\n")
                    sys.stdout.write("".join(buf_parts))
                    sys.stdout.flush()
                else:
                    text = "\n".join(_lns)
                    buf = (f"\x1b[{self._lines}A\x1b[J" if self._lines else "") + text + "\n"
                    sys.stdout.write(buf)
                    sys.stdout.flush()
                self._prev_lns = _lns
                self._tall = len(_lns) > _rows - 1
                self._lines = min(len(_lns), _rows - 1)
            except OSError as _e:
                _flog(f"[ignored] _blit: {_e!r}")

    def show(self, board, **kw) -> None:
        if not self._ready():
            return
        text = self._compose(board, **kw)
        self._last_redraw_t = time.monotonic()
        self._blit(text)

    def start_clock(self, board, sente_ms, gote_ms, active_sente, **kw) -> None:
        if not self._ready():
            return
        self._stop_clock()
        if sente_ms is None and gote_ms is None:
            return
        with self._render_lock:
            self._clk_board = board
            self._clk_kw = kw
            self._clk_sente_ms = sente_ms
            self._clk_gote_ms = gote_ms
            self._clk_active_sente = active_sente
            self._clk_t0 = time.monotonic()
            self._clk_evt = threading.Event()
            t = _spawn('clock-tick', self._clock_tick, start_now=False)
            self._clk_th = t
        t.start()

    def _stop_clock(self) -> None:
        evt = self._clk_evt
        th = self._clk_th
        if evt is not None:
            evt.set()
        self._clk_th = None
        self._clk_evt = None
        self._clk_board = None
        if th is not None:
            th.join(timeout=2.0)

    def _clock_tick(self) -> None:
        evt = self._clk_evt
        while evt is not None and not evt.wait(1.0):
            t0 = self._clk_t0
            board = self._clk_board
            if t0 is None or board is None:
                break
            elapsed_ms = int((time.monotonic() - t0) * 1000)
            s_ms = self._clk_sente_ms
            g_ms = self._clk_gote_ms
            if self._clk_active_sente:
                s_ms = max(0, s_ms - elapsed_ms) if s_ms is not None else None
            else:
                g_ms = max(0, g_ms - elapsed_ms) if g_ms is not None else None
            kw = dict(self._clk_kw) if self._clk_kw else {}
            kw["sente_time"] = _sr_fmt_clock(s_ms)
            kw["gote_time"] = _sr_fmt_clock(g_ms)
            self._last_board = board
            self._last_kw = kw
            self._ensure_render_thread()
            self._render_dirty.set()

    def reset(self) -> None:
        self._stop_clock()
        with self._render_lock:
            if self._lines and self._ready():
                try:
                    sys.stdout.write(f"\x1b[{self._lines}A\x1b[J")
                    sys.stdout.flush()
                except OSError as _e:
                    _flog(f"[ignored] reset: {_e!r}")
            self._transition("RESET")


_LIVE = _LiveConsole()


def _force_utf8_stream(stream, mode, errors):
    enc = (getattr(stream, "encoding", None) or "").lower().replace("-", "")
    if enc != "utf8":
        try:
            return open(stream.fileno(), mode=mode, encoding="utf-8",
                        errors=errors, buffering=1, closefd=False)
        except Exception as _e:
            _flog(f"[ignored] _force_utf8_stream: {_e!r}")
    try:
        stream.reconfigure(errors=errors)
    except Exception as _e:
        _flog(f"[ignored] _force_utf8_stream: {_e!r}")
    return stream

sys.stdout = _force_utf8_stream(sys.stdout, "w", "backslashreplace")
sys.stderr = _force_utf8_stream(sys.stderr, "w", "backslashreplace")
sys.stdin  = _force_utf8_stream(sys.stdin,  "r", "replace")

_init_windows_console()


def _popen_utf8(args, **kw):
    kw.setdefault("text", True)
    kw.setdefault("encoding", "utf-8")
    kw.setdefault("errors", "replace")
    return subprocess.Popen(args, **kw)

_flog_lock = threading.RLock()
_FLOG_FH = None

_IO_RATE_BPS     = [0]
_IO_RATE_BURST   = 262144
_IO_RATE_FLUSH_S = 2.0
_IO_RATE_LOCK    = threading.Lock()
_IO_RATE_BUCKET  = {"tokens": float(_IO_RATE_BURST), "ts": 0.0}
_IO_RATE_PENDING = {}
_IO_RATE_THREAD  = [None]

def _io_rate_gate(key, text, meta=None):
    if _IO_RATE_BPS[0] <= 0:
        return True
    n = len(text)
    with _IO_RATE_LOCK:
        rec = _IO_RATE_PENDING.get(key)
        if rec is None:
            b = _IO_RATE_BUCKET
            now = time.monotonic()
            if b["ts"]:
                b["tokens"] = min(float(_IO_RATE_BURST),
                                  b["tokens"] + (now - b["ts"]) * _IO_RATE_BPS[0])
            b["ts"] = now
            if b["tokens"] >= n:
                b["tokens"] -= n
                return True
            rec = _IO_RATE_PENDING[key] = {"meta": meta, "items": []}
            if _IO_RATE_THREAD[0] is None:
                _t = _spawn('io-rate-flush', _io_rate_flusher, start_now=False)
                _IO_RATE_THREAD[0] = _t
                _t.start()
        rec["items"].append(text)
        return False

def _io_rate_drain(key=None):
    import contextlib
    with _IO_RATE_LOCK:
        _keys = (list(_IO_RATE_PENDING) if key is None
                 else ([key] if key in _IO_RATE_PENDING else []))
    for _k in _keys:
        try:
            with _IO_RATE_LOCK:
                _rec = _IO_RATE_PENDING.get(_k)
                if _rec is None:
                    continue
                _outer = (_flog_lock if _k == "_flog"
                          else (_rec["meta"][1] or contextlib.nullcontext()))
            with _outer:
                with _IO_RATE_LOCK:
                    _rec = _IO_RATE_PENDING.pop(_k, None)
                    if _rec is None:
                        continue
                    _IO_RATE_BUCKET["tokens"] -= sum(len(_t) for _t in _rec["items"])
                _joined = "".join(_rec["items"])
                if _k == "_flog":
                    _flog_write_raw(_joined)
                else:
                    _atomic_append(_rec["meta"][0], _joined, lock=None, fsync=False,
                                   os_write=True, _rate_exempt=True)
        except Exception as _e:
            _flog(f"[ignored] _io_rate_drain: {_e!r}")

def _io_rate_flusher():
    while True:
        time.sleep(_IO_RATE_FLUSH_S)
        try:
            _io_rate_drain()
        except Exception as _e:
            _flog(f"[ignored] _io_rate_flusher: {_e!r}")

atexit.register(_io_rate_drain)

def _flog_write_raw(_line):
    global _FLOG_FH
    try:
        with _flog_lock:
            if _FLOG_FH is None:
                _FLOG_FH = open(_LOG_PATH, "a", encoding="utf-8")
            try:
                _FLOG_FH.write(_line)
                _FLOG_FH.flush()
            except (ValueError, OSError):
                try:
                    _FLOG_FH.close()
                except Exception:
                    pass
                _FLOG_FH = open(_LOG_PATH, "a", encoding="utf-8")
                _FLOG_FH.write(_line)
                _FLOG_FH.flush()
    except Exception:
        pass

def _flog(msg):
    if globals().get("_log_diagnosis", True) is False:
        return
    if _MP_LIGHT_IMPORT and not any(
            k in str(msg) for k in ("FATAL", "Error", "error", "失敗",
                                    "Exception", "Traceback", "WARN")):
        return
    _line = f"[{time.strftime('%H:%M:%S')}] {msg}\n"
    if not _io_rate_gate("_flog", _line):
        return
    _flog_write_raw(_line)

def _safe_format_exc(exc_type=None, exc_value=None, exc_tb=None):
    if exc_type is None and exc_value is None and exc_tb is None:
        exc_type, exc_value, exc_tb = sys.exc_info()
    try:
        return "".join(traceback.format_exception(exc_type, exc_value, exc_tb)).strip()
    except Exception as _e:
        _flog(f"[ignored] _safe_format_exc: {_e!r}")
    try:
        lines = [f"{exc_type.__name__ if exc_type else 'Exception'}: {exc_value}"]
        for fr in traceback.extract_tb(exc_tb):
            lines.append(f'  File "{fr.filename}", line {fr.lineno}, in {fr.name}')
            if fr.line:
                lines.append(f"    {fr.line}")
        return "\n".join(lines)
    except Exception as _fmt_e:
        return f"(traceback formatting failed: {_fmt_e!r})"


def _thread_safe_target(name):
    def _wrap(fn):
        @functools.wraps(fn)
        def _inner(*a, **kw):
            try:
                return fn(*a, **kw)
            except (KeyboardInterrupt, SystemExit):
                raise
            except Exception:
                _flog(f"[G-06] thread '{name}' dead:\n"
                      + _safe_format_exc().strip())
        return _inner
    return _wrap


def _spawn(name, target, *args, daemon=True, start_now=True):
    _wrapped = _thread_safe_target(name)(target)
    _th = threading.Thread(target=_wrapped, args=args, daemon=daemon, name=name)
    if start_now:
        _th.start()
    return _th


def _atomic_append(path, text, lock=None, fsync=True, os_write=False,
                   _rate_exempt=False):
    import contextlib
    if not _rate_exempt and _IO_RATE_BPS[0] > 0:
        if fsync or not isinstance(text, str):
            _io_rate_drain(path)
        elif not _io_rate_gate(path, text, meta=(path, lock)):
            return
    ctx_mgr = lock if lock else contextlib.nullcontext()
    with ctx_mgr:
        if os_write:
            _data = text.encode("utf-8") if isinstance(text, str) else text
            fd = os.open(path, os.O_WRONLY | os.O_CREAT | os.O_APPEND)
            try:
                os.write(fd, _data)
                if fsync:
                    try:
                        os.fsync(fd)
                    except OSError as _e:
                        _flog(f"[ignored] _atomic_append: {_e!r}")
            finally:
                os.close(fd)
        else:
            with open(path, "a", encoding="utf-8") as f:
                f.write(text)
                f.flush()
                if fsync:
                    try:
                        os.fsync(f.fileno())
                    except OSError as _e:
                        _flog(f"[ignored] _atomic_append: {_e!r}")


_PHIT_TRACE = {"t0": 0.0, "ev": None}

def _phit_trace_start():
    _PHIT_TRACE["t0"] = time.perf_counter()
    _PHIT_TRACE["ev"] = []

def _phit_trace(tag, **kw):
    if _PHIT_TRACE["ev"] is None:
        return
    try:
        _kv = ("(" + ",".join("%s=%s" % _p for _p in kw.items()) + ")") if kw else ""
        _PHIT_TRACE["ev"].append(
            "%s@%.2fs%s" % (tag, time.perf_counter() - _PHIT_TRACE["t0"], _kv))
    except Exception as _e:
        _flog(f"[ignored] _phit_trace: {_e!r}")

def _phit_trace_emit(path, bestmove):
    ev = _PHIT_TRACE["ev"]
    if ev is None:
        return
    _PHIT_TRACE["ev"] = None
    try:
        total = time.perf_counter() - _PHIT_TRACE["t0"]
        if total >= 3.0 or any(("reject" in e or "flush_fail" in e) for e in ev):
            _flog("[PH-TRACE] path=%s total=%.2fs bestmove=%r :: %s"
                  % (path, total, bestmove, " ".join(ev)))
    except Exception as _e:
        _flog(f"[ignored] _phit_trace_emit: {_e!r}")


import urllib.request as _zenrei_urlreq


_ZENREI_BOARD_CODES = {
    '.':  '0',
    'P':  '100',      'p':  '101',
    'L':  '110000',   'l':  '110001',
    'N':  '110010',   'n':  '110011',
    '+P': '110100',   '+p': '110101',
    'G':  '110110',   'g':  '110111',
    '+L': '111000',   '+l': '111001',
    '+N': '111010',   '+n': '111011',
    'S':  '1111000',  's':  '1111010',
    '+S': '1111001',  '+s': '1111011',
    'B':  '11111000', 'b':  '11111010',
    '+B': '11111001', '+b': '11111011',
    'R':  '11111100', 'r':  '11111110',
    '+R': '11111101', '+r': '11111111',
}
_ZENREI_HAND_ORDER = ['P', 'L', 'N', 'S', 'G', 'B', 'R']

_ZENREI_COUNT_RE_ALTS = [
    re.compile(r"（\s*([0-9,]+)\s*件中"),
    re.compile(r"\(\s*([0-9,]+)\s*件中"),
    re.compile(r"全\s*([0-9,]+)\s*件"),
    re.compile(r"該当\s*([0-9,]+)\s*件"),
    re.compile(r"([0-9,]+)\s*件中"),
    re.compile(r"([0-9,]+)\s*局"),
]


_ZENREI_GAME_ID_RE = re.compile(r"/games/([0-9a-f]{16,})")
_ZENREI_MIN_PLY = 11


def _zenrei_parse_count(html: str):
    for _re in _ZENREI_COUNT_RE_ALTS:
        m = _re.search(html)
        if m:
            try:
                v = int(m.group(1).replace(",", ""))
            except ValueError:
                continue
            if v > 0:
                return v
            break
    return len(set(_ZENREI_GAME_ID_RE.findall(html)))


def _zenrei_strip_sfen(sfen: str):
    s = sfen.strip()
    if s.startswith("position "):
        s = s[len("position "):].strip()
    if s.startswith("sfen "):
        s = s[5:].strip()
    if s.startswith("startpos"):
        raise ValueError("startpos")
    f = s.split()
    return f[0], (f[1] if len(f) > 1 else 'b'), (f[2] if len(f) > 2 else '-')


def _zenrei_sfen_ply(sfen: str):
    s = sfen.strip()
    if s.startswith("position "):
        s = s[len("position "):].strip()
    if s.startswith("sfen "):
        s = s[5:].strip()
    f = s.split()
    if len(f) >= 4:
        try:
            return int(f[3])
        except ValueError:
            return None
    return None


def _zenrei_parse_board(board_part: str):
    grid = {}
    for r_idx, row in enumerate(board_part.split('/')):
        rank = r_idx + 1
        file = 9
        promo = False
        for ch in row:
            if ch == '+':
                promo = True
                continue
            if ch.isdigit():
                file -= int(ch)
                continue
            grid[(rank - 1) * 9 + (9 - file)] = ('+' if promo else '') + ch
            promo = False
            file -= 1
    return grid


def _zenrei_parse_hand(hand_part: str):
    counts = {}
    if hand_part in ('-', ''):
        return counts
    num = ''
    for ch in hand_part:
        if ch.isdigit():
            num += ch
            continue
        counts[ch] = int(num) if num else 1
        num = ''
    return counts


def _zenrei_encode_packed_sfen(sfen: str) -> str:
    board_part, stm, hand_part = _zenrei_strip_sfen(sfen)
    grid = _zenrei_parse_board(board_part)
    bk = next(sq for sq, p in grid.items() if p == 'K')
    wk = next(sq for sq, p in grid.items() if p == 'k')
    kset = {bk, wk}
    bits = [0 if stm == 'b' else 1]
    for ksq in (bk, wk):
        for i in range(7):
            bits.append((ksq >> i) & 1)
    for sq in range(81):
        if sq in kset:
            continue
        for c in _ZENREI_BOARD_CODES[grid.get(sq, '.')]:
            bits.append(int(c))
    hc = _zenrei_parse_hand(hand_part)
    for pc in _ZENREI_HAND_ORDER:
        bits += [1] * hc.get(pc, 0) + [0]
    for pc in _ZENREI_HAND_ORDER:
        bits += [1] * hc.get(pc.lower(), 0) + [0]
    while len(bits) % 8 or len(bits) < 256:
        bits.append(0)
    out = bytearray(len(bits) // 8)
    for i, b in enumerate(bits):
        if b:
            out[i // 8] |= 1 << (i & 7)
    return out.hex()


def _zenrei_same_url(sfen: str) -> str:
    return "https://shogidb2.com/same?packed_sfen=" + _zenrei_encode_packed_sfen(sfen)


def _zenrei_position_key(sfen: str) -> str:
    bp, stm, hand = _zenrei_strip_sfen(sfen)
    hc = _zenrei_parse_hand(hand)
    _parts = []
    for _p in _ZENREI_HAND_ORDER:
        for _k in (_p, _p.lower()):
            _n = hc.get(_k, 0)
            if _n:
                _parts.append((str(_n) if _n > 1 else "") + _k)
    return f"{bp}|{stm}|{''.join(_parts) or '-'}"


class _Shogidb2Zenrei:

    def __init__(self, timeout=4.0, user_agent="Pyfamate/zenrei",
                 max_cache=8192, logger=None):
        self._timeout = timeout
        self._ua = user_agent
        self._max_cache = max_cache
        self._log = logger or (lambda msg: None)
        self._lock = threading.Lock()
        self._cache = {}
        self._inflight = set()
        self._pending_cbs = {}
        self._sem = threading.Semaphore(3)

    def prefetch(self, sfen, ply=None, on_complete=None):
        key = _zenrei_position_key(sfen)
        if ply is None:
            ply = _zenrei_sfen_ply(sfen)
        _cached_cnt = None
        _cached_hit = False
        with self._lock:
            _hit = self._cache.get(key)
            if _hit is not None:
                _cached_cnt = _hit[0]
                _cached_hit = True
            elif key in self._inflight:
                if on_complete is not None:
                    self._pending_cbs.setdefault(key, []).append(on_complete)
                return
            else:
                self._inflight.add(key)
        if _cached_hit:
            if on_complete is not None:
                try:
                    on_complete(sfen, _cached_cnt)
                except Exception as _e:
                    _flog(f"[ignored] prefetch: {_e!r}")
            return
        _spawn('zenrei-fetch', self._worker, sfen, key, ply, on_complete)

    def get_count(self, sfen):
        key = _zenrei_position_key(sfen)
        with self._lock:
            hit = self._cache.get(key)
        return hit[0] if hit else None

    def _worker(self, sfen, key, ply, on_complete=None):
        count = None
        _fetch_ok = False
        try:
            url = _zenrei_same_url(sfen)
            req = _zenrei_urlreq.Request(url, headers={"User-Agent": self._ua})
            with self._sem:
                with _zenrei_urlreq.urlopen(req, timeout=self._timeout) as resp:
                    charset = resp.headers.get_content_charset() or "utf-8"
                    html = resp.read().decode(charset, errors="replace")
            _fetch_ok = True
            count = _zenrei_parse_count(html)
            self._log(f"[ZENREI] ply={ply} count={count} url={url}")
            if count in (None, 0):
                _dc = getattr(self, "_diag_count", 0)
                if _dc < 3:
                    self._diag_count = _dc + 1
                    _idx = html.find("件")
                    if _idx >= 0:
                        _snip = html[max(0, _idx - 40): _idx + 10]
                    else:
                        _snip = "(『件』表記が HTML に存在しない: " + html[:120] + ")"
                    _snip = _snip.replace("\n", " ").replace("\r", " ")
                    self._log(f"[ZENREI-DIAG] ply={ply} count={count} "
                              f"html_around_件={_snip!r}")
                if count == 0 and not getattr(self, "_selfcheck_done", False):
                    self._selfcheck_done = True
                    try:
                        _sc_sfen = ("lnsgkgsnl/1r5b1/pppppp1pp/6p2/9/2P6/"
                                    "PP1PPPPPP/1B5R1/LNSGKGSNL b - 3")
                        _sc_req = _zenrei_urlreq.Request(
                            _zenrei_same_url(_sc_sfen),
                            headers={"User-Agent": self._ua})
                        with _zenrei_urlreq.urlopen(
                                _sc_req, timeout=self._timeout) as _sc_resp:
                            _sc_cs = (_sc_resp.headers.get_content_charset()
                                      or "utf-8")
                            _sc_html = _sc_resp.read().decode(
                                _sc_cs, errors="replace")
                        _sc_count = _zenrei_parse_count(_sc_html)
                        if not _sc_count:
                            self._log("[ZENREI][WARN] self-check: 定跡局面でも "
                                      "count=0 — 符号化/サイト仕様変更を疑う "
                                      "(本局の 0 は信用しない)")
                        else:
                            self._log(f"[ZENREI] self-check OK: 定跡局面 "
                                      f"count={_sc_count} — 本局の 0 は真の新手")
                    except Exception as _sc_e:
                        self._log(f"[ZENREI] self-check failed: {_sc_e!r}")
        except Exception as e:
            self._log(f"[ZENREI] fetch failed ply={ply}: {e!r}")
        finally:
            _extra_cbs = []
            with self._lock:
                self._inflight.discard(key)
                if _fetch_ok:
                    self._cache[key] = (count, ply)
                    if len(self._cache) > self._max_cache:
                        for k in list(self._cache)[: self._max_cache // 4]:
                            self._cache.pop(k, None)
                _extra_cbs = self._pending_cbs.pop(key, [])
            if _fetch_ok and on_complete is not None:
                try:
                    on_complete(sfen, count)
                except Exception as _e:
                    _flog(f"[ignored] _worker: {_e!r}")
            if _fetch_ok:
                for _cb in _extra_cbs:
                    try:
                        _cb(sfen, count)
                    except Exception as _e:
                        _flog(f"[ignored] _worker: {_e!r}")


_zenrei_live_ref = [None]
_zenrei_consec_zero = [0]


def _zenrei_live_reset():
    _zenrei_consec_zero[0] = 0


def _zenrei_live_push(board):
    if not _LIVE._ready() or not _cfg_bool("Live_Zenrei_Enable", True):
        return
    if _zenrei_consec_zero[0] >= 3:
        return
    try:
        _ply = getattr(board, "ply", None)
        if _ply is None or _ply < _ZENREI_MIN_PLY:
            _LIVE.set_zenrei("")
            return
        _sf = board.sfen()
    except Exception:
        return
    _z = _zenrei_live_ref[0]
    if _z is None:
        _z = _zenrei_live_ref[0] = _Shogidb2Zenrei(logger=_flog)

    def _txt(c):
        if isinstance(c, int) and c > 0:
            return "前例多数" if c >= 20 else ("前例約%d局" % c)
        return None

    _c_cached = _z.get_count(_sf)
    if isinstance(_c_cached, int) and _c_cached == 0:
        _LIVE.set_zenrei("")
    else:
        _t = _txt(_c_cached)
        if _t is not None:
            _LIVE.set_zenrei(_t)

    def _cb(sf, cnt):
        if isinstance(cnt, int) and cnt == 0:
            _zenrei_consec_zero[0] += 1
            if _LIVE._ready():
                try:
                    _LIVE.set_zenrei("")
                    _LIVE._redraw()
                except Exception as _e:
                    _flog(f"[ignored] _zenrei_live_push/_cb: {_e!r}")
            return
        elif isinstance(cnt, int) and cnt > 0:
            _zenrei_consec_zero[0] = 0
        _t2 = _txt(cnt)
        if _t2 is not None and _LIVE._ready():
            try:
                _LIVE.set_zenrei(_t2)
                _LIVE._redraw()
            except Exception as _e:
                _flog(f"[ignored] _zenrei_live_push/_cb: {_e!r}")

    _z.prefetch(_sf, _ply, on_complete=_cb)


def _wdoor_url_from_game_id(game_id: str):
    try:
        gid = str(game_id or "").strip()
        if not gid:
            return None
        ts = gid.rsplit("+", 1)[-1]
        if len(ts) < 8 or not ts[:8].isdigit():
            return None
        y, mo, d = ts[0:4], ts[4:6], ts[6:8]
        return (f"http://wdoor.c.u-tokyo.ac.jp/shogi/x/{y}/{mo}/{d}/{gid}.csa", gid)
    except Exception:
        return None


def _wdoor_parse_csa_moves(text: str):
    moves = []
    end_sym = None
    summary = None
    end_time = None
    for raw in text.splitlines():
        line = raw.rstrip("\r\n")
        s = line.lstrip("'")
        if s.startswith("$END_TIME:"):
            end_time = s[len("$END_TIME:"):]
        if s.startswith("summary:"):
            summary = s
        ls = line.strip()
        if ls in ("%TORYO", "%KACHI", "%SENNICHITE", "%JISHOGI",
                  "%TIME_UP", "%CHUDAN", "%+ILLEGAL_ACTION",
                  "%-ILLEGAL_ACTION"):
            end_sym = ls
            continue
        m = re.match(r"^([+-]\d{4}[A-Z]{2})(?:,T(\d+))?$", line)
        if m:
            moves.append((m.group(1),
                          int(m.group(2)) if m.group(2) is not None else None))
            continue
        m2 = re.match(r"^T(\d+)$", line)
        if m2 and moves and moves[-1][1] is None:
            moves[-1] = (moves[-1][0], int(m2.group(1)))
    return moves, end_sym, summary, end_time


def _wdoor_consistency_check(game_id, local_kifu_moves, local_result,
                             local_end_reason, timeout_s=8.0):
    return
    built = _wdoor_url_from_game_id(game_id)
    if not built:
        _flog(f"[WDOOR-CHECK] game_id から URL を組めず skip: {game_id!r}")
        return
    url, gid = built
    try:
        req = _zenrei_urlreq.Request(url, headers={"User-Agent": "Pyfamate/wdoor-check"})
        with _zenrei_urlreq.urlopen(req, timeout=timeout_s) as resp:
            charset = resp.headers.get_content_charset() or "utf-8"
            raw = resp.read()
        text = None
        for enc in (charset, "utf-8", "cp932", "euc-jp"):
            try:
                text = raw.decode(enc)
                break
            except (UnicodeDecodeError, LookupError):
                continue
        if text is None:
            text = raw.decode("utf-8", errors="replace")
    except Exception as e:
        _flog(f"[WDOOR-CHECK] 取得失敗 (skip, 対局には無影響): url={url} err={e!r}")
        _flog("[WDOOR-CHECK] ヒント: egress 許可リストに "
              "wdoor.c.u-tokyo.ac.jp を追加すると自動照合が有効になります。")
        return

    w_moves, w_end_sym, w_summary, w_end_time = _wdoor_parse_csa_moves(text)
    l_moves = [(e.get("csa"), e.get("t")) for e in (local_kifu_moves or [])]

    n = max(len(l_moves), len(w_moves))
    move_mismatch = []
    time_mismatch = []
    for i in range(n):
        a = l_moves[i][0] if i < len(l_moves) else None
        b = w_moves[i][0] if i < len(w_moves) else None
        if a != b:
            move_mismatch.append((i + 1, a, b))
            continue
        la = l_moves[i][1] if i < len(l_moves) else None
        wb = w_moves[i][1] if i < len(w_moves) else None
        if la is not None and wb is not None and la != wb:
            time_mismatch.append((i + 1, a, la, wb))

    _flog("[WDOOR-CHECK] ============ 局後整合性チェック ============")
    _flog(f"[WDOOR-CHECK] game_id={gid}")
    _flog(f"[WDOOR-CHECK] url={url}")
    _flog(f"[WDOOR-CHECK] 手数 local={len(l_moves)} wdoor={len(w_moves)} "
          f"end_sym={w_end_sym} end_time={w_end_time}")
    if w_summary:
        _flog(f"[WDOOR-CHECK] wdoor summary: {w_summary}")
    if not move_mismatch:
        _flog(f"[WDOOR-CHECK] 指し手列: 全 {min(len(l_moves), len(w_moves))} 手一致")
    else:
        _flog(f"[WDOOR-CHECK] 指し手列: 不一致 {len(move_mismatch)} 件 ↓")
        for ply, a, b in move_mismatch[:40]:
            tag = ""
            if a is None:
                tag = "  <= local 未記録 (最終手/終局の書き落とし疑い)"
            elif b is None:
                tag = "  <= wdoor 側に無い (local 余分記録)"
            _flog(f"[WDOOR-CHECK]   ply{ply}: local={a} wdoor={b}{tag}")
    if not time_mismatch:
        _flog("[WDOOR-CHECK] 消費時間(T): 両者にTのある手は全一致")
    else:
        _flog(f"[WDOOR-CHECK] 消費時間(T): 不一致 {len(time_mismatch)} 件 ↓")
        for ply, mv, la, wb in time_mismatch[:40]:
            _flog(f"[WDOOR-CHECK]   ply{ply} {mv}: local=T{la} wdoor=T{wb}")
    _flog(f"[WDOOR-CHECK] 終局: local result={local_result} "
          f"reason={local_end_reason or '-'} / wdoor end_sym={w_end_sym} "
          f"summary={w_summary or '-'}")
    if len(w_moves) > len(l_moves):
        _missing = [m[0] for m in w_moves[len(l_moves):]]
        _flog(f"[WDOOR-CHECK] [警告] local kifu が末尾 {len(_missing)} 手を未記録: "
              f"{_missing}  — 終局直前のクラッシュ/送信前終局の可能性")
    elif len(l_moves) > len(w_moves):
        _flog(f"[WDOOR-CHECK] [警告] local kifu が wdoor より長い "
              f"({len(l_moves)} vs {len(w_moves)}) — 送信されなかった手の記録疑い")
    if not move_mismatch and not time_mismatch and len(w_moves) == len(l_moves):
        _flog("[WDOOR-CHECK] 判定: 完全整合 (指し手・時間・手数すべて一致)")
    elif not [m for m in move_mismatch if m[1] is not None and m[2] is not None]:
        _flog("[WDOOR-CHECK] 判定: 指し手取り違えなし。差分は記録漏れ/時間のみ "
              "(対局再現性は保たれている)")
    else:
        _flog("[WDOOR-CHECK] 判定: *** 指し手の取り違えあり *** 盤面追跡/変換層を要調査")
    _flog("[WDOOR-CHECK] ============================================")




_diag_lock = threading.Lock()
_diag_buf  = []
_dlog_enabled = True
_dlog_strftime_cache = ("", 0.0)

def _dlog(msg):
    if not _dlog_enabled:
        return
    try:
        with _diag_lock:
            global _dlog_strftime_cache
            _now = time.time()
            if _now - _dlog_strftime_cache[1] >= 1.0:
                _dlog_strftime_cache = (time.strftime('%H:%M:%S'), _now)
            text = msg() if callable(msg) else msg
            _diag_buf.append(f"[{_dlog_strftime_cache[0]}] {text}")
    except Exception as _e:
        _flog(f"[ignored] _dlog: {_e!r}")

def _diag_reset():
    try:
        with _diag_lock:
            _diag_buf.clear()
    except Exception as _ie:
        _flog(f"[ignored] _diag_reset: {_ie!r}")

def _diag_collect():
    try:
        with _diag_lock:
            out = list(_diag_buf)
            _diag_buf.clear()
            return out
    except Exception:
        return []



if sys.platform == "win32":
    import ctypes as _ctypes
    from ctypes import wintypes as _wintypes

    _kernel32 = _ctypes.WinDLL("kernel32", use_last_error=True)

    _JobObjectExtendedLimitInformation = 9
    _JOB_OBJECT_LIMIT_KILL_ON_JOB_CLOSE = 0x00002000
    _PROCESS_TERMINATE      = 0x0001
    _PROCESS_SET_QUOTA      = 0x0100
    _PROCESS_ALL_ACCESS     = 0x1F0FFF

    class _JOBOBJECT_BASIC_LIMIT_INFORMATION(_ctypes.Structure):
        _fields_ = [
            ("PerProcessUserTimeLimit", _wintypes.LARGE_INTEGER),
            ("PerJobUserTimeLimit",     _wintypes.LARGE_INTEGER),
            ("LimitFlags",              _wintypes.DWORD),
            ("MinimumWorkingSetSize",   _ctypes.c_size_t),
            ("MaximumWorkingSetSize",   _ctypes.c_size_t),
            ("ActiveProcessLimit",      _wintypes.DWORD),
            ("Affinity",                _ctypes.POINTER(_wintypes.ULONG)),
            ("PriorityClass",           _wintypes.DWORD),
            ("SchedulingClass",         _wintypes.DWORD),
        ]

    class _IO_COUNTERS(_ctypes.Structure):
        _fields_ = [
            ("ReadOperationCount",  _ctypes.c_ulonglong),
            ("WriteOperationCount", _ctypes.c_ulonglong),
            ("OtherOperationCount", _ctypes.c_ulonglong),
            ("ReadTransferCount",   _ctypes.c_ulonglong),
            ("WriteTransferCount",  _ctypes.c_ulonglong),
            ("OtherTransferCount",  _ctypes.c_ulonglong),
        ]

    class _JOBOBJECT_EXTENDED_LIMIT_INFORMATION(_ctypes.Structure):
        _fields_ = [
            ("BasicLimitInformation", _JOBOBJECT_BASIC_LIMIT_INFORMATION),
            ("IoInfo",                _IO_COUNTERS),
            ("ProcessMemoryLimit",    _ctypes.c_size_t),
            ("JobMemoryLimit",        _ctypes.c_size_t),
            ("PeakProcessMemoryUsed", _ctypes.c_size_t),
            ("PeakJobMemoryUsed",     _ctypes.c_size_t),
        ]

    _kernel32.CreateJobObjectW.restype  = _wintypes.HANDLE
    _kernel32.CreateJobObjectW.argtypes = [_wintypes.LPVOID, _wintypes.LPCWSTR]
    _kernel32.SetInformationJobObject.restype  = _wintypes.BOOL
    _kernel32.SetInformationJobObject.argtypes = [
        _wintypes.HANDLE, _ctypes.c_int, _wintypes.LPVOID, _wintypes.DWORD]
    _kernel32.OpenProcess.restype  = _wintypes.HANDLE
    _kernel32.OpenProcess.argtypes = [_wintypes.DWORD, _wintypes.BOOL, _wintypes.DWORD]
    _kernel32.AssignProcessToJobObject.restype  = _wintypes.BOOL
    _kernel32.AssignProcessToJobObject.argtypes = [_wintypes.HANDLE, _wintypes.HANDLE]
    _kernel32.TerminateJobObject.restype  = _wintypes.BOOL
    _kernel32.TerminateJobObject.argtypes = [_wintypes.HANDLE, _wintypes.UINT]
    _kernel32.CloseHandle.restype  = _wintypes.BOOL
    _kernel32.CloseHandle.argtypes = [_wintypes.HANDLE]

    def _job_create():
        try:
            h = _kernel32.CreateJobObjectW(None, None)
            if not h:
                _flog(f"[job] CreateJobObject failed err={_ctypes.get_last_error()}")
                return None
            info = _JOBOBJECT_EXTENDED_LIMIT_INFORMATION()
            info.BasicLimitInformation.LimitFlags = _JOB_OBJECT_LIMIT_KILL_ON_JOB_CLOSE
            ok = _kernel32.SetInformationJobObject(
                h, _JobObjectExtendedLimitInformation,
                _ctypes.byref(info), _ctypes.sizeof(info))
            if not ok:
                _flog(f"[job] SetInformationJobObject failed err={_ctypes.get_last_error()}")
                _kernel32.CloseHandle(h)
                return None
            return h
        except Exception as e:
            _flog(f"[job] create exception: {e}")
            return None

    def _job_assign_pid(job_handle, pid):
        if not job_handle:
            return False
        hproc = None
        try:
            hproc = _kernel32.OpenProcess(
                _PROCESS_SET_QUOTA | _PROCESS_TERMINATE, False, int(pid))
            if not hproc:
                hproc = _kernel32.OpenProcess(_PROCESS_ALL_ACCESS, False, int(pid))
            if not hproc:
                _flog(f"[job] OpenProcess(pid={pid}) failed err={_ctypes.get_last_error()}")
                return False
            ok = _kernel32.AssignProcessToJobObject(job_handle, hproc)
            if not ok:
                _flog(f"[job] AssignProcessToJobObject(pid={pid}) failed "
                      f"err={_ctypes.get_last_error()}")
                return False
            return True
        except Exception as e:
            _flog(f"[job] assign exception (pid={pid}): {e}")
            return False
        finally:
            if hproc:
                _kernel32.CloseHandle(hproc)

    def _job_terminate(job_handle, exit_code=1):
        if not job_handle:
            return False
        try:
            ok = _kernel32.TerminateJobObject(job_handle, int(exit_code))
            if not ok:
                _flog(f"[job] TerminateJobObject failed err={_ctypes.get_last_error()}")
                return False
            return True
        except Exception as e:
            _flog(f"[job] terminate exception: {e}")
            return False

    def _job_close(job_handle):
        if not job_handle:
            return
        try:
            _kernel32.CloseHandle(job_handle)
        except Exception as e:
            _flog(f"[job] close exception: {e}")

    _TH32CS_SNAPTHREAD = 0x00000004
    _THREAD_SUSPEND_RESUME = 0x0002

    class _THREADENTRY32(_ctypes.Structure):
        _fields_ = [
            ("dwSize",             _wintypes.DWORD),
            ("cntUsage",           _wintypes.DWORD),
            ("th32ThreadID",       _wintypes.DWORD),
            ("th32OwnerProcessID", _wintypes.DWORD),
            ("tpBasePri",          _wintypes.LONG),
            ("tpDeltaPri",         _wintypes.LONG),
            ("dwFlags",            _wintypes.DWORD),
        ]

    _kernel32.CreateToolhelp32Snapshot.restype  = _wintypes.HANDLE
    _kernel32.CreateToolhelp32Snapshot.argtypes = [_wintypes.DWORD, _wintypes.DWORD]
    _kernel32.Thread32First.restype  = _wintypes.BOOL
    _kernel32.Thread32First.argtypes = [_wintypes.HANDLE, _ctypes.POINTER(_THREADENTRY32)]
    _kernel32.Thread32Next.restype   = _wintypes.BOOL
    _kernel32.Thread32Next.argtypes  = [_wintypes.HANDLE, _ctypes.POINTER(_THREADENTRY32)]
    _kernel32.OpenThread.restype  = _wintypes.HANDLE
    _kernel32.OpenThread.argtypes = [_wintypes.DWORD, _wintypes.BOOL, _wintypes.DWORD]
    _kernel32.ResumeThread.restype  = _wintypes.DWORD
    _kernel32.ResumeThread.argtypes = [_wintypes.HANDLE]

    def _decode_wsl_list(raw: bytes) -> str:
        if not raw:
            return ""
        if b"\x00" in raw:
            return raw.decode("utf-16-le", errors="replace")
        return raw.decode("utf-8", errors="replace")

    def _wsl_kill_by_batpath(bat_path, tag=None):
        _distro = None
        _target = None
        try:
            with open(bat_path, "r", encoding="utf-8", errors="replace") as _bf:
                _lines = _bf.readlines()
            for _ln in _lines:
                _s = _ln.strip()
                if not _s or _s.lower().startswith(("@echo", "rem", "::")):
                    continue
                _toks = _s.split()
                if not _toks:
                    continue
                if os.path.basename(_toks[0]).lower().rstrip(".exe").rstrip(".") != "wsl":
                    continue
                for _i, _t in enumerate(_toks):
                    if _t in ("-d", "--distribution") and _i + 1 < len(_toks):
                        _distro = _toks[_i + 1]
                    if _t.startswith("/") and _target is None:
                        _target = _t
                if _target:
                    break
        except Exception as e:
            _flog(f"[wsl-kill] cannot read bat '{bat_path}': {e}")
            if tag is None:
                return False

        if tag:
            _pat = tag
            _desc = f"tag '{tag}'"
        elif _target:
            _pat = _target
            _desc = f"path '{_target}'"
        else:
            _flog(f"[wsl-kill] no target/tag for '{bat_path}' — skip")
            return False

        _argv = ["wsl"]
        if _distro:
            _argv += ["-d", _distro]
        _argv += ["--", "pkill", "-9", "-f", _pat]
        _killed = False
        for _attempt in range(2):
            _pk_rc, _ = _hp_run(_argv, 6)
            if _pk_rc == 0:
                _flog(f"[wsl-kill] pkill -9 -f {_desc} succeeded "
                      f"(distro={_distro or 'default'} attempt={_attempt})")
                _killed = True
                break
            elif _pk_rc == 1:
                _flog(f"[wsl-kill] pkill -9 -f {_desc} rc=1 "
                      f"(distro={_distro or 'default'} attempt={_attempt} "
                      f"— no matching process)")
                _killed = True
                break
            elif _pk_rc is not None:
                _flog(f"[wsl-kill] pkill -9 -f {_desc} rc={_pk_rc} "
                      f"(distro={_distro or 'default'} attempt={_attempt} "
                      f"— kill 失敗の可能性: pkill エラー or WSL 転送失敗。"
                      f"zombie 残存を疑え)")
            else:
                _flog(f"[wsl-kill] pkill timeout (6s) {_desc} "
                      f"(distro={_distro or 'default'} attempt={_attempt} "
                      f"— WSL が無応答の可能性)")
            if _attempt == 0:
                time.sleep(0.5)
        if _killed:
            try:
                _pgrep_argv = ["wsl"]
                if _distro:
                    _pgrep_argv += ["-d", _distro]
                _pgrep_argv += ["--", "pgrep", "-f", _pat]
                _pr_rc, _pr_out = _hp_run(_pgrep_argv, 4, capture=True)
                if _pr_rc == 0 and _pr_out.strip():
                    _flog(f"[wsl-kill] WARNING: pgrep still finds process after "
                          f"pkill {_desc} — zombie risk "
                          f"(pids={_pr_out.decode(errors='replace').strip()})")
                    _killed = False
            except Exception as _e:
                _flog(f"[ignored] _wsl_kill_by_batpath: {_e!r}")
        return _killed

    def _resume_process_main_thread(pid):
        snap = _kernel32.CreateToolhelp32Snapshot(_TH32CS_SNAPTHREAD, 0)
        if snap == _wintypes.HANDLE(-1).value or not snap:
            _flog(f"[job] CreateToolhelp32Snapshot failed err={_ctypes.get_last_error()}")
            return False
        resumed_any = False
        try:
            entry = _THREADENTRY32()
            entry.dwSize = _ctypes.sizeof(_THREADENTRY32)
            ok = _kernel32.Thread32First(snap, _ctypes.byref(entry))
            while ok:
                if entry.th32OwnerProcessID == int(pid):
                    hthr = _kernel32.OpenThread(
                        _THREAD_SUSPEND_RESUME, False, entry.th32ThreadID)
                    if hthr:
                        try:
                            rc = _kernel32.ResumeThread(hthr)
                            if rc != 0xFFFFFFFF:
                                resumed_any = True
                        finally:
                            _kernel32.CloseHandle(hthr)
                ok = _kernel32.Thread32Next(snap, _ctypes.byref(entry))
            return resumed_any
        except Exception as e:
            _flog(f"[job] resume exception (pid={pid}): {e}")
            return resumed_any
        finally:
            _kernel32.CloseHandle(snap)

else:
    def _job_create():            return None
    def _job_assign_pid(h, pid):  return False
    def _job_terminate(h, ec=1):  return False
    def _job_close(h):            return None
    def _resume_process_main_thread(pid): return True
    def _wsl_kill_by_batpath(bat_path, tag=None): return False


def _hp_run(args, wait_s, capture=False):
    import tempfile as _hp_tempfile
    _out_f = None
    _out_path = None
    _p = None
    try:
        if capture:
            _hp_fd, _out_path = _hp_tempfile.mkstemp(prefix="pyf_hp_")
            _out_f = os.fdopen(_hp_fd, "wb")
        _p = subprocess.Popen(
            args, stdin=subprocess.DEVNULL,
            stdout=(_out_f if capture else subprocess.DEVNULL),
            stderr=subprocess.DEVNULL,
            creationflags=(0x08000000 if sys.platform == "win32" else 0))
    except Exception as _hp_e:
        _flog(f"[hp-run] spawn failed {args[:2]}: {_hp_e!r}")
    if _p is None:
        if _out_f is not None:
            try:
                _out_f.close()
            except Exception as _e:
                _flog(f"[ignored] _hp_run: {_e!r}")
        if _out_path:
            try:
                os.unlink(_out_path)
            except Exception as _e:
                _flog(f"[ignored] _hp_run: {_e!r}")
        return None, b""
    _hp_end = time.monotonic() + wait_s
    _hp_rc = None
    while time.monotonic() < _hp_end:
        _hp_rc = _p.poll()
        if _hp_rc is not None:
            break
        time.sleep(0.25)
    if _hp_rc is None:
        try:
            _p.kill()
        except Exception as _e:
            _flog(f"[ignored] _hp_run: {_e!r}")
        try:
            _p.wait(timeout=3)
        except Exception as _e:
            _flog(f"[ignored] _hp_run: {_e!r}")
    _hp_out = b""
    if _out_f is not None:
        try:
            _out_f.close()
        except Exception as _e:
            _flog(f"[ignored] _hp_run: {_e!r}")
        if _hp_rc is not None and _out_path:
            try:
                with open(_out_path, "rb") as _hp_rf:
                    _hp_out = _hp_rf.read()
            except Exception as _e:
                _flog(f"[ignored] _hp_run: {_e!r}")
        if _out_path:
            try:
                os.unlink(_out_path)
            except Exception as _e:
                _flog(f"[ignored] _hp_run: {_e!r}")
    return _hp_rc, _hp_out



def _assert_turn_integrity(position_cmd, context, move_count=None):
    if move_count is None:
        move_count = _count_moves(position_cmd)
    side = "sente" if (move_count % 2 == 0) else "gote"
    if _DEBUG_ASSERTIONS:
        _dlog(f"[TURN-CHECK] {context}: ply={move_count} side={side}")
    return move_count, side


def _assert_position_integrity(position_cmd, ctx_position, context):
    if not _DEBUG_ASSERTIONS:
        return
    if not position_cmd or not ctx_position:
        return
    if position_cmd == ctx_position:
        return
    p_tail = position_cmd.split("moves")[-1].strip()[-50:] if "moves" in position_cmd else ""
    c_tail = ctx_position.split("moves")[-1].strip()[-50:] if "moves" in ctx_position else ""
    if p_tail != c_tail:
        msg = (f"[POS-MISMATCH] {context}: "
               f"param='{p_tail}' ctx='{c_tail}'")
        _dlog(msg)
        _flog(msg)



if _IS_FROZEN:
    _ENGINES_DIR = os.path.dirname(os.path.dirname(sys.executable))
else:
    _ENGINES_DIR = os.path.dirname(os.path.dirname(os.path.abspath(__file__)))


_DL_ENGINE_BASENAME  = "engine.bat" if sys.platform == "win32" else "engine"

if sys.platform != "win32":
    _trt_libs_dir = None
    for _prefix in (sys.prefix, "/usr/local", "/usr"):
        for _pkg in ("dist-packages", "site-packages"):
            _candidate = os.path.join(
                _prefix, "lib",
                f"python{sys.version_info.major}.{sys.version_info.minor}",
                _pkg, "tensorrt_libs")
            if os.path.isdir(_candidate):
                _trt_libs_dir = _candidate
                break
        if _trt_libs_dir:
            break
    if _trt_libs_dir:
        _ld = os.environ.get("LD_LIBRARY_PATH", "")
        if _trt_libs_dir not in _ld:
            os.environ["LD_LIBRARY_PATH"] = (
                f"{_trt_libs_dir}:{_ld}" if _ld else _trt_libs_dir)


def _dl_engine_file(_dir):
    if sys.platform == "win32":
        _bat = os.path.join(_dir, "engine.bat")
        if os.path.isfile(_bat):
            return _bat
        _exe = os.path.join(_dir, "engine.exe")
        if os.path.isfile(_exe):
            return _exe
        return _bat
    return os.path.join(_dir, "engine")


def _nnue_engine_file(_dir):
    if sys.platform == "win32":
        for _name in ("engine.bat", "engine.exe", "engine"):
            _p = os.path.join(_dir, _name)
            if os.path.isfile(_p):
                return _p
        return os.path.join(_dir, "engine.bat")
    return os.path.join(_dir, "engine")


