for _bk, _bv in (list(_cfg.items()) if not _MP_LIGHT_IMPORT else []):
    if not (isinstance(_bk, str) and _bk.endswith("_Path")):
        continue
    _bv_s = str(_bv)
    _bv_ext = os.path.splitext(_bv_s)[1].lower()
    if _bv_ext in (".bat", ".cmd"):
        if os.path.exists(_bv_s):
            continue
        _bv_alts = [os.path.splitext(_bv_s)[0] + ".exe",
                    os.path.splitext(_bv_s)[0],
                    os.path.splitext(_bv_s)[0] + ".sh"]
    elif _bv_ext == ".exe":
        if os.path.exists(_bv_s):
            continue
        _bv_alts = [os.path.splitext(_bv_s)[0] + ".bat",
                    os.path.splitext(_bv_s)[0],
                    os.path.splitext(_bv_s)[0] + ".sh"]
    elif _bv_ext == "":
        if os.name == "nt":
            _bv_alts = [_bv_s + ".exe", _bv_s + ".bat"]
        elif os.path.exists(_bv_s):
            continue
        else:
            _bv_alts = [_bv_s + ".exe", _bv_s + ".bat", _bv_s + ".sh"]
    else:
        continue
    for _bv_alt in _bv_alts:
        if os.path.exists(_bv_alt):
            _cfg[_bk] = _bv_alt
            break

for _lpk in (list(_cfg) if not _MP_LIGHT_IMPORT else []):
    if not (_lpk.endswith(("_Path", "Dir"))):
        continue
    _lpv = str(_cfg.get(_lpk) or "").strip()
    if not _lpv:
        continue
    if _lpv.startswith("~"):
        _lpv_x = os.path.expanduser(_lpv)
        _flog(f"[LINUX-PATH] {_lpk}: '~' 展開 {_lpv} → {_lpv_x}")
        _cfg[_lpk] = _lpv = _lpv_x
    if sys.platform != "win32":
        _lp_ext = os.path.splitext(_lpv)[1].lower()
        if _lp_ext in (".exe", ".bat", ".cmd") and not os.path.exists(_lpv):
            _lp_stem = os.path.splitext(_lpv)[0]
            for _lp_cand in (_lp_stem, _lp_stem + ".sh"):
                if os.path.exists(_lp_cand):
                    _flog(f"[LINUX-PATH] {_lpk}: {_lpv} 不在 → {_lp_cand} へ "
                          f"自動フォールバック")
                    print(f"[WARN] {_lpk}: {os.path.basename(_lpv)} が無いため "
                          f"{os.path.basename(_lp_cand)} を使います",
                          file=sys.stderr, flush=True)
                    _cfg[_lpk] = _lpv = _lp_cand
                    break
        if re.match(r"^[A-Za-z]:[\\/]", _lpv):
            print(f"[WARN] {_lpk}={_lpv} は Windows パスです — Linux では "
                  "config.txt でこのキーを実在パスに上書きしてください",
                  file=sys.stderr, flush=True)
            _flog(f"[LINUX-PATH-GUARD] {_lpk}={_lpv} (Windows path on POSIX)")

