def _book_no_child_check(_idx: int) -> bool:
    _n = (_cfg.get(f"Book_Pool_{_idx}_BookFile", "") or "").strip().lower()
    if _n.endswith(".sbk"):
        return True
    if _n.endswith((".db", ".ybb")):
        _im = _norm_str(_cfg.get(f"Book_Pool_{_idx}_DB_InMemory", "false"))
        return _im in ("true", "1", "yes", "on")
    return False

