def _resolve_fv_scale(resolved_path: str, cfg_key: str) -> str:
    norm = os.path.normcase(os.path.normpath(resolved_path))
    for idx, pool_norm in _NNUE_POOL_PATHS_NORM.items():
        if norm == pool_norm:
            auto_val = str(_NNUE_POOL_FV_SCALE[idx])
            if cfg_key in _user_cfg_keys:
                return str(_cfg[cfg_key])
            return auto_val
    return str(_cfg[cfg_key])

