_revive_cooldown_s        = _cfloat(_cfg, "Revive_Cooldown_S", 45.0, lo=5.0)



_log_engine_stderr = bool(_cfg["Log_Engine_Stderr"])
_log_config        = bool(_cfg["Log_Config"])
_log_diagnosis     = bool(_cfg["Log_Diagnosis"])



_unreapable_procs = []
_unreapable_lock  = threading.Lock()

_LEASE_TLS = threading.local()


def _lease_acquire(eng, owner):
    prev = getattr(eng, "_lease_owner", None)
    if prev is not None and prev != owner:
        _flog(f"[LEASE-VIOLATION] {getattr(eng, 'name', '?')}: "
              f"'{owner}' が取得 — 保持中 '{prev}' と競合 (二重読み手の疑い)")
    eng._lease_owner = owner
    prev_tag = getattr(_LEASE_TLS, "tag", None)
    _LEASE_TLS.tag = owner
    return (prev, prev_tag)


def _lease_release(eng, token):
    prev, prev_tag = token
    eng._lease_owner = prev
    _LEASE_TLS.tag = prev_tag


def _leased(owner):
    def _wrap(fn):
        @functools.wraps(fn)
        def _inner(eng, *args, **kwargs):
            _tok = _lease_acquire(eng, owner)
            try:
                return fn(eng, *args, **kwargs)
            finally:
                _lease_release(eng, _tok)
        return _inner
    return _wrap


class HealthState(enum.Enum):
    UNINIT      = enum.auto()
    RESTARTING  = enum.auto()
    ALIVE       = enum.auto()
    TERMINATING = enum.auto()
    DEAD        = enum.auto()


_HEALTH_CANONICAL = frozenset({
    (HealthState.UNINIT,      HealthState.RESTARTING),
    (HealthState.UNINIT,      HealthState.TERMINATING),
    (HealthState.RESTARTING,  HealthState.ALIVE),
    (HealthState.RESTARTING,  HealthState.DEAD),
    (HealthState.RESTARTING,  HealthState.TERMINATING),
    (HealthState.ALIVE,       HealthState.DEAD),
    (HealthState.ALIVE,       HealthState.TERMINATING),
    (HealthState.ALIVE,       HealthState.RESTARTING),
    (HealthState.TERMINATING, HealthState.DEAD),
    (HealthState.TERMINATING, HealthState.RESTARTING),
    (HealthState.DEAD,        HealthState.RESTARTING),
    (HealthState.DEAD,        HealthState.TERMINATING),
    (HealthState.DEAD,        HealthState.ALIVE),
})


def _health_of(eng) -> "HealthState":
    return getattr(eng, "_health", HealthState.UNINIT)


def _health_transition(eng, new_state, reason, caller=""):
    old = _health_of(eng)
    if old is new_state:
        eng._alive = (new_state is HealthState.ALIVE)
        return
    eng._health = new_state
    eng._alive = (new_state is HealthState.ALIVE)
    if (old, new_state) not in _HEALTH_CANONICAL:
        _flog(f"[HEALTH-FSM-VIOLATION] {getattr(eng, 'name', '?')}: "
              f"non-canonical {old.name}->{new_state.name} ({reason} @{caller})")
    else:
        _dlog(f"[HEALTH-FSM] {getattr(eng, 'name', '?')}: "
              f"{old.name}->{new_state.name} ({reason})")
    if new_state is HealthState.DEAD and getattr(eng, "name", "") == "nnue_1":
        _ctx = _REVIVE_CTX_REF
        try:
            if _ctx is not None and _ctx.ps.phase in _PS_PHASE_ACTIVE:
                _flog(f"[HEALTH-FSM-VIOLATION] I2: nnue_1 DEAD while "
                      f"phase={_ctx.ps.phase.name} ({reason})")
        except AttributeError:
            pass


class USIEngine:
    def __init__(self, path, name):
        self.path   = path
        self.name   = name
        self.proc   = None
        self._q     = queue.Queue(maxsize=50000)
        self._q_drop_count = 0
        self._alive = False
        self._health = HealthState.UNINIT
        self._send_lock = threading.Lock()
        self._via_shell = False
        self._job = None
        self._bat_path = None
        self._wsl_tag = None
        self._wsl_gen = 0
        self._force_stderr = False
        self._last_multipv_sent = None
        self._live_info_cb = None
        self._live_scored_latest = None
        self.announced_options: set = set()

        self._dld_logged: set = set()
        self._go_sent: int = 0
        self._bm_seen: int = 0
        self._bm_arrived: int = 0
        self._last_ack_gen: int | None = None
        self._bm_gen: int | None = None
        self._last_rec: dict | None = None
        self._last_drained_bm: str | None = None
        self._dup_drained_bm: bool = False
        self._start_gen: int = 0
        self._ssh_hb_stop: threading.Event = threading.Event()
        self._cuda_visible_devices: str = ""

    def _ssh_stdin_heartbeat(self, proc):
        _n = 0
        _flog(f"[{self.name}] SSH-HB thread started (pid={proc.pid})")
        while not self._ssh_hb_stop.wait(3.0):
            if proc is not self.proc:
                _flog(f"[{self.name}] SSH-HB stopped: proc replaced")
                break
            if not self._alive:
                _flog(f"[{self.name}] SSH-HB stopped: not alive")
                break
            try:
                with self._send_lock:
                    if proc.stdin and not proc.stdin.closed:
                        proc.stdin.write("\n")
                        proc.stdin.flush()
                        _n += 1
            except Exception as _e:
                _flog(f"[{self.name}] SSH-HB stopped: write error {_e!r}")
                break
        _flog(f"[{self.name}] SSH-HB thread exited (sent={_n})")

    def start(self):
        _health_transition(self, HealthState.RESTARTING, "start", caller="USIEngine.start")
        if self.proc is not None:
            _terminate_proc_full(
                self.proc, job=self._job, via_shell=self._via_shell,
                bat_path=self._bat_path, wsl_tag=self._wsl_tag, name=self.name)
            self._job = None
            try:
                self.proc.wait(timeout=5)
            except Exception as _fe:
                _flog(f"[ignored] {__file__}:1529: {_fe}")
            _drain_deadline = time.perf_counter() + 3.0
            while time.perf_counter() < _drain_deadline:
                try:
                    item = self._q.get(timeout=0.1)
                    if item is None:
                        break
                except queue.Empty:
                    continue
            while True:
                try:
                    self._q.get_nowait()
                except queue.Empty:
                    break
            self._q = queue.Queue(maxsize=50000)
            self.proc = None
            self._last_multipv_sent = None
            self._last_sp_sent = None
            self.announced_options = set()
            self._dld_logged = set()
            self._dyn_threads_last = None
            self._pvmate_last = None
            self._go_sent = 0
            self._bm_seen = 0
            self._bm_arrived = 0
            self._last_ack_gen = None
            self._bm_gen = None
            self._last_rec = None
            self._last_drained_bm = None
            self._dup_drained_bm = False

        _popen_kwargs = dict(
            stdin=subprocess.PIPE,
            stdout=subprocess.PIPE,
            stderr=(subprocess.PIPE
                    if (_log_engine_stderr or self._force_stderr)
                    else subprocess.DEVNULL),
            bufsize=1,
            cwd=os.path.dirname(os.path.abspath(self.path)),
        )
        if self._cuda_visible_devices:
            _env = os.environ.copy()
            _env["CUDA_VISIBLE_DEVICES"] = self._cuda_visible_devices
            _popen_kwargs["env"] = _env

        _ext = os.path.splitext(self.path)[1].lower()
        if sys.platform == "win32" and _ext in (".bat", ".cmd"):
            _argv = ["cmd", "/c", self.path]
            self._via_shell = True
            self._bat_path = self.path
            self._wsl_gen += 1
            _reap_key = os.environ.get("PYFAMATE_WSL_REAP_KEY") or str(os.getpid())
            self._wsl_tag = f"PYFMTAG_{self.name}_{_reap_key}_{self._wsl_gen}"
            _argv.append(self._wsl_tag)
            if not getattr(self, "_bat_warned", False):
                try:
                    _bat_src = open(self.path, "r", encoding="utf-8", errors="replace").read()
                    if "%*" not in _bat_src:
                        _msg = (f"[{self.name}] WARNING: engine.bat does not forward %* "
                                f"— WSL pkill will silently miss and Linux nnue will leak. "
                                f"Add `%*` to the wsl line in: {self.path}")
                        _flog(_msg)
                        try:
                            print(_msg, file=sys.stderr, flush=True)
                        except Exception as _e:
                            _flog(f"[ignored] start: {_e!r}")
                except Exception as _e:
                    _flog(f"[ignored] start: {_e!r}")
                self._bat_warned = True
        elif sys.platform != "win32" and _ext == ".sh":
            _argv = ["/bin/sh", os.path.abspath(self.path)]
            self._via_shell = True
            self._bat_path = None
            self._wsl_tag = None
            _popen_kwargs["start_new_session"] = True
        else:
            if sys.platform != "win32" and not os.access(self.path, os.X_OK):
                try:
                    os.chmod(self.path, 0o755)
                except OSError as _e:
                    _flog(f"[ignored] start: {_e!r}")
            _argv = [os.path.abspath(self.path)]
            self._via_shell = False
            self._bat_path = None
            self._wsl_tag = None
            if sys.platform != "win32":
                _popen_kwargs["start_new_session"] = True

        _CREATE_NO_WINDOW  = 0x08000000
        _CREATE_SUSPENDED  = 0x00000004
        self._job = None
        _use_job = (sys.platform == "win32" and self._via_shell)
        if sys.platform == "win32":
            _flags = _CREATE_NO_WINDOW
            if _use_job:
                _flags |= _CREATE_SUSPENDED
            _popen_kwargs["creationflags"] = _flags

        self.proc = _popen_utf8(_argv, **_popen_kwargs)

        if _use_job:
            self._job = _job_create()
            _assigned = _job_assign_pid(self._job, self.proc.pid) if self._job else False
            if not _assigned and self._job is not None:
                _flog(f"[{self.name}] job assign failed — closing job, "
                      "will rely on taskkill fallback in quit()")
                _job_close(self._job)
                self._job = None
            _resumed = _resume_process_main_thread(self.proc.pid)
            if not _resumed:
                _flog(f"[{self.name}] ResumeThread failed — "
                      f"killing suspended pid={self.proc.pid}, "
                      f"retrying without CREATE_SUSPENDED")
                try:
                    self.proc.kill()
                    self.proc.wait(timeout=3)
                except Exception as _e:
                    _flog(f"[ignored] start: {_e!r}")
                if self._job:
                    _job_close(self._job)
                    self._job = None
                _popen_kwargs["creationflags"] = _CREATE_NO_WINDOW
                self.proc = _popen_utf8(_argv, **_popen_kwargs)
                self._job = _job_create()
                if self._job:
                    if not _job_assign_pid(self._job, self.proc.pid):
                        _job_close(self._job)
                        self._job = None
                _flog(f"[{self.name}] restarted without SUSPENDED "
                      f"(pid={self.proc.pid} job={'yes' if self._job else 'no'})")
            else:
                _flog(f"[{self.name}] started under Job Object "
                      f"(pid={self.proc.pid} job={'yes' if self._job else 'no'})")

        _health_transition(self, HealthState.ALIVE, "start-ok", caller="USIEngine.start")
        self._start_gen += 1
        _proc = self.proc
        _spawn(f"reader/{self.name}", self._reader, _proc, self._q)
        if (_log_engine_stderr or self._force_stderr) and _proc.stderr:
            _spawn(f"stderr/{self.name}", self._stderr_reader, _proc)
        if self._via_shell:
            self._ssh_hb_stop = threading.Event()
            _spawn(f"ssh-hb/{self.name}", self._ssh_stdin_heartbeat, _proc)

    def _stderr_reader(self, proc):
        try:
            for line in proc.stderr:
                line = line.rstrip("\n")
                if line:
                    _flog(f"[{self.name}] STDERR: {line}")
        except Exception as _fe:
            _flog(f"[{self.name}] stderr reader died: {_fe!r} "
                  f"— closing child stderr to unblock writer (EPIPE)")
            try:
                proc.stderr.close()
            except Exception as _ce:
                _flog(f"[{self.name}] stderr close after reader death failed: {_ce!r}")

    def _reader(self, proc, q):
        try:
            for line in proc.stdout:
                _ln = _parse_usi_line(line.rstrip("\n"))
                if q.full() and _ln.kind == "info":
                    self._q_drop_count = getattr(self, "_q_drop_count", 0) + 1
                    if self._q_drop_count % 1000 == 1:
                        _flog(f"[{self.name}] reader queue full — "
                              f"dropped {self._q_drop_count} scoreless "
                              f"info lines (cumulative)")
                    continue
                q.put(_ln)
                if _ln.kind == "bestmove" and self.proc is proc:
                    self._bm_arrived += 1
                if _ln.kind == "scored" and self._live_info_cb is not None:
                    self._live_scored_latest = _ln
        except (KeyboardInterrupt, SystemExit):
            raise
        except Exception:
            _flog(f"[{self.name}] reader dead:\n" + _safe_format_exc().strip())
        finally:
            if self.proc is proc:
                _health_transition(self, HealthState.DEAD, "reader-eof", caller="USIEngine._reader")
            q.put(None)

    def send(self, cmd):
        _lo = getattr(self, "_lease_owner", None)
        if _lo is not None and getattr(_LEASE_TLS, "tag", None) != _lo:
            _flog(f"[LEASE-VIOLATION] {self.name}.send({cmd[:40]!r}) — "
                  f"リース保持者 '{_lo}' 以外の文脈から書き込み")
        if not self._alive or not self.proc or not self.proc.stdin:
            _flog(f"[{self.name}] send skipped (not alive): {cmd}")
            return
        try:
            with self._send_lock:
                self.proc.stdin.write(cmd + "\n")
                self.proc.stdin.flush()
                if cmd.startswith("go"):
                    self._go_sent += 1
        except BrokenPipeError:
            _health_transition(self, HealthState.DEAD, "send-brokenpipe", caller="USIEngine.send")
            try:
                self.proc.stdin.close()
            except Exception as _fe:
                _flog(f"[ignored] {__file__}:1604: {_fe}")
            _flog(f"[{self.name}] send BrokenPipe (process exited): {cmd}")
        except Exception as e:
            _health_transition(self, HealthState.DEAD, "send-error", caller="USIEngine.send")
            _flog(f"[{self.name}] send error: {e}")

    def _note_line(self, line):
        if line is not None:
            if line.startswith("bestmove"):
                with self._send_lock:
                    self._bm_seen += 1
                    self._bm_gen = self._last_ack_gen
                    self._last_ack_gen = None
            elif line.startswith("info string pyfa_ack "):
                try:
                    with self._send_lock:
                        self._last_ack_gen = int(line.split()[-1])
                except (ValueError, IndexError) as _e:
                    _flog(f"[ignored] _note_line: {_e!r}")
            elif line.startswith("info string pyfa_rec "):
                try:
                    self._last_rec = json.loads(line[len("info string pyfa_rec "):])
                except (json.JSONDecodeError, ValueError) as _e:
                    _flog(f"[ignored] _note_line: {_e!r}")
        return line

    def bm_is_current(self):
        return self._bm_seen == self._go_sent

    def search_outstanding(self):
        if self._go_sent <= 0:
            return True
        return self._go_sent > self._bm_arrived

    def classify_bestmove(self):
        if self._bm_gen is None:
            return "unknown"
        if self._bm_gen == self._go_sent:
            return "current"
        return "stale"

    def wait_for(self, keyword, timeout=300.0):
        deadline = time.perf_counter() + timeout
        while True:
            remaining = deadline - time.perf_counter()
            if remaining <= 0:
                return None
            try:
                line = self._note_line(self._q.get(timeout=min(remaining, 1.0)))
            except queue.Empty:
                continue
            if line is None:
                _health_transition(self, HealthState.DEAD, "sentinel", caller="USIEngine.wait_for")
                return None
            if keyword in line:
                return line

    def read_until(self, keyword, timeout=60.0):
        lines = []
        deadline = time.perf_counter() + timeout
        while True:
            remaining = deadline - time.perf_counter()
            if remaining <= 0:
                break
            try:
                line = self._note_line(self._q.get(timeout=min(remaining, 1.0)))
            except queue.Empty:
                continue
            if line is None:
                _health_transition(self, HealthState.DEAD, "sentinel", caller="USIEngine.read_until")
                break
            lines.append(line)
            if keyword in line:
                break
        return lines

    def iter_until(self, keyword, timeout=60.0):
        deadline = time.perf_counter() + timeout
        while True:
            remaining = deadline - time.perf_counter()
            if remaining <= 0:
                return
            try:
                line = self._note_line(self._q.get(timeout=min(remaining, 1.0)))
            except queue.Empty:
                continue
            if line is None:
                _health_transition(self, HealthState.DEAD, "sentinel", caller="USIEngine.iter_until")
                return
            yield line
            if keyword in line:
                return

    def readline(self, timeout=5.0):
        _lo = getattr(self, "_lease_owner", None)
        if _lo is not None and getattr(_LEASE_TLS, "tag", None) != _lo:
            _flog(f"[LEASE-VIOLATION] {self.name}.readline() — "
                  f"リース保持者 '{_lo}' 以外の文脈から読み取り (H3 型二重読み手)")
        try:
            line = self._note_line(self._q.get(timeout=timeout))
            if line is None:
                _health_transition(self, HealthState.DEAD, "sentinel", caller="USIEngine.readline")
                return None
            return line
        except queue.Empty:
            return ""

    def _force_accept_resync(self):
        with self._send_lock:
            self._bm_seen = self._go_sent
            self._bm_arrived = self._go_sent
            self._last_ack_gen = None
            self._bm_gen = None

    def flush_until_ready(self, timeout=30.0, max_stale_lines=500, relay_cb=None):
        if not self._alive or not self.proc or not self.proc.stdin:
            return False
        self.send("isready")
        deadline = time.perf_counter() + timeout
        _drained_count = 0
        _drained_tail: list = []
        def _tail_dump() -> str:
            if not _drained_tail:
                return ""
            return " tail=" + " | ".join(_l[:120] for _l in _drained_tail[-8:])
        _found_bestmove = False
        self._drained_bm_line = None
        while True:
            if _drained_count >= max_stale_lines:
                if _found_bestmove:
                    _flog(f"[{self.name}] flush_until_ready: stale line limit "
                          f"reached but bestmove was recovered — barrier OK")
                    self._force_accept_resync()
                    return True
                _flog(f"[{self.name}] flush_until_ready: stale line limit "
                      f"({max_stale_lines}) exceeded — treating as error "
                      f"(elapsed={time.perf_counter() - (deadline - timeout):.1f}s)"
                      f"{_tail_dump()}")
                return False
            remaining = deadline - time.perf_counter()
            if remaining <= 0:
                if _found_bestmove:
                    _flog(f"[{self.name}] flush_until_ready: timeout but "
                          f"bestmove was recovered during drain — barrier OK"
                          f"{_tail_dump()}")
                    self._force_accept_resync()
                    return True
                _flog(f"[{self.name}] flush_until_ready: timeout "
                      f"after draining {_drained_count} stale line(s)"
                      f"{_tail_dump()}")
                return False
            try:
                line = self._note_line(self._q.get(timeout=min(remaining, 1.0)))
            except queue.Empty:
                continue
            if line is None:
                if _found_bestmove:
                    _flog(f"[{self.name}] flush_until_ready: process exited "
                          f"but bestmove was recovered — barrier OK")
                    self._force_accept_resync()
                    return True
                _flog(f"[{self.name}] flush_until_ready: process exited "
                      f"after draining {_drained_count} stale line(s)"
                      f"{_tail_dump()}")
                return False
            if "readyok" in line:
                if _drained_count > 5:
                    _flog(f"[{self.name}] flush_until_ready: drained "
                          f"{_drained_count} stale line(s) before readyok")
                elif _drained_count > 0:
                    _dlog(f"[{self.name}] flush_until_ready: drained "
                          f"{_drained_count} stale line(s) before readyok")
                self._force_accept_resync()
                return True
            if relay_cb is not None and ("dl_live_policy " in line or
                                         "info " in line and " score " in line):
                try:
                    relay_cb(line)
                except Exception as _e:
                    _flog(f"[ignored] flush_until_ready: {_e!r}")
            if line.startswith("bestmove") and not _found_bestmove:
                _found_bestmove = True
                self._drained_bm_line = line
                if (" ponder " in line
                        and line == getattr(self, "_last_drained_bm", None)):
                    self._dup_drained_bm = True
                self._last_drained_bm = line
                _flog(f"[{self.name}] flush_until_ready: bestmove observed "
                      f"during drain (line {_drained_count}) — stop-flush 経由"
                      f"では ponder/停止応答の正常な読み捨て (取り逃しではない)"
                      f": {line[:80]}")
            if "Illegal Input Move" in line:
                try:
                    _bad = line.split("Illegal Input Move")[-1].split(":")[-1].strip().split()[0]
                except Exception:
                    _bad = "?"
                _flog(f"[{self.name}] ILLEGAL-INPUT detected during drain: "
                      f"child rejected move {_bad!r} — orchestrator/child board "
                      f"desync suspected; forcing full position resync on next go")
                self._force_position_resync = True
            _drained_count += 1
            _drained_tail.append(line)
            if len(_drained_tail) > 8:
                del _drained_tail[0]
            if _drained_count == 20:
                _flog(f"[{self.name}] flush_until_ready: drain count >= 20 (WARN)")

    def flush_with_stop(self, timeout=30.0, max_stale_lines=500):
        self.send("stop")
        return self.flush_until_ready(timeout=timeout, max_stale_lines=max_stale_lines)

    _DLD_DROP_NOTE = {
        "USI_Hash": "DNN MCTS は USI_Hash 非対応 — メモリ上限は UCT_NodeLimit / "
                    "DfPn_Hash で指定する (eval_options.txt 経由)",
    }

    _DLD_NUM_BASE = {
        "DNN_Model1":      "DNN_Model",
        "DNN_Batch_Size1": "DNN_Batch_Size",
        "UCT_Threads1":    "UCT_Threads",
    }

    def _dld_log_once(self, key, msg):
        if key not in self._dld_logged:
            self._dld_logged.add(key)
            _flog(f"[DLD][{self.name}] {msg}")

    _DNN_MODEL_KEYS = {"DNN_Model", "DNN_Model1"}

    def _dld_fix_dnn_model_value(self, key, val):
        if key not in self._DNN_MODEL_KEYS:
            return val
        _v = str(val)
        if re.match(r"^[A-Za-z]:[\\/]", _v) or _v.startswith(("/", "\\")):
            return val
        _norm = _v.replace("\\", "/")
        if _norm.lower().startswith("eval/"):
            _stripped = _norm[len("eval/"):]
            if _stripped and not _stripped.startswith("/"):
                self._dld_log_once(
                    "DNN_Model@" + key,
                    f"{key}: '{_v}' → '{_stripped}' に正規化 "
                    f"(EvalDir 基準の二重 eval/ を解消)")
                return _stripped
        return val

    def translate_option(self, key, val):
        ann = self.announced_options
        if not ann:
            return [(key, self._dld_fix_dnn_model_value(key, val))]
        if key in ann:
            return [(key, self._dld_fix_dnn_model_value(key, val))]
        base = self._DLD_NUM_BASE.get(key)
        if base is not None and base in ann:
            self._dld_log_once(
                key, f"{key} → {base} に正規化 (このビルドは番号なしキー / V9.00+)")
            return [(base, self._dld_fix_dnn_model_value(base, val))]
        if base is None:
            for _num, _base in self._DLD_NUM_BASE.items():
                if _base == key and _num in ann:
                    self._dld_log_once(
                        key, f"{key} → {_num} に正規化 "
                             f"(このビルドは番号付きキー / V9.00 未満)")
                    return [(_num, self._dld_fix_dnn_model_value(_num, val))]
        if key in self._DLD_DROP_NOTE and self._dld_is_dnn_engine():
            self._dld_log_once(
                key, f"{key} を破棄 (未 announce) — {self._DLD_DROP_NOTE[key]}")
            return []
        return [(key, self._dld_fix_dnn_model_value(key, val))]

    def _dld_is_dnn_engine(self):
        ann = self.announced_options
        return any(k in ann for k in
                   ("DNN_Model", "DNN_Model1", "UCT_Threads", "UCT_Threads1",
                    "UCT_Hash"))

    def setoption(self, key, val):
        for _k, _v in self.translate_option(key, val):
            self.send(f"setoption name {_k} value {_v}")
        if key == "Stochastic_Ponder":
            self._last_sp_sent = str(val)

    def initialize(self, options):
        self.send("usi")
        _usi_lines = self.read_until("usiok", timeout=60)
        if not any("usiok" in _l for _l in (_usi_lines or [])):
            raise RuntimeError(f"{self.name}: usiok timeout")
        for _l in _usi_lines:
            _m = re.match(r"option\s+name\s+(\S+)\s", _l)
            if _m:
                self.announced_options.add(_m.group(1))
        if self.announced_options:
            if self._dld_is_dnn_engine():
                if ("DNN_Model1" in self.announced_options
                        or "UCT_Threads1" in self.announced_options
                        or "DNN_Batch_Size1" in self.announced_options):
                    _flog(f"[DLD][{self.name}] DNN MCTS / 番号付きキー (ふかうら王 "
                          f"V9.00 未満系) を検出 — announce キーへ正規化して送信")
                else:
                    _flog(f"[DLD][{self.name}] DNN MCTS / 番号なしキー (ふかうら王 "
                          f"V9.00 以降系) を検出 — announce キーへ正規化して送信")
        _ann = self.announced_options
        _is_numberless = (_ann and self._dld_is_dnn_engine()
                          and "DNN_Model" in _ann and "DNN_Model1" not in _ann)
        _numbered_gpu_max = 0
        if _is_numberless:
            for _ok in options:
                _mb = re.match(r"DNN_Model(\d+)$", _ok)
                if _mb:
                    _numbered_gpu_max = max(_numbered_gpu_max, int(_mb.group(1)))
        _drop_numbered = set()
        if _numbered_gpu_max >= 2 and "Max_GPU" in options:
            try:
                _numbered_gpu_max = min(_numbered_gpu_max, int(options["Max_GPU"]))
            except (TypeError, ValueError) as _e:
                _flog(f"[ignored] initialize: {_e!r}")
        if _is_numberless and _numbered_gpu_max >= 2:
            for _gi in range(2, _numbered_gpu_max + 1):
                for _base in ("DNN_Model", "DNN_Batch_Size", "UCT_Threads"):
                    _drop_numbered.add(f"{_base}{_gi}")
            if "Max_GPU" in _ann:
                self.send(f"setoption name Max_GPU value {_numbered_gpu_max}")
                _flog(f"[DLD] {', '.join(sorted(_drop_numbered))} → "
                      f"Max_GPU={_numbered_gpu_max} に集約 (V9.00+ Multi-GPU)")
            else:
                _drop_numbered.clear()
                _flog(f"[DLD][WARN] Multi-GPU 指定を集約できない "
                      f"(Max_GPU 未 announce) — 単一GPUで続行")
        for key, val in options.items():
            if key in _drop_numbered:
                continue
            self.setoption(key, val)
        self.send("isready")

    def quit(self):
        _health_transition(self, HealthState.TERMINATING, "quit", caller="USIEngine.quit")
        self._ssh_hb_stop.set()
        if not self.proc:
            return
        try:
            with self._send_lock:
                if self.proc.stdin and not self.proc.stdin.closed:
                    self.proc.stdin.write("quit\n")
                    self.proc.stdin.flush()
        except (BrokenPipeError, ValueError, OSError) as _e:
            _flog(f"[ignored] quit: {_e!r}")
        try:
            with self._send_lock:
                if self.proc.stdin and not self.proc.stdin.closed:
                    self.proc.stdin.close()
        except OSError as _fe:
            if self.proc.poll() is None:
                _flog(f"[{self.name}] quit: stdin.close() failed on live child: {_fe!r}")
        except Exception as _fe:
            _flog(f"[{self.name}] quit: stdin.close() unexpected: {_fe!r}")
        try:
            self.proc.wait(timeout=15)
            _flog(f"[{self.name}] quit: graceful exit (rc={self.proc.returncode})")
            if self._bat_path:
                try:
                    _wsl_kill_by_batpath(self._bat_path, self._wsl_tag)
                except Exception as _we:
                    _flog(f"[{self.name}] post-graceful WSL pkill failed (non-fatal): {_we!r}")
            return
        except subprocess.TimeoutExpired:
            _flog(f"[{self.name}] quit timeout (15s) — killing")
        except Exception as e:
            _flog(f"[{self.name}] quit wait error: {e}")
        _terminate_proc_full(
            self.proc, job=self._job, via_shell=self._via_shell,
            bat_path=self._bat_path, wsl_tag=self._wsl_tag, name=self.name)
        self._job = None
        try:
            self.proc.wait(timeout=5)
            _flog(f"[{self.name}] quit: killed and reaped (rc={self.proc.returncode})")
        except subprocess.TimeoutExpired:
            _flog(f"[{self.name}] quit: reap timeout after kill — "
                  f"tracking pid={self.proc.pid} for deferred reap")
            with _unreapable_lock:
                _unreapable_procs.append(self.proc)
        except Exception as e:
            _flog(f"[{self.name}] quit: reap error: {e}")
        _health_transition(self, HealthState.DEAD, "quit-complete", caller="USIEngine.quit")



def _calc_remaining_moves(move_count, our_ms=0, *, cfg):
    _min_rem = cfg.dl_min_remaining_moves
    _expected = cfg.rem_moves_expected_game_ply
    _limit = min(_expected, 512)
    base_moves = max(1.0, (_limit - move_count) / 2.0)
    return _clamp(int(math.ceil(base_moves)), _min_rem, 256)


