def _pos_hash8(pos: str) -> str:
    return hashlib.md5((pos or "").encode()).hexdigest()[:8]


_NI_RECORD_KEYS = ("confidence", "depth_quality", "confidence_dq",
                    "sharpness", "momentum",
                    "regime_conviction", "regime_label",
                    "regime_collapse", "regime_force_crisis")

def _ni_record_fields(ni) -> dict:
    if not ni:
        return {k: None for k in _NI_RECORD_KEYS}
    return {k: ni.get(k) for k in _NI_RECORD_KEYS}


def _build_move_record(fields):
    unknown = [k for k in fields if k not in _MOVE_RECORD_DEFAULTS]
    if unknown:
        _flog(f"[C1] _build_move_record: 未登録キー {unknown} "
              f"— _MOVE_RECORD_DEFAULTS への追加を検討")
    rec = dict(_MOVE_RECORD_FROZEN, **fields)
    return rec


def _record_side(rec):
    for d in (rec.get("_diag") or []):
        if "side=sente" in d:
            return "sente"
        if "side=gote" in d:
            return "gote"
    return None


def _append_move_record(ctx, rec):
    _spd = ctx.game_progress.sp_move_diag
    rec["sp_early_collected"] = bool(_spd.get("sp_early_collected")) if _spd else False
    rec["sp_early_depth"]     = _spd.get("sp_early_depth")           if _spd else None
    rec["sp_echo_rejected"]   = _spd.get("sp_echo_rejected", 0)     if _spd else 0
    rec["sp_gen_rejected"]    = _spd.get("sp_gen_rejected", 0)      if _spd else 0
    rec["sp_adopt_gate"]      = _spd.get("sp_adopt_gate")           if _spd else None
    rec["sp_early_board"]     = _spd.get("sp_early_board")          if _spd else None
    ctx.game_progress.sp_move_diag = None

    rec["decided"] = ctx.game_progress.decided_latched

    if not ctx.game_progress.decided_latched:
        sc = rec.get("nnue_score_cp")
        if sc is not None and abs(sc) < _MATE_SCORE_CP:
            side = _record_side(rec)
            if side is None:
                _ply_side = rec.get("ply")
                if isinstance(_ply_side, int):
                    side = "sente" if _ply_side % 2 == 0 else "gote"
            win_th, lose_th = _decided_thresholds(side)
            if sc > win_th or sc < lose_th:
                ctx.game_progress.decided_latched = True

    if ctx.cfg.log_stats:
        try:
            _obs_board = _board_for_position(ctx.current_position)
        except Exception as _obe:
            _obs_board = None
            _dlog(f"[OBSERVE] board build skipped: {_obe!r}")
        if _obs_board is not None and rec.get("stance") is None:
            try:
                _st_mc = _count_moves(ctx.current_position)
                _mover_is_sente = (_side_to_move(_st_mc) == "gote")
                _sig = _obs_board.stance_signals(_mover_is_sente)
                _obs_dev, _obs_contact = _gp_dev_contact_core(_obs_board)
                _game_phase_now = _calc_state_phase(*_game_phase_state_counts_core(_obs_board),
                                         cfg=ctx.cfg, DEV=_obs_dev, CONTACT=_obs_contact)
                _game_phase_signed = _calc_game_phase_signed_delta(_game_phase_now, ctx.game_progress.stance_last_game_phase)
                _sc_now = rec.get("nnue_score_cp")
                _stance = _classify_stance_core(
                    game_phase_signed_delta=_game_phase_signed,
                    score_cp=_sc_now,
                    score_prev_cp=ctx.game_progress.stance_last_score,
                    material=_sig["material"],
                    king_pressure_opp=_sig["king_pressure_opp"],
                    king_pressure_self=_sig["king_pressure_self"],
                    in_check_opp=_sig["in_check_opp"],
                )
                rec["game_phase_signed_delta"]    = _game_phase_signed
                rec["stance"]             = _stance
                rec["stance_material"]    = _sig["material"]
                rec["stance_kp_opp"]      = _sig["king_pressure_opp"]
                rec["stance_kp_self"]     = _sig["king_pressure_self"]
                rec["stance_gives_check"] = _sig["in_check_opp"]
                ctx.game_progress.stance_last_game_phase = _game_phase_now
                if _sc_now is not None:
                    ctx.game_progress.stance_last_score = _sc_now
            except Exception as _ste:
                _dlog(f"[STANCE] classify skipped: {_ste!r}")

    ctx.game_log.append(rec)

    _live_stats_append_move(ctx, rec)

    if _REC_EMIT_ENABLED:
        _REC_EMIT_KEYS = _DISPLAY_KEYS
        try:
            _emit = {}
            for _ek in _REC_EMIT_KEYS:
                _ev = rec.get(_ek)
                if _ev is not None:
                    _emit[_ek] = _ev
            _emit.setdefault("nnue_bestmove",
                             rec.get("council_winner") or rec.get("bestmove"))
            if "pos_hash" not in _emit:
                _pos = getattr(ctx, "current_position", None) or ""
                _emit["pos_hash"] = _pos_hash8(_pos)
            for _csm_k in ("confidence", "sharpness", "momentum"):
                if _emit.get(_csm_k) is None:
                    _prev = _REC_EMIT_LAST_CSM.get(_csm_k)
                    if _prev is not None:
                        _emit[_csm_k] = _prev
                else:
                    _REC_EMIT_LAST_CSM[_csm_k] = _emit[_csm_k]
            for _rk in ("nnue_bestmove", "confidence", "sharpness",
                        "momentum", "pos_hash"):
                if _emit.get(_rk) is None:
                    _flog("[REC-EMIT-GAP] key=%s source=%s handler=%s"
                          % (_rk, rec.get("source", "?"),
                             rec.get("handler", "?")))
            _js = json.dumps(_emit, ensure_ascii=True, separators=(",", ":"), default=str)
            for _victim in ("dl_display_policy", "nnue_pv", "dl_1_pv", "regime_label"):
                if len(_js) <= 8192:
                    break
                _emit.pop(_victim, None)
                _js = json.dumps(_emit, ensure_ascii=True, separators=(",", ":"), default=str)
            print(f"info string pyfa_rec {_js}", flush=True)
        except (KeyboardInterrupt, SystemExit, MemoryError):
            raise
        except OSError as _e:
            _flog(f"[ignored] _append_move_record: {_e!r}")
        except Exception as _re_exc:
            _flog(f"[WO-2] pyfa_rec emit error: {_re_exc!r}")


_live_stats_lock = threading.Lock()
_stats_write_lock = _live_stats_lock


def _live_stats_enabled(ctx) -> bool:
    if _RUN_MODE is RunMode.DLP_CAL:
        return False
    return bool(ctx.cfg.log_stats)


def _live_stats_new_game(ctx, game_meta=None):
    if not _live_stats_enabled(ctx):
        return
    try:
        _meta = {"ts": time.time()}
        if game_meta:
            for _k in ("game_id", "result", "byoyomi_ms", "inc_ms", "total_ms"):
                if _k in game_meta:
                    _meta[_k] = game_meta[_k]
        _atomic_append(_STATS_PATH,
                       "#GAME " + json.dumps(_meta, ensure_ascii=False) + "\n",
                       lock=_stats_write_lock)
    except Exception as _e:
        _flog(f"[STATS] new_game write failed (ignored): {_e!r}")


def _live_stats_append_move(ctx, rec):
    if not _live_stats_enabled(ctx):
        return
    try:
        _out = {k: v for k, v in rec.items() if k != "_diag"} if _SPSA_MODE else dict(rec)
        if "ts" not in _out:
            _out["ts"] = round(time.time(), 3)
        if "pos_hash" not in _out:
            try:
                _pos = getattr(ctx, "current_position", None) or ""
                _out["pos_hash"] = _pos_hash8(_pos)
            except Exception as _e:
                _flog(f"[ignored] _live_stats_append_move: {_e!r}")
        _line = json.dumps(_out, ensure_ascii=False, default=str)
        _atomic_append(_STATS_PATH, _line + "\n", lock=_stats_write_lock,
                       fsync=False, os_write=True)
    except Exception as _e:
        _flog(f"[STATS] move write failed (ignored): {_e!r}")



def _council_lookup_prefetch_cache(ctx):
    cached, dl_cache_src = ctx.prefetch.get(ctx.current_position)
    prefetch_hit = cached is not None
    return cached, prefetch_hit, dl_cache_src




def _dyn_apply_nnue_threads(ctx, eng, path):
    return
    if not _dyn_threads_enable or eng is None:
        return
    if _RUN_MODE is RunMode.DLP_CAL:
        return
    try:
        _idle = _mon_idle_cores
        if _idle is None:
            return
        _spare = _RESOURCE_THREADS_SPARE_MIN
        _wc = (_tuning_worker_count
               if _tuning_mode and not _tuning_is_solo and _tuning_worker_count > 1
               else 1)
        _my_idle = _idle / _wc
        _nnue_now = getattr(eng, "_dyn_threads_last", None)
        if _nnue_now is None:
            _nnue_now = _cint(_cfg, _K_NNUE_1_THREADS, 4)
        _target = max(1, int(_nnue_now + _my_idle - _spare))
        _floor = max(1, _effective_cores() - _spare)
        _target = max(_target, _floor)
        _target = min(_target, _effective_cores())
        if _target == getattr(eng, "_dyn_threads_last", None):
            return
        eng.setoption("Threads", _target)
        _last = getattr(eng, "_dyn_threads_last", None)
        if _last != _target:
            _flog(f"[BUDGET-DYN] {getattr(eng, 'name', '?')} Threads "
                  f"{_last if _last is not None else '(規定値)'}→{_target} "
                  f"(idle={_idle:.1f} my_share={_my_idle:.1f} "
                  f"spare={_spare} path={path})")
        eng._dyn_threads_last = _target
    except Exception as _de:
        _flog(f"[BUDGET-DYN] 適用失敗 (無視・規定値で続行): "
              f"{type(_de).__name__}: {_de}")


def _dl_main_slot(ctx):
    return "dl_1"


_pvmate_dynamic = _cfg_bool("DL_PVMate_Dynamic", False)
_pvmate_main_threads_cfg = str(_cfg.get("DL_PVMate_Main_Threads", "")).strip()
_pvmate_sub_threads_cfg = str(_cfg.get("DL_PVMate_Sub_Threads", "")).strip()


def _dl_apply_pv_mate_threads(ctx, reason, budget_s=None):
    if not _pvmate_dynamic:
        return
    ctx._pvmate_pending = None
    try:
        _plan = _pvmate_threads_plan_core(_effective_cores())
        _main_t = (int(_pvmate_main_threads_cfg)
                   if _pvmate_main_threads_cfg else _plan["main"])
        _sub_t = (int(_pvmate_sub_threads_cfg)
                  if _pvmate_sub_threads_cfg else _plan["sub"])
        _main_slot = _dl_main_slot(ctx)
        _slots_map = {}
        for _sn, _eng, _opts_name in (
            ("dl_1", ctx.dl_1, "_dl_1_opts"),
        ):
            if _eng is None or not _eng_alive(_eng):
                continue
            _t = _main_t if _sn == _main_slot else _sub_t
            _ds_cfg_key = {"dl_1": "DL_1"}.get(_sn)
            if _ds_cfg_key:
                _user_key = f"{_ds_cfg_key}_PV_Mate_Search_Threads"
                if _user_key in _user_cfg_keys:
                    continue
            _slots_map[_sn] = (_eng, _opts_name, _t)
        for _sn, (_eng, _opts_name, _t) in _slots_map.items():
            if "PV_Mate_Search_Threads" not in _eng.announced_options:
                continue
            if _eng.classify_bestmove() != "current":
                ctx._pvmate_pending = True
                continue
            if getattr(_eng, "_pvmate_last", None) == _t:
                continue
            if budget_s is not None and budget_s < 1.0:
                ctx._pvmate_pending = True
                continue
            _eng.setoption("PV_Mate_Search_Threads", _t)
            _eng.flush_until_ready(timeout=2.0, max_stale_lines=50)
            _old = getattr(_eng, "_pvmate_last", None)
            _eng._pvmate_last = _t
            try:
                _opts_dict = globals().get(_opts_name)
                if _opts_dict is not None:
                    _opts_dict["PV_Mate_Search_Threads"] = str(_t)
            except Exception as _e:
                _flog(f"[ignored] _dl_apply_pv_mate_threads: {_e!r}")
            _flog(f"[PVMATE-DYN] {_sn} PV_Mate_Search_Threads "
                  f"{_old if _old is not None else '(既定)'}→{_t} "
                  f"(main={_main_slot} reason={reason})")
    except Exception as _pe:
        _flog(f"[PVMATE-DYN] 適用失敗 (旧値維持): {type(_pe).__name__}: {_pe}")


def _dyn_apply_nnue_hash(eng, eng_name, readyok_budget_s=None):
    if not _dyn_threads_enable or eng is None:
        return
    if _RUN_MODE is RunMode.DLP_CAL:
        return
    if _HASH_STATIC_ENABLED:
        return
    try:
        _avail = _mon_avail_mb
        if _avail is None:
            return
        _orig = getattr(eng, "_dyn_hash_original", None)
        if _orig is None:
            eng._dyn_hash_original = _cint(_cfg,
                f"{eng_name}_Hash", _cfg.get("USI_Hash", 256))
            _orig = eng._dyn_hash_original
        _current = getattr(eng, "_dyn_hash_last", _orig)
        _wc = (_tuning_worker_count
               if _tuning_mode and not _tuning_is_solo
               and _tuning_worker_count > 1 else 1)
        _my_avail = _avail // max(1, _wc)
        _margin = 2048
        _avail0 = getattr(eng, "_dyn_hash_avail0", None)
        if _avail0 is None:
            eng._dyn_hash_avail0 = _my_avail
            _avail0 = _my_avail
        _resident = min(_current, max(0, _avail0 - _my_avail))
        _target = max(64, min(_orig, _resident + _my_avail - _margin))
        _target = min(_target, _HASH_ABS_CAP_MB)
        if (_target > _current and readyok_budget_s is not None
                and readyok_budget_s < 55.0):
            _HASH_CLEAR_MB_PER_S = _HASH_CLEAR_MBPS
            _clear_budget_s = float(readyok_budget_s) * 0.6
            _max_increase = int(_clear_budget_s * _HASH_CLEAR_MB_PER_S)
            _ceiling = _current + _max_increase
            if _target > _ceiling:
                _flog(f"[BUDGET-DYN] {eng_name} Hash 拡大制限: "
                      f"{_current}→{_target}MB を {_ceiling}MB に抑制 "
                      f"(budget={readyok_budget_s:.1f}s "
                      f"clear_cap={_max_increase}MB)")
                _target = max(_current, _ceiling)
        if _target == _current:
            return
        _crisis_mb = 2048
        if (abs(_target - _current) < max(1024, _current // 4)
                and not (_target < _current and _my_avail < _crisis_mb)):
            _skip = getattr(eng, "_dyn_hash_skip_n", 0) + 1
            eng._dyn_hash_skip_n = _skip
            if abs(_target - _current) > 256 and _skip % 10 == 1:
                _flog(f"[BUDGET-DYN] {eng_name} Hash {_current}MB 維持 "
                      f"(目標 {_target}MB / 差 {_target - _current:+d}MB "
                      f"< 不感帯 {max(1024, _current // 4)}MB; "
                      f"avail={_avail}MB per_worker={_my_avail}MB "
                      f"見送り {_skip} 回目)")
            return
        eng.setoption("USI_Hash", _target)
        eng.send("isready")
        eng.flush_until_ready(
            timeout=(60.0 if readyok_budget_s is None
                     else max(5.0, min(60.0, float(readyok_budget_s)))))
        _flog(f"[BUDGET-DYN] {eng_name} Hash "
              f"{_current}→{_target}MB "
              f"(avail={_avail}MB per_worker={_my_avail}MB)")
        eng._dyn_hash_last = _target
        eng._dyn_hash_avail0 = _my_avail + _resident
        eng._dyn_hash_skip_n = 0
    except Exception as _e:
        _flog(f"[BUDGET-DYN] Hash adjust failed (ignored): {_e}")


_dl_dyn_nodes_enable = _cfg_bool("DL_Dynamic_Nodes_Enable", False)
_dl_dyn_nodes_gpu_thresh = _cint(_cfg, "DL_Dynamic_Nodes_GPU_Thresh", "85")
_dl_dyn_nodes_floor_ratio = _cfloat(_cfg, "DL_Dynamic_Nodes_Floor_Ratio", "0.25")


def _dyn_dl_nodes(base_nodes):
    if not _dl_dyn_nodes_enable:
        return base_nodes
    gpu = _mon_gpu_util
    if gpu is None or gpu < _dl_dyn_nodes_gpu_thresh:
        return base_nodes
    excess = (gpu - _dl_dyn_nodes_gpu_thresh) / max(1, 100 - _dl_dyn_nodes_gpu_thresh)
    floor = max(32, int(base_nodes * _dl_dyn_nodes_floor_ratio))
    target = max(floor, int(base_nodes * (1.0 - excess)))
    if target != base_nodes:
        _flog(f"[DL-DYN-NODES] nodes {base_nodes}→{target} "
              f"(gpu={gpu}% thresh={_dl_dyn_nodes_gpu_thresh}%)")
    return target




def _council_launch_nnue(ctx, line, move_count, go_clock, narrow_search_moves=None):
    _apply_slow_mover(ctx.nnue_1, _nnue_1_opts,
                      ctx.cfg.nnue_slowmover_user_set, "nnue_1-council", go_clock=go_clock, cfg=ctx.cfg)
    _dyn_apply_nnue_threads(ctx, ctx.nnue_1, "council")
    if getattr(ctx, "_pvmate_pending", None):
        _dl_apply_pv_mate_threads(ctx, "council(pending)")
    _dyn_apply_nnue_hash(ctx.nnue_1, "nnue_1",
                         readyok_budget_s=getattr(go_clock, "eff_s", None))
    ctx.nnue_1.send(ctx.current_position)
    _go_line = go_clock.patched_line
    if narrow_search_moves:
        _go_line = _go_line + " searchmoves " + " ".join(narrow_search_moves)
        _dlog(f"[NARROW-SEARCH] nnue_1 searchmoves={narrow_search_moves}")
    ctx.nnue_1.send(_go_line)





