def _ucfg_int(key, default):
    try:
        return int(_cfg.get(key, default))
    except Exception:
        return default

def _u_join_budget_s(st, floor_s=0.05, cap_s=None, tag="join"):
    if st.ledger is not None:
        want = st.ledger.left_s() if cap_s is None else cap_s
        return st.ledger.draw(tag, want, floor_s=floor_s)
    left = _move_budget_left_s(st.eff_s, st.t_go_start)
    if cap_s is not None:
        left = min(left, cap_s)
    return max(floor_s, left)

def _u_thresholds(st):
    try:
        return _calc_per_move_thresholds(st.eff_s, cfg=st.ctx.cfg, game_phase=st.gp)
    except Exception:
        return None

def _u_ta_disagree_nudge(st):
    votes = [m for m in (st.dl_top, st.nnue_top) if m]
    _n = len(votes)
    if _n < 2:
        return 1.0
    _top_ct = max(votes.count(_m) for _m in set(votes))
    _disagree_frac = (_n - _top_ct) / _n
    _cap = float(st.ctx.cfg.disagree_ta_nudge_cap)
    return 1.0 + (_cap - 1.0) * _disagree_frac



def _u_ph_setup(st):
    ctx = st.ctx
    _diag_reset()
    ctx.game_progress.decided_latched = False
    ctx.nnue_1._live_info_cb = None
    if _eng_alive(ctx.dl_1):
        ctx.dl_1._live_info_cb = _make_dl1_multipv_cb(ctx, ctx.current_position)
        _LIVE._live_register(ctx.dl_1)
    _mate_ponder_cancel(ctx, "ponderhit")
    if (ctx.ps.phase not in _PS_PHASE_ACTIVE
            and ctx.ps.phase is not PsPhase.MATE_SKIP):
        _flog("ponderhit: WARNING — phase=%s (ponderhit received without prior "
              "go ponder); proceeding to stale/cache-miss recovery path"
              % ctx.ps.phase.name)
    if ctx.ps.phase is PsPhase.MATE_SKIP:
        _ps_transition(ctx, PsPhase.PONDERING, "ponderhit-head (mate-skip 解除)")
    _ps_transition(ctx, PsPhase.PONDERHIT, "ponderhit")
    _patch_ponder_clock_from_ponderhit(ctx.ps, st.line)
    st.position_cmd = ctx.current_position or ctx.ps.position
    st.move_count = _count_moves(st.position_cmd)
    _assert_turn_integrity(st.position_cmd, "ponderhit", move_count=st.move_count)
    _assert_position_integrity(ctx.ps.position, ctx.current_position, "ponderhit")
    if ctx.ps.ponder_line:
        _ph_ck, _, _ = _parse_go_clock_base(ctx.ps.ponder_line, st.move_count, cfg=ctx.cfg)
        if _ph_ck.eff_s > 0:
            ctx.ps.ponder_clock = _ph_ck
            try:
                ctx.ps.ponder_clock_opp, _, _ = _parse_go_clock_base(
                    ctx.ps.ponder_line, st.move_count - 1, cfg=ctx.cfg)
            except Exception as _e:
                _flog(f"[ignored] _u_ph_setup: {_e!r}")
            _dlog("[PH-CLOCK-PATCH] ponder_clock updated: eff_s=%.3fs remaining_ms=%s"
                  % (_ph_ck.eff_s, _ph_ck.remaining_ms))
    try:
        _apply_time_dynamics(ctx, st.line, st.move_count, label="ponderhit",
                             clock_base=ctx.ps.ponder_clock)
    except (KeyboardInterrupt, SystemExit, MemoryError):
        raise
    except Exception as _ta_e:
        _flog(f"[PH-TA-REFRESH] failed (non-fatal): {type(_ta_e).__name__}: {_ta_e!r}")
    ctx.game_progress.ponderhit_emit_ni = None
    ctx.ps.last_go_position = ctx.current_position
    st.t_go_start = time.perf_counter()
    st.go_clock = _resolve_ponder_clock(ctx, "ponderhit")
    st.eff_s = (st.go_clock.eff_s if st.go_clock is not None else 0.0) or 0.0
    st.clock_rem_ms = st.go_clock.remaining_ms if st.go_clock is not None else None
    try:
        st.ledger = MoveBudget(eff_s=st.eff_s, remaining_ms=st.clock_rem_ms,
                               t0=st.t_go_start)
        ctx.ledger = st.ledger
    except Exception as _le:
        _flog(f"[ignored] ponderhit ledger init: {_le!r}")
    try:
        st.gp = _calc_game_phase(st.position_cmd, cfg=ctx.cfg,
                                 child_agreement=ctx.game_progress.last_child_agreement)
    except Exception:
        st.gp = 0.0


def _u_ph_dispatch(st):
    ctx = st.ctx
    r = _ponderhit_handle_mate_skip(ctx, st.position_cmd, st.move_count)
    if r is not None:
        st.verdict, st.ponder_move = r
        st.ph_branch, st.ph_short = "mate_skip", True
        return
    r = _ponderhit_handle_stale(ctx, st.position_cmd, st.move_count)
    if r is not None:
        st.verdict, st.ponder_move, st.pv_val = r
        st.ph_branch, st.ph_short = "stale_recovery", True
        return
    _pending = ctx.game_progress.opponent_id_pending
    if _pending is not None:
        try:
            _base_tokens_p2, _nnue_pred_p2, _dl_pred_p2 = _pending
            _ph_actual = _opponent_id_extract_actual_core(
                _base_tokens_p2, (st.position_cmd or "").split())
            if _nnue_pred_p2 and _ph_actual and _ph_actual == _nnue_pred_p2:
                ctx.game_progress.opponent_id_pending = None
                _dlog("[OPP-ID] ponderhit 経路: actual==nnue_pred 恒等観測を skip "
                      "(片側ペギング抑止)")
        except Exception as _r2e:
            _flog(f"[ignored] OPP-ID ponderhit null-obs: {_r2e!r}")
    _opponent_id_observe(ctx, st.position_cmd)
    _harvest_dl_ponders(ctx, st.position_cmd,
                        eff_s=(ctx.ps.ponder_clock.eff_s
                               if ctx.ps.ponder_clock is not None else None))
    _phit_trace("harvest")
    try:
        dl1_cache, dl1_src = ctx.prefetch.get(st.position_cmd)
    except Exception as _pe:
        _flog(f"[unify:ponderhit] prefetch.get: {_pe!r}")
        dl1_cache = dl1_src = None
    if dl1_cache is not None:
        st.ph_branch = "cache_hit"
        st.prefetch_hit = True
        st.dl1_cache = dl1_cache
        st.dl_cache_src = dl1_src
        _dlog("[PH-CACHE-HIT] prefetch cache consumed (dl1=%s)"
              % (dl1_cache is not None,))
        if dl1_cache is not None and dl1_cache.policy:
            st.extra_stats["_live_dl1_policy"] = list(dl1_cache.policy)
    else:
        st.ph_branch = "cache_miss"
        _dlog("[PH-MISS] normal relay path")


def _u_ph_restart(st, caller, slowmover_label=None):
    holder = [None]
    r = _ponderhit_restart_nnue1_and_movetime(
        st.ctx, st.position_cmd, st.move_count, st.eff_s, st.clock_rem_ms,
        caller, slowmover_label=slowmover_label,
        ponder_line=(st.ctx.ps.ponder_line or st.ctx.ps.go_line or "go movetime 1000"),
        relay_kwargs={"partial_pv_holder": holder},
        go_clock=st.go_clock)
    return r, holder


def _u_ph_short_empty(st, reason):
    _flog(f"[PH/unify] {reason} — 空で返し finalize 救済カスケードへ")
    st.verdict, st.ponder_move, st.pv_val = "", None, None
    st.ph_short = True


def _u_ph_relay(st):
    ctx = st.ctx
    eff_s = st.eff_s
    _crm = st.clock_rem_ms
    _tag = "PH-CACHE-HIT" if st.ph_branch == "cache_hit" else "PH-MISS"
    _pv = [None]
    _ni = None
    try:
        cb = _make_live_think_cb(ctx, "ponderhit", st.position_cmd,
                                 game_phase=st.gp,
                                 game_phase_delta=_calc_game_phase_delta(
                                     st.gp, ctx.game_progress.last_game_phase))
    except Exception:
        cb = None

    if not ctx.nnue_1._alive:
        _flog(f"[{_tag}] nnue_1 dead — attempting restart")
        r, _pv = _u_ph_restart(st, "ponderhit-entry",
                               slowmover_label="nnue_1-ph-entry-restart")
        if r is None:
            _u_ph_short_empty(st, "nnue_1 restart failed (entry)")
            return
        _pm, _ni = r
    elif st.ph_branch == "cache_miss" and "nnue_1" not in ctx.ps.pending_bestmove:
        _dlog("[PH-MISS/B-c] nnue_1 債務なし → bypass ponderhit; "
              "send position+go directly to idle nnue_1")
        _bp_mt = max(100, int(eff_s * 1000)) if eff_s and eff_s > 0 else 1000
        ctx.nnue_1.send(st.position_cmd)
        ctx.nnue_1.send(f"go movetime {_bp_mt}")
        _bp_to = max(0.5, _bp_mt / 1000.0 + 0.5)
        _phit_trace("cm_bypass_relay_start", to="%.1f" % _bp_to)
        _bp_rem = _ph_recovery_rem_ms(_crm)
        _pm, _ni = relay_window(
            ctx.nnue_1, timeout=_bp_to, intercept_bestmove=True,
            partial_pv_holder=_pv, go_clock=st.go_clock,
            remaining_ms=(max(1, int(_bp_rem)) if _bp_rem is not None else None),
            live_info_cb=cb)
        _bm, _pd = _unpack_bestmove(_ni)
        _phit_trace("cm_bypass_relay_end", bm=_bm or "-")
        if _sp_echo_reject(ctx, _bm, "PH-MISS/B-c"):
            _phit_trace("echo_reject", bm=_bm)
            _bm, _pd, _pv[0] = "", None, None
        st.verdict, st.ponder_move, st.pv_val = _bm, _pd, _pv[0]
        st.nnue_info = _ni or {}
        st.ph_short = True
        return
    else:
        _sp = None
        if "nnue_1" in ctx.ps.pending_bestmove:
            _sp = _ponderhit_try_collect_sp_early(ctx, st.position_cmd, eff_s, _tag)
        if _sp is not None:
            _sp_bm, _sp_pd, _sp_ni = _sp
            _phit_trace("sp_early", bm=_sp_bm or "-")
            if st.ph_branch == "cache_hit":
                st.nnue_info = _sp_ni or {}
                st.ponder_move = st.nnue_info.get("ponder")
                st.pv_val = _sp_bm or None
                if _sp_ni is not None and not _sp_ni.get("score_cp") and _sp_bm:
                    _ponderhit_capture_emit_ni(ctx, _sp_ni, _sp_bm)
                return
            st.verdict, st.ponder_move = _sp_bm, _sp_pd
            st.nnue_info = _sp_ni or {}
            st.pv_val = _sp_bm or None
            ctx.game_progress.ponder_move_nnue = _sp_bm or None
            _ponderhit_capture_emit_ni(ctx, _sp_ni, _sp_bm)
            st.ph_short = True
            return
        _ponder_line = ctx.ps.ponder_line or ctx.ps.go_line
        if _ponder_line and st.go_clock:
            _relay_to = _ponderhit_calc_relay_timeout(
                _ponder_line, st.move_count, st.go_clock, cfg=ctx.cfg)
        else:
            _relay_to = max(1.0, eff_s * 1.5) if eff_s else 10.0
        if True:
            _apply_slow_mover(ctx.nnue_1, _nnue_1_opts,
                              ctx.cfg.nnue_slowmover_user_set, "nnue_1-ph-%s" % st.ph_branch,
                              eff_s=eff_s, cfg=ctx.cfg)
            _line = _ponderhit_line_for_nnue(ctx.ps)
            _idle_gate = _nnue_idle_structurally(ctx.nnue_1)
            if _idle_gate:
                _relay_to = min(_relay_to, _clamp(eff_s * 0.1, 0.3, 2.0))
                _flog("[PH-SKIP-UNIFY/%s] nnue_1 structurally idle "
                      "(go_sent=%d bm_arrived=%d) — ponderhit suppressed, "
                      "relay clamped to %.1fs"
                      % (_tag, getattr(ctx.nnue_1, "_go_sent", 0),
                         getattr(ctx.nnue_1, "_bm_arrived", 0), _relay_to))
            else:
                ctx.nnue_1.send(_line)
                _dlog("[%s] %r sent to nnue_1 (SP=%s)"
                      % (_tag, _line, _nnue_1_opts.get("Stochastic_Ponder", "?")))
            _phit_trace("ph_relay_start", to="%.1f" % _relay_to)
        if st.ledger is not None:
            st.ledger.note("relay", _relay_to)
        _rw_rem = _ph_recovery_rem_ms(_crm)
        _pm, _ni = relay_window(
            ctx.nnue_1, timeout=_relay_to, intercept_bestmove=True,
            partial_pv_holder=_pv, go_clock=st.go_clock,
            remaining_ms=(max(1, int(_rw_rem)) if _rw_rem is not None else None),
            kill_on_empty=False, live_info_cb=cb)
        _phit_trace("ph_relay_end", bm=(_ni.get("bestmove", "") if _ni else "") or "-")
        if _ni and _ni.get("bestmove", "") and not ctx.nnue_1.bm_is_current():
            _g_bm = _ni.get("bestmove", "")
            _flog("[%s/SP-GEN] relay bestmove %r is stale generation "
                  "(bm_seen=%d go_sent=%d) — rejecting"
                  % (_tag, _g_bm, ctx.nnue_1._bm_seen, ctx.nnue_1._go_sent))
            _phit_trace("gen_reject", bm=_g_bm)
            _ni["bestmove"] = ""
            _pv[0] = None
            _spd = ctx.game_progress.sp_move_diag
            if _spd is None:
                _spd = {}
                ctx.game_progress.sp_move_diag = _spd
            _spd["sp_gen_rejected"] = _spd.get("sp_gen_rejected", 0) + 1
        if _ni and _ni.get("bestmove", ""):
            _e_bm = _ni.get("bestmove", "")
            _e_board = _get_tracking_board(ctx)
            if (_e_board is not None
                    and not _bestmove_is_for_board(_e_bm, _e_board)):
                _flog("[%s/SP-echo] relay bestmove %r after ponderhit is not a "
                      "move for the current board — rejecting, fall through to "
                      "re-search recovery" % (_tag, _e_bm))
                _phit_trace("echo_reject", bm=_e_bm)
                _ni["bestmove"] = ""
                _pv[0] = None

    if not (_ni and _ni.get("bestmove", "")):
        _flog("[%s] relay returned empty bestmove after ponderhit (SP=%s) "
              "— stop+drain then position+go re-search"
              % (_tag, _nnue_1_opts.get("Stochastic_Ponder", "?")))
        _ts_rem = _ph_recovery_rem_ms(_crm)
        if _ts_rem is not None and _ts_rem < _move_overhead_ms + 1500:
            _flog("[%s/TIGHT-SKIP] recovery 残 %.0fms < overhead+1500ms "
                  "— stop/restart/再探索を放棄し即 finalize 救済へ "
                  "(nnue_1 は async revive)" % (_tag, _ts_rem))
            _phit_trace("tight_skip", rem="%.0f" % _ts_rem)
            try:
                if ctx.nnue_1._alive:
                    ctx.nnue_1.send("stop")
                else:
                    _revive_dead_nnue_async(ctx)
            except Exception as _ts_e:
                _flog(f"[{_tag}/TIGHT-SKIP] non-fatal: {_ts_e}")
            _u_ph_short_empty(st, "TIGHT-SKIP")
            return
        if not ctx.nnue_1._alive:
            _flog(f"[{_tag}] nnue_1 died during ponderhit relay — restarting before re-search")
            r, _pv = _u_ph_restart(st, "ponderhit-recovery",
                                   slowmover_label="nnue_1-ph-recovery-restart")
            if r is None:
                _u_ph_short_empty(st, "nnue_1 restart failed (recovery)")
                return
            _pm, _ni = r
        else:
            ctx.nnue_1.send("stop")
            _rc_rem = _ph_recovery_rem_ms(_crm)
            _drain_to = _stop_drain_timeout_safe(ctx, eff_s)
            if _rc_rem is not None:
                _drain_to = min(_drain_to, max(0.3, _rc_rem / 1000.0 - _move_overhead_s))
            relay_drain(ctx.nnue_1, timeout=_drain_to,
                        remaining_ms=(max(1, int(_rc_rem)) if _rc_rem is not None else None),
                        intercept_bestmove=True, kill_on_empty=False)
            _phit_trace("ph_drain")
            if not ctx.nnue_1._alive:
                _flog(f"[{_tag}] nnue_1 died during stop+drain — restarting before re-search")
                r, _pv = _u_ph_restart(st, "ponderhit-recovery-drain",
                                       slowmover_label="nnue_1-ph-recovery-drain-restart")
                if r is None:
                    _u_ph_short_empty(st, "nnue_1 restart failed (drain)")
                    return
                _pm, _ni = r
            else:
                if not _flush_or_mark_dirty(ctx, _tag, eff_s):
                    _u_ph_short_empty(st, "flush_or_mark_dirty failed")
                    return
                _apply_slow_mover(ctx.nnue_1, _nnue_1_opts,
                                  ctx.cfg.nnue_slowmover_user_set,
                                  "nnue_1-ph-empty-recovery", eff_s=eff_s, cfg=ctx.cfg)
                _rs_mt = max(500, int(eff_s * 200 * _time_aggression_base_gain(
                    getattr(_time_dyn, 'time_aggression', _TA_BASE_ANCHOR) or _TA_BASE_ANCHOR)))
                _rc_rem = _ph_recovery_rem_ms(_crm)
                if _rc_rem is not None:
                    _rs_mt = int(_clamp(_rc_rem - _move_overhead_ms - 300, 300, _rs_mt))
                ctx.nnue_1.send(st.position_cmd)
                ctx.nnue_1.send("go movetime %d" % _rs_mt)
                _rs_to = _rs_mt / 1000.0 + _clamp(eff_s * 0.5, 0.5, 3.0)
                if _rc_rem is not None:
                    _rs_to = min(_rs_to, max(0.3, _rc_rem / 1000.0 - _move_overhead_s))
                _pv = [None]
                _pm, _ni = relay_window(
                    ctx.nnue_1, timeout=_rs_to, partial_pv_holder=_pv,
                    go_clock=st.go_clock,
                    remaining_ms=(max(1, int(_rc_rem)) if _rc_rem is not None else None),
                    intercept_bestmove=True, kill_on_empty=False, live_info_cb=cb)
                _phit_trace("ph_research",
                            bm=(_ni.get("bestmove", "") if _ni else "") or "-")
        if _ni and _ni.get("bestmove", ""):
            _r_bm = _ni.get("bestmove", "")
            _r_board = _get_tracking_board(ctx)
            if (_r_board is not None
                    and not _bestmove_is_for_board(_r_bm, _r_board)):
                _flog("[%s/SP-echo] recovery bestmove %r is not a move for the "
                      "current board — dropping (phantom-go residue)" % (_tag, _r_bm))
                _phit_trace("echo_reject2", bm=_r_bm)
                _ni = None
                _pv = [None]

    st.nnue_info = _ni or {}
    st.ponder_move = st.nnue_info.get("ponder")
    st.pv_val = _pv[0]


def _u_ph_capture_emit(st):
    ctx = st.ctx
    _nn_bm = st.nnue_info.get("bestmove") or None
    ctx.game_progress.ponder_move_nnue = _nn_bm
    if st.ph_branch == "cache_hit":
        try:
            if st.verdict and st.verdict not in ("resign", "win"):
                _score = _ponderhit_pick_emit_score(
                    st.verdict, _nn_bm, st.nnue_info.get("score_cp"),
                    st.dl_top, st.dl_top_score)
                if _score is not None:
                    ctx.game_progress.ponderhit_emit_ni = {
                        "score_cp": int(_score),
                        "depth":    st.nnue_info.get("depth", 0) or 0,
                        "seldepth": st.nnue_info.get("seldepth", 0) or 0,
                        "pv":       st.nnue_info.get("pv", "") or "",
                        "bestmove": st.verdict,
                    }
        except Exception as _ee:
            _flog(f"[PH-EMIT] capture failed (ignored): {_ee!r}")
    else:
        _ponderhit_capture_emit_ni(ctx, st.nnue_info, st.verdict)


def _u_ph_cm_dl_restore(st):
    ctx = st.ctx
    if st.ph_branch != "cache_miss":
        return
    bestmove = st.verdict
    eff_s = st.eff_s
    _cm_dl_top_move = None
    _cm_dl_top_score = None
    try:
        _cm_overhead_ms = _move_overhead_ms if _move_overhead_ms else 100
        _cm_remaining = st.clock_rem_ms if st.clock_rem_ms is not None else (eff_s * 1000)
        _cm_budget_ms = _cm_remaining - _cm_overhead_ms - 500
        if (bestmove and _cm_budget_ms > 300
                and _eng_alive(ctx.dl_1)
                and ctx.prefetch is not None):
            ctx.prefetch.cancel()
            _cm_lock_timeout = min(0.3, _cm_budget_ms / 1000 * 0.3)
            if ctx.prefetch.dl_1_lock.acquire(timeout=_cm_lock_timeout):
                try:
                    ctx.dl_1.flush_until_ready(timeout=1.0)
                    _cm_dl_mt = _clamp(int(_cm_budget_ms * 0.4), 100, 500)
                    if st.ledger is not None:
                        st.ledger.note("cm-dl-restore", _cm_dl_mt / 1000.0)
                    _cm_ms, _, _, _, _ = _run_dl_1_search(
                        ctx.dl_1, st.position_cmd, 2, 100,
                        timeout=_cm_dl_mt / 1000.0 + 1.0,
                        movetime_ms=_cm_dl_mt)
                    if _cm_ms:
                        _cm_ranked = sorted(_cm_ms.items(), key=lambda x: x[1], reverse=True)
                        _cm_dl_top_move = _cm_ranked[0][0]
                        _cm_dl_top_score = _cm_ranked[0][1]
                        _dlog(f"[CM-DL-RESTORE] DL_1 top={_cm_dl_top_move} "
                              f"score={_cm_dl_top_score} nnue={bestmove} "
                              f"agree={_cm_dl_top_move == bestmove}")
                finally:
                    ctx.prefetch.dl_1_lock.release()
            else:
                _dlog("[CM-DL-RESTORE] dl_1_lock timeout — skipped")
        else:
            _dlog(f"[CM-DL-RESTORE] skipped (budget={_cm_budget_ms:.0f}ms "
                  f"dl_alive={_eng_alive(ctx.dl_1) if ctx.dl_1 else False})")
    except Exception as _cm_e:
        _flog(f"[ignored] CM-DL-RESTORE: {_cm_e!r}")
    _cm_nnue_cp = st.nnue_info.get("score_cp")
    if _cm_dl_top_score is not None:
        ctx.game_progress.ponder_move_dl = _cm_dl_top_move
        st.dl_top = _cm_dl_top_move
        st.dl_top_score = _cm_dl_top_score
    _cm_overridden = False
    if (_cm_dl_top_move is not None
            and _cm_dl_top_score is not None
            and _cm_dl_top_move != bestmove
            and _cm_dl_top_move != "resign"
            and _cm_dl_top_score >= 0):
        _cm_ov_legal = True
        try:
            _cm_ov_board = _get_tracking_board(ctx)
            if (_cm_ov_board is not None
                    and not _bestmove_is_for_board(_cm_dl_top_move, _cm_ov_board)):
                _flog(f"[CM-DL-OVERRIDE] DL_1={_cm_dl_top_move!r} illegal on "
                      f"current board — rejecting override, keeping NNUE={bestmove!r}")
                _cm_ov_legal = False
        except Exception as _cm_leg_e:
            _flog(f"[ignored] CM-DL-OVERRIDE legality check: {_cm_leg_e!r}")
        if _cm_ov_legal:
            try:
                _cm_gap_thresh = ctx.cfg.disagree_score_gap_threshold_cp
                _cm_nnue_int = int(_cm_nnue_cp) if _cm_nnue_cp is not None else 0
                _cm_signed_gap = int(_cm_dl_top_score) - _cm_nnue_int
                if _cm_signed_gap >= _cm_gap_thresh:
                    _flog(f"[CM-DL-OVERRIDE] DL_1={_cm_dl_top_move}({_cm_dl_top_score}cp) "
                          f"> NNUE={bestmove}({_cm_nnue_cp}cp) gap={_cm_signed_gap}cp "
                          f">= thresh={_cm_gap_thresh}cp → override")
                    st.verdict = _cm_dl_top_move
                    st.ponder_move = None
                    st.council_override = True
                    st.council_override_source = "cm_dl_restore"
                    _cm_overridden = True
            except Exception as _cm_ov_e:
                _flog(f"[ignored] CM-DL-OVERRIDE: {_cm_ov_e!r}")
    if not _cm_overridden and _cm_dl_top_move is not None and _cm_dl_top_move != bestmove:
        _dlog(f"[CM-DL-RESTORE] disagree but no override: "
              f"DL={_cm_dl_top_move}({_cm_dl_top_score}) "
              f"NNUE={bestmove}({_cm_nnue_cp}) "
              f"gap={'%d' % (int(_cm_dl_top_score or 0) - int(_cm_nnue_cp or 0))}cp")


def _run_search(ctx, line, move_count, variant, *, go_clock=None,
                is_infinite=False, dl_ponder_hit=False, dl_timeout=0.0):
    st = _USS(ctx=ctx, variant=variant, line=line, move_count=move_count,
              go_clock=go_clock, is_infinite=is_infinite, dl_ponder_hit=dl_ponder_hit)
    _u_setup(st, dl_timeout)
    if variant.ph:
        _u_ph_dispatch(st)
        if not st.ph_short:
            _u_ph_relay(st)
        if not st.ph_short:
            _u_vote(st)
            _u_override(st)
            if st.council_override:
                st.ponder_move = None
            _u_ph_capture_emit(st)
            _u_ph_cm_dl_restore(st)
        try:
            _time_dyn.ta_disagree_nudge = (_u_ta_disagree_nudge(st)
                                           if variant.apply_boost else 1.0)
        except Exception as _e:
            _flog(f"[ignored] _run_search(ph) ta_disagree_nudge: {_e!r}")
        _u_finalize(st)
        return
    if _u_cache(st) is _NnueGuard.HANDLED:
        return
    if _ensure_nnue_or_recover(ctx, phase="pre", go_clock=st.go_clock, eff_s=st.eff_s,
                               t_go_start=st.t_go_start, label=variant.label) is _NnueGuard.HANDLED:
        return
    try:
        _narrow_moves = None
        _ns_n = ctx.cfg.council_narrow_search_topn
        if (_ns_n >= 4 and st.dl1_cache is not None
                and getattr(st.dl1_cache, 'policy', None)
                and st.eff_s >= ctx.cfg.council_narrow_search_min_eff_s):
            _narrow_moves = [m for m, *_ in st.dl1_cache.policy[:_ns_n] if m]
            if len(_narrow_moves) < 4:
                _narrow_moves = None
        _council_launch_nnue(ctx, line, move_count, st.go_clock,
                             narrow_search_moves=_narrow_moves)
    except Exception as e:
        _flog(f"[unify:{variant.label}] launch_nnue: {e}")
    _u_launch(st)
    st.ponder_move, st.nnue_info = _u_relay(st)
    if _ensure_nnue_or_recover(ctx, phase="post", go_clock=st.go_clock, eff_s=st.eff_s,
                               t_go_start=st.t_go_start, label=variant.label) is _NnueGuard.HANDLED:
        return
    _u_vote(st)
    _u_override(st)
    if variant.apply_boost:
        try:
            _time_dyn.ta_disagree_nudge = _u_ta_disagree_nudge(st)
        except Exception as _e:
            _flog(f"[ignored] _run_search ta_disagree_nudge: {_e!r}")
    else:
        try:
            _time_dyn.ta_disagree_nudge = 1.0
        except Exception as _e:
            _flog(f"[ignored] _run_search: {_e!r}")
    _u_finalize(st)

def _u_setup(st, dl_timeout):
    ctx, v = st.ctx, st.variant
    st.dl_timeout = dl_timeout
    if v.ph:
        _u_ph_setup(st)
        return
    if st.go_clock is None and not st.is_infinite:
        try:
            st.go_clock = _parse_go_clock(st.line, move_count=st.move_count, cfg=ctx.cfg)
        except Exception:
            st.go_clock = None
    st.eff_s = (getattr(st.go_clock, "eff_s", 0.0) if st.go_clock else 0.0) or 0.0
    st.t_go_start = time.perf_counter()
    st.ledger = MoveBudget(eff_s=st.eff_s,
                           remaining_ms=getattr(st.go_clock, "remaining_ms", None),
                           t0=st.t_go_start)
    ctx.ledger = st.ledger
    try:
        st.gp = _calc_game_phase(ctx.current_position, ctx.cfg)
    except Exception:
        st.gp = 0.0
    try:
        st.nodes = _calc_dynamic_policy_nodes(st.eff_s, ctx.cfg)
    except Exception:
        st.nodes = 0
    for fn in (lambda: _apply_slow_mover(ctx.nnue_1, _nnue_1_opts, False, "nnue_1", ctx.cfg, eff_s=st.eff_s, go_clock=st.go_clock),
               lambda: _dyn_apply_nnue_threads(ctx, ctx.nnue_1, v.label),
               lambda: _dyn_apply_nnue_hash(ctx.nnue_1, "nnue_1")):
        try:
            fn()
        except Exception as _e:
            _flog(f"[ignored] _u_setup: {_e!r}")
    if v.reserve_dl1_budget:
        try:
            st.budget = _allocate_time_budget(st.eff_s, dl_timeout, ctx.cfg)
        except Exception:
            st.budget = None

def _u_cache(st):
    ctx, v = st.ctx, st.variant
    try:
        if v.cache is _UCache.MATE_PV:
            mv = _consume_mate_pv(ctx, ctx.current_position)
            if mv:
                _safe_bestmove(mv, label="mate")
                return _NnueGuard.HANDLED
        elif v.cache is _UCache.DL_POLICY:
            c = _council_lookup_prefetch_cache(ctx)
            if c:
                st.dl1_cache = c[0] if len(c) > 0 else None
                st.prefetch_hit = bool(c[1]) if len(c) > 1 else False
                st.dl_cache_src = c[2] if len(c) > 2 else None
    except Exception as e:
        _flog(f"[unify:{v.label}] cache: {e}")
    return _NnueGuard.ALIVE

def _u_launch(st):
    ctx, v = st.ctx, st.variant
    try:
        if v.cache in (_UCache.DL_POLICY, _UCache.DL3):
            ctx.prefetch.cancel()
    except Exception as _e:
        _flog(f"[ignored] _u_launch: {_e!r}")
    st.pv_head_event = threading.Event()
    st.pv_head_lock = threading.Lock()
    if _UVote.DL1 in v.voters and st.dl1_cache is None:
        try:
            st.dl1_state = Dl1FetchState()
            p = Dl1FetchParams(ctx=ctx, n=_ucfg_int(_K_POLICY_MOVES, 8), nodes=st.nodes,
                               dl_timeout=(st.dl_timeout or st.eff_s),
                               dl_gap_min=_calc_dl_score_gap_min(st.eff_s, ctx.cfg, st.gp),
                               eff_s=st.eff_s, dl_time_min_ms=_dl_time_min_ms,
                               position=ctx.current_position)
            if st.ledger is not None:
                st.ledger.note("dl1-fetch", st.dl_timeout or st.eff_s)
            st.dl1_thread = _spawn("dl1-fetch", _dl_1_fetch_thread_fn, p, st.dl1_state, start_now=False)
            st.dl1_thread.start()
        except Exception as e:
            _flog(f"[unify] dl1 launch: {e}")
    if v.use_mate_solver:
        try:
            st.mate_thread = _u_spawn_mate(st)
        except Exception:
            st.mate_thread = None


def _u_spawn_mate(st):
    ctx = st.ctx
    try:
        if not _mate_solver_active(ctx):
            st.mate_state = None
            return None
        st.mate_state = MateResult()
        _mv = _mate_solver_movetime_core(st.eff_s, ctx.cfg)
        if ctx._zyfamate:
            _zf_sfen = _sfen_for_position(ctx.current_position)
            th = _spawn('zf_mate_parallel', _zf_mate_worker, st.mate_state, _zf_sfen, max(0.1, _mv / 1000.0), ctx.cfg.mate_solver_path, start_now=False)
        else:
            _go = _mate_go_cmd(ctx, _mv)
            th = _spawn('ctx.mate_solver', _run_mate_solver_thread, ctx, ctx.current_position, _go, st.mate_state, st.eff_s, 5.0, st.variant.label, start_now=False)
        th.start()
        return th
    except Exception as e:
        _flog(f"[unify] mate spawn: {e}")
        st.mate_state = None
        return None

def _u_harvest_mate(st):
    th, mr, ctx = st.mate_thread, st.mate_state, st.ctx
    if th is None or mr is None:
        return None
    try:
        _to = getattr(ctx.cfg, "mate_solver_join_timeout_s", 3.0)
        _bl = (st.ledger.draw("join/mate", _to, floor_s=0.15)
               if (st.ledger is not None and st.eff_s > 0) else _to)
        th.join(timeout=_clamp(_bl, 0.0, _to))
    except Exception as _e:
        _flog(f"[ignored] _u_harvest_mate: {_e!r}")
    try:
        if mr.result == "mate" and mr.best_move not in (None, "", "resign", "win"):
            if _mate_move_accepted(ctx, mr.best_move, "unify-mate"):
                return mr.best_move
            return None
    except Exception as _e:
        _flog(f"[ignored] _u_harvest_mate: {_e!r}")
    return None

def _u_relay(st):
    ctx, v = st.ctx, st.variant
    relay_eff_s = (st.budget.relay_s
                   if (v.relay_reduced_eff_s and st.budget) else st.eff_s)
    if st.ledger is not None:
        st.ledger.note("relay", relay_eff_s)
    try:
        cb = _make_live_think_cb(ctx, v.label, ctx.current_position, mode=None)
    except Exception:
        cb = None
    kw = {}
    if v.relay_pv_head:
        kw = dict(partial_pv_depth_holder=st.pv_head_holder,
                  pv_head_event=st.pv_head_event, pv_head_lock=st.pv_head_lock)
    try:
        return relay_timed(ctx.nnue_1, intercept_bestmove=True, eff_s=relay_eff_s,
                                    go_clock=st.go_clock, live_info_cb=cb,
                                    full_pv_holder=st.nnue_full_pv_holder, **kw)
    except Exception as e:
        _flog(f"[unify:{v.label}] relay: {e}")
        return (None, {"bestmove": None, "score_cp": None})

def _u_harvest_dl1(st):
    ctx = st.ctx
    res = st.dl1_cache
    if res is None and st.dl1_thread is not None:
        if st.dl1_thread.is_alive():
            try:
                ctx.dl_1.send("stop")
            except Exception as _e:
                _flog(f"[ignored] _u_harvest_dl1: {_e!r}")
        st.dl1_thread.join(timeout=_u_join_budget_s(st, tag="join/dl1"))
        res = st.dl1_state.result if st.dl1_state else None
    if res is None or not res.policy:
        return None
    policy = res.policy
    st.dl_mate = bool(res.mate)
    pv_lines = res.pv_lines
    st.dl1_pv_lines = pv_lines
    depth_best = res.depth_best
    score_hist = res.score_hist
    top = policy[0]
    if isinstance(top, dict):
        move, score = top.get("move"), top.get("score")
    else:
        move = top[0]
        score = top[1] if len(top) > 1 else None
    if not move:
        return None
    st.dl_top_score = score
    try:
        st.dl_top_depth = depth_best.get(move) if depth_best else None
    except Exception:
        st.dl_top_depth = None
    try:
        st.dl_pv_overlap = (_pv_overlap_count(pv_lines, move, n_top=3)
                            if pv_lines else None)
    except Exception:
        st.dl_pv_overlap = None
    try:
        st.dl_stability_spread = (_score_stability(score_hist, move)
                                  if score_hist else None)
        _th = _u_thresholds(st)
        if (_th is not None and _th.stab and _th.stab > 0
                and st.dl_stability_spread is not None
                and move != st.nnue_top
                and st.dl_stability_spread > _th.stab):
            _dlog(f"[unify:{st.variant.label}] DL stability withdraw: {move}")
            return None
    except Exception as e:
        _flog(f"[unify] dl1 stability: {e!r}")
    try:
        if _check_council_stale(ctx, move):
            _dlog(f"[unify:{st.variant.label}] DL stale withdraw: {move}")
            return None
    except Exception as e:
        _flog(f"[unify] dl1 stale: {e!r}")
    return move



def _council_ballot(ctx, *, dl_top, nnue_top,
                    dl_top_score=None, dl_top_depth=None,
                    dl_pv_overlap=None,
                    nnue_score_cp=None, nnue_full_pv=None, nnue_depth=None,
                    game_phase=None, move_count=0, eff_s=0.0,
                    position_cmd=None, dl3_proxy_allowed=False,
                    dl_full_pv=None, rem_ms=None, nnue_nodes=None,
                    telemetry=None, label="ballot"):
    cfg = ctx.cfg
    tel = telemetry if telemetry is not None else {}
    _arb = _sv_arbiter_get()
    _arb.load(cfg)
    _av = None
    _sm = ctx.game_progress.book_seed_move
    try:
        _cands = [ArbCand(move=nnue_top, source="nnue", pv=nnue_full_pv,
                          cp=nnue_score_cp, depth=nnue_depth, nodes=nnue_nodes)]
        if dl_top and dl_top != nnue_top:
            _cands.append(ArbCand(move=dl_top, source="dl1", pv=dl_full_pv,
                                  cp=dl_top_score, depth=dl_top_depth))
        if _sm and _sm not in (nnue_top, dl_top):
            _cands.append(ArbCand(move=_sm, source="seed"))
        if _arb.ok and nnue_top and len(_cands) >= 2:
            _scalars = {"gp": game_phase or 0.0, "eff_s": eff_s, "rem_ms": rem_ms,
                        "move_count": move_count, "nnue_depth": nnue_depth or 0,
                        "nnue_nodes": nnue_nodes or 0, "nnue_top": nnue_top,
                        "position_cmd": position_cmd or ctx.current_position}
            _dl_ms = max(0.001, float(getattr(cfg, "arbiter_deadline_ms", 30)) / 1000.0)
            _av = _arb.judge(ctx, _cands, _scalars, deadline_s=_dl_ms)
    except Exception as _ae:
        _flog(f"[ballot:{label}] arbiter: {_ae!r}")
        _av = None

    def _seed_oneshot_clear():
        if _sm is not None:
            ctx.game_progress.book_seed_move = None
            ctx.game_progress.book_seed_weight = 0.0
            ctx.game_progress.book_seed_trust = ""

    if _av is not None:
        tel["arb_p_pairwise"] = _av.p_win_pairwise
        tel["arb_abstained"] = _av.abstained
        tel["arb_tier"] = _av.tier
        tel["arb_tau_eff"] = _av.tau_eff
        tel["arb_latency_ms"] = _av.latency_ms
        if _av.q_values:
            tel["arb_q_nnue"] = _av.q_values.get(nnue_top)
            tel["arb_q_dl"] = _av.q_values.get(dl_top)
        tel["council_source"] = "sv_arbiter"
        _seed_won = bool(_sm is not None and _av.move == _sm)
        _seed_oneshot_clear()
        _ovr = bool(_av.move == dl_top and dl_top != nnue_top and not _av.abstained)
        return _av.move, _ovr, "sv_arbiter", _seed_won
    try:
        print("info string arbiter=absent fallback=nnue", flush=True)
    except Exception:
        pass
    tel["council_source"] = "nnue_fallback"
    _seed_won = bool(_sm is not None and nnue_top == _sm)
    _seed_oneshot_clear()
    return (nnue_top or dl_top), False, "nnue_fallback", _seed_won


def _u_vote(st):
    ctx, v = st.ctx, st.variant
    st.nnue_top = st.nnue_info.get("bestmove") or None
    if _UVote.DL1 in v.voters:
        st.dl_top = _u_harvest_dl1(st)
        try:
            _cp0 = st.nnue_info.get("score_cp")
            st.conviction = _conviction(
                (st.dl_top_score - int(_cp0))
                if (st.dl_top_score is not None and _cp0 is not None) else None,
                st.dl_stability_spread, st.dl_top_depth, st.dl_pv_overlap,
                ctx.cfg)
            _dlog(f"[CONV-HUB/{v.label}] conviction={st.conviction:.3f} "
                  f"(gap={st.dl_top_score}-{_cp0} stab={st.dl_stability_spread} "
                  f"d={st.dl_top_depth} ovl={st.dl_pv_overlap})")
        except Exception as _ce:
            _flog(f"[unify:{v.label}] conviction hub: {_ce!r}")
    if v.name in ("council", "ponderhit"):
        try:
            (st.verdict, st.council_override,
             st.council_override_source, st.book_seed_won) = _council_ballot(
                ctx,
                dl_top=st.dl_top, nnue_top=st.nnue_top,
                dl_top_score=st.dl_top_score, dl_top_depth=st.dl_top_depth,
                dl_pv_overlap=st.dl_pv_overlap,
                nnue_score_cp=st.nnue_info.get("score_cp"),
                nnue_full_pv=st.nnue_full_pv_holder[0],
                nnue_depth=st.nnue_info.get("depth"),
                game_phase=st.gp, move_count=st.move_count, eff_s=st.eff_s,
                dl3_proxy_allowed=v.dl3_proxy,
                dl_full_pv=(st.dl1_pv_lines or {}).get(st.dl_top),
                rem_ms=st.clock_rem_ms, nnue_nodes=st.nnue_info.get("nodes"),
                telemetry=st.nnue_info, label=v.label)
        except Exception as e:
            _flog(f"[unify:{v.label}] vote failed: {e!r} — nnue 単独へ縮退")
            st.verdict = st.nnue_top or st.dl_top
    else:
        st.verdict = st.nnue_top

def _u_override(st):
    v = st.variant
    if v.use_mate_solver:
        _m = _u_harvest_mate(st)
        if _m:
            st.verdict = _m
            return
    if v.name == "council":
        _u_council_overrides(st)
        _u_override_conviction_mate(st)
    _u_override_pv_mate(st)


def _u_override_pv_mate(st):
    ctx, v = st.ctx, st.variant
    try:
        cfg = ctx.cfg
        if not getattr(cfg, "pv_mate_enable", True):
            return
        if float(getattr(st, "gp", 0.0) or 0.0) < cfg.pv_mate_gp_min:
            return
        if st.verdict in (None, "", "resign", "win"):
            return
        if st.eff_s < cfg.pv_mate_min_eff_s:
            return
        if not (isinstance(st.gp, (int, float))
                and st.gp >= cfg.mate_solver_min_game_phase):
            return
        if not _mate_solver_active(ctx):
            return
        _pvl = dict(st.dl1_pv_lines or {})
        _ms = None
        if not _pvl:
            return
        _order = (sorted(_ms, key=_ms.get, reverse=True)[:2]
                  if _ms else list(_pvl)[:2])
        lines = []
        for _mv in _order:
            _pv = _pvl.get(_mv)
            if isinstance(_pv, (list, tuple)) and len(_pv) >= 1:
                _pv = list(_pv) if _pv[0] == _mv else [_mv] + list(_pv)
                if len(_pv) >= 2:
                    lines.append((_mv, _pv))
        if not lines:
            return
        _max_k = max(1, int(cfg.pv_mate_max_positions))
        for _head, _pv in lines:
            if _head in ("resign", "win", ""):
                continue
            for _k in range(1, _max_k + 1):
                _n = 2 * _k
                if len(_pv) < _n:
                    break
                _jt = (st.ledger.draw(f"pv-mate/dl1/{_n}",
                                      cfg.pv_mate_join_timeout_s)
                       if st.ledger is not None
                       else min(cfg.pv_mate_join_timeout_s,
                                _move_budget_left_s(st.eff_s, st.t_go_start)))
                if _jt < 0.05:
                    return
                _pos = _position_after_moves(ctx.current_position, _pv[:_n])
                _go = _mate_go_cmd(ctx, int(min(_jt, cfg.pv_mate_join_timeout_s) * 1000))
                _res, _bm = _run_single_pv_mate_check(
                    ctx, _pos, _go, st.eff_s, _jt, f"pv-mate-dl1-{_n}")
                if _res != "mate":
                    continue
                st.pv_mate_step = _n
                st.pv_mate_source = "dl1_pv"
                if _head != st.verdict and _n > int(cfg.pv_mate_override_max_step):
                    _dlog(f"[PV-MATE] DL_1 PV +{_n}手先の証明は override 上限 "
                          f"({cfg.pv_mate_override_max_step}) 超 — 記録のみ")
                elif _head != st.verdict:
                    if not _mate_move_accepted(ctx, _head, "pv-mate-dl1"):
                        _flog(f"[PV-MATE] DL_1 PV 証明 (+{_n}手先) だが "
                              f"{_head} は検問棄却 — verdict 維持")
                        return
                    _flog(f"[PV-MATE] OVERRIDE: {st.verdict} → {_head} "
                          f"(DL_1 PV +{_n}手先で df-pn 証明。DL df-pn 全オフ設計の補完)")
                    st.verdict = _head
                    st.ponder_move = _pv[1] if len(_pv) > 1 else None
                    st.council_override = True
                    st.council_override_source = "pv_mate"
                    st.pv_mate_override = True
                else:
                    _dlog(f"[PV-MATE] confirm: verdict {st.verdict} は "
                          f"DL_1 PV +{_n}手先で df-pn 証明済みライン上")
                return
    except Exception as _pme:
        _flog(f"[unify:{v.label}] pv-mate: {_pme!r}")


def _u_override_conviction_mate(st):
    ctx = st.ctx
    try:
        if (_dl_conviction_mate_core(st.council_override, st.dl_top,
                                     st.nnue_top, st.dl_mate, ctx.cfg)
                and st.dl_top not in (None, "", "resign", "win")
                and _mate_move_accepted(ctx, st.dl_top, "dl1-conviction-mate")):
            st.verdict = st.dl_top
            st.council_override = True
            st.council_override_source = "dl1_conviction"
            _flog(f"[CONVICTION-MATE/unify] DL_1 mate 検出 — {st.dl_top} を強制採用")
    except Exception as _cme:
        _flog(f"[unify:council] conviction-mate: {_cme!r}")





def _u_council_overrides(st):
    try:
        _u_council_mate_ponder(st)
    except Exception as _e:
        _flog(f"[unify:council] mate-ponder: {_e!r}")
    try:
        _u_council_sennichite(st)
    except Exception as _e:
        _flog(f"[unify:council] sennichite: {_e!r}")
    try:
        _u_council_tonshi_guard(st)
    except Exception as _e:
        _flog(f"[unify:council] tonshi-guard: {_e!r}")

def _u_council_mate_ponder(st):
    ctx = st.ctx
    if st.verdict in (None, "", "resign", "win"):
        return
    rec = _mate_ponder_harvest(ctx, ctx.current_position)
    if (rec is not None and rec[0] == "mate"
            and rec[1] not in (None, "", "resign", "win")):
        mv = rec[1]
        if _mate_move_accepted(ctx, mv, "mate-ponder-council"):
            st.verdict = mv
            st.ponder_move = None
            _flog(f"[MPON] OVERRIDE (unify council): bestmove -> {mv} "
                  "(相手番 df-pn 証明済み詰み)")

def _u_council_sennichite(st):
    ctx = st.ctx
    mc = st.move_count
    if mc is None or st.verdict in (None, "", "resign", "win"):
        return
    on = (ctx.cfg.sennichite_reject_sente if (mc % 2 == 0)
          else ctx.cfg.sennichite_reject_gote)
    if not on:
        return
    board = _get_tracking_board(ctx)
    if board is None or not board.would_repeat_position(st.verdict, 2):
        return
    _flog(f"[SENNICHITE-REJECT] ply={mc} {st.verdict} repeats but no "
          "non-repeating alternative; keeping original")

def _u_council_tonshi_guard(st):
    ctx = st.ctx
    mc = st.move_count
    if (st.verdict in (None, "", "resign", "win") or mc is None
            or st.eff_s < ctx.cfg.tonshi_guard_min_eff_s):
        return
    if not (isinstance(st.gp, (int, float))
            and st.gp >= ctx.cfg.mate_solver_min_game_phase):
        return
    if (st.conviction is not None
            and st.conviction > ctx.cfg.conviction_hub_tonshi_max):
        _dlog(f"[CONV-HUB/tonshi] conviction={st.conviction:.3f} > "
              f"{ctx.cfg.conviction_hub_tonshi_max:.2f} — 頓死ガード省略")
        return
    kp = ctx.cfg.tonshi_guard_kp_threshold
    rl = getattr(getattr(ctx, "game_progress", None), "regime_label", None)
    if rl == _REGIME_ALERT:
        kp = max(0, kp - _REGIME_ALERT_TONSHI_KP_REDUCE)
    elif rl == _REGIME_CRISIS:
        kp = max(0, kp - _REGIME_CRISIS_TONSHI_KP_REDUCE)
    sig = _board_for_position(ctx.current_position).stance_signals(mc % 2 == 0)
    if not (sig.get("in_check_self") or sig.get("king_pressure_self", 0) >= kp):
        return
    ladder = [st.verdict]
    for cand in ladder:
        jt = (st.ledger.draw(f"tonshi/{cand}", ctx.cfg.tonshi_guard_movetime_max_s)
              if st.ledger is not None
              else _move_budget_left_s(st.eff_s, st.t_go_start))
        if jt < 0.05:
            break
        go = _mate_go_cmd(ctx, int(min(jt, ctx.cfg.tonshi_guard_movetime_max_s) * 1000))
        res, _bm = _run_single_pv_mate_check(
            ctx, _position_after_moves(ctx.current_position, [cand]),
            go, st.eff_s, jt, f"tonshi-{cand}")
        if res != "mate":
            if cand != st.verdict:
                _flog(f"[TONSHI-GUARD] ply={mc} {st.verdict} は相手の頓死詰み "
                      f"→ 次善 {cand} へ差替 (king_danger; unify council)")
                st.verdict = cand
                st.ponder_move = None
            break

def _gps_writeback(st):
    ctx = getattr(st, "ctx", None)
    gps = getattr(ctx, "game_progress", None)
    if gps is None:
        return
    ni = st.nnue_info if isinstance(getattr(st, "nnue_info", None), dict) else {}
    vname = getattr(getattr(st, "variant", None), "name", None)
    try:
        gps.last_nnue_score_cp = int(ni.get("score_cp", 0) or 0)
    except Exception as _e:
        _flog(f"[ignored] _gps_writeback: {_e!r}")
    try:
        gps.last_nnue_mate_ply = ni.get("mate_ply")
    except Exception as _e:
        _flog(f"[ignored] _gps_writeback: {_e!r}")
    try:
        _gp = getattr(st, "gp", None)
        if isinstance(_gp, (int, float)):
            gps.last_game_phase = _gp
    except Exception as _e:
        _flog(f"[ignored] _gps_writeback: {_e!r}")
    try:
        verdict = getattr(st, "verdict", None)
        prev_streak = int(getattr(gps, "council_agree_streak", 0) or 0)
        if vname == "endgame":
            gps.council_agree_streak = 0
            gps.last_child_agreement = 1.0
        else:
            _dl1 = getattr(st, "dl_top", None)
            _nn = getattr(st, "nnue_top", None)
            gps.council_agree_streak = (prev_streak + 1) if (_dl1 is not None and _dl1 == _nn) else 0
            _voices = [m for m in (_dl1, _nn) if m]
            gps.last_child_agreement = (sum(1 for m in _voices if m == verdict) / len(_voices)) if _voices else None
    except Exception as _e:
        _flog(f"[ignored] _gps_writeback: {_e!r}")


def _u_record_fields(st):
    ctx, v, ni = st.ctx, st.variant, st.nnue_info
    f = {
        "ply": st.move_count,
        "go_line": st.line,
        "handler": "go",
        "source": v.label,
        "eff_s": st.eff_s,
        "handover_game_phase": ctx.ps.handover_game_phase,
        "council_winner": st.verdict,
        "council_override": st.council_override,
        "council_override_source": st.council_override_source,
        "nnue_bestmove": ni.get("bestmove"),
        "nnue_score_cp": ni.get("score_cp"),
        "nnue_depth": ni.get("depth"),
        "dl_top_move": st.dl_top,
        "dl_top_score": st.dl_top_score,
        "dl_top_depth": st.dl_top_depth,
        "dl_pv_overlap": st.dl_pv_overlap,
        "dl_stability_spread": st.dl_stability_spread,
        "dl_used": bool(st.dl_top is not None or st.dl1_thread is not None
                        or st.dl1_cache is not None),
        "mate_detected": bool(st.dl_mate),
        "book_seed_won": st.book_seed_won,
        "prefetch_hit": st.prefetch_hit,
        "dl_cache_src": st.dl_cache_src,
        "time_budget_summary": (st.ledger.summary() if st.ledger is not None else None),
        "council_wr_discount": ni.get("council_wr_discount"),
        "score_gap_dl_nnue": ni.get("score_gap"),
        "dl3_proxy_wr_leaf": ni.get("dl3_proxy_wr_leaf"),
        "game_phase_policy_dir": ni.get("game_phase_policy_dir", 0),
        "game_phase_policy_fired": ni.get("game_phase_policy_fired"),
        "game_phase_policy_urgent": ni.get("game_phase_policy_urgent", False),
        "opponent_id_style": ni.get("opponent_id_style"),
        "game_phase_surge_prospective": ni.get("game_phase_surge_prospective"),
        "bestmove": st.verdict,
        "ponder": st.ponder_move,
        "path": v.label,
        "prefetch_voi_weighted_hit": _voi_weighted_hit_core(st.prefetch_hit, None)[1],
        "opponent_id_sample": ctx.game_progress.opponent_id_last_sample,
        "opponent_id_samples": ctx.game_progress.opponent_id_samples,
        "pv_mate_step": st.pv_mate_step,
        "pv_mate_source": st.pv_mate_source,
        "pv_mate_override": st.pv_mate_override,
    }
    f.update(_ni_record_fields(ni))
    if v.ph:
        gps = ctx.game_progress
        f.update({
            "handler": "ponderhit",
            "go_line": None,
            "path": st.ph_branch,
            "_diag": _diag_collect(),
            "ponder_elapsed_s":      gps.ponder_elapsed_s,
            "ponder_hit":            gps.ponder_hit,
            "ponder_sp":             gps.ponder_sp,
            "ponder_miss_reason":    gps.ponder_miss_reason,
            "ponder_conf_level":     gps.ponder_conf_level,
            "ponder_conf_action":    gps.ponder_conf_action,
            "ponder_move_dl":        gps.ponder_move_dl,
            "ponder_move_nnue":      gps.ponder_move_nnue,
            "ponder_move_agreement": (
                (gps.ponder_move_dl == gps.ponder_move_nnue)
                if (gps.ponder_move_dl is not None and gps.ponder_move_nnue is not None)
                else None),
            "ponder_prefetch_corr":  gps.ponder_prefetch_corr,
        })
        f.update(_ni_record_fields(st.ph_emit_ni))
    try:
        feats = _calc_game_phase_features(st.position_cmd if v.ph else ctx.current_position)
        f.update(_gp_record_fields(
            st.gp, feats, ctx.game_progress.last_game_phase,
            surge=bool(ni.get("game_phase_surge_prospective"))))
        f["game_phase"] = st.gp
    except Exception as _ge:
        _flog(f"[unify:{v.label}] gp record fields: {_ge!r}")
        f["game_phase"] = st.gp
    return f


def _u_ph_finalize(st):
    ctx = st.ctx
    bestmove = st.verdict or ""
    ponder_move = st.ponder_move
    position_cmd, move_count = st.position_cmd, st.move_count
    ponderhit_pv_val = st.pv_val
    extra_stats = st.extra_stats

    if ctx.ps.pending_bestmove & {"dl_1"}:
        _settle_debts(ctx, ["dl_1"], reason="ph-finalize-backstop")
        ctx.ps.dl_ponder_pos = None

    if _sp_echo_reject(ctx, bestmove, "PH-FINAL"):
        bestmove = ""

    if not bestmove:
        if _sp_echo_reject(ctx, ponderhit_pv_val, "PH-FINAL"):
            ponderhit_pv_val = None
        if ponderhit_pv_val:
            bestmove = ponderhit_pv_val
            _dlog("[PH-FINAL] WARNING: empty bestmove — using PV head %s" % bestmove)
        else:
            _emerg_eff_s = 3.0
            _pc = ctx.ps.ponder_clock
            if _pc:
                _rem_s = (_pc.remaining_ms or 0) / 1000.0 - _move_overhead_s
                _ef = max(0.0, _pc.eff_s or 0.0)
                _emerg_eff_s = _clamp(max(_ef * 3.0, 15.0), _ef, _rem_s)
            if position_cmd:
                _set_current_position(ctx, position_cmd)
            _cached_mv = _ponderhit_cached_fallback_move(ctx, extra_stats)
            if _cached_mv:
                bestmove = _cached_mv
                ponder_move = None
                _flog(f"[PH-FINAL] empty bestmove — cached DL policy top {_cached_mv!r} "
                      "(resign avoided, zero engine cost)")
            _emerg = None
            if not bestmove:
                try:
                    _emerg = _emergency_move_from_any_engine(ctx, _emerg_eff_s)
                except Exception as _ee:
                    _flog(f"[PH-FINAL] emergency move raised (ignored): {_ee}")
            if _emerg:
                bestmove = _emerg
                ponder_move = None
                _flog(f"[PH-FINAL] empty bestmove — EMERGENCY move {_emerg!r} from "
                      "surviving engine (resign avoided)")
            elif not bestmove:
                _waited = None
                try:
                    _waited = _wait_revive_nnue_and_move(
                        ctx, caller="ph-final", deadline_s=_emerg_eff_s)
                except Exception as _we:
                    _flog(f"[PH-FINAL] wait-revive raised (ignored): {_we}")
                if _waited:
                    bestmove = _waited
                    ponder_move = None
                    _flog(f"[PH-FINAL] empty bestmove — WAIT-REVIVE move {_waited!r} "
                          "after reviving nnue (resign avoided)")
                else:
                    bestmove = "resign"
                    _flog("[PH-FINAL] CRITICAL: no bestmove, no PV head, no surviving "
                          "engine, nnue revive failed — resign")

    _emit_ni = None
    if bestmove not in ("resign", "win", ""):
        _captured = getattr(ctx.game_progress, "ponderhit_emit_ni", None)
        if _captured and _captured.get("bestmove") == bestmove:
            _emit_ni = {
                "score_cp": _captured.get("score_cp", 0) or 0,
                "depth":    _captured.get("depth", 0) or 0,
                "seldepth": _captured.get("seldepth", 0) or 0,
                "pv":       (_captured.get("pv") or (str(ponderhit_pv_val) if ponderhit_pv_val else "")),
                "bestmove": bestmove,
            }
        elif ponderhit_pv_val:
            _emit_ni = {"score_cp": 0, "depth": 0,
                        "pv": str(ponderhit_pv_val), "bestmove": bestmove}
    ctx.game_progress.ponderhit_emit_ni = None
    if _emit_ni is not None:
        try:
            _m_hist = (st.dl1_cache.score_hist if st.dl1_cache is not None else None)
            _m_policy = extra_stats.get("_live_dl1_policy")
            _m_nnue_bm = st.nnue_info.get("bestmove")
            _m_gap = st.nnue_info.get("score_gap")
            _m_spread = (_score_stability(_m_hist, st.dl_top)
                         if (_m_hist and st.dl_top) else None)
            _m_dl_gap = None
            if _m_policy and len(_m_policy) >= 2:
                _m_dl_gap = _m_policy[0][1] - _m_policy[1][1]
            _emit_ni["confidence"] = _compute_confidence(
                bestmove, st.dl_top, _m_nnue_bm,
                _emit_ni.get("score_cp"),
                dl_spread_cp=_m_spread,
                time_aggression_ratio=_ta_rescue_ratio())
            _m_dq = _compute_depth_quality(_emit_ni.get("depth"))
            _emit_ni["depth_quality"] = _m_dq
            _emit_ni["confidence_dq"] = _clamp01(_emit_ni["confidence"] * _m_dq)
            _emit_ni["sharpness"] = _compute_sharpness(
                dl_spread_cp=_m_spread, dl_gap_cp=_m_dl_gap,
                dl_top=st.dl_top, nnue_top=_m_nnue_bm,
                nnue_score_cp=_emit_ni.get("score_cp"),
                score_gap_dl_nnue=_m_gap)
            _emit_ni["momentum"] = _compute_momentum(
                score_cp=_emit_ni.get("score_cp"),
                prev_score_cp=ctx.game_progress.last_nnue_score_cp,
                game_phase=st.gp,
                prev_game_phase=ctx.game_progress.last_game_phase,
                council_agree_streak=ctx.game_progress.council_agree_streak,
                tesuki_n=ctx.game_progress.last_tesuki_n)
            ctx.game_progress.last_momentum = _emit_ni["momentum"]
            ctx.game_progress.last_sharpness = _emit_ni["sharpness"]
            _regime_agree = bool(bestmove and st.dl_top and _m_nnue_bm
                                 and bestmove == st.dl_top == _m_nnue_bm)
            _regime_collapse = _regime_update_ema(
                ctx.game_progress, _emit_ni.get("confidence"),
                _emit_ni.get("sharpness"), _regime_agree)
            _emit_ni["regime_conviction"] = ctx.game_progress.regime_conviction
            _emit_ni["regime_label"] = ctx.game_progress.regime_label
            _emit_ni["regime_collapse"] = _regime_collapse
            _emit_ni["regime_force_crisis"] = ctx.game_progress.regime_force_crisis
        except Exception as _ph_met_e:
            _flog(f"[METRICS-PH] compute failed: {_ph_met_e!r}")
    st.ph_emit_ni = _emit_ni
    st.verdict, st.ponder_move = bestmove, ponder_move

    if ponder_move:
        _safe_bestmove(bestmove, ponder_move, label="ponderhit", nnue_info=_emit_ni)
    else:
        _safe_bestmove(bestmove, label="ponderhit", nnue_info=_emit_ni)
    _phit_trace_emit(st.ph_branch, bestmove)

    if bestmove not in ("resign", "win", ""):
        next_pos = _position_after_move(position_cmd, bestmove)
        _start_prefetch_after_bestmove(ctx, next_pos, ponder_move, move_count)

    _ph_live_dl1_policy = extra_stats.pop("_live_dl1_policy", None) if extra_stats else None
    try:
        _rec = _build_move_record(_u_record_fields(st))
        ctx.game_progress.ponder_move_agreement = _rec.get("ponder_move_agreement")
        if _LIVE._ready():
            _ph_rec = dict(_rec)
            _ph_rec["council_winner"] = bestmove
            _ph_pv_think = (ponderhit_pv_val.split()
                            if isinstance(ponderhit_pv_val, str) and ponderhit_pv_val else None)
            _gc = ctx.ps.ponder_clock
            _ph_ck_think = ({"remaining_ms": _gc.remaining_ms, "floor_ms": _gc.floor_ms,
                             "inc_ms": _gc.inc_ms, "move_count": move_count}
                            if _gc else None)
            _ph_policy_think = _ph_live_dl1_policy
            _LIVE.set_think(_ph_rec, position_cmd, _ph_policy_think,
                            _ph_pv_think, _ph_ck_think)
        _append_move_record(ctx, _rec)
    except Exception as _re:
        _flog(f"[unify:ponderhit] move record: {_re!r}")
    ctx.game_progress.last_game_phase = st.gp
    ctx.game_progress.opponent_id_last_sample = None

    _ps_debt_clear(ctx, "nnue_1", "ponderhit-finalize")
    _ps_transition(ctx, PsPhase.IDLE, "ponderhit-finalize")

    _ph_cp = st.nnue_info.get("score_cp")
    if _ph_cp is not None:
        ctx.game_progress.last_nnue_score_cp = int(_ph_cp)
    ctx.game_progress.last_nnue_mate_ply = None
    _ph_dl_top = st.dl_top
    _ph_nnue_bm = st.nnue_info.get("bestmove")
    _ph_agree = (_ph_dl_top is not None and _ph_nnue_bm is not None
                 and _ph_dl_top == _ph_nnue_bm)
    ctx.game_progress.council_agree_streak = (
        (ctx.game_progress.council_agree_streak + 1) if _ph_agree else 0)
    _ph_voices = sum(1 for _v in (_ph_dl_top, _ph_nnue_bm) if _v)
    _ph_agree_n = (sum(1 for _v in (_ph_dl_top, _ph_nnue_bm) if _v and _v == bestmove)
                   if _ph_voices else 0)
    ctx.game_progress.last_child_agreement = (
        (_ph_agree_n / _ph_voices) if _ph_voices > 0 else None)


def _u_finalize(st):
    ctx, v = st.ctx, st.variant
    try:
        if (st.nnue_top and st.dl_top and st.nnue_top != st.dl_top):
            _pos = st.position_cmd if v.ph else ctx.current_position
            _dlpv = (st.dl1_pv_lines or {}).get(st.dl_top)
            _rec = {
                "sfen": _pos,
                "pos_hash": _pos_hash8(_pos) if _pos else None,
                "cands": [
                    {"move": st.nnue_top, "source": "nnue",
                     "pv": st.nnue_full_pv_holder[0],
                     "cp": st.nnue_info.get("score_cp"),
                     "depth": st.nnue_info.get("depth"),
                     "nodes": st.nnue_info.get("nodes")},
                    {"move": st.dl_top, "source": "dl1", "pv": _dlpv,
                     "cp": st.dl_top_score, "depth": st.dl_top_depth,
                     "nodes": st.nodes},
                ],
                "gp": st.gp, "eff_s": st.eff_s, "rem_ms": st.clock_rem_ms,
                "move_count": st.move_count, "ply": st.move_count,
                "label": getattr(v, "label", None),
            }
            _atomic_append(_ARBITER_SAMPLES_PATH,
                           json.dumps(_rec, ensure_ascii=False, default=str) + "\n",
                           lock=_arbiter_sample_lock, fsync=False, os_write=True)
    except Exception as _ase:
        _flog(f"[arbiter-sample] {_ase!r}")
    if v.ph:
        return _u_ph_finalize(st)
    if not st.verdict:
        try:
            st.verdict = _emergency_move_from_any_engine(ctx, st.eff_s) or "resign"
        except Exception:
            st.verdict = "resign"
    try:
        _apply_csm_and_regime(ctx, st.nnue_info, st.verdict,
                              dl_top=st.dl_top, nnue_top=st.nnue_top,
                              nnue_score_cp=st.nnue_info.get("score_cp"),
                              game_phase=st.gp, label=v.label)
    except Exception as _e:
        _flog(f"[ignored] _u_finalize: {_e!r}")
    _safe_bestmove(st.verdict, st.ponder_move, label=v.label, nnue_info=st.nnue_info)
    try:
        if not (v.prefetch is _UPref.GATED
                and not _lc_prefetch_gate_core(getattr(st.budget, "dl_timeout_s", 0.0), ctx.cfg)):
            _start_prefetch_after_bestmove(
                ctx, _position_after_move(ctx.current_position, st.verdict),
                st.ponder_move, st.move_count)
    except Exception as _e:
        _flog(f"[ignored] _u_finalize: {_e!r}")
    try:
        _append_move_record(ctx, _build_move_record(_u_record_fields(st)))
    except Exception as _re:
        _flog(f"[unify:{v.label}] move record: {_re!r}")
    ctx.game_progress.opponent_id_last_sample = None
    _gps_writeback(st)


def _run_council_search(ctx, line, move_count, dl_timeout,
                        use_dl, go_clock=None):
    return _run_search(ctx, line, move_count, _UV_COUNCIL,
                       go_clock=go_clock, dl_timeout=dl_timeout)


def _run_mate_solver_thread(ctx, position_cmd, go_cmd,
                            mate_res: "MateResult",
                            eff_s=0.0, flush_timeout=5.0, label="mate_solver"):
    if not ctx.mate_solver_lock.acquire(blocking=False):
        mate_res.result = "busy"
        _dlog(f"ctx.mate_solver ({label}): prior thread still draining — skipping")
        return
    try:
        if not ctx.mate_solver._alive:
            _dlog(f"ctx.mate_solver ({label}): not alive after lock — skipping")
            mate_res.result = "busy"
            return
        if not ctx.mate_solver.flush_until_ready(timeout=flush_timeout):
            _dlog(f"ctx.mate_solver ({label}): flush_until_ready did not complete "
                  f"in {flush_timeout}s — skipping (engine may be hung)")
            mate_res.result = "busy"
            return
        ctx.mate_solver.send(position_cmd)
        ctx.mate_solver.send(go_cmd)
        _readline_timeout = (_clamp(eff_s * 2.0, 5.0, 120.0)
                             if eff_s > 0 else 120.0)
        _max_iters = 100000
        _proc_died = False
        for _i in range(_max_iters):
            _out = ctx.mate_solver.readline(timeout=_readline_timeout)
            if _out is None:
                _proc_died = True
                mate_res.result = "busy"
                break
            if not _out:
                continue
            if _out.startswith("info string"):
                low = _out.lower()
                if "nomate" in low or "no mate" in low:
                    mate_res.result = "nomate"
                    _dlog(f"ctx.mate_solver ({label}) info: {_out}")
                    break
            elif _out.startswith("checkmate"):
                _ck = _out.split()
                _arg = _ck[1] if len(_ck) > 1 else ""
                if _arg == "notimplemented":
                    ctx._mate_go_mate_ok = False
                    _flog(f"ctx.mate_solver ({label}): go mate notimplemented "
                          f"→ go movetime へフォールバック (以後恒久)")
                    mate_res.result = "busy"
                elif _arg == "nomate":
                    ctx._mate_go_mate_ok = True
                    mate_res.result = "nomate"
                    mate_res.proof = True
                elif _arg in ("timeout", ""):
                    ctx._mate_go_mate_ok = True
                    mate_res.result = "timeout"
                else:
                    ctx._mate_go_mate_ok = True
                    mate_res.best_move = _arg
                    mate_res.result = "mate"
                    mate_res.proof = True
                    mate_res.pv_moves = _ck[1:]
                    _dlog(f"ctx.mate_solver ({label}): checkmate 手順 "
                          f"{len(_ck) - 1} 手 (中央値9手/99%≤33手の分布内か)")
                break
            elif _out.startswith("bestmove"):
                _mv = _out.split()[1] if len(_out.split()) > 1 else ""
                mate_res.best_move = _mv
                if go_cmd.startswith("go mate"):
                    ctx._mate_go_mate_ok = True
                if _mv in ("resign", "win", ""):
                    if mate_res.result is None:
                        mate_res.result = "nomate"
                else:
                    mate_res.result = "mate"
                break
        else:
            _dlog(f"ctx.mate_solver ({label}): readline loop exceeded {_max_iters} "
                  f"iterations without bestmove — aborting")
            mate_res.result = "busy"
        if (go_cmd.startswith("go mate") and mate_res.result is None
                and not _proc_died
                and getattr(ctx, "_mate_go_mate_ok", None) is None):
            _n = getattr(ctx, "_mate_go_mate_silent", 0) + 1
            ctx._mate_go_mate_silent = _n
            if _n >= 2:
                ctx._mate_go_mate_ok = False
                _flog(f"ctx.mate_solver ({label}): go mate 無応答 {_n} 回 "
                      f"→ go movetime へフォールバック (以後恒久)")
    except Exception as _e:
        _dlog(f"ctx.mate_solver ({label}) thread error: {_e}")
        if mate_res.result is None:
            mate_res.result = "busy"
    finally:
        try:
            if mate_res.result == "nomate" and getattr(mate_res, "proof", False):
                _cache = getattr(ctx, "_mate_nomate_cache", None)
                if _cache is None:
                    _cache = collections.OrderedDict()
                    ctx._mate_nomate_cache = _cache
                    ctx._mate_cache_hits = 0
                _cache[position_cmd] = (None, "nomate")
                _cache_trim(_cache)
            elif (mate_res.result == "mate" and mate_res.best_move
                  and ctx.cfg.mate_cache_bidirectional):
                _cache = getattr(ctx, "_mate_nomate_cache", None)
                if _cache is None:
                    _cache = collections.OrderedDict()
                    ctx._mate_nomate_cache = _cache
                    ctx._mate_cache_hits = 0
                _cache[position_cmd] = (mate_res.best_move, "mate")
                _cache_trim(_cache)
                _dlog(f"[MATE-CACHE] stored mate proof ({label}) "
                      f"move={mate_res.best_move} (writer=thread finally)")
        except Exception as _ce:
            _dlog(f"ctx.mate_solver ({label}): finally cache write failed: {_ce!r}")
        try:
            if (mate_res.result == "mate" and mate_res.pv_moves
                    and len(mate_res.pv_moves) >= 1):
                _store_mate_pv(ctx, position_cmd, mate_res.pv_moves,
                               origin="mate_solver")
        except Exception as _pe:
            _dlog(f"ctx.mate_solver ({label}): mate_pv store failed: {_pe!r}")
        ctx.mate_solver_lock.release()



_ZF_CREATE_FLAGS = getattr(subprocess, "CREATE_NO_WINDOW", 0)


def _zf_norm_sfen(sfen):
    _s = (sfen or "").strip()
    return _s[5:].lstrip() if _s.startswith("sfen ") else _s


class _ZfServer:


    def __init__(self, path, index):
        self._path = path
        self._index = index
        self.lock = threading.Lock()
        self._proc = None
        self._q = None
        self._broken_until = 0.0

    def _spawn(self):
        _env = os.environ.copy()
        if self._index > 0:
            _env.setdefault("ZYFAMATE_HASH_MB", "512")
        self._proc = subprocess.Popen(
            [self._path, "serve"],
            stdin=subprocess.PIPE, stdout=subprocess.PIPE,
            stderr=subprocess.DEVNULL,
            creationflags=_ZF_CREATE_FLAGS, env=_env)
        self._q = queue.Queue()

        def _reader(_proc=self._proc, _q=self._q, _idx=self._index):
            try:
                for _raw in iter(_proc.stdout.readline, b""):
                    _q.put(_raw.decode("utf-8", errors="replace").rstrip("\r\n"))
            except Exception as _zr_exc:
                try:
                    _flog(f"[ZF-SERVE] reader#{_idx} error: {type(_zr_exc).__name__}: {_zr_exc!r}")
                except Exception as _e:
                    _flog(f"[ignored] _spawn/_reader: {_e!r}")
            _q.put(None)

        _spawn(f'zf_serve_reader_{self._index}', _reader)
        self._proc.stdin.write(b"ping\n")
        self._proc.stdin.flush()
        _deadline = time.perf_counter() + 10.0
        while True:
            _ln = self._q.get(timeout=max(0.05, _deadline - time.perf_counter()))
            if _ln is None:
                raise RuntimeError("serve process died at startup")
            if _ln == "=done":
                break
        _dlog(f"[ZF-SERVE] server#{self._index} spawned (pid={self._proc.pid})")

    def kill(self):
        try:
            if self._proc is not None:
                self._proc.kill()
                self._proc.wait(timeout=3)
        except Exception as _e:
            _flog(f"[ignored] kill: {_e!r}")
        self._proc = None
        self._q = None

    def request(self, line, timeout_s):
        try:
            if self._proc is None or self._proc.poll() is not None:
                if time.perf_counter() < self._broken_until:
                    return "dead", None
                self._spawn()
        except Exception as _e:
            _dlog(f"[ZF-SERVE] spawn failed: {_e!r} — 30s は再試行しない")
            self.kill()
            self._broken_until = time.perf_counter() + 30.0
            return "dead", None
        try:
            self._proc.stdin.write(line.encode("utf-8") + b"\n")
            self._proc.stdin.flush()
        except Exception as _e:
            _dlog(f"[ZF-SERVE] write failed: {_e!r}")
            self.kill()
            return "dead", None
        _deadline = time.perf_counter() + timeout_s + 1.5
        _lines = []
        while True:
            _left = _deadline - time.perf_counter()
            if _left <= 0:
                _dlog("[ZF-SERVE] request deadline exceeded — server restart")
                self.kill()
                return "timeout", None
            try:
                _ln = self._q.get(timeout=_left)
            except queue.Empty:
                continue
            if _ln is None:
                self.kill()
                return "dead", None
            if _ln == "=done":
                return "ok", _lines
            _lines.append(_ln)


_zf_pool_cfg = str(_cfg.get("ZF_Serve_Pool_Max", "")).strip()
_ZF_SERVE_POOL_MAX = (int(_zf_pool_cfg) if _zf_pool_cfg
                      else _zf_pool_max_core(_effective_cores()))
_zf_servers = {}
_zf_servers_lock = threading.Lock()


def _zf_serve_request(path, line, timeout_s):
    if not _zyfamate_has_serve:
        return None, None
    _path = path or _mate_solver_path
    with _zf_servers_lock:
        _pool = _zf_servers.setdefault(_path, [])
        _cands = list(_pool)
    _srv = None
    for _s in _cands:
        if _s.lock.acquire(blocking=False):
            _srv = _s
            break
    if _srv is None:
        with _zf_servers_lock:
            if len(_pool) < _ZF_SERVE_POOL_MAX:
                _srv = _ZfServer(_path, len(_pool))
                _srv.lock.acquire()
                _pool.append(_srv)
    if _srv is None:
        return None, None
    try:
        _st, _lines = _srv.request(line, timeout_s)
        if _st == "dead":
            return None, None
        return _st, _lines
    finally:
        _srv.lock.release()


def _zf_serve_warm(path=None):
    if not _zyfamate_has_serve:
        return
    def _w():
        try:
            _zf_serve_request(path, "ping", 10.0)
        except Exception as _e:
            _flog(f"[ignored] _zf_serve_warm/_w: {_e!r}")
    _spawn('zf_serve_warm', _w)


def _zf_serve_shutdown():
    with _zf_servers_lock:
        _all = [s for _pl in _zf_servers.values() for s in _pl]
        _zf_servers.clear()
    for _s in _all:
        if not _s.lock.acquire(timeout=1.0):
            _s.kill()
            continue
        try:
            if _s._proc is not None:
                _s._proc.stdin.write(b"quit\n")
                _s._proc.stdin.flush()
        except Exception as _e:
            _flog(f"[ignored] _zf_serve_shutdown: {_e!r}")
        finally:
            _s.lock.release()
        _s.kill()


atexit.register(_zf_serve_shutdown)

_CSA_RANK_TO_USI = {'1': 'a', '2': 'b', '3': 'c', '4': 'd', '5': 'e',
                     '6': 'f', '7': 'g', '8': 'h', '9': 'i'}
_CSA_DROP_TO_USI = {'FU': 'P', 'KY': 'L', 'KE': 'N', 'GI': 'S',
                     'KI': 'G', 'KA': 'B', 'HI': 'R'}
_CSA_PROMOTED = frozenset(('TO', 'NY', 'NK', 'NG', 'UM', 'RY'))

_CSA_ROW = _CSA_RANK_TO_USI
_CSA_TO_USI_PIECE = {
    "FU": "P", "KY": "L", "KE": "N", "GI": "S", "KI": "G", "KA": "B", "HI": "R", "OU": "K",
    "TO": "+P", "NY": "+L", "NK": "+N", "NG": "+S", "UM": "+B", "RY": "+R",
}


def _sfen_piece_promoted(sfen, file, rank):
    _toks = sfen.split()
    if _toks and _toks[0] == 'sfen' and len(_toks) >= 2:
        _bp = _toks[1]
    else:
        _bp = _toks[0] if _toks else ''
    _ranks = _bp.split('/')
    if not (1 <= rank <= 9 and 1 <= file <= 9):
        return None
    _rs = _ranks[rank - 1]
    _col = 0
    _pro = False
    for _ch in _rs:
        if _ch == '+':
            _pro = True
            continue
        if _ch.isdigit():
            _col += int(_ch)
            _pro = False
            continue
        if 9 - _col == file:
            return _pro
        _col += 1
        _pro = False
    return None


def _csa_first_move_to_usi(csa_pv_line, sfen):
    _parts = csa_pv_line.strip().split()
    if not _parts:
        return None
    _m = _parts[0]
    if len(_m) < 7 or _m[0] not in ('+', '-'):
        return None
    _fc, _fr, _tc, _tr = _m[1], _m[2], _m[3], _m[4]
    _piece = _m[5:7]
    if _fc == '0' and _fr == '0':
        _p = _CSA_DROP_TO_USI.get(_piece)
        if not _p or _tr not in _CSA_RANK_TO_USI:
            return None
        return f"{_p}*{_tc}{_CSA_RANK_TO_USI[_tr]}"
    if _fr not in _CSA_RANK_TO_USI or _tr not in _CSA_RANK_TO_USI:
        return None
    _usi = f"{_fc}{_CSA_RANK_TO_USI[_fr]}{_tc}{_CSA_RANK_TO_USI[_tr]}"
    if _piece not in _CSA_PROMOTED:
        return _usi
    if _sfen_piece_promoted(sfen, int(_fc), int(_fr)) is False:
        return _usi + '+'
    return _usi


def _sfen_for_position(position_cmd):
    return _board_for_position(position_cmd).sfen()


def _zf_mate_worker(mr, sfen, timeout_s, path=None):
    r, m, _ = _zyfamate_solve(sfen, timeout_s=timeout_s, nodes=20000000, path=path)
    mr.result = r
    mr.best_move = m
    if r == "mate":
        mr.proof = True


def _zf_parse_solve_lines(_lines, sfen):
    for _i, _ln in enumerate(_lines):
        if _ln.startswith("mate "):
            _tok = _ln.split()
            try:
                _mate_len = int(_tok[1]) if len(_tok) > 1 else 0
            except ValueError:
                _mate_len = 0
            _pv = _lines[_i + 1] if _i + 1 < len(_lines) else ""
            _usi_mv = _csa_first_move_to_usi(_pv, sfen) if _pv else None
            return "mate", _usi_mv, _mate_len
        if _ln.startswith("nomate"):
            return "nomate", None, 0
        if _ln.startswith("unknown"):
            return "timeout", None, 0
        if _ln.startswith("parse error"):
            _dlog(f"[ZYFAMATE] parse error from solver: {sfen[:60]!r}")
            return "busy", None, 0
    return "timeout", None, 0


def _zyfamate_solve(sfen, timeout_s=30.0, nodes=20000000, path=None):
    _path = path or _mate_solver_path
    sfen = _zf_norm_sfen(sfen)
    try:
        _st, _lines = _zf_serve_request(
            _path, f"solve {nodes} {timeout_s} {sfen}", timeout_s)
        if _st == "timeout":
            return "timeout", None, 0
        if _st == "ok":
            return _zf_parse_solve_lines(_lines, sfen)
    except Exception as _e:
        _dlog(f"[ZF-SERVE] solve error (one-shot fallback): {_e!r}")
    try:
        _r = subprocess.run(
            [_path, "sfen", sfen, str(nodes), str(timeout_s)],
            capture_output=True, timeout=timeout_s + 2,
            stdin=subprocess.DEVNULL,
            creationflags=_ZF_CREATE_FLAGS,
        )
        _lines = (_r.stdout or b"").decode("utf-8", errors="replace").strip().splitlines()
        return _zf_parse_solve_lines(_lines, sfen)
    except subprocess.TimeoutExpired:
        return "timeout", None, 0
    except Exception as _e:
        _dlog(f"[ZYFAMATE] solve error: {_e!r}")
        return "busy", None, 0


def _zf_parse_tsumero_lines(_lines):
    if not _lines:
        return False, 0, ""
    _first = _lines[0]
    if _first.startswith("True"):
        _threat_n = 0
        if "(threat " in _first:
            try:
                _threat_n = int(_first.split("(threat ")[1].rstrip(")"))
            except (IndexError, ValueError) as _e:
                _flog(f"[ignored] _zf_parse_tsumero_lines: {_e!r}")
        _pv = _lines[1] if len(_lines) > 1 else ""
        return True, _threat_n, _pv
    return False, 0, ""


def _zyfamate_tsumero(sfen, timeout_s=10.0, nodes=5000000, path=None):
    _path = path or _mate_solver_path
    sfen = _zf_norm_sfen(sfen)
    try:
        _st, _lines = _zf_serve_request(
            _path, f"tsumero {nodes} {timeout_s} {sfen}", timeout_s)
        if _st == "timeout":
            return False, 0, ""
        if _st == "ok":
            return _zf_parse_tsumero_lines(_lines)
    except Exception as _e:
        _dlog(f"[ZF-SERVE] tsumero error (one-shot fallback): {_e!r}")
    try:
        _r = subprocess.run(
            [_path, "sfen-tsumero", sfen, str(nodes), str(timeout_s)],
            capture_output=True, timeout=timeout_s + 2,
            stdin=subprocess.DEVNULL,
            creationflags=_ZF_CREATE_FLAGS,
        )
        _lines = (_r.stdout or b"").decode("utf-8", errors="replace").strip().splitlines()
        return _zf_parse_tsumero_lines(_lines)
    except Exception as _e:
        _dlog(f"[ZYFAMATE] tsumero error: {_e!r}")
        return False, 0, ""


def _zf_parse_tesuki_lines(_lines):
    if not _lines:
        return None
    _first = _lines[0]
    if not _first.startswith("tesuki "):
        return None
    _val = _first.split()[1]
    if _val in ("-", "unknown"):
        return None
    try:
        if _val.startswith(">"):
            return int(_val[1:]) + 1
        return int(_val)
    except ValueError:
        return None


def _zyfamate_tesuki(sfen, maxn=3, timeout_s=3.0, nodes=2000000, path=None):
    _path = path or _mate_solver_path
    sfen = _zf_norm_sfen(sfen)
    try:
        _st, _lines = _zf_serve_request(
            _path, f"tesuki {maxn} {nodes} {timeout_s} {sfen}", timeout_s)
        if _st == "timeout":
            return None
        if _st == "ok":
            return _zf_parse_tesuki_lines(_lines)
    except Exception as _e:
        _dlog(f"[ZF-SERVE] tesuki error (one-shot fallback): {_e!r}")
    try:
        _r = subprocess.run(
            [_path, "sfen-tesuki", sfen, str(maxn), str(nodes), str(timeout_s)],
            capture_output=True, timeout=timeout_s + 2,
            stdin=subprocess.DEVNULL,
            creationflags=_ZF_CREATE_FLAGS,
        )
        _lines = (_r.stdout or b"").decode("utf-8", errors="replace").strip().splitlines()
        return _zf_parse_tesuki_lines(_lines)
    except Exception as _e:
        _dlog(f"[ZYFAMATE] tesuki error: {_e!r}")
        return None


def _mate_solver_active(ctx):
    if ctx._zyfamate:
        return True
    return _eng_alive(ctx.mate_solver)


def _run_single_pv_mate_check(ctx, position_cmd, go_cmd, eff_s,
                              join_timeout_s, label):
    _cache = getattr(ctx, "_mate_nomate_cache", None)
    if _cache is None:
        _cache = collections.OrderedDict()
        ctx._mate_nomate_cache = _cache
        ctx._mate_cache_hits = 0
    if position_cmd in _cache:
        _cache.move_to_end(position_cmd)
        ctx._mate_cache_hits += 1
        _cached = _cache[position_cmd]
        if isinstance(_cached, tuple) and len(_cached) == 2:
            _c_move, _c_kind = _cached
            _dlog(f"[MATE-CACHE] hit#{ctx._mate_cache_hits} ({label}) — "
                  f"証明済み{_c_kind}を再利用 (df-pn 呼び出し省略)")
            return _c_kind, _c_move
        _dlog(f"[MATE-CACHE] hit#{ctx._mate_cache_hits} ({label}) — "
              f"証明済み不詰を再利用 (df-pn 呼び出し省略)")
        return "nomate", None
    if ctx._zyfamate:
        try:
            _zf_sfen = _sfen_for_position(position_cmd)
        except Exception as _zf_e:
            _dlog(f"[ZYFAMATE] sfen extraction failed ({label}): {_zf_e!r}")
            return "busy", None
        _zf_res, _zf_mv, _zf_len = _zyfamate_solve(
            _zf_sfen, timeout_s=max(0.1, join_timeout_s), nodes=20000000, path=ctx.cfg.mate_solver_path)
        if _zf_res == "nomate":
            _cache[position_cmd] = (None, "nomate")
            _cache_trim(_cache)
        elif _zf_res == "mate" and _zf_mv and ctx.cfg.mate_cache_bidirectional:
            _cache[position_cmd] = (_zf_mv, "mate")
            _cache_trim(_cache)
            _dlog(f"[ZYFAMATE] solve ({label}): mate in {_zf_len}, move={_zf_mv}")
        return _zf_res, _zf_mv
    _mr = MateResult()
    _th = _spawn(f'mate_solver_{label}', _run_mate_solver_thread, ctx, position_cmd, go_cmd, _mr, eff_s, 5.0, label, start_now=False)
    _th.start()
    _th.join(timeout=join_timeout_s)
    if _th.is_alive():
        if _eng_alive(ctx.mate_solver):
            ctx.mate_solver.send("stop")
        _dlog(f"[PV-MATE] {label}: join timeout — stop sent")
        return "timeout", None
    return _mr.result, _mr.best_move





def _mate_ponder_due_core(enable, solver_alive, last_score_cp, game_phase, min_game_phase,
                          opponent_s_ema, min_opp_s):
    if not enable or not solver_alive:
        return False
    if last_score_cp is not None and last_score_cp >= _MATE_CP:
        return False
    if game_phase is not None and min_game_phase > 0.0 and game_phase < min_game_phase:
        return False
    return _dlponder_forward_gate_core(opponent_s_ema, min_opp_s)


def _mate_ponder_movetime_core(ponder_eff_s, join_timeout_s):
    _jt = max(0.1, float(join_timeout_s))
    if ponder_eff_s is None or float(ponder_eff_s) <= 0:
        _base = _jt
    else:
        _base = float(ponder_eff_s) * 3.0 + 5.0
    return int(round(_clamp(_base, _jt, 120.0) * 1000.0))


def _mate_ponder_harvest(ctx, position_cmd):
    _book = getattr(ctx, "assets", None)
    if _book is None or not _book.any("mpon"):
        return None
    _a = _book.withdraw(position_cmd, "mpon")
    _book.sweep("mpon-consume", kinds={"mpon"})
    if _a is None:
        _DLPONDER_STATE.mpon_misses += 1
        _dlog("[MPON] 局面不一致 — 記録破棄のみ (ponder miss)")
        return None
    _DLPONDER_STATE.mpon_hits += 1
    _rec = _a.payload
    _payload = (_rec[1], _rec[2], _rec[3])
    _dlog(f"[MPON] 収穫 hit: result={_payload[0]} bm={_payload[1]} "
          f"proven={_payload[2]}")
    return _payload


def _mate_ponder_worker(ctx, pos, movetime_ms, cancel_ev):
    try:
        if cancel_ev.is_set():
            return
        _go = _mate_go_cmd(ctx, int(movetime_ms))
        _res, _bm = _run_single_pv_mate_check(
            ctx, pos, _go, 0.0, movetime_ms / 1000.0 + 3.0, "mate-ponder")
        _results = []
        if _res == "mate" and _bm not in (None, "", "resign", "win"):
            _results.append((pos, "mate", _bm, True))
            _DLPONDER_STATE.mpon_mate = int(_DLPONDER_STATE.mpon_mate) + 1
            _flog(f"[MPON] 予測局面に詰みを発見: {_bm} "
                  "(ponderhit 時に検問つき即採用候補)")
        elif _res == "nomate":
            _cache = getattr(ctx, "_mate_nomate_cache", None)
            _proven = bool(_cache is not None and pos in _cache)
            _results.append((pos, "nomate", None, _proven))
            if _proven:
                _DLPONDER_STATE.mpon_nomate_proof = \
                    int(_DLPONDER_STATE.mpon_nomate_proof) + 1
            _dlog(f"[MPON] 予測局面は不詰 (proven={_proven})"
                  + (" — 自分番の現局面チェックを省略可" if _proven else ""))
        else:
            _dlog(f"[MPON] 結果 {_res} — 未証明のため記録なし")
        for _mp_rec in _results:
            ctx.assets.deposit(_mp_rec[0], "mpon", _mp_rec, src="mate-ponder")
    except (KeyboardInterrupt, SystemExit, MemoryError):
        raise
    except Exception as _e:
        _DLPONDER_STATE.mpon_worker_err = int(_DLPONDER_STATE.mpon_worker_err) + 1
        _flog(f"[MPON-WORKER-ERR] {type(_e).__name__}: {_e!r} "
              f"(streak={_DLPONDER_STATE.mpon_worker_err})")
        if _DLPONDER_STATE.mpon_worker_err >= 10:
            try:
                print(f"info string [WARN] 詰みポンダー worker が連続失敗 "
                      f"streak={_DLPONDER_STATE.mpon_worker_err}", flush=True)
            except Exception as _e:
                _flog(f"[ignored] _mate_ponder_worker: {_e!r}")


def _mate_solver_stop_safe(ctx, label: str) -> bool:
    if not _eng_alive(ctx.mate_solver):
        return True
    try:
        ctx.mate_solver.send("stop")
        return True
    except (KeyboardInterrupt, SystemExit, MemoryError):
        raise
    except Exception as _se:
        ctx._mate_ponder_cancel = None
        _flog(f"[MATE-SOLVER-STOP/{label}] send failed: "
              f"{type(_se).__name__}: {_se!r} (ev cleared, mate_solver alive={ctx.mate_solver._alive})")
        return False


def _mate_ponder_cancel(ctx, reason, join_s=0.15):
    _t = getattr(ctx, "_mate_ponder_thread", None)
    if _t is None:
        return
    if not _t.is_alive():
        ctx._mate_ponder_thread = None
        return
    _ev = getattr(ctx, "_mate_ponder_cancel", None)
    if _ev is not None:
        _ev.set()
    _mate_solver_stop_safe(ctx, f"mpon-cancel/{reason}")
    _t.join(timeout=join_s)
    if _t.is_alive():
        _dlog(f"[MPON] cancel({reason}): drain 継続中 — "
              "後続の自分番 df-pn は busy フォールバック")
    else:
        ctx._mate_ponder_thread = None
        _dlog(f"[MPON] cancel({reason}): 停止完了")


def _mate_ponder_dispatch(ctx, go_ponder_clock_arg, cur_game_phase, label="go-ponder"):
    try:
        if not _mate_ponder_due_core(
                ctx.cfg.mate_ponder_enable,
                _mate_solver_active(ctx),
                getattr(ctx.game_progress, "last_nnue_score_cp", None),
                cur_game_phase, _mate_ponder_min_game_phase,
                _DLPONDER_STATE.opponent_s_ema,
                _cfloat(_cfg, "DLP_Ponder_Min_Opp_S", 1.5)):
            return
        _pos = ctx.current_position
        _t = getattr(ctx, "_mate_ponder_thread", None)
        if _t is not None and _t.is_alive():
            if getattr(ctx, "_mate_ponder_pos", None) == _pos:
                _dlog(f"[MPON/{label}] dedup: 同一局面を探索中 — 継続")
                return
            _mate_ponder_cancel(ctx, f"{label}-restart", join_s=0.3)
            if getattr(ctx, "_mate_ponder_thread", None) is not None:
                _dlog(f"[MPON/{label}] 旧ワーカー drain 未完 — 今回は発行見送り")
                return
        ctx.assets.sweep("mpon-stale (局面前進)", kinds={"mpon"})
        _eff = getattr(go_ponder_clock_arg, "eff_s", None) if go_ponder_clock_arg is not None else None
        _mt_ms = _mate_ponder_movetime_core(_eff, ctx.cfg.mate_solver_join_timeout_s)
        _ev = threading.Event()
        ctx._mate_ponder_cancel = _ev
        ctx._mate_ponder_pos = _pos
        _th = _spawn('mate_ponder', _mate_ponder_worker, ctx, _pos, _mt_ms, _ev, start_now=False)
        ctx._mate_ponder_thread = _th
        _th.start()
        _DLPONDER_STATE.mpon_dispatched = \
            int(_DLPONDER_STATE.mpon_dispatched) + 1
        _flog(f"[MPON/{label}] 相手番 df-pn 起動 movetime={_mt_ms}ms "
              f"(game_phase={cur_game_phase if cur_game_phase is None else round(float(cur_game_phase), 3)})")
    except (KeyboardInterrupt, SystemExit, MemoryError):
        raise
    except Exception as _de:
        try:
            ctx._mate_ponder_thread = None
            ctx._mate_ponder_cancel = None
        except Exception as _e:
            _flog(f"[ignored] _mate_ponder_dispatch: {_e!r}")
        _DLPONDER_STATE.mpon_dispatch_err = int(_DLPONDER_STATE.mpon_dispatch_err) + 1
        _flog(f"[MPON-DISPATCH-ERR] {type(_de).__name__}: {_de!r} "
              f"(streak={_DLPONDER_STATE.mpon_dispatch_err})")



def _revive_dead_nnue_async(ctx):
    if ctx.nnue_1 is not None and not getattr(ctx.nnue_1, "_alive", False):
        try:
            _restart_nnue_1(ctx, "revive-async(nnue_1)",
                            readyok_timeout=30, async_launch=True)
        except Exception as _re:
            _flog(f"[REVIVE] nnue_1 async revive raised: {_re}")


def _emergency_move_from_any_engine(ctx, eff_s):
    _revive_dead_nnue_async(ctx)

    _nodes   = _params[_K_POLICY_NODES]
    _timeout = _clamp(eff_s if eff_s else 3.0, 1.0, 5.0)
    _board = _get_tracking_board(ctx)

    _engines = [("dl_1", ctx.dl_1)]
    for _name, _eng in _engines:
        if _eng is None or not _eng_alive(_eng):
            continue
        try:
            _r = fetch_dl_policy(
                _eng, ctx.current_position, 1, _nodes,
                timeout=_timeout, eff_s=eff_s)
        except Exception as _fe:
            _flog(f"[EMERGENCY] {_name} fetch raised: {_fe}")
            continue
        if _r is None or not _r.policy:
            _flog(f"[EMERGENCY] {_name} returned no policy")
            continue
        _mv = _r.policy[0][0]
        if _mv in (None, "", "resign", "win"):
            continue
        if _board is not None:
            try:
                if _board.usi_to_csa(_mv) == "":
                    _flog(f"[EMERGENCY-DIAG] {_name} move {_mv} flagged illegal by "
                          f"orchestrator board (likely orchestrator board desync); "
                          f"trusting child and emitting as-is")
                elif _board.is_perpetual_check_move(_mv):
                    _flog(f"[EMERGENCY-DIAG] {_name} move {_mv} flagged perpetual-check; "
                          f"trusting child and emitting as-is")
            except Exception as _ed:
                _flog(f"[ignored] EMERGENCY-DIAG: {_ed}")
        _flog(f"[EMERGENCY] nnue dead (revive launched) — {_name} provides bestmove "
              f"{_mv!r} for this move (continuing game instead of resigning)")
        return _mv
    _flog("[EMERGENCY] no surviving engine could provide a move "
          "— escalating to wait-and-revive nnue (WAIT-REVIVE)")
    return None


class RecoverKind(enum.Enum):
    SYNC_RESTARTED = enum.auto()
    ASYNC_FIRED    = enum.auto()
    WAIT_REVIVED   = enum.auto()
    EMERGENCY      = enum.auto()
    SKIPPED        = enum.auto()
    FAILED         = enum.auto()


class RecoverReason(enum.Enum):
    GO_ENTRY            = enum.auto()
    DISPATCH_GUARD      = enum.auto()
    EMERGENCY_FALLBACK  = enum.auto()


@dataclasses.dataclass(frozen=True)
class RecoverResult:
    kind: "RecoverKind"
    final_state: "HealthState"
    movetime_ms: object = None
    reason_used: str = ""
    damper_hit: bool = False
    gate_hit: object = None


def _recover(eng, *, reason, clock=None, ctx=None):
    slot = getattr(eng, "name", "") if eng is not None else ""
    reason_used = f"{reason.name}/{slot}"
    is_dl = slot in ("dl_1",)


    ft = getattr(eng, "_restart_fail_t", None) if eng is not None else None
    if (slot != "nnue_1"
            and ft is not None and (time.perf_counter() - ft) < 45.0):
        return RecoverResult(kind=RecoverKind.SKIPPED,
                             final_state=_health_of(eng),
                             reason_used=reason_used,
                             damper_hit=True)

    if is_dl and reason is RecoverReason.GO_ENTRY and _dl_restart_ram_critical():
        return RecoverResult(kind=RecoverKind.SKIPPED,
                             final_state=_health_of(eng),
                             reason_used=reason_used,
                             gate_hit="ram")


    if reason is RecoverReason.GO_ENTRY and is_dl:
        caller_tag = "go"
        _restart_child_async(ctx, slot, caller_tag)
        return RecoverResult(kind=RecoverKind.ASYNC_FIRED,
                             final_state=_health_of(eng),
                             reason_used=reason_used)

    if reason is RecoverReason.GO_ENTRY and slot == "nnue_1":
        return _recover_nnue1_go_entry(eng, clock=clock, ctx=ctx,
                                       reason_used=reason_used)

    if reason in (RecoverReason.DISPATCH_GUARD,
                  RecoverReason.EMERGENCY_FALLBACK):
        _default_s = 3.0 if reason is RecoverReason.EMERGENCY_FALLBACK else 10.0
        _deadline = _wait_revive_deadline_s(ctx, _default_s)
        _caller_tag = reason.name.lower().replace("_", "-")
        _label = _caller_tag
        _mv = None
        try:
            _mv = _wait_revive_nnue_and_move(ctx, caller=_caller_tag,
                                             deadline_s=_deadline, go_clock=clock)
        except Exception as _we:
            _flog(f"[RECOVER/{_caller_tag}] wait-revive raised: {_we!r}")
        if _mv:
            _safe_bestmove(_mv, label=_label)
            return RecoverResult(kind=RecoverKind.WAIT_REVIVED,
                                 final_state=_health_of(eng),
                                 reason_used=reason_used,
                                 movetime_ms=int(_deadline * 1000))
        _emerg = None
        try:
            _emerg = _emergency_move_from_any_engine(ctx, _deadline)
        except Exception as _ee:
            _flog(f"[RECOVER/{_caller_tag}] emergency raised: {_ee!r}")
        if _emerg and _emerg not in ("resign", "win"):
            try:
                _settle_debts(ctx, keys=["nnue_1"], reason=f"recover-emergency/{_caller_tag}")
            except Exception as _se:
                _flog(f"[RECOVER/{_caller_tag}] settle_debts raised (ignored): {_se!r}")
            _safe_bestmove(_emerg, label=_label)
            return RecoverResult(kind=RecoverKind.EMERGENCY,
                                 final_state=_health_of(eng),
                                 reason_used=reason_used,
                                 movetime_ms=int(_deadline * 1000))
        _safe_bestmove("resign", label=_label)
        return RecoverResult(kind=RecoverKind.FAILED,
                             final_state=_health_of(eng),
                             reason_used=reason_used)

    return RecoverResult(kind=RecoverKind.FAILED,
                         final_state=_health_of(eng),
                         reason_used=reason_used)


def _recover_nnue1_go_entry(eng, *, clock=None, ctx=None, reason_used=""):
    _rem_ms = getattr(clock, "remaining_ms", None) if clock is not None else None
    _floor_ms = getattr(clock, "floor_ms", None) if clock is not None else None
    _eff_s = getattr(clock, "eff_s", 0.0) if clock is not None else 0.0
    _tc = ((_rem_ms is not None and _rem_ms <= 5000 and (_floor_ms or 0) <= 3000)
           or (_eff_s > 0 and _restart_readyok_budget_s(ctx, default_s=8.0) > _eff_s * 0.5))
    if _tc:
        _restart_nnue_1(ctx, "recover-go-tc", async_launch=True)
        _ok = False
    else:
        _ok = _restart_nnue_1(ctx, "recover-go")
    if _ok and _eng_alive(eng):
        return RecoverResult(kind=RecoverKind.SYNC_RESTARTED,
                             final_state=_health_of(eng),
                             reason_used=reason_used)
    _deadline = _wait_revive_deadline_s(ctx, 10.0)
    _mv = None
    try:
        _mv = _wait_revive_nnue_and_move(ctx, caller="recover-go",
                                         deadline_s=_deadline, go_clock=clock)
    except Exception as _we:
        _flog(f"[RECOVER/go-entry] wait-revive raised: {_we!r}")
    if _mv:
        _safe_bestmove(_mv, label="recover-go")
        return RecoverResult(kind=RecoverKind.WAIT_REVIVED,
                             final_state=_health_of(eng),
                             reason_used=reason_used,
                             movetime_ms=int(_deadline * 1000))
    _emerg = None
    try:
        _emerg = _emergency_move_from_any_engine(ctx, _deadline)
    except Exception as _ee:
        _flog(f"[RECOVER/go-entry] emergency raised: {_ee!r}")
    if _emerg and _emerg not in ("resign", "win"):
        try:
            _settle_debts(ctx, keys=["nnue_1"], reason="recover-emergency/go-entry")
        except Exception as _se:
            _flog(f"[RECOVER/go-entry] settle_debts raised (ignored): {_se!r}")
        _safe_bestmove(_emerg, label="recover-go")
        return RecoverResult(kind=RecoverKind.EMERGENCY,
                             final_state=_health_of(eng),
                             reason_used=reason_used,
                             movetime_ms=int(_deadline * 1000))
    _safe_bestmove("resign", label="recover-go")
    return RecoverResult(kind=RecoverKind.FAILED,
                         final_state=_health_of(eng),
                         reason_used=reason_used)


def _wait_revive_deadline_s(ctx, default_s):
    try:
        _cands = []
        if ctx is not None and getattr(ctx, "ps", None) is not None:
            for _ck in (ctx.ps.go_clock, ctx.ps.ponder_clock):
                if _ck is None:
                    continue
                _tot = (_ck.remaining_ms or 0) + max((_ck.floor_ms or 0), (_ck.inc_ms or 0))
                if _tot > 0:
                    _cands.append(_tot / 1000.0)
        if not _cands:
            return float(default_s)
        return _clamp(min(_cands) * 0.5, 1.0, float(default_s))
    except Exception:
        return float(default_s)


def _wait_revive_nnue_and_move(ctx, caller="emergency", deadline_s=None, go_clock=None):
    _budget = float(deadline_s) if deadline_s and deadline_s > 0 else 12.0
    try:
        _cs_floor = _dur_get_cold_start("nnue_1", _move_overhead_s)
    except Exception:
        _cs_floor = _move_overhead_s
    _readyok_to = min(max(_cs_floor, _move_overhead_s), _budget - _move_overhead_s)
    _move_ms = int(max(int(_move_overhead_ms), (_budget - _readyok_to) * 1000))

    _board = _get_tracking_board(ctx)

    for _slot, _eng, _restart, _opts in (
        ("nnue_1", ctx.nnue_1, _restart_nnue_1, _nnue_1_opts),
    ):
        if _eng is None:
            continue
        if not _eng_alive(_eng):
            try:
                _ok = _restart(ctx, f"{caller}/wait-revive",
                               readyok_timeout=_readyok_to, async_launch=False)
            except Exception as _re:
                _flog(f"[WAIT-REVIVE] {_slot} restart raised: {_re}")
                continue
            if not _ok or not _eng_alive(_eng):
                _flog(f"[WAIT-REVIVE] {_slot} did not come back — trying next")
                continue
            _flog(f"[WAIT-REVIVE] {_slot} revived synchronously — searching this move")
        try:
            _eng.send(ctx.current_position)
            _eng.send("go movetime %d" % _move_ms)
            _pm, _ni = relay_window(
                _eng, timeout=_move_ms / 1000.0 + min(1.0, _budget * 0.1),
                intercept_bestmove=True,
                kill_on_empty=False,
                go_clock=go_clock,
                slow_mover_opts=_opts)
        except Exception as _se:
            _flog(f"[WAIT-REVIVE] {_slot} search raised: {_se}")
            continue
        _mv = (_ni.get("bestmove", "") if _ni else "") or ""
        if _mv in (None, "", "resign", "win"):
            _flog(f"[WAIT-REVIVE] {_slot} returned no usable move — trying next")
            continue
        if _board is not None:
            try:
                if _board.usi_to_csa(_mv) == "":
                    _flog(f"[WAIT-REVIVE-DIAG] {_slot} move {_mv} flagged illegal by "
                          f"orchestrator board; trusting child and emitting as-is")
                elif _board.is_perpetual_check_move(_mv):
                    _flog(f"[WAIT-REVIVE-DIAG] {_slot} move {_mv} flagged perpetual-check; "
                          f"trusting child and emitting as-is")
            except Exception as _ie:
                _flog(f"[ignored] _wait_revive_nnue_and_move: {_ie!r}")
        _flog(f"[WAIT-REVIVE] {_slot} provides bestmove {_mv!r} "
              "(resign avoided by waiting for nnue)")
        return _mv

    _flog("[WAIT-REVIVE] no nnue could be revived and searched — resign is unavoidable")
    return None


def _position_move_list(position_cmd):
    if not position_cmd or "moves" not in position_cmd:
        return []
    return position_cmd.split("moves", 1)[1].split()


def _store_mate_pv(ctx, base_position, pv_moves, origin=""):
    if not pv_moves:
        _clear_mate_pv(ctx)
        return
    try:
        _scr_board = _get_tracking_board(
            type('_ctx', (), {
                'current_position': base_position,
                'csa_board': getattr(ctx, 'csa_board', None)
            })()
        )
        if _scr_board is not None:
            _sb = _scr_board.clone()
            _seen = collections.Counter()
            _seen[_sb.sfen_key()] += 1
            for _idx, _pm in enumerate(pv_moves):
                if _pm in ("resign", "win", "", None):
                    break
                _sb.apply_usi(_pm)
                _k = _sb.sfen_key()
                _seen[_k] += 1
                if _seen[_k] >= 4:
                    _flog(f"[MATE-PV-SCREEN] PV contains 4-fold repetition at ply {_idx} "
                          f"(move {_pm}) — refusing to cache this mate sequence")
                    return
    except Exception as _scr_e:
        _flog(f"[MATE-PV-SCREEN] PV screening failed (non-fatal): {_scr_e}")
    ctx.mate_pv = list(pv_moves)
    ctx.mate_pv_base_position = base_position or ""
    ctx.mate_pv_origin = origin or ""
    _flog(f"[MATE-PV] cached mate sequence ({len(ctx.mate_pv)} plies, "
          f"origin={ctx.mate_pv_origin or 'unspecified'}): "
          f"{' '.join(ctx.mate_pv[:8])}{' ...' if len(ctx.mate_pv) > 8 else ''}")


def _clear_mate_pv(ctx):
    ctx.mate_pv = []
    ctx.mate_pv_base_position = ""
    ctx.mate_pv_origin = ""


def _consume_mate_pv(ctx, current_position):
    if not ctx.mate_pv or not ctx.mate_pv_base_position:
        return None
    _base_moves = _position_move_list(ctx.mate_pv_base_position)
    _cur_moves  = _position_move_list(current_position)
    if len(_cur_moves) < len(_base_moves):
        _flog("[MATE-PV] current position shorter than base — discarding cache")
        _clear_mate_pv(ctx)
        return None
    if _cur_moves[:len(_base_moves)] != _base_moves:
        _flog("[MATE-PV] base prefix mismatch — discarding cache")
        _clear_mate_pv(ctx)
        return None
    _played = _cur_moves[len(_base_moves):]
    i = len(_played)
    if _played != ctx.mate_pv[:i]:
        _flog(f"[MATE-PV] opponent deviated from mate line "
              f"(played={_played[-2:]}) — discarding cache, falling back to search")
        _clear_mate_pv(ctx)
        return None
    if i % 2 != 0:
        _flog(f"[MATE-PV] unexpected parity i={i} — discarding cache")
        _clear_mate_pv(ctx)
        return None
    if i >= len(ctx.mate_pv):
        _flog("[MATE-PV] mate sequence exhausted — clearing cache")
        _clear_mate_pv(ctx)
        return None
    _next = ctx.mate_pv[i]
    try:
        _mpv_board = _get_tracking_board(ctx)
        if _mpv_board is not None:
            _mpv_ill = _mpv_board.illegal_drop_reason(_next)
            if _mpv_ill is not None:
                _flog(f"[MATE-PV] cached move {_next!r} is illegal on current board "
                      f"(reason={_mpv_ill}) — discarding cache, falling back to search")
                _clear_mate_pv(ctx)
                return None
    except Exception as _mpv_chk_e:
        _flog(f"[ignored] MATE-PV illegal check: {_mpv_chk_e}")
    _flog(f"[MATE-PV] following cached mate line: ply-offset {i} → bestmove {_next} "
          f"(no engine search needed)")
    if getattr(ctx, "mate_pv_origin", "") == "mate_solver":
        if not _mate_move_accepted(ctx, _next, "mate-pv-cache"):
            _flog(f"[MATE-PV] cached move {_next!r} rejected by _mate_move_accepted "
                  f"(perpetual-check sennichite) — discarding cache, falling back to search")
            _clear_mate_pv(ctx)
            return None
    return _next



_INFINITE_COUNCIL_INTERVAL_S = 5.0
_INFINITE_COUNCIL_EFF_S      = 5.0

def _run_infinite_council(ctx, eng, move_count):
    position = ctx.current_position
    _n = _params[_K_POLICY_MOVES]
    _nodes = _calc_dynamic_policy_nodes(_INFINITE_COUNCIL_EFF_S, cfg=ctx.cfg)
    _game_phase = _calc_game_phase(position, cfg=ctx.cfg)
    _latest_nnue = {"move": None, "score_cp": 0, "depth": 0}
    _council_result = {"winner": None, "confidence": 0.0}
    _stop_event = threading.Event()

    def _council_cycle():
        if _stop_event.is_set():
            return
        if not _eng_alive(ctx.dl_1):
            return
        _snap = _latest_nnue
        nnue_move = _snap["move"]
        if not nnue_move:
            return
        nnue_cp = _snap["score_cp"]
        try:
            with ctx.prefetch.dl_1_lock:
                _raw = fetch_dl_policy(
                    ctx.dl_1, position, _n, _nodes,
                    timeout=_INFINITE_COUNCIL_EFF_S,
                    eff_s=_INFINITE_COUNCIL_EFF_S, cfg=ctx.cfg)
        except (KeyboardInterrupt, SystemExit, MemoryError):
            raise
        except Exception as _e:
            _flog(f"[INF-COUNCIL] DL_1 fetch failed: {_e!r}")
            return
        if not _raw:
            return
        policy = _raw.policy
        if not policy:
            return
        dl_top = policy[0][0]
        dl_top_score = policy[0][1]
        winner, _override, _src, _ = _council_ballot(
            ctx, dl_top=dl_top, nnue_top=nnue_move,
            dl_top_score=dl_top_score,
            nnue_score_cp=nnue_cp, game_phase=_game_phase,
            move_count=move_count, eff_s=_INFINITE_COUNCIL_EFF_S,
            position_cmd=position, dl3_proxy_allowed=False,
            telemetry=None, label="infinite")
        _inf_gap = None
        if policy and len(policy) >= 2:
            _inf_gap = policy[0][1] - policy[1][1]
        _inf_score_gap_dl_nnue = (abs(dl_top_score - nnue_cp)
                                  if dl_top_score is not None and nnue_cp is not None
                                  else None)
        confidence = _compute_confidence(winner, dl_top, nnue_move, nnue_cp,
                                         dl_gap_cp=_inf_gap)
        sharpness = _compute_sharpness(
            dl_gap_cp=_inf_gap, dl_top=dl_top, nnue_top=nnue_move,
            nnue_score_cp=nnue_cp,
            score_gap_dl_nnue=_inf_score_gap_dl_nnue)
        _council_result["winner"] = winner
        _council_result["confidence"] = confidence
        _council_result["sharpness"] = sharpness
        _voices = []
        if dl_top:
            _voices.append(f"DL1={dl_top}" + (f"({dl_top_score})" if dl_top_score is not None else ""))
        _voices.append(f"NNUE={nnue_move}({nnue_cp}cp)")
        try:
            print(f"info string [council] winner={winner} "
                  f"{' '.join(_voices)} confidence={confidence} sharpness={sharpness}",
                  flush=True)
        except OSError as _e:
            _flog(f"[ignored] _run_infinite_council/_council_cycle: {_e!r}")

    def _poller():
        while not _stop_event.is_set():
            _stop_event.wait(_INFINITE_COUNCIL_INTERVAL_S)
            if _stop_event.is_set():
                break
            try:
                _council_cycle()
            except (KeyboardInterrupt, SystemExit, MemoryError):
                raise
            except Exception as _e:
                _flog(f"[INF-COUNCIL] poller error: {_e!r}")

    _poller_thread = _spawn("inf-council-poller", _poller, start_now=False)
    _poller_thread.start()

    def _relay_and_vote():
        nonlocal _latest_nnue
        _nnue_bestmove = [None, None]
        try:
            while True:
                out = eng.readline(timeout=120)
                if out is None:
                    break
                if not out:
                    continue
                if out.kind == "scored" and out.depth is not None:
                    if out.depth >= _latest_nnue["depth"]:
                        _prev = _latest_nnue
                        _new_cp = out.score_cp if out.score_cp is not None else _prev["score_cp"]
                        _new_mv = out.pv.split()[0] if out.pv else _prev["move"]
                        _latest_nnue = {"move": _new_mv, "score_cp": _new_cp, "depth": out.depth}
                if out.kind == "bestmove":
                    _nnue_bestmove[0] = out.bestmove
                    _nnue_bestmove[1] = out.ponder_move
                    break
                if "pyfa_" in out:
                    continue
                if not _suppress_info_print:
                    try:
                        print(out, flush=True)
                    except OSError as _e:
                        _flog(f"[ignored] _run_infinite_council/_relay_and_vote: {_e!r}")
        except (KeyboardInterrupt, SystemExit, MemoryError):
            raise
        except Exception as _rv_exc:
            _flog(f"[INF-COUNCIL] _relay_and_vote error: {_rv_exc!r}")

        _stop_event.set()
        _poller_thread.join(timeout=3.0)

        _final = _council_result["winner"] or _nnue_bestmove[0]
        _conf = _council_result["confidence"]
        _shp = _council_result.get("sharpness")
        _ni = {"score_cp": _latest_nnue["score_cp"], "depth": _latest_nnue["depth"],
               "bestmove": _nnue_bestmove[0]}
        if _conf > 0:
            _ni["confidence"] = _conf
            _ic_dq = _compute_depth_quality(_latest_nnue.get("depth"))
            _ni["depth_quality"]  = _ic_dq
            _ni["confidence_dq"] = _clamp01(_conf * _ic_dq)
        if _shp is not None:
            _ni["sharpness"] = _shp
        _safe_bestmove(_final, _nnue_bestmove[1], label="infinite-council", nnue_info=_ni)

    _spawn("inf-council-relay", _relay_and_vote)



def _run_endgame_search(ctx, line, move_count, is_infinite, go_clock=None):
    return _run_search(ctx, line, move_count, _UV_ENDGAME, go_clock=go_clock,
                       is_infinite=is_infinite, dl_ponder_hit=False)



def _shutdown(ctx, reason="unknown"):
    with _shutdown_lock:
        if _shutdown_done[0]:
            return
        _shutdown_done[0] = True
    _LIVE._stop_clock()
    _flog(f"_shutdown called: reason={reason}")
    try:
        _learn_shutdown()
    except Exception as _e:
        _flog(f"[ignored] _shutdown: {_e!r}")
    try:
        if _tuning_mode:
            _flog("[DLP] state save suppressed (tuning mode — halve 資源の nps で"
                  "本番較正を汚染しない)")
            raise _DlponderSaveSkip()
        _g = _dlponder_gain_core(_DLPONDER_STATE.nps_ema, _DLPONDER_STATE.opponent_s_ema,
                            _dlponder_eff_policy_nodes(_cfg))
        _flog(f"[DLP] state saved: nps_ema="
              f"{_DLPONDER_STATE.nps_ema and round(_DLPONDER_STATE.nps_ema)} "
              f"opponent_s_ema={_DLPONDER_STATE.opponent_s_ema and round(_DLPONDER_STATE.opponent_s_ema, 1)} "
              f"samples={_DLPONDER_STATE.samples} "
              f"gain={None if _g is None else round(_g, 2)} "
              f"ponder_hit={_DLPONDER_STATE.dlp_hits}/"
              f"{int(_DLPONDER_STATE.dlp_hits) + int(_DLPONDER_STATE.dlp_misses)} "
              f"dispatched={_DLPONDER_STATE.dlp_dispatched} "
              f"mp_alt={_DLPONDER_STATE.mp_alt_hits}/"
              f"{_DLPONDER_STATE.mp_alt_dispatched} "
              f"→ 次回 auto 判定に使用")
        _dlponder_save_state()
    except Exception as _ie:
        _flog(f"[ignored] _shutdown: {_ie!r}")
    try:
        if ctx.game_log:
            ctx.game_meta["dlp_mode"] = str(_DLPONDER_STATE.mode)
            ctx.game_meta["dlp_diff"] = _dlp_game_diff()
            _write_game_stats(ctx.game_log, ctx.game_meta, cfg=ctx.cfg)
            if not _tuning_mode:
                _dlponder_save_state()
            try:
                _usi_game_sfen_flush(ctx, "shutdown")
            except Exception as _sk_e:
                _flog(f"_shutdown: sfen flush failed (non-fatal): {_sk_e!r}")
            _suppressed = (_RUN_MODE is RunMode.DLP_CAL
                           or not ctx.cfg.log_stats)
            _flog(f"_shutdown: flushed {len(ctx.game_log)} pending move(s) "
                  f"(result={ctx.game_meta.get('result')})"
                  + (" [write suppressed: dlp-cal/log_stats gate]"
                     if _suppressed else ""))
            ctx.game_log.clear()
    except Exception as _stats_e:
        _flog(f"_shutdown: stats flush failed (non-fatal): {_stats_e}")
    try:
        ctx.prefetch.cancel()
    except Exception as _fe:
        _flog(f"[ignored] _shutdown: prefetch.cancel: {_fe}")
    def _quit_one(label, engine):
        try:
            engine.quit()
        except Exception as e:
            _flog(f"_shutdown {label}.quit error: {e}")

    _quit_targets = [("ctx.dl_1", ctx.dl_1), ("ctx.nnue_1", ctx.nnue_1)]
    if ctx.mate_solver is not None:
        _quit_targets.append(("ctx.mate_solver", ctx.mate_solver))
    if getattr(ctx, "book", None) is not None:
        _quit_targets.append(("ctx.book", ctx.book))
    if getattr(ctx, "book2", None) is not None:
        _quit_targets.append(("ctx.book2", ctx.book2))

    _quit_threads = []
    for _label, _engine in _quit_targets:
        _t = _spawn(f'shutdown-quit-{_label}', _quit_one, _label, _engine, start_now=False)
        _t.start()
        _quit_threads.append((_label, _t))

    for _label, _t in _quit_threads:
        _t.join(timeout=22.0)
        if _t.is_alive():
            _flog(f"_shutdown {_label}.quit did not return in 22s (non-fatal)")

    for _label, _engine in _quit_targets:
        try:
            _proc = getattr(_engine, "proc", None)
            if _proc is not None and _proc.poll() is None:
                _flog(f"_shutdown: {_label} still alive after quit — forcing kill")
                try:
                    _terminate_proc_full(
                        _proc,
                        job=getattr(_engine, "_job", None),
                        via_shell=getattr(_engine, "_via_shell", False),
                        bat_path=getattr(_engine, "_bat_path", None),
                        wsl_tag=getattr(_engine, "_wsl_tag", None),
                        name=_label)
                    _proc.wait(timeout=5)
                    _health_transition(_engine, HealthState.DEAD, "shutdown-forced", caller="_shutdown")
                    _flog(f"_shutdown: {_label} forced kill complete (rc={_proc.returncode})")
                except Exception as _ke:
                    _flog(f"_shutdown: {_label} forced kill failed (non-fatal): {_ke}")
        except Exception as _fe:
            _flog(f"[ignored] _shutdown: force-kill probe: {_fe}")
    _flog("_shutdown complete")


def _handle_usi(ctx, line):
    _flog("usi received — sending usiok")
    if _suppress_info_print:
        _flog("usiok (suppressed in CSA console)")
        return
    print("id name Pyfamate", flush=True)
    print("id author Penne_Ponne", flush=True)
    print(f"option name POLICY_MOVES type spin default {_params[_K_POLICY_MOVES]} min 3 max 30", flush=True)
    print(f"option name POLICY_NODES type spin default {_params[_K_POLICY_NODES]} min 100 max 10000", flush=True)
    _ram_total_mb, _ = _sys_ram_info()
    if _ram_total_mb:
        _usihash_default = _clamp(_ram_total_mb // 4, 256, 32768)
        _usihash_min     = _clamp(_ram_total_mb // 64, 64, _usihash_default)
    else:
        _usihash_default = 2048
        _usihash_min     = 1024
    print(f"option name USI_Hash type spin default {_usihash_default} "
          f"min {_usihash_min} max 1048576", flush=True)
    print("option name USI_Ponder type check default true", flush=True)
    print(f"option name Move_Overhead_Ms type spin default {_move_overhead_ms} min 0 max 5000", flush=True)
    print(f"option name Tournament_Mode type check default "
          f"{'true' if _tournament_mode else 'false'}", flush=True)
    print(f"option name Opponent_Style type combo default {_opponent_style}"
          f" var auto var nnue var dl var none", flush=True)
    print(f"option name MaxMovesToDraw type spin default {_draw_ply} "
          f"min 0 max 100000", flush=True)
    print(f"option name OppID_NNUE_Names type string default "
          f"{','.join(_opponent_id_nnue_names) or '<empty>'}", flush=True)
    print(f"option name OppID_DL_Names type string default "
          f"{','.join(_opponent_id_dl_names) or '<empty>'}", flush=True)
    print(f"option name OppID_Hybrid_Names type string default "
          f"{','.join(_opponent_id_hybrid_names) or '<empty>'}", flush=True)
    print("usiok", flush=True)
    _flog("usiok sent")



def _forward_draw_ply_to_children(ctx) -> None:
    if _draw_ply <= 0 or ctx.cfg.draw_ply_child_margin < 0:
        return
    child_val = str(_draw_ply + ctx.cfg.draw_ply_child_margin)
    for _opts in (_dl_1_opts, _nnue_1_opts):
        try:
            _opts["MaxMovesToDraw"] = child_val
        except Exception as _ie:
            _flog(f"[ignored] _forward_draw_ply_to_children: {_ie!r}")
    if ctx is None:
        _flog(f"[DP-MARGIN] MaxMovesToDraw {child_val} を opts へ記録 "
              f"(ctx なし — 起動時 initialize で伝達)")
        return
    _sent = []
    for _nm in ("nnue_1", "dl_1"):
        _eng = getattr(ctx, _nm, None)
        if _eng_alive(_eng):
            try:
                _eng.setoption("MaxMovesToDraw", child_val)
                _sent.append(_nm)
            except Exception as _de:
                _flog(f"[DP-MARGIN] {_nm} への MaxMovesToDraw 送信失敗 "
                      f"(継続): {_de}")
    _flog(f"[DP-MARGIN] 子へ MaxMovesToDraw={child_val} "
          f"(実制限 {_draw_ply} + 余裕 {ctx.cfg.draw_ply_child_margin}) を伝達"
          + (f" — 即送: {','.join(_sent)}" if _sent else " — opts 記録のみ"))


def _sp_last_sent(eng, default=None):
    _v = getattr(eng, "_last_sp_sent", None)
    return _v if _v is not None else default


def _nnue_idle_structurally(eng):
    try:
        return (getattr(eng, "_go_sent", 0) > 0
                and getattr(eng, "_bm_arrived", 0) >= eng._go_sent)
    except Exception:
        return False


def _broadcast_setoption(engines, key, value):
    for eng in engines:
        if _eng_alive(eng):
            try:
                eng.setoption(key, value)
            except (KeyboardInterrupt, SystemExit, MemoryError):
                raise
            except Exception as _bse:
                _flog(f"[BROADCAST-SETOPTION] {getattr(eng, 'name', '?')} "
                      f"{key}={value} failed: {_bse!r}")

def _handle_setoption(ctx, line):
    global _draw_ply, _tournament_mode, _opponent_style
    global _opponent_id_nnue_names, _opponent_id_dl_names, _opponent_id_hybrid_names
    m = _RE_SETOPTION.match(line)
    if m:
        key, val = m.group(1), m.group(2)
        if key == _K_POLICY_MOVES:
            _params[_K_POLICY_MOVES] = int(val)
        elif key == _K_POLICY_NODES:
            _params[_K_POLICY_NODES] = int(val)
        elif key == "USI_Hash":
            _flog(f"[BUDGET] GUI USI_Hash={val} accepted-but-ignored "
                  f"(Resource_Budget_Enable=1: 配分は導出値で固定)")
        elif key == "Book_Turn_Hint":
            ctx.book_state.turn_hint = val.strip()
        elif key == "USI_Ponder":
            ponder_enabled_str = val.strip().lower()
            ponder_enabled = (ponder_enabled_str == "true")
            _dl_1_opts["USI_Ponder"] = ponder_enabled_str
            _nnue_1_opts["USI_Ponder"] = ponder_enabled_str
            if not ponder_enabled:
                global _early_ponder
                _early_ponder = False
                _nnue_1_opts["Stochastic_Ponder"] = "false"
                _dl_1_opts["Stochastic_Ponder"] = "false"
                _flog("USI_Ponder=false: EarlyPonder and Stochastic_Ponder overridden to false")
            else:
                _early_ponder = True
                _nnue_1_opts["Stochastic_Ponder"] = str(_cfg["nnue_1_Stochastic_Ponder"])
                if _dl_ponder_enable:
                    _dl_1_opts["Stochastic_Ponder"] = str(_cfg.get("DL_1_Stochastic_Ponder", "true"))
                else:
                    _dl_1_opts["Stochastic_Ponder"] = "false"
                _flog("USI_Ponder=true: EarlyPonder forced true (GUI setoption order workaround)")
            _ponder_targets = [ctx.dl_1, ctx.nnue_1]
            _broadcast_setoption(_ponder_targets, "USI_Ponder", ponder_enabled_str)
            if not ponder_enabled:
                _broadcast_setoption(_ponder_targets, "Stochastic_Ponder", "false")
            else:
                for _pt_eng, _pt_opts in ((ctx.dl_1, _dl_1_opts),
                                          (ctx.nnue_1, _nnue_1_opts)):
                    if _pt_eng in _ponder_targets:
                        _pt_sp = _pt_opts.get("Stochastic_Ponder")
                        if _pt_sp is not None:
                            _broadcast_setoption([_pt_eng],
                                                 "Stochastic_Ponder", _pt_sp)
            _flog(f"USI_Ponder set to {ponder_enabled_str} (forwarded to child engines, dl_ponder_enable={_dl_ponder_enable})")
        elif key in ("MaxMovesToDraw", "Draw_Ply"):
            try:
                _draw_ply = max(0, int(val))
            except (ValueError, TypeError):
                _flog(f"[GP-POL] MaxMovesToDraw 値が不正: {val!r} (無視)")
            else:
                _flog(f"[GP-POL] draw_ply={_draw_ply} (手数制限を捕捉)")
                _forward_draw_ply_to_children(ctx)
        elif key == "Tournament_Mode":
            _tournament_mode = (val.strip().lower() == "true")
            _flog(f"[GP-POL] Tournament_Mode={_tournament_mode}")
        elif key == "Opponent_Style":
            _os_v = val.strip().lower()
            if _os_v in ("auto", "nnue", "dl", "none"):
                _opponent_style = _os_v
                _flog(f"[OPP-ID] Opponent_Style={_opponent_style}")
            else:
                _flog(f"[OPP-ID] Opponent_Style 値が不正: {val!r} (無視)")
        elif key in ("OppID_NNUE_Names", "OppID_DL_Names", "OppID_Hybrid_Names"):
            _names = _opponent_id_parse_names("" if val.strip() == "<empty>" else val)
            if key == "OppID_NNUE_Names":
                _opponent_id_nnue_names = _names
            elif key == "OppID_DL_Names":
                _opponent_id_dl_names = _names
            else:
                _opponent_id_hybrid_names = _names
            _flog(f"[OPP-ID] {key}={_names!r}")
        elif key in _SETOPTION_INT_SPIN:
            _soi_lo, _soi_hi, _soi_gname = _SETOPTION_INT_SPIN[key]
            try:
                _soi_val = _clamp(int(val), _soi_lo, _soi_hi)
                globals()[_soi_gname] = _soi_val
                if _soi_gname == "_move_overhead_ms":
                    globals()["_move_overhead_s"] = max(0.05, _soi_val / 1000.0)
                _soi_cfg_attr = {
                    "DL_Min_Remaining_Moves":     "dl_min_remaining_moves",
                    "Rem_Moves_Expected_Game_Ply": "rem_moves_expected_game_ply",
                }.get(key)
                if _soi_cfg_attr and ctx.cfg is not None:
                    setattr(ctx.cfg, _soi_cfg_attr, _soi_val)
                _flog(f"{key}={_soi_val}")
            except (ValueError, TypeError):
                _flog(f"{key} invalid value: {val!r} (ignored)")
        elif key in (
            "USI_OwnBook", "NarrowBook", "BookMoves", "BookIgnoreRate",
            _K_BOOKFILE, "BookDir", "BookEvalDiff", "BookEvalBlackLimit",
            "BookEvalWhiteLimit", "BookDepthLimit", "BookOnTheFly",
            "ConsiderBookMoveCount", "BookPvMoves", "IgnoreBookPly", "FlippedBook",
        ):
            _flog(f"[bookloader] setoption {key}={val} ignored "
                  f"(Book は config.txt 専用・GUI 非公開)")


def _warmup_engine(eng, label: str, timeout: float = 30) -> None:
    if not _eng_alive(eng):
        return
    eng.send("position startpos")
    eng.send("go nodes 1")
    if eng.wait_for("bestmove", timeout=timeout):
        _flog(f"{label} warmup: complete")
    else:
        _flog(f"{label} warmup: timeout (non-fatal)")
        try:
            eng.send("stop")
            eng.flush_until_ready(timeout=5.0)
        except Exception as _e:
            _flog(f"[ignored] _warmup_engine: {_e!r}")

def _handle_isready(ctx, line):
    if _eng_alive(getattr(ctx, "dl_1", None)):
        _flog("isready: engines already initialized — skipping re-init, "
              "replying readyok only")
        if not _suppress_info_print:
            print("readyok", flush=True)
        _flog("readyok sent (already-initialized fast path)")
        return

    _dl_1_opts["MultiPV"] = str(_params[_K_POLICY_MOVES])
    _flog(f"ctx.dl_1  exists={os.path.exists(DL_1_PATH)}")
    _flog(f"ctx.nnue_1  exists={os.path.exists(nnue_1_PATH)}")
    _dl1_model_rel = _dl_1_opts.get("DNN_Model1", "eval/model.onnx")
    _dl1_mb = _model_size_mb(DL_1_PATH, _dl1_model_rel)
    global _dl1_mb_for_stab
    _dl1_mb_for_stab = _dl1_mb if _dl1_mb else 115.0
    _flog(
        f"Model sizes: DL_1={_dl1_mb} MB ({_dl1_model_rel})"
    )
    _nnue_1_opts["Stochastic_Ponder"] = (
        str(_cfg["nnue_1_Stochastic_Ponder"]) if _early_ponder else "false")
    if not _nnue_slowmover_user_set:
        _nnue_1_opts["SlowMover"] = str(round(_lerp(*_LERP_SLOWMOVER, _time_aggression_nnue)))
    _flog(f"dl_1_opts={_dl_1_opts}")
    _flog(f"nnue_1_opts={_nnue_1_opts}")
    try:
        ctx.dl_1.start();   _flog("ctx.dl_1 started")
        ctx.nnue_1.start(); _flog("ctx.nnue_1 started")

        def _init_usiok_retry(_ir_label, _ir_eng, _ir_opts):
            try:
                _ir_eng.initialize(_ir_opts)
                _flog(f"{_ir_label} isready sent")
            except Exception as _ir_e:
                _flog(f"{_ir_label} initialize failed: {_ir_e!r} — "
                      f"one-shot restart & retry")
                time.sleep(2.0)
                _ir_eng.start()
                _flog(f"{_ir_label} restarted (usiok retry)")
                _ir_eng.initialize(_ir_opts)
                _flog(f"{_ir_label} isready sent (retry)")
        _init_usiok_retry("ctx.dl_1", ctx.dl_1, _dl_1_opts)
        _init_usiok_retry("ctx.nnue_1", ctx.nnue_1, _nnue_1_opts)

        results = {}
        def wait_r(eng, key):
            _t0 = time.perf_counter()
            results[key] = eng.wait_for("readyok", timeout=300)
            _dt = time.perf_counter() - _t0
            if results[key] is not None:
                _flog(f"[INIT] {eng.name} readyok arrived ({_dt:.1f}s)")
            else:
                _flog(f"[INIT] {eng.name} readyok WAIT timeout ({_dt:.1f}s)")
        _safe_wait_r = _thread_safe_target("wait_r")(wait_r)
        t1 = _spawn("waitr/dl_1", _safe_wait_r, ctx.dl_1, 'f', start_now=False)
        t2 = _spawn("waitr/nnue_1", _safe_wait_r, ctx.nnue_1, 'y', start_now=False)
        threads = [t1, t2]
        for t in threads: t.start()
        _join_t0 = time.perf_counter()
        _hb_n = 0
        _bat_engs = []
        for _eng_candidate in [ctx.dl_1]:
            if _eng_candidate is not None and _eng_candidate._alive and getattr(_eng_candidate, "_via_shell", False):
                _bat_engs.append(_eng_candidate)
        while any(t.is_alive() for t in threads):
            for t in threads:
                t.join(timeout=3.0)
            if any(t.is_alive() for t in threads):
                for _be in _bat_engs:
                    if _be._alive:
                        try:
                            _be.send("")
                        except Exception as _e:
                            _flog(f"[ignored] _handle_isready: {_e!r}")
                _hb_n += 1
                _got = sorted(k for k, v in results.items() if v is not None)
                _flog(f"[INIT] readyok wait heartbeat #{_hb_n} "
                      f"({time.perf_counter() - _join_t0:.0f}s elapsed; "
                      f"got={_got})")
                if not _suppress_info_print:
                    print(f"info string initializing... "
                          f"({time.perf_counter() - _join_t0:.0f}s)",
                          flush=True)

        def _retry_ready_on_timeout(label, eng, opts, key, timeout_s=30,
                                    degrade_hash=False):
            if results.get(key) is not None:
                return
            if eng is None:
                return
            _flog(f"{label}: ready timeout — attempting restart/reinit")
            try:
                if not eng._alive:
                    eng.start()
                    _flog(f"{label}: restarted")
                eng.initialize(opts)
                _ok = eng.wait_for("readyok", timeout=timeout_s)
                if _ok is not None:
                    results[key] = _ok
                    _flog(f"{label}: recovery readyok OK")
                else:
                    _flog(f"{label}: recovery readyok timeout (non-fatal)")
                    if degrade_hash:
                        try:
                            _h_cur = int(opts.get("USI_Hash", "0"))
                        except Exception:
                            _h_cur = 0
                        if _h_cur > 64:
                            _h_new = max(64, _h_cur // 2)
                            _flog(
                                f"{label}: retry with lower Hash {_h_cur} -> {_h_new}"
                            )
                            try:
                                if eng._alive:
                                    eng.quit()
                                eng.start()
                                opts["USI_Hash"] = str(_h_new)
                                eng.initialize(opts)
                                _ok2 = eng.wait_for("readyok", timeout=timeout_s)
                                if _ok2 is not None:
                                    results[key] = _ok2
                                    _flog(
                                        f"{label}: recovery readyok OK "
                                        f"(Hash={_h_new})"
                                    )
                                else:
                                    _flog(
                                        f"{label}: recovery readyok timeout "
                                        f"(Hash={_h_new})"
                                    )
                            except Exception as e2:
                                _flog(
                                    f"{label}: lower-Hash recovery failed "
                                    f"(non-fatal): {e2}"
                                )
            except Exception as e:
                _flog(f"{label}: recovery failed (non-fatal): {e}")

        _retry_ready_on_timeout("ctx.dl_1", ctx.dl_1, _dl_1_opts, "f", timeout_s=30)
        _retry_ready_on_timeout(
            "ctx.nnue_1", ctx.nnue_1, _nnue_1_opts, "y", timeout_s=30, degrade_hash=True
        )

        if results.get("f") is None:
            log("WARNING: ctx.dl_1 readyok timeout")
            _flog("WARNING: ctx.dl_1 readyok timeout")
        else:
            _flog("ctx.dl_1  readyok OK")
        if results.get("y") is None:
            log("WARNING: ctx.nnue_1 readyok timeout")
            _flog("WARNING: ctx.nnue_1 readyok timeout")
            if not ctx.cfg.log_engine_stderr:
                _flog("HINT: set Log_Engine_Stderr=true in config.txt to capture ctx.nnue_1 crash stderr")
        else:
            _flog("ctx.nnue_1 readyok OK")

        if ctx.mate_solver is not None:
            _flog(
                f"ctx.mate_solver deferred: start() will be called on first usinewgame  "
                f"path={ctx.cfg.mate_solver_path}  "
                f"Hash={ctx.cfg.mate_solver_hash}MB  Threads={ctx.cfg.mate_solver_threads}  "
                f"join_timeout={ctx.cfg.mate_solver_join_timeout_s*1000:.0f}ms  "
                f"min_ply={ctx.cfg.mate_solver_min_ply}"
            )

        _warmup_engine(ctx.dl_1, "DL_1", timeout=30)


        log("2 engines ready")
        _flog("Init complete")
        if _book_enabled and ctx.book is None:
            _book_start_engine(ctx)
    except Exception as e:
        tb = _safe_format_exc()
        log(f"Init error: {e}")
        _flog(f"Init error: {e}\n{tb}")
        if os.environ.get("PYFAMATE_DLP_CAL") == "1":
            _flog("[dlp-cal-child] init failed — fail-fast exit (readyok 送信せず)")
            try:
                _shutdown(ctx, "dlp-cal-init-failfast")
            except Exception as _ff_e:
                _flog(f"[ignored] dlp-cal failfast shutdown: {_ff_e}")
            sys.exit(1)

    if not _suppress_info_print:
        print("readyok", flush=True)
    _flog("readyok sent")




def _parallel_stop_drain(engines, timeout_each, join_timeout, label, mode="flush"):
    if not engines:
        return set()
    _done = {}
    def _do_drain(e):
        try:
            if mode == "flush":
                _done[e.name] = bool(e.flush_with_stop(timeout=timeout_each))
            else:
                e.send("stop")
                _got_bm = False
                try:
                    for _l in e.read_until("bestmove", timeout=timeout_each):
                        if "bestmove" in _l:
                            _got_bm = True
                            break
                except Exception as _e:
                    _flog(f"[ignored] _parallel_stop_drain/_do_drain: {_e!r}")
                _done[e.name] = _got_bm
        except Exception as _fe:
            _flog(f"[ignored] {label} drain {e.name}: {_fe}")
            _done[e.name] = False
    _ths = [(_spawn(f'dlpd_{e.name}', _do_drain, e, start_now=False), e) for e in engines]
    for _t, _ in _ths:
        _t.start()
    _incomplete = set()
    for _t, _e in _ths:
        _t.join(timeout=join_timeout)
        if _t.is_alive() or not _done.get(_e.name, False):
            _incomplete.add(_e.name)
    return _incomplete


def _stop_dl_ponders(ctx, reason="", eff_s=None):
    ctx.ps.dl_ponder_pos = None
    _drain_s = 0.5
    _eff_for_drain = eff_s if (eff_s is not None and eff_s > 0) else getattr(ctx.ps, "last_eff_s", None)
    if isinstance(_eff_for_drain, (int, float)) and _eff_for_drain > 0:
        _drain_s = _clamp(_eff_for_drain * 0.2, 0.1, 0.5)
    _dl_ledger = getattr(ctx, "ledger", None)
    if _dl_ledger is not None and _dl_ledger.eff_s > 0:
        _drain_s = _dl_ledger.draw(f"dl-drain/{reason}", _drain_s, floor_s=0.1)
    _to_drain = []
    for _ek, _eng in (("dl_1", ctx.dl_1),):
        if _ek in ctx.ps.pending_bestmove:
            _ps_debt_clear(ctx, _ek, f"stop-dl-ponders/{reason}")
            if _eng_alive(_eng):
                _to_drain.append(_eng)
    _incomplete = _parallel_stop_drain(
        _to_drain, _drain_s, _drain_s + 0.5,
        f"DL-Ponder-stop/{reason}", mode="bestmove")
    if _incomplete:
        _DLPONDER_STATE.dlp_drain_incomplete = \
            int(_DLPONDER_STATE.dlp_drain_incomplete) + len(_incomplete)
    for _e in _to_drain:
        _dlog(f"[DL-Ponder] {_e.name} go ponder stopped+drained "
              f"({reason}; bestmove={'未着' if _e.name in _incomplete else '消費'} "
              f"budget={_drain_s:.2f}s)")


def _settle_debts(ctx, keys=None, *, reason="", transition=False,
                  nnue_timeout=None, flush_after=False):
    ps = ctx.ps
    targets = (set(ps.pending_bestmove) if keys is None
               else set(keys) & set(ps.pending_bestmove))
    if transition and ps.phase in _PS_PHASE_ACTIVE and targets:
        _ps_transition(ctx, PsPhase.DRAINING, f"settle/{reason}")
    if "nnue_1" in targets:
        _ps_debt_clear(ctx, "nnue_1", f"settle/{reason}")
        if _eng_alive(ctx.nnue_1):
            try:
                ctx.nnue_1.send("stop")
                _to = (nnue_timeout if nnue_timeout is not None
                       else _stop_drain_timeout_safe(ctx, None))
                _led = getattr(ctx, "ledger", None)
                if _led is not None:
                    _led.note(f"settle/{reason}", _to)
                relay_drain(ctx.nnue_1, timeout=_to,
                            owner=f"settle/{reason}")
                if flush_after and ctx.nnue_1._alive:
                    ctx.nnue_1.flush_until_ready(timeout=2.0, max_stale_lines=50)
                _dlog(f"[SETTLE] nnue_1 債務決済 ({reason}, 窓={_to:.2f}s)")
            except Exception as _se:
                _flog(f"[SETTLE] nnue_1 drain failed (non-fatal, {reason}): {_se!r}")
    if targets & {"dl_1"}:
        _stop_dl_ponders(ctx, f"settle/{reason}")
    if transition and ps.phase is PsPhase.DRAINING:
        _ps_transition(ctx, PsPhase.IDLE, f"settle/{reason} 完了")


def _stop_nnue_ponders(ctx, reason=""):
    _settle_debts(ctx, ["nnue_1"], reason=f"stop-nnue-ponders/{reason}",
                  nnue_timeout=2.0)


def _dl_ponder_dispatch(ctx, line, pos=None, label="go-ponder"):
    if not _dl_ponder_enable:
        return
    _dl_pos = pos if pos is not None else ctx.current_position
    _any_flag = bool(ctx.ps.pending_bestmove & {"dl_1"})
    _continuing = (_any_flag and ctx.ps.dl_ponder_pos == _dl_pos)

    _skip = set()
    if _continuing:
        _rejoin_candidates = []
        for _ek, _eng in (("dl_1", ctx.dl_1),):
            if _ek not in ctx.ps.pending_bestmove and _eng_alive(_eng):
                _rejoin_candidates.append(_eng)
        if not _rejoin_candidates:
            _dlog(f"[DL-Ponder/{label}] dedup: 同一局面を ponder 中 — 再送せず継続")
            return
        _skip = _parallel_stop_drain(
            _rejoin_candidates, 1.5, 2.0,
            f"DL-Ponder/{label}/rejoin", mode="flush")
        _n_rejoined = len(_rejoin_candidates) - len(_skip)
        if _n_rejoined > 0:
            _DLPONDER_STATE.dlp_rejoin =                 int(_DLPONDER_STATE.dlp_rejoin) + _n_rejoined
        for _dn in _skip:
            _flog(f"[DL-Ponder/{label}] {_dn} rejoin drain 未完 — "
                  "復帰送信をスキップ (kill はしない)")
    elif _any_flag:
        _drain = []
        for _ek, _eng in (("dl_1", ctx.dl_1),):
            if _ek in ctx.ps.pending_bestmove and _eng_alive(_eng):
                _drain.append(_eng)
            _ps_debt_clear(ctx, _ek, f"dl-dispatch-drain/{label}")
        _skip = _parallel_stop_drain(
            _drain, 1.5, 2.0, f"DL-Ponder/{label}", mode="flush")
        for _dn in _skip:
            _flog(f"[DL-Ponder/{label}] {_dn} drain 未完 — "
                  "今回の go ponder 送信をスキップ (kill はしない)")
        ctx.ps.dl_ponder_pos = None

    if not _dlponder_forward_gate_core(_DLPONDER_STATE.opponent_s_ema,
                                  _cfloat(_cfg, "DLP_Ponder_Min_Opp_S", 1.5)):
        _DLPONDER_STATE.dlp_gate_skips =             int(_DLPONDER_STATE.dlp_gate_skips) + 1
        _flog(f"[DLP-GATE/{label}] DL go ponder skipped this move "
              f"(opponent_s_ema={round(_DLPONDER_STATE.opponent_s_ema, 1)}s < "
              f"{_cfg.get('DLP_Ponder_Min_Opp_S', 1.5)}s — 木が育つ前に終わる相手番)")
        return

    _targets = [("dl_1", ctx.dl_1, True, _dl_pos, None)]
    _sent_any = False
    for _ek, _eng, _gate, _send_pos, _sp_want in _targets:
        if not _gate or not _eng_alive(_eng) or _eng.name in _skip:
            continue
        if _continuing and _ek in ctx.ps.pending_bestmove:
            continue
        try:
            if _sp_want is not None and _sp_last_sent(_eng) != _sp_want:
                _eng.setoption("Stochastic_Ponder", _sp_want)
            if getattr(_eng, "_force_position_resync", False):
                _flog(f"[DL-Ponder/{label}] {_eng.name} _force_position_resync "
                      "消費 — 予測局面ではなく確定局面で再同期")
                _send_pos = ctx.current_position
                _eng._force_position_resync = False
            _eng.send(_send_pos)
            _eng.send(line)
            _ps_debt_add(ctx, _ek, f"dl-dispatch/{label}")
            _sent_any = True
        except Exception as _pe:
            _flog(f"[DL-Ponder/{label}] {_eng.name} send failed (non-fatal): {_pe}")
            _ps_debt_clear(ctx, _ek, f"dl-dispatch-sendfail/{label}")
    if _sent_any:
        ctx.ps.dl_ponder_pos = _dl_pos
        _DLPONDER_STATE.dlp_dispatched = int(_DLPONDER_STATE.dlp_dispatched) + 1
        _flog(f"[DL-Ponder/{label}] go ponder forwarded "
              f"(pending={sorted(ctx.ps.pending_bestmove)})")


def _stop_all_ponders(ctx, reason=""):
    _stop_dl_ponders(ctx, reason)
    _mate_ponder_cancel(ctx, reason, join_s=1.0)
    ctx.assets.sweep(f"mpon/{reason}", kinds={"mpon"})
    _stop_nnue_ponders(ctx, reason)


def _teardown_game(ctx, reason):
    _stop_all_ponders(ctx, reason)
    ctx.prefetch.cancel()


_MGMT_GEN = [0]


def _mgmt_deferred_send(eng, lock, cmd, label, src, my_gen, horizon_s=25.0):
    _go0 = getattr(eng, "_go_sent", 0)
    _t0 = time.perf_counter()

    def _run():
        deadline = _t0 + horizon_s
        while time.perf_counter() < deadline:
            if _MGMT_GEN[0] != my_gen:
                _flog(f"[{src}][MGMT-HUB] {label}: deferred {cmd!r} superseded "
                      f"(gen {my_gen}->{_MGMT_GEN[0]}) — drop")
                return
            if not _eng_alive(eng):
                _flog(f"[{src}][MGMT-HUB] {label}: engine dead — deferred {cmd!r} "
                      "drop (restart が状態を再構築)")
                return
            if getattr(eng, "_go_sent", 0) != _go0:
                _flog(f"[{src}][MGMT-HUB] {label}: new go issued since queueing — "
                      f"deferred {cmd!r} drop (対局進行に割込まない)")
                return
            if lock.acquire(timeout=1.0):
                try:
                    if (_MGMT_GEN[0] != my_gen
                            or getattr(eng, "_go_sent", 0) != _go0):
                        _flog(f"[{src}][MGMT-HUB] {label}: raced at send — "
                              f"deferred {cmd!r} drop")
                        return
                    try:
                        eng.send(cmd)
                        _flog(f"[{src}][MGMT-HUB] {label}: deferred {cmd!r} sent "
                              f"({time.perf_counter() - _t0:.1f}s late)")
                        try:
                            _DLPONDER_STATE.pending_forced_resend = \
                                int(_DLPONDER_STATE.pending_forced_resend) + 1
                        except Exception as _e:
                            _flog(f"[ignored] _mgmt_deferred_send/_run: {_e!r}")
                    except Exception as _de:
                        _flog(f"[{src}][MGMT-HUB] {label}: deferred send failed: {_de!r}")
                finally:
                    lock.release()
                return
        _flog(f"[{src}][MGMT-HUB] {label}: deferred {cmd!r} GAVE UP after "
              f"{horizon_s:.0f}s — 状態持越しの可能性 (M6 残留ケース)")
        try:
            if cmd == "usinewgame":
                _DLPONDER_STATE.pending_ttl_drop_usinewgame += 1
            else:
                _DLPONDER_STATE.pending_ttl_drop_gameover += 1
        except Exception as _e:
            _flog(f"[ignored] _mgmt_deferred_send/_run: {_e!r}")

    _spawn(f'mgmt-{label}', _run)


def _mgmt_send_locked(eng, lock, cmd, label, src):
    if not _eng_alive(eng):
        return
    if lock.acquire(timeout=5.0):
        try:
            eng.send(cmd)
        finally:
            lock.release()
        return
    _flog(f"[{src}][MGMT-HUB] {label}_lock acquire timeout (5s) — "
          "stop 送信で保持者 fetch をアンブロックして再試行")
    try:
        eng.send("stop")
    except Exception as _fe:
        _flog(f"[ignored] {src} MGMT-HUB {label} stop: {_fe}")
    if lock.acquire(timeout=3.0):
        try:
            eng.send(cmd)
        finally:
            lock.release()
        return
    _mgmt_deferred_send(eng, lock, cmd, label, src, _MGMT_GEN[0])


def _locked_usinewgame(lock, eng, label: str) -> None:
    _mgmt_send_locked(eng, lock, "usinewgame", label, "usinewgame")


_usinewgame_last_t = [0.0]

def _handle_usinewgame(ctx, line):
    _now_ung = time.perf_counter()
    if _now_ung - _usinewgame_last_t[0] < 7.0 and _usinewgame_last_t[0] > 0:
        _flog("[P6-6] usinewgame: duplicate within %.1fs — skipping heavyweight re-init"
              % (_now_ung - _usinewgame_last_t[0]))
        return
    _usinewgame_last_t[0] = _now_ung
    _MGMT_GEN[0] += 1
    _zenrei_live_reset()
    try:
        _time_dyn.ta_disagree_nudge = 1.0
    except Exception as _e:
        _flog(f"[ignored] _handle_usinewgame: {_e!r}")
    _diag_reset()
    _teardown_game(ctx, "usinewgame")
    _locked_usinewgame(ctx.prefetch.dl_1_lock, ctx.dl_1, "dl_1")
    _dl_apply_pv_mate_threads(ctx, "usinewgame")
    ctx._pvmate_pending = None
    _wsl_restore = []
    for _eng_attr_r in ("nnue_1",):
        _eng_r = getattr(ctx, _eng_attr_r, None)
        if (_eng_alive(_eng_r)
                and getattr(_eng_r, "_bat_path", None) is not None):
            _orig_h = getattr(_eng_r, "_dyn_hash_original", None)
            if _orig_h is not None and _orig_h > 1:
                _wsl_restore.append((_eng_attr_r, _eng_r, _orig_h))
    if _wsl_restore:
        _wr_results = {}
        def _wsl_restore_one(_attr, _e, _o):
            try:
                _e.setoption("USI_Hash", _o)
                _e.send("isready")
                _e.flush_until_ready(timeout=30.0)
                _flog(f"[WSL-HASH-RESTORE] {_attr} Hash 1→{_o}MB (game start, isready committed)")
                _e._dyn_hash_last = _o
                _e._dyn_hash_avail0 = None
                _wr_results[_attr] = True
            except (KeyboardInterrupt, SystemExit):
                raise
            except Exception:
                _flog(f"[G-06][WSL-HASH-RESTORE] {_attr} FAILED (Hash stays 1MB):\n"
                      + _safe_format_exc().strip())
                _wr_results[_attr] = False
        if len(_wsl_restore) > 1:
            _wr_threads = []
            for _wr_attr, _wr_eng, _wr_orig in _wsl_restore:
                _t = _spawn(f'wsl-restore-{_wr_attr}', _wsl_restore_one, _wr_attr, _wr_eng, _wr_orig, start_now=False)
                _t.start()
                _wr_threads.append(_t)
            for _t in _wr_threads:
                _t.join(timeout=30.0)
            for _wr_k, _wr_ok in _wr_results.items():
                if not _wr_ok:
                    _flog(f"[WSL-HASH-RESTORE] {_wr_k} は Hash 1MB のまま — 弱化/draw の温床")
        else:
            _wsl_restore_one(*_wsl_restore[0])
    _wsl_did_nnue_1 = any(_e is ctx.nnue_1 for (_a, _e, _o) in _wsl_restore)
    _wsl_nnue_1_orig = next((_o for (_a, _e, _o) in _wsl_restore if _e is ctx.nnue_1), None)
    _hdr_lock = _NNUE_RESTART_LOCKS.get("nnue_1")
    if ctx.nnue_health.hash_degraded and _eng_alive(ctx.nnue_1) and not _wsl_did_nnue_1:
        if _hdr_lock and _hdr_lock.acquire(blocking=False):
            try:
                _hdr_orig = ctx.nnue_health.hash_original
                ctx.nnue_1.setoption("USI_Hash", _hdr_orig)
                ctx.nnue_1.send("isready")
                _hdr_ok = ctx.nnue_1.flush_until_ready(timeout=30.0)
                if _hdr_ok:
                    ctx.nnue_1._dyn_hash_last = _hdr_orig
                    ctx.nnue_1._dyn_hash_avail0 = None
                    ctx.nnue_health.hash_degraded = False
                    ctx.nnue_health.hash_original = 0
                    _flog(f"[HASH-DEGRADE-RESTORE] nnue_1 Hash restored to {_hdr_orig}MB")
                else:
                    _flog("[HASH-DEGRADE-DEFER] flush failed — flags maintained for next usinewgame")
            except (KeyboardInterrupt, SystemExit):
                raise
            except Exception:
                _flog(f"[HASH-DEGRADE-RESTORE] nnue_1 Hash restore to {_hdr_orig}MB FAILED "
                      f"(memory still tight); keeping degraded Hash:\n"
                      + _safe_format_exc().strip())
            finally:
                _hdr_lock.release()
        else:
            _flog("[HASH-DEGRADE-DEFER] nnue_1 restart lock held — deferring to next usinewgame")
    elif ctx.nnue_health.hash_degraded and _wsl_did_nnue_1:
        ctx.nnue_1._dyn_hash_last = _wsl_nnue_1_orig
        ctx.nnue_health.hash_degraded = False
        ctx.nnue_health.hash_original = 0
        _flog("[HASH-DEGRADE-RESTORE] WSL already restored nnue_1 this tick — flags cleared, isready skipped")
    if ctx.nnue_1._alive:
        if not ctx.nnue_1.flush_with_stop(timeout=5.0):
            _flog("[STALE-GUARD] usinewgame: nnue_1 が局頭で無応答 "
                  "(前局の stale bestmove 残留の疑い) — 再起動して健全化")
            _restart_nnue_1(ctx, "usinewgame-stale")
    ctx.nnue_1.send("usinewgame")
    if ctx.nnue_1._alive:
        if not ctx.nnue_1.flush_until_ready(timeout=10.0):
            _flog("[STALE-GUARD] usinewgame: nnue_1 が usinewgame 後の "
                  "readyok で無応答 — 再起動して健全化")
            _restart_nnue_1(ctx, "usinewgame-post-flush")
    _ms_async_launched = False
    if ctx._zyfamate:
        _zf_caps = "solve" + ("+tsumero" if ctx._zyfamate_has_tsumero else "") + ("+tesuki" if ctx._zyfamate_has_tesuki else "")
        _zf_mode = "serve+one-shot" if _zyfamate_has_serve else "one-shot CLI"
        _flog(f"[{'ZYFAMATE' if ctx._zyfamate_has_tsumero and ctx._zyfamate_has_tesuki else 'CSA-MATE'}] "
              f"ready ({_zf_mode}, {_zf_caps}): {_mate_solver_path}")
        _zf_serve_warm(ctx.cfg.mate_solver_path)
    elif ctx.mate_solver is not None:
        if not ctx.mate_solver._alive:
            _ms_eng = ctx.mate_solver
            ctx.mate_solver = None
            def _bg_ms(_eng=_ms_eng, _ctx=ctx):
                _ms_lock = _CHILD_RESTART_LOCKS.get("mate_solver")
                if _ms_lock and not _ms_lock.acquire(blocking=False):
                    _flog("[MATE-SOLVER] lock held by another path — skipping async start")
                    return
                try:
                    _eng.start()
                    _eng.initialize(_mate_solver_opts)
                    _ms_result = _eng.wait_for("readyok", timeout=30)
                    if _ms_result is None:
                        _flog("ctx.mate_solver: async start readyok timeout — disabling")
                        _revive_register(_ctx, "mate_solver", "mate_solver",
                                         _eng, _mate_solver_opts, 30)
                        return
                    _eng.send("usinewgame")
                    _ctx.mate_solver = _eng
                    _flog(
                        f"ctx.mate_solver started (async): "
                        f"path={_ctx.cfg.mate_solver_path}  "
                        f"Hash={_ctx.cfg.mate_solver_hash}MB  "
                        f"Threads={_ctx.cfg.mate_solver_threads}")
                except Exception as _e:
                    _flog(f"ctx.mate_solver: async start failed: {_e} — disabling")
                    _revive_register(_ctx, "mate_solver", "mate_solver",
                                     _eng, _mate_solver_opts, 30)
                finally:
                    if _ms_lock:
                        try:
                            _ms_lock.release()
                        except RuntimeError as _e:
                            _flog(f"[ignored] _handle_usinewgame/_bg_ms: {_e!r}")
            _spawn('mate-solver-async-start', _bg_ms)
            _ms_async_launched = True
        else:
            ctx.mate_solver.send("usinewgame")
    _cr_rl = getattr(ctx, "_revive_lock", None)
    if _cr_rl:
        _cr_rl.acquire()
    try:
        _cr_slots = getattr(ctx, "revive", None)
        if _cr_slots:
            for _cr_name, _cr_slot in list(_cr_slots.items()):
                _cr_slot.attempts = 0
                _cr_slot.next_ok_s = 0.0
                _cr_slot.in_progress = False
            _flog(f"[CLEANROOM-REVIVE] revive slots re-armed for new game: "
                  f"{list(_cr_slots.keys())}")
    finally:
        if _cr_rl:
            try:
                _cr_rl.release()
            except RuntimeError as _e:
                _flog(f"[ignored] _handle_usinewgame: {_e!r}")
    for _cr_dl in ("dl_1",):
        _cr_eng = getattr(ctx, _cr_dl, None)
        if _cr_eng is not None and not _cr_eng._alive:
            _restart_child_async(ctx, _cr_dl, "usinewgame-revive")
    if ctx.mate_solver is None and _cr_slots and "mate_solver" in _cr_slots and not _ms_async_launched:
        _revive_kick()
    if ctx._passthru_mode:
        if _passthru_should_enter(ctx):
            _flog("[PASSTHRU] death markers still in window — staying in passthru mode")
        else:
            ctx._passthru_mode = False
            _flog("[PASSTHRU] death markers expired — returning to normal council mode")
    global _usi_session_active, _GO_RECV_GEN, _BM_SENT_GEN, _STOP_REARM
    _usi_session_active = True
    _GO_RECV_GEN = 0
    _BM_SENT_GEN = 0
    _STOP_REARM = False
    ctx.time_aggression.reset_to_static()
    ctx.game_meta["dlp_mode"] = str(_DLPONDER_STATE.mode)
    ctx.game_meta["dlp_diff"] = _dlp_game_diff()
    if ctx.game_log:
        _write_game_stats(ctx.game_log, ctx.game_meta, cfg=ctx.cfg)
        _usi_game_sfen_flush(ctx, "usinewgame")
    if not _tuning_mode:
        _dlponder_save_state()
    _dlp_snapshot_for_diff()
    ctx.reset_game()

    _flog("usinewgame: game state reset")
    _live_stats_new_game(ctx, getattr(ctx, "game_meta", None))
    if _book_enabled:
        _book_begin_game(ctx, turn=ctx.book_state.turn_hint)
    ctx.book2_state.reset()
    if _book_enabled:
        _book2_start_resident(ctx)
    for _dl_eng in (ctx.dl_1,):
        if _dl_eng is not None:
            _dl_eng._last_sp_sent = None
    _assert_sp_consistency(ctx, "usinewgame")


def _sync_sp_setoption(ctx, clock, label):
    if ctx.cfg.sp_min_eff_s < 0.0:
        return
    _eff = clock.eff_s if clock is not None else 0.0
    _val = _bstr(_eff >= ctx.cfg.sp_min_eff_s)
    if _val != _sp_last_sent(ctx.nnue_1,
                             default=_nnue_1_opts.get("Stochastic_Ponder", "true")):
        ctx.nnue_1.setoption("Stochastic_Ponder", _val)
        _nnue_1_opts["Stochastic_Ponder"] = _val
        _dlog(f"go ponder({label}): nnue_1 Stochastic_Ponder → {_val} (eff_s={_eff:.2f}s)")
    else:
        _dlog(f"go ponder({label}): nnue_1 Stochastic_Ponder={_val} (no change, eff_s={_eff:.2f}s)")

def _handle_position(ctx, line):
    _set_current_position(ctx, line)

def _wire_ponder_live_cb(ctx):
    if not _LIVE._ready():
        return
    _pos = ctx.current_position
    try:
        _pb = _board_for_position(_pos) if _pos else None
    except Exception:
        _pb = None
    _feed = _LiveFeed(_pos, _pb, mode="ponder", source="nnue_ponder")

    def _cb(ln):
        _sc = ln.score_cp
        if _sc is None and ln.mate is not None:
            _sc = _mate_sign_score(ln.mate)
        _pv = ln.pv.split() if ln.pv else None
        _feed.on_nnue(_pv, _sc)
    ctx.nnue_1._live_info_cb = _cb
    _LIVE._live_register(ctx.nnue_1)

    if _eng_alive(ctx.dl_1):
        ctx.dl_1._live_info_cb = _make_dl1_multipv_cb(ctx, _pos)
        _LIVE._live_register(ctx.dl_1)

def _ps_begin_ponder(ctx, line, label):
    _has_time = any(_k in line.split()
                    for _k in ("btime", "wtime", "byoyomi", "movetime"))
    ctx.ps.ponder_line = line if _has_time else (ctx.ps.go_line or line)
    ctx.ps.position = ctx.current_position
    _pb = _get_tracking_board(ctx)
    ctx.ps.ponder_board_key = _pb._board_key() if _pb is not None else None
    _ps_transition(ctx, PsPhase.PONDERING, f"go-ponder/{label}")
    move_count = _count_moves(ctx.current_position)
    _assert_turn_integrity(ctx.current_position, f"go_ponder/{label}", move_count)
    _dlog(f"[DBG-GP] go ponder saved ({label}): ply={move_count} "
          f"line={line!r} has_clock={_has_time}")
    clock, _, _ = _parse_go_clock_base(ctx.ps.ponder_line, move_count, cfg=ctx.cfg)
    clock_opp, _, _ = _parse_go_clock_base(ctx.ps.ponder_line, move_count - 1, cfg=ctx.cfg)
    ctx.ps.ponder_clock = clock
    ctx.ps.ponder_clock_opp = clock_opp
    gp = _calc_game_phase(ctx.current_position, cfg=ctx.cfg)
    handover = _get_handover_game_phase(clock.eff_s if clock is not None else None,
                                        cfg=ctx.cfg)
    ctx.ps.handover_game_phase = handover
    return move_count, clock, clock_opp, gp, handover


def _gp_gates(ctx):
    if not _early_ponder:
        _dlog("go ponder ignored (EarlyPonder=false)")
        return False
    if _nnue_1_opts.get("USI_Ponder", "true") == "false":
        _dlog("go ponder ignored (USI_Ponder=false)")
        return False
    ctx.nnue_1._live_info_cb = None
    if ctx.dl_1 is not None:
        ctx.dl_1._live_info_cb = None
    _gen_new_thinking("go-ponder")
    return True




def _gp_normal_branch(ctx, line):
    if (ctx.ps.phase in _PS_PHASE_ACTIVE
            and "nnue_1" in ctx.ps.pending_bestmove and ctx.nnue_1._alive):
        _flog("go ponder received while ponder already active — stopping previous ponder first")
        _ov_eff_s = ctx.ps.ponder_clock.eff_s if ctx.ps.ponder_clock else 5.0
        _ov_timeout = _clamp(_ov_eff_s * 0.5 + _move_overhead_s, _move_overhead_s, _ov_eff_s)
        _settle_debts(ctx, ["nnue_1"], reason="gp-overlap",
                      transition=True, nnue_timeout=_ov_timeout, flush_after=True)
    if not ctx.nnue_1._alive:
        _flog("go ponder: nnue_1 killed by overlap drain")
        ctx.prefetch.cancel()
        return
    (move_count, _go_ponder_clock, _go_ponder_clock_opp,
     _cur_game_phase, _handover_game_phase) = _ps_begin_ponder(ctx, line, "main")
    use_dl     = ctx.dl_1._alive and (_cur_game_phase < _handover_game_phase)

    if ctx.ps.nnue1_dirty and ctx.nnue_1._alive:
        _to = 3.0
        if ctx.nnue_1.flush_until_ready(timeout=_to, max_stale_lines=100):
            ctx.ps.nnue1_dirty = False
            _flog("[SP-DIRTY] nnue_1 resynced before go ponder")
        else:
            _flog("[SP-DIRTY] resync failed — restarting nnue_1 before go ponder")
            _restart_nnue_1(ctx, "sp-dirty-goponder")
            ctx.ps.nnue1_dirty = False

    if not ctx.nnue_1._alive:
        _flog("go ponder: ctx.nnue_1 not alive — skipping ponder")
        _restart_nnue_1(ctx, "go-ponder-revive", async_launch=True)
        ctx.prefetch.cancel()
        _ps_transition(ctx, PsPhase.IDLE, "gp-nnue-dead")
    elif ctx.cfg.mate_score_ponder_skip and ctx.game_progress.last_nnue_score_cp >= _MATE_CP:
        _flog(
            f"go ponder: mate score ({ctx.game_progress.last_nnue_score_cp}cp >= 30000) "
            f"— skipping ctx.nnue_1 ponder to avoid relay timeout on ponderhit "
            f"(stop emergency bestmove armed)"
        )
        _ps_transition(ctx, PsPhase.MATE_SKIP, "gp-mate-skip")
    elif (not ctx.cfg.mate_score_ponder_skip) and ctx.game_progress.last_nnue_score_cp >= _MATE_CP:
        _flog(
            f"go ponder: mate score ({ctx.game_progress.last_nnue_score_cp}cp >= 30000) "
            f"— forwarding to nnue_1 (Mate_Score_Ponder_Skip=false)"
        )
        ctx.nnue_1.send(ctx.current_position)
        ctx.ps.tree_invalid = False
        _sync_sp_setoption(ctx, _go_ponder_clock_opp, "mate-b")
        ctx.nnue_1.send(line)
        _ps_debt_add(ctx, "nnue_1", "go-ponder/mate-b")
        _wire_ponder_live_cb(ctx)
    else:
        if ctx.ps.tree_invalid:
            _flog("go ponder: tree_invalid=True (prev ponderhit was stale recovery)"
                  " — position resent, clearing flag")
        ctx.nnue_1.send(ctx.current_position)
        ctx.ps.tree_invalid  = False

        _sync_sp_setoption(ctx, _go_ponder_clock_opp, "ponder")
        ctx.nnue_1.send(line)
        _ps_debt_add(ctx, "nnue_1", "go-ponder")
        _wire_ponder_live_cb(ctx)


        if not ctx.nnue_1._alive:
            _flog("go ponder: ctx.nnue_1 died on send — cancelling ctx.prefetch")
            ctx.prefetch.cancel()
        elif use_dl:
            _prefetch_nodes_eff = ctx.cfg.dl_prefetch_nodes
            _prefetch_timeout_eff = _time_dyn.dl_time_fallback_ms / 1000.0
            if ctx.cfg.gpu_ponder_enable:
                _go_ponder_eff_for_pf = _go_ponder_clock_opp.eff_s if _go_ponder_clock_opp is not None else 0.0
                _prefetch_nodes_eff = min(
                    ctx.cfg.gpu_ponder_nodes_max,
                    max(ctx.cfg.dl_prefetch_nodes,
                        int(_go_ponder_eff_for_pf * ctx.cfg.gpu_ponder_nodes_per_eff_s)))
                _prefetch_timeout_eff = max(
                    _time_dyn.dl_time_fallback_ms / 1000.0,
                    min(_go_ponder_eff_for_pf * 3.0 + 5.0, 120.0))
                _dlog(lambda: f"[GPU-Ponder] prefetch nodes={_prefetch_nodes_eff} "
                              f"timeout={_prefetch_timeout_eff:.1f}s "
                              f"(eff_s={_go_ponder_eff_for_pf:.1f} × {ctx.cfg.gpu_ponder_nodes_per_eff_s} "
                              f"capped {ctx.cfg.gpu_ponder_nodes_max})")
            if not _dl_ponder_enable:
                ctx.prefetch.start(ctx.dl_1, ctx.current_position,
                               _params[_K_POLICY_MOVES], _prefetch_nodes_eff,
                               timeout=_prefetch_timeout_eff)

            _dl_ponder_dispatch(ctx, line, label="gui-go-ponder")
        else:
            ctx.prefetch.cancel()

    _mate_ponder_dispatch(ctx, _go_ponder_clock_opp, _cur_game_phase, label="gui-go-ponder")

    if not ctx.dl_1._alive:
        _restart_child_async(ctx, "dl_1", "go-ponder-revive")





def _handle_go_ponder(ctx, line):
    if not _gp_gates(ctx):
        return
    _gp_normal_branch(ctx, line)


def _engine_lifecycle_restart(eng, opts, caller, readyok_timeout=30,
                              quit_first=False, post_flush=True):
    try:
        eng.quit()
    except Exception as _e:
        _flog(f"[ignored] _engine_lifecycle_restart: {_e!r}")
    eng.start()
    eng.initialize(opts)
    result = eng.wait_for("readyok", timeout=readyok_timeout)
    if result is None:
        if not eng._alive:
            _flog(f"{caller}: {eng.name} restart failed — process died before readyok")
        else:
            _flog(f"{caller}: {eng.name} restart readyok timeout")
        return False
    eng.send("usinewgame")
    if post_flush:
        _prefetch_flush(eng, label=f"{eng.name}-post-restart", eff_s=None)
    return True


_DL_SLOTS_SET = frozenset(("dl_1",))
_PASSTHRU_WINDOW_S   = 300.0
_PASSTHRU_THRESHOLD  = 2


def _record_dl_death(ctx, eng, slot, caller):
    if slot not in _DL_SLOTS_SET:
        return
    _gen = getattr(eng, "_start_gen", 0)
    _mark = getattr(eng, "_death_mark_gen", -1)
    if _mark == _gen:
        return
    eng._death_mark_gen = _gen
    _now = time.monotonic()
    ctx.dl_death_marks.append(_now)
    _flog(f"[DL-DEATH-MARK] {slot} death recorded by {caller} "
          f"(gen={_gen}, total={len(ctx.dl_death_marks)})")


def _passthru_should_enter(ctx):
    if _RUN_MODE is not RunMode.CSA:
        return False
    if _ACTIVE_BESTMOVE_SINK is None:
        return False
    _now = time.monotonic()
    _cutoff = _now - _PASSTHRU_WINDOW_S
    while ctx.dl_death_marks and ctx.dl_death_marks[0] < _cutoff:
        ctx.dl_death_marks.popleft()
    return len(ctx.dl_death_marks) >= _PASSTHRU_THRESHOLD


_CHILD_RESTART_SLOTS = {
    "dl_1":        {"opts": "_dl_1_opts",        "timeout": 30, "flush": True},
    "mate_solver": {"opts": "_mate_solver_opts", "timeout": 30, "flush": False},
}

_CHILD_RESTART_LOCKS = {_s: threading.Lock() for _s in _CHILD_RESTART_SLOTS}

_CHILD_ENG_LOCK_MAP = {
    "dl_1":        ("prefetch", "dl_1_lock"),
    "mate_solver": (None, "mate_solver_lock"),
}

_DL_RESTART_RAM_FLOOR_MB = 2048


def _dl_restart_ram_critical():
    try:
        _av = _mon_avail_mb
        return _av is not None and _av < _DL_RESTART_RAM_FLOOR_MB
    except Exception:
        return False


def _restart_child_async(ctx, slot, caller):
    eng = getattr(ctx, slot, None)
    if eng is None or _eng_alive(eng):
        return
    _ft = getattr(eng, "_restart_fail_t", None)
    if _ft is not None and time.perf_counter() - _ft < 45.0:
        return
    def _bg():
        try:
            _restart_child(ctx, slot, caller)
        except Exception as _be:
            _flog(f"{caller}: ctx.{slot} async revive raised (ignored): {_be!r}")
    _spawn(f'child-revive-{slot}', _bg)
    _flog(f"{caller}: ctx.{slot} dead — async revive launched (相手番中に回復)")


def _restart_child(ctx, slot, caller, readyok_timeout=None):
    _s = _CHILD_RESTART_SLOTS[slot]
    opts = globals()[_s["opts"]]
    eng = getattr(ctx, slot)
    _to = _s["timeout"] if readyok_timeout is None else readyok_timeout
    if _to <= 0:
        _flog(f"{caller}: ctx.{slot} restart skipped (clock-tight) — continuing without")
        return False
    if readyok_timeout is not None:
        _rc_fail_t = getattr(eng, "_restart_fail_t", None)
        if _rc_fail_t is not None:
            _rc_since_fail = time.perf_counter() - _rc_fail_t
            if _rc_since_fail < 45.0:
                _flog(f"{caller}: ctx.{slot} restart skipped "
                      f"(last failure {_rc_since_fail:.0f}s ago) — continuing without")
                return False
    _clk = _CHILD_RESTART_LOCKS[slot]
    if not _clk.acquire(blocking=False):
        _flog(f"{caller}: ctx.{slot} restart already in progress (another thread) "
              "— skipping duplicate")
        return False
    _eng_lock = None
    _eng_lock_held = False
    try:
        _eli = _CHILD_ENG_LOCK_MAP.get(slot)
        if _eli:
            _eo, _ea = _eli
            _eh = ctx if _eo is None else getattr(ctx, _eo, None)
            if _eh:
                _eng_lock = getattr(_eh, _ea, None)
        if _eng_lock is not None:
            if not _eng_lock.acquire(timeout=2.0):
                _flog("[RESTART-CHILD] %s eng_lock timeout (2.0s) "
                      "— deferring" % slot)
                return False
            _eng_lock_held = True
        _record_dl_death(ctx, eng, slot, caller)
        if _eng_alive(eng):
            _flog(f"{caller}: ctx.{slot} already alive (revived concurrently) — skip")
            return True
        _flog(f"{caller}: ctx.{slot} not alive — attempting restart "
              f"(readyok_timeout={_to:.1f}s)")
        try:
            ok = _engine_lifecycle_restart(eng, opts, caller,
                                           readyok_timeout=_to,
                                           post_flush=_s["flush"])
            if ok:
                _flog(f"{caller}: ctx.{slot} restarted OK")
            else:
                _flog(f"{caller}: ctx.{slot} restart failed — continuing without")
                eng._restart_fail_t = time.perf_counter()
                if slot == "mate_solver":
                    _revive_register(ctx, "mate_solver", "mate_solver",
                                     eng, _mate_solver_opts, 30)
                    ctx.mate_solver = None
            return ok
        except Exception as e:
            _flog(f"{caller}: ctx.{slot} restart failed (non-fatal): {e}")
            try:
                eng._restart_fail_t = time.perf_counter()
            except Exception as _e:
                _flog(f"[ignored] _restart_child: {_e!r}")
            if slot == "mate_solver":
                _revive_register(ctx, "mate_solver", "mate_solver",
                                 eng, _mate_solver_opts, 30)
                ctx.mate_solver = None
            return False
    finally:
        if _eng_lock_held:
            _eng_lock.release()
        _clk.release()

def _compute_go_time_dynamics(
    *,
    time_aggression_base,
    score_cp,
    our_remaining_ms,
    guaranteed_ms,
    game_phase,
    time_aggression_k,
    time_aggression_time_floor,
    time_aggression_game_phase_lo,
    time_aggression_game_phase_hi,
    time_aggression_game_phase_gamma,
    time_aggression_score_start_cp,
    time_aggression_score_span_cp,
    time_aggression_score_floor,
    time_aggression_dl_resolved,
    time_aggression_nnue_resolved,
    time_aggression_rescue_resolved,
    lerp_dl_ratio,
    lerp_dl_max_ms,
    dl_time_ratio_user_set,
    dl_time_max_ms_user_set,
    dl_time_fallback_user_set,
    prev_score_cp=None,
    now_prev_score_cp=None,
    time_aggression_fall_gain=0.05,
    time_aggression_fall_floor=0.572,
    time_aggression_fall_ceil=1.708,
    stable_winner_streak=0,
    time_aggression_stable_reduction_min=0.85,
    time_aggression_stable_streak_min=3,
    is_ponder=False,
    time_aggression_ponder_bonus=1.0,
    trivial_cap=False,
    time_aggression_trivial_cap=1.0,
    time_aggression_decay_floor=0.0,
    last_momentum=0.0,
    last_sharpness=None,
    time_aggression_momentum_ext_gain=0.25,
    time_aggression_momentum_acc_gain=0.10,
    time_aggression_sharpness_base=0.85,
    time_aggression_sharpness_range=0.30,
    last_dl_cont_changed=False,
    time_aggression_dl_cont_change_ext=0.15,
):
    base = time_aggression_base

    if guaranteed_ms > 0:
        _denom = our_remaining_ms + time_aggression_k * guaranteed_ms
        margin = our_remaining_ms / _denom if _denom > 1.0 else 0.0
    else:
        margin = 1.0
    time_norm = time_aggression_time_floor + (1.0 - time_aggression_time_floor) * margin

    game_phase_prog = game_phase / 1.5
    if game_phase_prog < 0.0:
        game_phase_prog = 0.0
    elif game_phase_prog > 1.0:
        game_phase_prog = 1.0
    _gamma = time_aggression_game_phase_gamma if time_aggression_game_phase_gamma > 0.05 else 0.05
    game_phase_fac = time_aggression_game_phase_hi + (time_aggression_game_phase_lo - time_aggression_game_phase_hi) * (game_phase_prog ** _gamma)

    if score_cp > time_aggression_score_start_cp and time_aggression_score_span_cp > 0:
        sr = (score_cp - time_aggression_score_start_cp) / time_aggression_score_span_cp
        sr = sr if sr < 1.0 else 1.0
        score_fac = 1.0 - sr * (1.0 - time_aggression_score_floor)
    else:
        score_fac = 1.0

    time_norm = time_norm if time_norm > _TA_FAC_FLOOR else _TA_FAC_FLOOR
    game_phase_fac    = game_phase_fac    if game_phase_fac    > _TA_FAC_FLOOR else _TA_FAC_FLOOR
    score_fac = score_fac if score_fac > _TA_FAC_FLOOR else _TA_FAC_FLOOR

    if (prev_score_cp is not None and now_prev_score_cp is not None
            and time_aggression_fall_gain != 0.0):
        _drop = float(prev_score_cp) - float(now_prev_score_cp)
        falling_fac = 1.0 + time_aggression_fall_gain * (_drop / 100.0)
        falling_fac = (time_aggression_fall_floor if falling_fac < time_aggression_fall_floor
                       else time_aggression_fall_ceil if falling_fac > time_aggression_fall_ceil else falling_fac)
    else:
        falling_fac = 1.0

    if (stable_winner_streak >= time_aggression_stable_streak_min and time_aggression_stable_reduction_min < 1.0):
        _ramp = (stable_winner_streak - time_aggression_stable_streak_min + 1) / 6.0
        _ramp = _ramp if _ramp < 1.0 else 1.0
        stability_reduction = 1.0 + (time_aggression_stable_reduction_min - 1.0) * _ramp
        if stability_reduction < time_aggression_stable_reduction_min:
            stability_reduction = time_aggression_stable_reduction_min
    else:
        stability_reduction = 1.0

    _falling_dec = falling_fac if falling_fac < 1.0 else 1.0
    _falling_ext = falling_fac if falling_fac > 1.0 else 1.0
    _decay = score_fac * stability_reduction * _falling_dec
    if trivial_cap and time_aggression_trivial_cap != 1.0:
        _decay *= time_aggression_trivial_cap
    if _decay < time_aggression_decay_floor:
        _decay = time_aggression_decay_floor
    _momentum_ext = 1.0
    if last_momentum < 0.0:
        _momentum_ext = 1.0 + (-last_momentum) * time_aggression_momentum_ext_gain
    elif last_momentum > 0.0:
        _momentum_ext = 1.0 - last_momentum * time_aggression_momentum_acc_gain

    _sharpness_fac = 1.0
    if last_sharpness is not None:
        _sharpness_fac = time_aggression_sharpness_base + time_aggression_sharpness_range * last_sharpness

    _cont_ext = 1.0
    if last_dl_cont_changed:
        _cont_ext = 1.0 + time_aggression_dl_cont_change_ext

    time_aggression_merged = base * time_norm * game_phase_fac * _falling_ext * _momentum_ext * _sharpness_fac * _cont_ext * _decay

    if is_ponder and time_aggression_ponder_bonus != 1.0:
        time_aggression_merged *= time_aggression_ponder_bonus

    if time_aggression_merged < _TA_FAC_FLOOR:
        time_aggression_merged = _TA_FAC_FLOOR
    elif time_aggression_merged > _TA_CEIL:
        time_aggression_merged = _TA_CEIL

    time_aggression_dl_eff     = min(time_aggression_dl_resolved,     time_aggression_merged)
    time_aggression_nnue_eff   = min(time_aggression_nnue_resolved,   time_aggression_merged)
    time_aggression_rescue_eff = min(time_aggression_rescue_resolved, time_aggression_merged)

    gain = _time_aggression_base_gain(base)
    _lerp_dl_ratio_g  = (lerp_dl_ratio[0],  lerp_dl_ratio[1]  * gain)
    _lerp_dl_max_ms_g = (lerp_dl_max_ms[0], lerp_dl_max_ms[1] * gain)

    dl_ratio  = None if dl_time_ratio_user_set  else _lerp(*_lerp_dl_ratio_g,  time_aggression_dl_eff)
    dl_max_ms = None if dl_time_max_ms_user_set else _lerp(*_lerp_dl_max_ms_g, time_aggression_dl_eff)

    if dl_max_ms is None:
        dl_fallback = None
    else:
        dl_fallback = None if dl_time_fallback_user_set else dl_max_ms * 1.1


    return GoTimeDynamics(
        time_aggression        = time_aggression_merged,
        time_aggression_dl     = time_aggression_dl_eff,
        time_aggression_nnue   = time_aggression_nnue_eff,
        time_aggression_rescue = time_aggression_rescue_eff,
        dl_time_ratio          = dl_ratio,
        dl_time_max_ms         = dl_max_ms,
        dl_time_fallback_ms    = dl_fallback,
    )


def _apply_time_dynamics(ctx, line, move_count, label="go", clock_base=None):
    _score_cp_cur = ctx.game_progress.last_nnue_score_cp
    if clock_base is not None:
        _our_remaining_ms = clock_base.remaining_ms
        _byo_ms = clock_base.byo_ms
        _inc_ms_side = clock_base.inc_ms
    else:
        _our_remaining_ms, _byo_ms, _inc_ms_side = _extract_clock_sides(line, move_count)
    if _byo_ms > 0:
        _guaranteed_ms = _byo_ms
    elif _inc_ms_side > 0:
        _guaranteed_ms = _inc_ms_side
    elif _our_remaining_ms > 0:
        _rm = _calc_remaining_moves(move_count, _our_remaining_ms, cfg=ctx.cfg)
        _guaranteed_ms = _our_remaining_ms / max(1, _rm)
    else:
        _guaranteed_ms = 0.0

    _game_phase_for_ta = _calc_game_phase(ctx.current_position, cfg=ctx.cfg,
                                          child_agreement=ctx.game_progress.last_child_agreement)
    _game_phase_for_ta_folded = _game_phase_for_phase_council(
        _game_phase_for_ta, ctx.cfg.council_nyugyoku_dl_restore)
    _time_aggression_prev = _time_dyn.time_aggression
    _cfg_go = ctx.cfg
    _td = _compute_go_time_dynamics(
        time_aggression_base                   = _cfg_go.time_aggression_base,
        score_cp                               = _score_cp_cur,
        our_remaining_ms                       = _our_remaining_ms,
        guaranteed_ms                          = _guaranteed_ms,
        game_phase                             = _game_phase_for_ta_folded,
        time_aggression_k                      = ctx.cfg.time_aggression_margin_k,
        time_aggression_time_floor             = ctx.cfg.time_aggression_margin_floor,
        time_aggression_game_phase_lo          = ctx.cfg.time_aggression_game_phase_lo,
        time_aggression_game_phase_hi          = ctx.cfg.time_aggression_game_phase_hi,
        time_aggression_game_phase_gamma       = ctx.cfg.time_aggression_game_phase_gamma,
        time_aggression_score_start_cp         = ctx.cfg.time_aggression_score_start_cp,
        time_aggression_score_span_cp          = ctx.cfg.time_aggression_score_span_cp,
        time_aggression_score_floor            = ctx.cfg.time_aggression_score_floor,
        time_aggression_dl_resolved            = _resolve_ta(_K_TIME_AGGRESSION_DL,     _cfg_go.time_aggression_base),
        time_aggression_nnue_resolved          = _resolve_ta(_K_TIME_AGGRESSION_NNUE,   _cfg_go.time_aggression_base),
        time_aggression_rescue_resolved        = _resolve_ta(_K_TIME_AGGRESSION_RESCUE, _cfg_go.time_aggression_base),
        lerp_dl_ratio                          = (ctx.cfg.lerp_dl_ratio_lo, ctx.cfg.lerp_dl_ratio_hi),
        lerp_dl_max_ms                         = (ctx.cfg.lerp_dl_max_ms_lo, ctx.cfg.lerp_dl_max_ms_hi),
        dl_time_ratio_user_set                 = _cfg_go.dl_time_ratio_user_set,
        dl_time_max_ms_user_set                = _cfg_go.dl_time_max_ms_user_set,
        dl_time_fallback_user_set              = _cfg_go.dl_time_fallback_user_set,
        prev_score_cp                          = ctx.game_progress.prev_own_score_cp,
        now_prev_score_cp                      = _score_cp_cur,
        stable_winner_streak                   = ctx.game_progress.council_agree_streak,
        trivial_cap                            = (ctx.game_progress.last_nnue_score_cp is not None
                                                  and ctx.game_progress.last_nnue_score_cp >= _MATE_CP
                                                  and ctx.game_progress.last_nnue_mate_ply is not None
                                                  and abs(ctx.game_progress.last_nnue_mate_ply) <= ctx.cfg.trivial_cap_mate_ply_max),
        time_aggression_fall_gain              = ctx.cfg.time_aggression_fall_gain,
        time_aggression_fall_floor             = ctx.cfg.time_aggression_fall_floor,
        time_aggression_fall_ceil              = ctx.cfg.time_aggression_fall_ceil,
        time_aggression_stable_reduction_min   = ctx.cfg.time_aggression_stable_reduction_min,
        time_aggression_stable_streak_min      = ctx.cfg.time_aggression_stable_streak_min,
        time_aggression_ponder_bonus           = ctx.cfg.time_aggression_ponder_bonus,
        time_aggression_trivial_cap            = ctx.cfg.time_aggression_trivial_cap,
        time_aggression_decay_floor            = ctx.cfg.time_aggression_decay_floor,
        last_momentum                          = ctx.game_progress.last_momentum,
        last_sharpness                         = ctx.game_progress.last_sharpness,
        time_aggression_momentum_ext_gain      = ctx.cfg.time_aggression_momentum_ext_gain,
        time_aggression_momentum_acc_gain      = ctx.cfg.time_aggression_momentum_acc_gain,
        time_aggression_sharpness_base         = ctx.cfg.time_aggression_sharpness_base,
        time_aggression_sharpness_range        = ctx.cfg.time_aggression_sharpness_range,
        last_dl_cont_changed                   = ctx.game_progress.last_dl_cont_changed,
        time_aggression_dl_cont_change_ext     = ctx.cfg.time_aggression_dl_cont_change_ext,
    )
    ctx.game_progress.prev_own_score_cp = _score_cp_cur

    _time_dyn.time_aggression = _td.time_aggression
    _time_dyn.time_aggression_dl_dyn = _td.time_aggression_dl
    _time_dyn.time_aggression_nnue_dyn = _td.time_aggression_nnue
    _time_dyn.time_aggression_rescue_dyn = _td.time_aggression_rescue
    ctx.time_aggression.writeback_from_dynamics(_td)
    if abs(_time_dyn.time_aggression - _time_aggression_prev) > 0.001:
        _flog(
            f"time_aggression[{label}]: base={_time_aggression_base:.2f} "
            f"score_cp={_score_cp_cur} remaining={_our_remaining_ms}ms "
            f"guaranteed={_guaranteed_ms:.0f}ms game_phase={_game_phase_for_ta:.3f}"
            f"{'(→' + f'{_game_phase_for_ta_folded:.3f})' if _game_phase_for_ta > 1.0 else ''} "
            f"→ {_time_dyn.time_aggression:.3f}"
        )
    if _td.dl_time_ratio is not None:
        _time_dyn.dl_time_ratio = _td.dl_time_ratio
    if _td.dl_time_max_ms is not None:
        _time_dyn.dl_time_max_ms = _td.dl_time_max_ms
        if _td.dl_time_fallback_ms is not None:
            _time_dyn.dl_time_fallback_ms = _td.dl_time_fallback_ms


def _handle_go(ctx, line):
    if "ponder" not in line.split():
        ctx.ps.last_go_position = ctx.current_position
    _go_tokens = line.split()
    if len(_go_tokens) >= 2 and _go_tokens[1] == "mate":
        if _eng_alive(ctx.mate_solver):
            try:
                ctx.mate_solver.send(ctx.current_position)
                ctx.mate_solver.send(line)
                ctx._mate_go_active = True
                def _forward_mate():
                    try:
                        while True:
                            _out = ctx.mate_solver.readline(timeout=120)
                            if _out is None:
                                break
                            if not _out:
                                continue
                            try:
                                print(_out, flush=True)
                            except OSError as _e:
                                _flog(f"[ignored] _handle_go/_forward_mate: {_e!r}")
                            if _out.startswith(("checkmate", "bestmove")):
                                return
                    except (KeyboardInterrupt, SystemExit, MemoryError):
                        raise
                    except Exception as _fm_exc:
                        _flog(f"[GO-MATE] _forward_mate error: {_fm_exc!r}")
                    try:
                        print("checkmate notimplemented", flush=True)
                    except OSError as _e:
                        _flog(f"[ignored] _handle_go/_forward_mate: {_e!r}")
                    finally:
                        ctx._mate_go_active = False
                _spawn('go-mate-forward', _forward_mate)
                _flog(f"[GO-MATE] forwarded to mate_solver: {line!r}")
                ctx.game_progress.council_agree_streak = 0
                return
            except (KeyboardInterrupt, SystemExit, MemoryError):
                raise
            except Exception as _gme:
                _flog(f"[GO-MATE] forward failed: {_gme!r} — fallback to council go")
        else:
            print("checkmate notimplemented", flush=True)
            _flog("[GO-MATE] mate_solver unavailable — sent 'checkmate notimplemented'")
            return
    _gen_new_thinking("go")
    try:
        _dlponder_bm = _DLPONDER_STATE.bm_ts
        if _dlponder_bm is not None and _ACTIVE_BESTMOVE_SINK is None:
            _dlponder_opp = time.monotonic() - _dlponder_bm
            _DLPONDER_STATE.bm_ts = None
            if 0.2 <= _dlponder_opp <= 600.0:
                _DLPONDER_STATE.opponent_s_ema = _dlponder_ema(_DLPONDER_STATE.opponent_s_ema, _dlponder_opp)
    except Exception as _ie:
        _flog(f"[ignored] _handle_go: {_ie!r}")
    _diag_reset()
    _assert_turn_integrity(ctx.current_position, "go")
    is_infinite = "infinite" in line
    move_count  = _count_moves(ctx.current_position)
    _clock_base, _fischer_cap, _dl_skip = None, False, False
    if not is_infinite:
        _clock_base, _fischer_cap, _dl_skip = _parse_go_clock_base(line, move_count, cfg=ctx.cfg)
    _eff_s_go = _clock_base.eff_s if (_clock_base is not None and _clock_base.eff_s > 0) else 0.0
    if _dl_ponder_enable:
        _t_drain_start = time.perf_counter()
        _harvest_dl_ponders(ctx, ctx.current_position, eff_s=_eff_s_go)
        _stop_dl_ponders(ctx, "go ponder-miss/fresh-go", eff_s=_eff_s_go)
        _drain_elapsed_s = max(0.0, time.perf_counter() - _t_drain_start)
        if (_drain_elapsed_s > 0.05 and _clock_base is not None
                and _clock_base.eff_s > 0):
            _drain_floor_s = max(_clock_base.floor_ms / 1000.0, 0.05)
            _new_eff_s = max(_drain_floor_s, _clock_base.eff_s - _drain_elapsed_s)
            if _new_eff_s < _clock_base.eff_s:
                _flog("[FIX-DRAIN-BUDGET] eff_s %.2f→%.2fs (DL drain %.2fs 控除)"
                      % (_clock_base.eff_s, _new_eff_s, _drain_elapsed_s))
                _clock_base = _clock_base._replace(eff_s=_new_eff_s)
                _eff_s_go = _new_eff_s
    _mate_ponder_cancel(ctx, "go")
    if "nnue_1" in ctx.ps.pending_bestmove:
        _stop_nnue_ponders(ctx, "go fresh-go nnue-drain")
    _opponent_id_observe(ctx, ctx.current_position)
    if not is_infinite:
        ctx.ps.go_line = line

    if not ctx.nnue_1._alive:
        _readyok_to = 60
        _gc_dead = None
        if not is_infinite:
            try:
                _gc_dead, _, _ = _parse_go_clock_base(line, move_count, cfg=ctx.cfg)
                _rem_s = ((_gc_dead.remaining_ms + (_gc_dead.inc_ms or 0)) / 1000.0
                          - _move_overhead_s) if _gc_dead.remaining_ms else 0.0
                _ef = max(0.0, _gc_dead.eff_s or 0.0)
                _readyok_to = _clamp(max(_ef * 2.0, _rem_s * 0.5), _move_overhead_s, 60.0)
            except Exception:
                _readyok_to = 30
        _ok_restart = _restart_nnue_1(ctx, "go", readyok_timeout=_readyok_to)
        if not _ok_restart or not ctx.nnue_1._alive:
            _flog("go: ctx.nnue_1 restart failed — delegating this move to a "
                  "surviving engine (resign avoided)")
            try:
                if _gc_dead is None:
                    _gc_dead, _, _ = _parse_go_clock_base(line, move_count, cfg=ctx.cfg)
                _wv_rem = (_gc_dead.remaining_ms or 0) / 1000.0 - _move_overhead_s
                _wv_eff = max(0.0, _gc_dead.eff_s or 0.0)
                _wv_deadline = _clamp(
                    min(_wv_eff, _wv_rem * 0.1, 20.0),
                    2.0,
                    _wv_rem if _wv_rem > 0 else 9999.0)
            except Exception:
                _wv_deadline = 3.0
            _wait_mv = _wait_revive_nnue_and_move(ctx, caller="go", deadline_s=_wv_deadline)
            if _wait_mv:
                try:
                    _record = _build_move_record({
                        "ply": _count_moves(ctx.current_position),
                        "council_winner": _wait_mv,
                        "nnue_bestmove": _wait_mv,
                        "source": "wait_revive",
                    })
                    _append_move_record(ctx, _record)
                except Exception as _e:
                    _flog(f"[ignored] _handle_go: {_e!r}")
                _safe_bestmove(_wait_mv)
                return
            _emerg_movetime = 3.0
            try:
                _emerg_rem = (_gc_dead.remaining_ms or 0) / 1000.0 - _move_overhead_s if _gc_dead else 30.0
                _emerg_movetime = _clamp(min(3.0, _emerg_rem * 0.5), 0.5, 5.0)
            except Exception as _e:
                _flog(f"[ignored] _handle_go: {_e!r}")
            _emerg = None
            try:
                _emerg = _emergency_move_from_any_engine(ctx, _emerg_movetime)
            except Exception as _ge:
                _flog(f"go: emergency move raised (ignored): {_ge}")
            if _emerg:
                try:
                    _emr = _build_move_record({
                        "ply": _count_moves(ctx.current_position),
                        "council_winner": _emerg,
                        "nnue_bestmove": _emerg,
                        "source": "emergency",
                    })
                    _append_move_record(ctx, _emr)
                except Exception as _emr_e:
                    _flog(f"go: emergency stats write failed (ignored): {_emr_e}")
                _safe_bestmove(_emerg)
                _flog(f"go: nnue_1 dead — EMERGENCY move {_emerg!r} from surviving "
                      f"engine (movetime={_emerg_movetime:.1f}s, resign avoided)")
                return
            _flog("go: no surviving engine and nnue revive failed — resign")
            _safe_bestmove("resign")
            return

    if ctx._passthru_mode or _passthru_should_enter(ctx):
        if not ctx._passthru_mode:
            ctx._passthru_mode = True
            _flog("[PASSTHRU] DL systematic instability detected — entering passthru mode "
                  "(nnue_1 direct, CSA only)")
        ctx.nnue_1.send(ctx.current_position)
        ctx.nnue_1.send(line)
        _pt_go_clock = None
        if not is_infinite and _clock_base is not None:
            _pt_go_clock = _clock_base
        elif not is_infinite:
            _pt_go_clock, _, _ = _parse_go_clock_base(line, move_count, cfg=ctx.cfg)
        _pt_pm, _pt_ni = relay_timed(
            ctx.nnue_1, go_clock=_pt_go_clock,
            intercept_bestmove=(_ACTIVE_BESTMOVE_SINK is not None))
        _safe_bestmove(
            (_pt_ni or {}).get("bestmove", "resign"), None,
            label="passthru", nnue_info=_pt_ni)
        return

    if _clock_base is None:
        _clock_base, _fischer_cap, _dl_skip = _parse_go_clock_base(line, move_count, cfg=ctx.cfg)

    _restart_timeout = None if is_infinite else _restart_child_budget_s(_clock_base)
    if not _dl_skip:
        if not ctx.dl_1._alive:
            _recover(ctx.dl_1, reason=RecoverReason.GO_ENTRY,
                     clock=_clock_base, ctx=ctx)

    ctx.game_progress.book_seed_move   = None
    ctx.game_progress.book_seed_weight = 0.0
    ctx.game_progress.book_seed_trust  = ""
    _book_avail = (_book_enabled and not is_infinite and (
        (_eng_alive(ctx.book)
         and ctx.book_state.active and ctx.book_state.initialized)
        or (_eng_alive(ctx.book2)
            and ctx.book2_state.active and ctx.book2_state.initialized)
        or (ctx.book_state.consec >= ctx.cfg.book2_fire_consec)))
    if _book_avail:
        _book_move, _book_trust = _book_consult(ctx, ctx.current_position)
        if _book_move:
            if _book_trust == _TRUST_ABSOLUTE:
                _safe_bestmove(_book_move, label="book",
                               nnue_info={"score_cp": 0, "depth": 0, "pv": ""})
                _flog(f"[bookloader] bestmove (book) {_book_move!r} "
                      f"ply={move_count} trust={_book_trust} "
                      f"— council/nnue 探索をスキップ")
                book_gp = _calc_game_phase(
                    ctx.current_position, ctx.cfg) if ctx.current_position else None
                book_rec = _build_move_record({
                    "ply": move_count,
                    "council_winner": _book_move,
                    "nnue_bestmove": _book_move,
                    "source": "book",
                    "book_trust": _book_trust,
                    "go_line": line,
                    "game_phase": book_gp,
                    "game_phase_delta": _calc_game_phase_delta(
                        book_gp, ctx.game_progress.last_game_phase),
                })
                try:
                    _append_move_record(ctx, book_rec)
                except Exception as _bre:
                    _flog(f"[ignored] book move record: {_bre}")
                if _LIVE._ready():
                    _LIVE.set_think(book_rec, ctx.current_position, None)
                ctx.game_progress.last_child_agreement = None
                ctx.game_progress.last_nnue_mate_ply = None
                ctx.game_progress.last_game_phase = book_gp if book_gp is not None else ctx.game_progress.last_game_phase
                ctx.game_progress.council_agree_streak = 0
                ctx.game_progress.opponent_id_last_sample = None
                _apply_time_dynamics(ctx, line, move_count, label="book",
                                     clock_base=_clock_base)
                ctx.ps.go_clock = _clock_base
                return
            _book_bias = _book_council_bias_for_trust(_book_trust, ctx.cfg)
            ctx.game_progress.book_seed_move   = _book_move
            ctx.game_progress.book_seed_weight = _book_bias
            ctx.game_progress.book_seed_trust  = _book_trust
            _flog(f"[bookloader] 定跡 seed 注入 move={_book_move!r} "
                  f"trust={_book_trust} weight={_book_bias:.3f} ply={move_count} "
                  f"— council で検討 (劣勢なら council 勝者を採用)")

    if (not ctx._zyfamate and ctx.mate_solver is not None
            and not ctx.mate_solver._alive):
        _restart_child(ctx, "mate_solver", "go", readyok_timeout=_restart_timeout)

    _apply_time_dynamics(ctx, line, move_count, label="go", clock_base=_clock_base)

    _dl_timeout_s = _compute_dl_timeout_s(
        _clock_base, score_cp=ctx.game_progress.last_nnue_score_cp,
        fischer_cap_bound=_fischer_cap, dl_skip=_dl_skip)
    _go_clock_main = _clock_base._replace(dl_timeout_s=_dl_timeout_s)
    ctx.ps.go_clock = _go_clock_main
    _eff_s_go = _go_clock_main.eff_s
    ctx.ps.last_eff_s = _eff_s_go if _eff_s_go and _eff_s_go > 0 else None
    _route_dl_model_for_eff_s(ctx, _eff_s_go)

    dl_timeout = _go_clock_main.dl_timeout_s
    _cur_game_phase      = _calc_game_phase(ctx.current_position, cfg=ctx.cfg)
    _handover_game_phase = _get_handover_game_phase(_eff_s_go, cfg=ctx.cfg)
    ctx.ps.handover_game_phase = _handover_game_phase
    _book_active_now = _book_any_active(ctx)
    _dlog(
        f"nnue handover: ply={move_count} "
        f"cur_game_phase={_cur_game_phase:.3f} handover_game_phase={_handover_game_phase:.3f} "
        f"(eff_s={_eff_s_go:.1f})"
    )

    use_dl, _, _dl_timeout_threshold_s, _ = \
        _lc_dispatch_core(
            is_infinite, ctx.dl_1._alive,
            _cur_game_phase, _handover_game_phase, _book_active_now,
            ctx.cfg)

    if ctx.dl_1._alive and not is_infinite:
        use_dl = True

    if use_dl:
        _run_council_search(ctx, line, move_count, dl_timeout,
                            use_dl,
                            go_clock=_go_clock_main)
    else:
        if is_infinite:
            _council_launch_nnue(ctx, line, move_count, _go_clock_main)
            _run_infinite_council(ctx, ctx.nnue_1, move_count)
            return
        if ctx.game_progress.book_seed_move is not None:
            _flog(f"[bookloader] 定跡 seed={ctx.game_progress.book_seed_move!r} "
                  f"trust={ctx.game_progress.book_seed_trust} を破棄 — nnue 専任経路 "
                  f"(council 不在) のため検討不能。純粋探索に委譲。")
            ctx.game_progress.book_seed_move   = None
            ctx.game_progress.book_seed_weight = 0.0
            ctx.game_progress.book_seed_trust  = ""
        _run_endgame_search(ctx, line, move_count, is_infinite,
                              go_clock=_go_clock_main)


def _drain_sp_early_bestmove(eng, caller="ponderhit", grace_s=0.30):
    if eng is None or not _eng_alive(eng):
        return None, None, {}
    nnue_info = {}
    _deadline = time.perf_counter() + max(0.0, grace_s)
    while True:
        _has_q = hasattr(eng, "_q") and eng._q.qsize() > 0
        if not _has_q and time.perf_counter() >= _deadline:
            break
        _to = 0.0 if _has_q else _clamp(_deadline - time.perf_counter(), 0.0, 0.05)
        out = eng.readline(timeout=_to)
        if out is None:
            return None, None, {}
        if not out:
            if time.perf_counter() >= _deadline:
                break
            continue
        if not isinstance(out, UsiLine):
            out = _parse_usi_line(out)
        if out.kind == "scored":
            _d = out.depth if out.depth is not None else 0
            if _d >= nnue_info.get("depth", -1):
                nnue_info["depth"] = _d
                if out.score_cp is not None:
                    nnue_info["score_cp"] = out.score_cp
                elif out.mate is not None:
                    nnue_info["score_cp"] = _mate_sign_score(out.mate)
                    nnue_info["mate_ply"] = out.mate
            continue
        if out.kind == "bestmove":
            _bm = out.bestmove or ""
            _pd = out.ponder_move
            if _bm and _bm not in ("resign", "win", "(none)"):
                nnue_info["bestmove"] = _bm
                if _pd:
                    nnue_info["ponder"] = _pd
                _flog(f"[{caller}/SP-early] {eng.name} の SP 早期 bestmove を回収: "
                      f"{_bm} (ponder={_pd}) — ponderhit を送らず即採用")
                return _bm, _pd, nnue_info
            _flog(f"[{caller}/SP-early] {eng.name} bestmove={_bm!r} は早期採用対象外 "
                  "— 子は idle (search complete)、ponderhit 抑止シグナル")
            return None, None, {"__search_complete__": True}
    return None, None, {}




def _ponderhit_restart_nnue1_and_movetime(ctx, position_cmd, move_count, eff_s,
                                    clock_rem_ms, restart_caller,
                                    slowmover_label=None, ponder_line=None,
                                    apply_slowmover=True, relay_kwargs=None,
                                    go_clock=None):
    _phit_trace("restart", who=restart_caller)
    _rec_rem_ms = _ph_recovery_rem_ms(clock_rem_ms)
    if _rec_rem_ms is not None and _rec_rem_ms < 3000.0 + _move_overhead_ms:
        _flog(f"{restart_caller}: [RESTART-GATE] recovery 残 {_rec_rem_ms:.0f}ms "
              f"< 3000ms+overhead — 同期 restart 断念、async revive に委譲")
        try:
            _revive_dead_nnue_async(ctx)
        except Exception as _rg_e:
            _flog(f"{restart_caller}: [RESTART-GATE] async revive failed "
                  f"(non-fatal): {_rg_e}")
        return None
    _rec_readyok_to = (_clamp(_rec_rem_ms / 1000.0 * 0.5, 0.5, 30.0)
                       if _rec_rem_ms is not None else None)
    _restart_nnue_1(ctx, restart_caller, readyok_timeout=_rec_readyok_to)
    if not ctx.nnue_1._alive:
        return None
    _rec_rem_ms = _ph_recovery_rem_ms(clock_rem_ms)
    _movetime_ms = max(500, int(eff_s * 200 * _time_aggression_base_gain(getattr(_time_dyn,'time_aggression',_TA_BASE_ANCHOR) or _TA_BASE_ANCHOR)))
    if _rec_rem_ms is not None:
        _movetime_ms = int(_clamp(_rec_rem_ms - _move_overhead_ms - 300,
                                  300, _movetime_ms))
    if apply_slowmover and ponder_line is not None:
        _apply_slow_mover(ctx.nnue_1, _nnue_1_opts,
                          ctx.cfg.nnue_slowmover_user_set,
                          slowmover_label or restart_caller,
                          eff_s=eff_s, cfg=ctx.cfg)
    ctx.nnue_1.send(position_cmd)
    ctx.nnue_1.send("go movetime %d" % _movetime_ms)
    _relay_to = _movetime_ms / 1000.0 + _clamp(eff_s * 0.5, 0.5, 3.0)
    if _rec_rem_ms is not None:
        _relay_to = min(_relay_to, max(0.3, _rec_rem_ms / 1000.0 - _move_overhead_s))
    _kwargs = dict(timeout=_relay_to,
                   intercept_bestmove=True,
                   eff_s=eff_s, go_clock=go_clock,
                   remaining_ms=(max(1, int(_rec_rem_ms))
                                 if _rec_rem_ms is not None else None))
    if relay_kwargs:
        _kwargs.update(relay_kwargs)
    return relay_timed(ctx.nnue_1, **_kwargs)


def _ponderhit_try_collect_sp_early(ctx, position_cmd, eff_s, caller):
    if not (ctx.ps.position is not None and ctx.ps.position == position_cmd
            and str(_nnue_1_opts.get("Stochastic_Ponder", "true")) == "true"):
        return None
    _grace_s = (_clamp(eff_s * 0.05, 0.05, 0.30)
                if eff_s and eff_s > 0 else 0.30)
    _sp_bm, _sp_pd, _sp_ni = _drain_sp_early_bestmove(ctx.nnue_1, caller,
                                                  grace_s=_grace_s)
    if not _sp_bm:
        if _sp_ni.get("__search_complete__"):
            _flog(f"[{caller}/SP-IDLE] nnue_1 search complete (resign/win/none) "
                  "— suppressing ponderhit, delegating to rescue cascade")
            _ps_debt_clear(ctx, "nnue_1", "sp-idle-complete")
            _ps_transition(ctx, PsPhase.IDLE, "sp-idle-complete")
            _flush_or_mark_dirty(ctx, f"{caller}/SP-IDLE-sync", eff_s)
            return "", None, {"__search_complete__": True}
        return None
    if not ctx.nnue_1.bm_is_current():
        _flog(f"[{caller}/SP-GEN] early bestmove {_sp_bm!r} is stale "
              f"(bm_seen={ctx.nnue_1._bm_seen} go_sent={ctx.nnue_1._go_sent}) — rejecting")
        _spd = ctx.game_progress.sp_move_diag
        if _spd is None:
            _spd = {}
            ctx.game_progress.sp_move_diag = _spd
        _spd["sp_gen_rejected"] = _spd.get("sp_gen_rejected", 0) + 1
        return None
    _sp_track_board = _get_tracking_board(ctx)
    _sp_board_attr = None
    if _sp_track_board is not None:
        _own_legal = _bestmove_is_for_board(_sp_bm, _sp_track_board)
        _sp_board_attr = "own" if _own_legal else "none"
    if _sp_track_board is not None and not _bestmove_is_for_board(_sp_bm, _sp_track_board):
        _flog(f"[{caller}/SP-echo] collected early bestmove {_sp_bm!r} is not a "
              "move for the current board — rejecting, fall through to ponderhit relay")
        _phit_trace("sp_echo_reject", bm=_sp_bm)
        _spd = ctx.game_progress.sp_move_diag
        if _spd is not None:
            _spd["sp_echo_rejected"] = _spd.get("sp_echo_rejected", 0) + 1
        return None
    _spd = ctx.game_progress.sp_move_diag
    if _spd is None:
        _spd = {}
        ctx.game_progress.sp_move_diag = _spd
    _spd["sp_early_collected"] = True
    _spd["sp_early_depth"] = _sp_ni.get("depth") if _sp_ni else None
    _spd["sp_early_board"] = _sp_board_attr
    _ps_debt_clear(ctx, "nnue_1", "sp-early-collected")
    _ps_transition(ctx, PsPhase.IDLE, "sp-early-collected")
    _flush_or_mark_dirty(ctx, f"{caller}/SP-sync", eff_s)
    return _sp_bm, _sp_pd, _sp_ni


def _mark_nnue1_flush_failure(ctx, caller):
    ctx.ps.nnue1_dirty = True
    _flog(f"[{caller}/SP-DIRTY] flush_until_ready failed — nnue_1 marked "
          "dirty; will resync before next go ponder")


def _flush_or_mark_dirty(ctx, caller, eff_s, max_stale_lines=50):
    _to = _clamp((eff_s or 0) * 0.2, 0.3, 2.0) if eff_s else 2.0
    ok = ctx.nnue_1.flush_until_ready(timeout=_to, max_stale_lines=max_stale_lines)
    if not ok:
        _mark_nnue1_flush_failure(ctx, caller)
        _phit_trace(f"{caller}_flush_fail")
    return ok


def _assert_sp_consistency(ctx, when):
    _expect = {
        "nnue_1": str(_cfg["nnue_1_Stochastic_Ponder"]) if _early_ponder else "false",
    }
    for _name, _want in _expect.items():
        _cache = _nnue_1_opts
        _got = _cache.get("Stochastic_Ponder")
        if _got is None:
            continue
        if _got != _want and not (_name == "nnue_1" and _got == "false"
                                  and when == "post-restart"):
            _flog(f"[SP-CONSISTENCY] {when}: {_name} cache={_got!r} "
                  f"expected={_want!r}")



def _ponder_conf_readiness_core(
    board_hit: bool,
    sp_configured: bool,
    ponder_elapsed_s,
    min_elapsed_s: float,
    ponder_move_agreement,
) -> "tuple[str, str]":
    if not board_hit:
        return "low", "miss"

    if ponder_move_agreement is True:
        return "conv", "hit_conv"

    if not sp_configured:
        return "medium", "hit_no_sp"
    if ponder_elapsed_s is None or ponder_elapsed_s < min_elapsed_s:
        return "medium", "hit_sp_short"
    return "high", "hit_sp_deep"


def _ponder_conf_cap_factor_core(level, conv_f, high_f, medium_f, low_f, floor):
    if level is None:
        return 1.0, None
    table = {"conv": conv_f, "high": high_f, "medium": medium_f, "low": low_f}
    try:
        f = float(table.get(level, 1.0))
    except (TypeError, ValueError):
        return 1.0, None
    f = _clamp(f, float(floor), 1.0)
    if f >= 1.0:
        return 1.0, None
    return f, f"{level} x{f:.2f}"


@_leased("dl-harvest")
def _harvest_one_dl_ponder(eng, n, timeout_s, label, *, cfg=None):
    if cfg is None:
        cfg = EngineConfig.from_cfg(_cfg)

    moves_scores  = {}
    pv_lines      = {}
    depth_best    = {}
    score_hist    = {}
    mate_detected = False
    _got_bestmove = False
    for line in eng.iter_until("bestmove", timeout=timeout_s):
        if line.kind == "bestmove":
            _got_bestmove = True
        _mate_n = line.mate
        if _mate_n is not None and _mate_n > 0:
            mate_detected = True
        if line.pv is None:
            continue
        score = line.score_cp if line.score_cp is not None else 0
        if _mate_n is not None:
            score = _mate_sign_score(_mate_n)
        _pv_toks = line.pv.split()
        if not _pv_toks:
            continue
        root_move = _pv_toks[0]
        pv_moves  = _pv_toks
        moves_scores[root_move] = score
        depth = line.depth if line.depth is not None else 0
        score_hist.setdefault(root_move, []).append((depth, score))
        if depth > depth_best.get(root_move, -1):
            depth_best[root_move] = depth
            pv_lines[root_move]   = pv_moves

    if not _got_bestmove:
        _flog(f"[DL-HARVEST/{label}] bestmove 未着 ({timeout_s:.2f}s) — 収穫断念 "
              "(残骸は次 fetch の pre-flush が破棄)")
        return None

    ranked = sorted(moves_scores.items(), key=lambda x: x[1], reverse=True)
    result = ranked[:n]
    actual_gap = (result[0][1] - result[1][1]) if len(result) >= 2 else None

    policy = result
    _effective_gap_min = _calc_dl_score_gap_min(0.0, cfg=cfg)
    _lift_abstain, _lift_spread, _lift_reason = _dl_gap_lift_decision_core(
        actual_gap, _effective_gap_min, result, score_hist, cfg)
    if _lift_reason == "lifted":
        _dlog(f"[DL-HARVEST/{label}/GAP-LIFT] gap={actual_gap} < {_effective_gap_min} "
              f"but top1={result[0][1]} spread={_lift_spread} — abstention REVOKED")
    if _lift_abstain:
        _dlog(f"[DL-HARVEST/{label}] gap {actual_gap} < threshold {_effective_gap_min} "
              "— weak vote (w=0.5)")

    return DlFetchResult(policy, mate_detected, actual_gap, None,
                         depth_best, score_hist, from_cache=True)


def _harvest_dl_ponders(ctx, position_cmd, eff_s=None):
    _want_dl1 = "dl_1" in ctx.ps.pending_bestmove
    if not _dl_ponder_enable or not _want_dl1:
        return False
    _ps_debt_clear(ctx, "dl_1", "dl-harvest")

    _pondered = ctx.ps.dl_ponder_pos
    _pos_match     = (_pondered is not None and _pondered == position_cmd)
    if _pos_match:
        _DLPONDER_STATE.dlp_hits += 1
    else:
        _DLPONDER_STATE.dlp_misses += 1

    _tree_continue = (bool(_cfg.get("DLP_Tree_Continue_Enable", False))
                      and _pos_match)
    _tc_budget_s = 0.0
    if _tree_continue:
        _hl_tc = getattr(ctx, "ledger", None)
        _tc_budget_s = _clamp((eff_s or 0.0) * 0.15, 0.05, 0.5)
        if _hl_tc is not None:
            _tc_budget_s = _hl_tc.draw("dl-tree-cont", _tc_budget_s, floor_s=0.05)

    _dl1_ok = (_want_dl1 and _eng_alive(ctx.dl_1))
    if _tree_continue:
        for _eng, _ok in ((ctx.dl_1, _dl1_ok),):
            if _ok:
                try:
                    _eng.send("ponderhit")
                except Exception as _fe:
                    _flog(f"[ignored] harvest ponderhit {_eng.name}: {_fe}")
        if _tc_budget_s > 0:
            time.sleep(_tc_budget_s)
        for _eng, _ok in ((ctx.dl_1, _dl1_ok),):
            if _ok:
                try:
                    _eng.send("stop")
                except Exception as _fe:
                    _flog(f"[ignored] harvest stop {_eng.name}: {_fe}")
    else:
        for _eng, _ok in ((ctx.dl_1, _dl1_ok),):
            if _ok:
                try:
                    _eng.send("stop")
                except Exception as _fe:
                    _flog(f"[ignored] harvest stop {_eng.name}: {_fe}")
    if not _pos_match:
        _dlog(f"[DL-HARVEST] 局面不一致 — 破棄のみ "
              f"(pondered={_pondered[:60] if _pondered else None}...)")
        ctx.ps.dl_ponder_pos = None
        return False
    ctx.ps.dl_ponder_pos = None

    _h_timeout = _clamp((eff_s or 0.0) * 0.25, 0.3, 1.5) if eff_s else 1.0
    _hl = getattr(ctx, "ledger", None)
    if _hl is not None:
        _h_timeout = _hl.draw("dl-harvest", _h_timeout, floor_s=0.3)
    _t0 = time.perf_counter()
    _injected = False

    _audb_prefetch_result = ctx.prefetch.peek_dl_1(position_cmd)
    _audb_top = (
        _audb_prefetch_result.policy[0][0]
        if (_audb_prefetch_result is not None and _audb_prefetch_result.policy)
        else None
    )

    if _dl1_ok and _pos_match:
        _r1 = _harvest_one_dl_ponder(ctx.dl_1, _params[_K_POLICY_MOVES],
                                     _h_timeout, "DL_1", cfg=ctx.cfg)
        if _r1 is not None:
            ctx.prefetch.inject_dl_1(position_cmd, _r1)
            _injected = True
            _dlog(f"[DL-HARVEST] DL_1 注入: top={_r1.policy[0][0] if _r1.policy else None} "
                  f"gap={_r1.gap} moves={len(_r1.score_hist)}")
            _dl_ponder_bm = _r1.policy[0][0] if _r1.policy else None
            if _audb_top is not None:
                ctx.game_progress.ponder_move_dl       = _audb_top
                ctx.game_progress.ponder_prefetch_corr = (_audb_top == _dl_ponder_bm) if _dl_ponder_bm else None
            else:
                ctx.game_progress.ponder_move_dl       = _dl_ponder_bm
                ctx.game_progress.ponder_prefetch_corr = None

    _dlog(f"[DL-HARVEST] 完了 elapsed={(time.perf_counter()-_t0)*1000:.0f}ms "
          f"dl1={_injected} (相手番探索を council 票として収穫)")
    return _injected




def _ponderhit_handle_mate_skip(ctx, position_cmd, move_count):
    if not ctx.cfg.mate_score_ponder_skip:
        return None

    last_score = None
    if ctx.game_log:
        last_score = ctx.game_log[-1].get("nnue_score_cp")
    if last_score is None or abs(last_score) < _MATE_CP:
        return None

    _dlog("[PH-MATE-SKIP] last_score=%d — skipping full ponderhit" % last_score)
    _ps_transition(ctx, PsPhase.MATE_SKIP, "ph-mate-skip")

    eng = ctx.nnue_1
    label = "nnue_1"

    if "nnue_1" in ctx.ps.pending_bestmove and ctx.nnue_1._alive:
        _settle_debts(ctx, ["nnue_1"], reason="ph-pre-drain")

    eng.send(position_cmd)
    eng.send("go movetime %d" % ctx.cfg.mate_skip_emergency_movetime_ms)
    _ms_go_clock = _resolve_ponder_clock(ctx, "PH-MATE-SKIP")
    pm, ni = relay_window(
        eng, timeout=max(3.0, ctx.cfg.mate_skip_emergency_movetime_ms / 1000.0 + 2.0),
        go_clock=_ms_go_clock,
        intercept_bestmove=True,
    )
    bestmove, ponder = _unpack_bestmove(ni)
    _emit_ni = ni
    _phit_trace("mate_skip_relay", bm=bestmove or "-")

    if _sp_echo_reject(ctx, bestmove, "PH-MATE-SKIP"):
        _phit_trace("echo_reject", bm=bestmove)
        bestmove = ""
        ponder = None

    def _mate_skip_drop_ok(_mv):
        if not _mv or "*" not in _mv:
            return True
        _board = _get_tracking_board(ctx)
        if _board is None:
            return True
        _r = _board.illegal_drop_reason(_mv)
        if _r:
            _flog("[PH-MATE-SKIP] rejected illegal drop %s (reason=%s) — "
                  "not accepting stale move" % (_mv, _r))
            return False
        return True

    if bestmove and not _mate_skip_drop_ok(bestmove):
        bestmove = ""

    if bestmove:
        _dlog("[PH-MATE-SKIP] bestmove=%s ponder=%s via %s"
              % (bestmove, ponder, label))
    else:
        _dlog("[PH-MATE-SKIP] WARNING: no bestmove from %s" % label)
        _fb_move = None
        if ctx.game_log:
            _last = ctx.game_log[-1]
            _fb_move = (_last.get("ponder")
                        or _last.get("mate_solver_move")
                        or None)
        if _fb_move and not _mate_skip_drop_ok(_fb_move):
            _fb_move = None
        if _sp_echo_reject(ctx, _fb_move, "PH-MATE-SKIP"):
            _fb_move = None
        if _fb_move:
            bestmove = _fb_move
            _emit_ni = None
            _dlog("[PH-MATE-SKIP] fallback bestmove from game_log.ponder: %s"
                  % bestmove)
        else:
            _dlog("[PH-MATE-SKIP] no fallback available — returning empty (resign path)")

    _ponderhit_capture_emit_ni(ctx, _emit_ni, bestmove)

    return bestmove, ponder


def _ponderhit_handle_stale(ctx, position_cmd, move_count):

    _stale_board = _get_tracking_board(ctx)
    _pred_key = ctx.ps.ponder_board_key
    if _pred_key is not None and _stale_board is not None:
        if _pred_key == _stale_board._board_key():
            return None
    elif ctx.ps.position == position_cmd:
        return None
    if not ctx.ps.position:
        if "nnue_1" in ctx.ps.pending_bestmove:
            _DLPONDER_STATE.state_corruption_ps_pos_nnue1 = int(_DLPONDER_STATE.state_corruption_ps_pos_nnue1) + 1
            _flog(f"[PH-STALE] WARNING: ps.position=None but nnue1_ponder_sent=True "
                  f"(state corruption?) — falling through to cache_miss "
                  f"(cumulative={_DLPONDER_STATE.state_corruption_ps_pos_nnue1})")
            if _DLPONDER_STATE.state_corruption_ps_pos_nnue1 >= 10:
                try:
                    print(f"info string [WARN] state corruption: ps.position=None & "
                          f"nnue1_ponder_sent=True streak={_DLPONDER_STATE.state_corruption_ps_pos_nnue1}",
                          flush=True)
                except Exception as _e:
                    _flog(f"[ignored] _ponderhit_handle_stale: {_e!r}")
            return None
        _dlog("[PH-STALE] forced recovery: ps.position=None "
              "(go ponder never issued — endgame nnue dead/unstable path)")

    _dlog("[PH-STALE] position mismatch — recovery search")

    if "nnue_1" in ctx.ps.pending_bestmove and ctx.nnue_1._alive:
        _settle_debts(ctx, ["nnue_1"], reason="ph-pre-drain")
        if ctx.nnue_1._alive:
            _pc_eff = ctx.ps.ponder_clock.eff_s if ctx.ps.ponder_clock else 0
            _flush_or_mark_dirty(ctx, "PH-STALE", _pc_eff)

    go_clock = ctx.ps.ponder_clock
    _clock_rem_ms = go_clock.remaining_ms if go_clock is not None else None
    if go_clock is not None:
        _stale_eff_s = go_clock.eff_s
        _stale_search_r = _lerp(0.72, 0.88, _time_dyn.time_aggression)
        _stale_margin_r = _lerp(0.12, 0.28, _time_dyn.time_aggression)
        movetime_ms = max(100,
                          int(_stale_eff_s * 1000 * _stale_search_r)
                          if _stale_eff_s > 0
                          else int(_time_dyn.dl_time_fallback_ms * _stale_search_r))
        relay_timeout_s = movetime_ms / 1000.0 + max(0.5, _stale_eff_s * _stale_margin_r)
        movetime_ms = int(movetime_ms * 1.5 * _time_aggression_base_gain(getattr(_time_dyn,'time_aggression',_TA_BASE_ANCHOR) or _TA_BASE_ANCHOR))
    else:
        movetime_ms = 1000
        relay_timeout_s = 5.0

    ctx.nnue_1.send(position_cmd)
    recovery_line = "go movetime %d" % int(movetime_ms)
    _apply_slow_mover(
        ctx.nnue_1, _nnue_1_opts,
        ctx.cfg.nnue_slowmover_user_set, "nnue_1-ph-stale",
        eff_s=go_clock.eff_s if go_clock else 1.0,
        cfg=ctx.cfg,
    )
    ctx.nnue_1.send(recovery_line)
    ponderhit_pv_holder = [None]
    _stale_rem_ms = _ph_recovery_rem_ms(_clock_rem_ms)
    pm, ni = relay_window(
        ctx.nnue_1, timeout=relay_timeout_s,
        partial_pv_holder=ponderhit_pv_holder,
        go_clock=go_clock,
        remaining_ms=(max(1, int(_stale_rem_ms))
                      if _stale_rem_ms is not None else None),
        intercept_bestmove=True,
    )

    bestmove, ponder = _unpack_bestmove(ni)
    _phit_trace("stale_research", bm=bestmove or "-")

    if _sp_echo_reject(ctx, bestmove, "PH-STALE"):
        _phit_trace("echo_reject", bm=bestmove)
        bestmove = ""
        ponder = None
        ponderhit_pv_holder[0] = None

    _dlog("[PH-STALE] recovery bestmove=%s ponder=%s movetime=%dms"
          % (bestmove, ponder, movetime_ms))

    ctx.ps.tree_invalid = True

    _ponderhit_capture_emit_ni(ctx, ni, bestmove)

    return bestmove, ponder, ponderhit_pv_holder[0]




def _ponderhit_pick_emit_score(final_move, nnue_bm, nnue_score, dl_top, dl_score):
    if final_move == nnue_bm and nnue_score is not None:
        return nnue_score
    if dl_top is not None and final_move == dl_top and dl_score is not None:
        return dl_score
    if nnue_score is not None:
        return nnue_score
    if dl_score is not None:
        return dl_score
    return None


def _ponderhit_capture_emit_ni(ctx, ni, bestmove):
    try:
        if not bestmove or bestmove in ("resign", "win"):
            return
        if not ni:
            return
        ctx.game_progress.ponderhit_emit_ni = {
            "score_cp": ni.get("score_cp", 0) or 0,
            "depth":    ni.get("depth", 0) or 0,
            "seldepth": ni.get("seldepth", 0) or 0,
            "pv":       ni.get("pv", "") or "",
            "bestmove": bestmove,
        }
    except Exception as _e:
        _flog(f"[PH-EMIT] capture failed (ignored): {_e!r}")


def _ponderhit_cached_fallback_move(ctx, extra_stats):
    try:
        _board = _get_tracking_board(ctx)
    except Exception:
        _board = None
    if _board is None:
        return None
    _cands = []
    try:
        _pol = (extra_stats or {}).get("_live_dl1_policy")
        if _pol and _pol[0]:
            _cands.append(_pol[0][0])
    except Exception as _e:
        _flog(f"[ignored] _ponderhit_cached_fallback_move: {_e!r}")
    for _mv in _cands:
        if not _mv or _mv in ("resign", "win"):
            continue
        try:
            if _bestmove_is_for_board(_mv, _board):
                return _mv
        except Exception:
            continue
    return None




def _handle_ponderhit(ctx, line):
    _gen_new_thinking("ponderhit")
    _phit_trace_start()
    ctx.game_progress.sp_move_diag = {}
    _run_search(ctx, line, 0, _UV_PONDERHIT)


def _handle_stop(ctx, line):
    global _STOP_REARM
    _STOP_REARM = True
    ctx.nnue_1._live_info_cb = None
    if ctx.dl_1 is not None:
        ctx.dl_1._live_info_cb = None

    ctx.dl_1.send("stop")
    ctx.nnue_1.send("stop")
    _mate_ponder_cancel(ctx, "stop")
    if getattr(ctx, "_mate_go_active", False):
        _mate_solver_stop_safe(ctx, "go-mate-stop")
        ctx._mate_go_active = False

    if ctx.ps.phase in _PS_PHASE_ACTIVE:
        _flog("stop during go ponder — draining bestmove to GUI")
        _stop_clock = _resolve_ponder_clock(ctx, "stop-drain")
        _stop_eff_s = _stop_clock.eff_s if _stop_clock is not None else None
        _stop_rem_ms = _stop_clock.remaining_ms if _stop_clock is not None else None
        _stop_ponder = None
        _stop_nnue_info = None
        if "nnue_1" not in ctx.ps.pending_bestmove:
            _flog("[STOP-IDLE-GUARD] stop during go ponder but nnue_1 was "
                  "never sent go ponder — skip relay (engine preserved)")
        else:
            _stop_relay_to = _clamp(10.0 * _move_overhead_s, 0.5, 2.5)
            if _stop_rem_ms and _stop_rem_ms > 0:
                _stop_relay_to = _clamp(
                    _stop_rem_ms / 1000.0 * 0.25, 0.3, _stop_relay_to)
            _stop_ponder, _stop_nnue_info = relay_window(
                ctx.nnue_1, timeout=_stop_relay_to,
                intercept_bestmove=True,
                remaining_ms=_stop_rem_ms,
                kill_on_empty=False)
        if ("nnue_1" in ctx.ps.pending_bestmove and ctx.nnue_1._alive
                and not ((_stop_nnue_info or {}).get("bestmove"))):
            _stop_flush_to = 2.0
            if _stop_rem_ms and _stop_rem_ms > 0:
                _stop_flush_to = _clamp(_stop_rem_ms / 1000.0 * 0.25, 0.3, 2.0)
            _flog("stop-drain: no bestmove (SP idle) — flush_until_ready で同期 "
                  "(kill せず nnue_1 を温存)")
            ctx.nnue_1.flush_until_ready(timeout=_stop_flush_to, max_stale_lines=50)
        _stop_bestmove = (_stop_nnue_info.get("bestmove") or "").strip() if _stop_nnue_info else ""
        if _stop_bestmove:
            _safe_bestmove(_stop_bestmove, _stop_ponder, label="stop-ponder-miss",
                           nnue_info=_stop_nnue_info)
        elif _ACTIVE_BESTMOVE_SINK is not None:
            _flog("stop-ponder-miss: bestmove sink active (CSA/dlp) — "
                  "emergency 手の生成を skip (直後の本 go が破棄するため)")
        else:
            _emerg_sp = None
            try:
                _emerg_sp = _emergency_move_from_any_engine(
                    ctx, min(_stop_eff_s or 3.0, 1.5))
            except Exception as _ee:
                _flog(f"stop-ponder-miss: emergency move raised (ignored): {_ee!r}")
            if _emerg_sp and _emerg_sp not in ("resign", "win"):
                _flog(f"stop-ponder-miss: nnue_1 空 — 生存エンジンの emergency 手 "
                      f"{_emerg_sp!r} を返す (resign/沈黙 回避)")
                _safe_bestmove(_emerg_sp, label="stop-ponder-miss-emerg")
            else:
                _flog("stop-ponder-miss: nnue_1 空かつ生存エンジン皆無 — bestmove を "
                      "emit せず直後の本 go に委ねる (resign にはしない)")
        _ps_debt_clear(ctx, "nnue_1", "stop-ponder-miss")
        _ps_transition(ctx, PsPhase.IDLE, "stop-ponder-miss")
        _stop_dl_ponders(ctx, "stop-ponder-miss")

    elif ctx.ps.phase is PsPhase.MATE_SKIP:
        _flog(
            "stop emergency (mate-skip pending): "
            f"running short go movetime {ctx.cfg.mate_skip_emergency_movetime_ms}ms "
            "to produce bestmove for GUI"
        )
        _ps_transition(ctx, PsPhase.IDLE, "stop-emergency")

        _em_pos = ctx.ps.position or ctx.current_position
        _em_movetime = ctx.cfg.mate_skip_emergency_movetime_ms

        _em_mate_res    = MateResult()
        _em_mate_thread = None

        _mpon_prefetched = None
        try:
            _mpon_prefetched = _mate_ponder_harvest(ctx, _em_pos)
        except (KeyboardInterrupt, SystemExit, MemoryError):
            raise
        except Exception as _mphe:
            _flog(f"[STOP-EMERGENCY] _mate_ponder_harvest peek failed (non-fatal): {_mphe!r}")
        if (_mpon_prefetched and _mpon_prefetched[0] == "mate"
                and _mpon_prefetched[1] not in (None, "", "resign", "win")):
            _em_mate_res.result = "mate"
            _em_mate_res.best_move = _mpon_prefetched[1]
            _flog(f"[STOP-EMERGENCY/MPON-PEEK] 予測局面で詰み発見済 {_mpon_prefetched[1]} "
                  "— 再探索 skip で即採用")
        elif (_mate_solver_active(ctx)
                and _count_moves(_em_pos) >= ctx.cfg.mate_solver_min_ply):
            if ctx._zyfamate:
                _zf_res, _zf_mv, _ = _zyfamate_solve(
                    _sfen_for_position(_em_pos),
                    timeout_s=_em_movetime / 1000.0, nodes=5000000, path=ctx.cfg.mate_solver_path)
                _em_mate_res.result = _zf_res
                _em_mate_res.best_move = _zf_mv
            else:
                _em_mate_thread = _spawn('mate_solver_stop_emergency', _run_mate_solver_thread, ctx, _em_pos, f'go movetime {_em_movetime}', _em_mate_res, 0.0, 1.0, 'stop-emergency', start_now=False)
                _em_mate_thread.start()

        _em_engine = ctx.nnue_1
        _em_engine_name = "ctx.nnue_1"

        def _stop_emerg_fallback(reason):
            _flog(f"stop emergency: {reason} — delegating to _recover(EMERGENCY_FALLBACK)")
            try:
                _recover(ctx.nnue_1, reason=RecoverReason.EMERGENCY_FALLBACK,
                         clock=ctx.ps.ponder_clock, ctx=ctx)
            except Exception as _re:
                _flog(f"stop emergency: recover raised: {_re!r}")
                if not _GO_EMITTED:
                    _safe_bestmove("resign")

        if not _em_engine._alive:
            _stop_emerg_fallback(f"{_em_engine_name} not alive")
            return

        try:
            _em_engine.send(_em_pos)
            _em_engine.send(f"go movetime {_em_movetime}")
        except Exception as _em_se:
            _stop_emerg_fallback(f"send failed ({_em_se})")
            return

        _em_pm, _em_ni = relay_window(
            _em_engine,
            timeout=max(2.0, _em_movetime / 1000.0 + 1.5),
            go_clock=ctx.ps.ponder_clock,
            intercept_bestmove=True,
        )
        _em_best = _em_ni.get("bestmove") or ""

        if _em_mate_thread is not None:
            _em_mate_thread.join(timeout=max(0.1, _em_movetime / 1000.0 + 0.5))
            if _em_mate_thread.is_alive():
                _mate_solver_stop_safe(ctx, "stop-emergency")

        if (_em_mate_res.result == "mate" and _em_mate_res.best_move
                and _em_mate_res.best_move not in ("resign", "win", "")):
            _final_em = _em_mate_res.best_move
            _flog(
                f"stop emergency: mate_solver found checkmate: {_final_em} "
                f"— overriding {_em_engine_name} bestmove ({_em_best})"
            )
        else:
            _final_em = _em_best or "resign"

        _safe_bestmove(_final_em)
        _flog(f"stop emergency: bestmove {_final_em} sent to GUI")

        if _final_em not in ("resign", "win", ""):
            _em_next_pos = _position_after_move(_em_pos, _final_em)
            _start_prefetch_after_bestmove(
                ctx, _em_next_pos,
                _em_pm,
                _count_moves(_em_pos),
            )
        _ps_transition(ctx, PsPhase.IDLE, "stop-emergency-finalize")


def _usi_game_sfen_flush(ctx, tag: str) -> None:
    if _RUN_MODE is not RunMode.USI or _SPSA_RUNNER_ACTIVE[0]:
        return
    try:
        pos = (getattr(ctx, "current_position", "") or "").strip()
        if not pos.startswith("position"):
            return
        toks = pos.split()
        if "moves" in toks:
            _mi = toks.index("moves")
            prefix_toks, moves = toks[1:_mi], toks[_mi + 1:]
        else:
            prefix_toks, moves = toks[1:], []
        _conf = getattr(ctx.ps, "last_go_position", None)
        _spec = getattr(ctx.ps, "position", None)
        if isinstance(_conf, str) and _conf.startswith("position"):
            _ct = _conf.split()
            if "moves" in _ct:
                _cmi = _ct.index("moves")
                _cprefix, _cmoves = _ct[1:_cmi], _ct[_cmi + 1:]
            else:
                _cprefix, _cmoves = _ct[1:], []
            if (_cprefix == prefix_toks and len(moves) == len(_cmoves) + 2
                    and moves[:len(_cmoves)] == _cmoves
                    and (_spec == pos or _spec is None)):
                _flog(f"[USI-SFEN-KIFU][{tag}] speculative ponder move "
                      f"'{moves[-1]}' dropped (go-ponder prediction, "
                      f"never confirmed by ponderhit/go)")
                moves = moves[:-1]
        my_side = None
        last_move_added = None
        if ctx.game_log:
            for _r in ctx.game_log:
                _p = _r.get("ply")
                if isinstance(_p, int):
                    my_side = "sente" if _p % 2 == 0 else "gote"
                    break
            _last = ctx.game_log[-1]
            _lm = _last.get("council_winner") or _last.get("bestmove")
            _lp = _last.get("ply")
            if (_lm and isinstance(_lm, str) and len(_lm) >= 4
                    and _lm not in ("resign", "win", "none", "0000")
                    and isinstance(_lp, int)
                    and _lp == _count_moves(pos)):
                moves = moves + [_lm]
                last_move_added = _lm
        if not moves:
            return
        pos_full = ("position " + " ".join(prefix_toks)
                    + " moves " + " ".join(moves))
        _res = (getattr(ctx, "game_meta", None) or {}).get("result")
        try:
            _final_sfen = _sfen_for_position(pos_full)
        except Exception as _bfe:
            _final_sfen = f"<build failed: {_bfe!r}>"
        _flog(f"[USI-SFEN-KIFU][{tag}] {pos_full}")
        _flog(f"[USI-SFEN-KIFU][{tag}] final_sfen={_final_sfen} "
              f"result={_res} side={my_side}"
              + (f" (+last bestmove {last_move_added})"
                 if last_move_added else ""))
        _sfen_result = None
        if _res == "draw":
            _sfen_result = "draw"
        elif _res in ("win", "lose") and my_side in ("sente", "gote"):
            _winner = (my_side if _res == "win"
                       else ("gote" if my_side == "sente" else "sente"))
            _sfen_result = _winner + "_win"
        if _sfen_result and bool(globals().get("SFEN_Kifu_Enable", True)):
            _path = (globals().get("SFEN_Kifu_Path", "") or "").strip()
            if not _path:
                _path = os.path.join(_BASE_DIR, "usi_games.sfen")
            if prefix_toks and prefix_toks[0] == "startpos":
                _prefix = "startpos"
            else:
                _start = (" ".join(prefix_toks[1:])
                          if (prefix_toks and prefix_toks[0] == "sfen") else "")
                _prefix = ("startpos"
                           if _start.split()[:1] == [_HIRATE_SFEN.split()[0]]
                           else ("sfen " + _start if _start else "startpos"))
            _sfen_kifu_append(_path, _prefix, moves, _sfen_result, None)
            _flog(f"[USI-SFEN-KIFU][{tag}] appended → {_path} ({_sfen_result})")
    except Exception as _ue:
        _flog(f"[USI-SFEN-KIFU][{tag}] failed (ignored): {_ue!r}")


def _handle_gameover(ctx, line):
    _MGMT_GEN[0] += 1
    _teardown_game(ctx, "gameover")
    _mgmt_send_locked(ctx.dl_1, ctx.prefetch.dl_1_lock, line, "dl_1", "gameover")
    ctx.nnue_1.send(line)
    if _eng_alive(ctx.mate_solver):
        ctx.mate_solver.send(line)
    if _eng_alive(ctx.book):
        ctx.book.send(line)
    _LIVE._stop_clock()
    parts = line.split()
    ctx.game_meta["result"] = parts[1] if len(parts) > 1 else "unknown"
    ctx.game_meta["dlp_mode"] = str(_DLPONDER_STATE.mode)
    ctx.game_meta["dlp_diff"] = _dlp_game_diff()
    _write_game_stats(ctx.game_log, ctx.game_meta, cfg=ctx.cfg)
    if not _tuning_mode:
        _dlponder_save_state()
    _dlp_snapshot_for_diff()
    _usi_game_sfen_flush(ctx, "gameover")
    ctx.reset_game()
    _assert_sp_consistency(ctx, "gameover")
    global _usi_session_active
    _usi_session_active = False
    ctx.time_aggression.reset_to_static()
    try:
        _tele_keys = (
            "mpon_worker_err", "mpon_dispatch_err",
            "stats_write_fail_disk", "stats_write_fail_other",
            "stats_write_fail_streak",
            "prefetch_none_dl1", "prefetch_none_idp", "prefetch_none_jext",
            "mon_loop_err", "tonshi_guard_err",
            "state_corruption_ps_pos_nnue1",
            "csm_compute_total",
            "csm_sharp_difficult", "csm_sharp_clear",
            "csm_conf_unknown", "csm_sharp_unknown",
            "csm_sharp_nnue_score_none",
            "csm_voices_n2", "csm_voices_n1",
            "regime_cruise_count", "regime_alert_count",
            "regime_crisis_count", "regime_collapse_count",
            "pending_ttl_drop_usinewgame", "pending_ttl_drop_gameover",
            "pending_forced_resend",
        )
        _tele_all = dataclasses.asdict(_DLPONDER_STATE)
        _tele = {k: int(_tele_all[k]) for k in _tele_keys}
        if any(_tele.values()):
            _parts = " ".join(f"{k}={v}" for k, v in _tele.items() if v)
            print(f"info string [telemetry] {_parts}", flush=True)
            _flog(f"[TELEMETRY-DUMP] {_parts}")
    except Exception as _te:
        _flog(f"[TELEMETRY-DUMP] failed (non-fatal): {_te!r}")


def _handle_bare_sfen(ctx, line):
    _out_path = os.path.join(_BASE_DIR, "sfen_links.txt")
    try:
        url = _zenrei_same_url(line.strip())
        with open(_out_path, "a", encoding="utf-8") as _f:
            _f.write(url + "\n")
        _flog(f"[sfen_links] {line.strip()!r} → {url}")
    except Exception as e:
        _flog(f"[sfen_links] error for {line.strip()!r}: {e}")


def _reject_if_session_active(tag: str) -> bool:
    if _usi_session_active:
        _flog(f"[{tag}] rejected — USI session already active (usinewgame received)")
        _console(f"info string [WARN] {tag} を拒否: USI セッションが動作中です。")
        return True
    return False

def _handle_quit(ctx, line):
    _flog("quit")
    _shutdown(ctx, "quit-command")
    sys.exit(0)


def _handle_spsa(ctx, line):
    _flog("[SPSA] 'spsa' command received — starting built-in SPSA tuning")
    print("info string [setup] SPSA チューニングを開始しました (内蔵ワーカー)", flush=True)
    _spsa_args = line.split()[1:]
    def _run():
        for _sh_attr in ("nnue_1",):
            _sh_eng = getattr(ctx, _sh_attr, None)
            if _sh_eng is None or not getattr(_sh_eng, "_alive", False):
                continue
            try:
                _sh_eng.send("stop")
                _sh_eng.setoption("USI_Hash", "1")
                _sh_eng.send("isready")
                _sh_eng.flush_until_ready(timeout=30.0)
                _flog("[FIX-SPSA-PARENT-HASH] %s Hash→1MB (WSL RAM released)"
                      % _sh_attr)
            except Exception as _sh_e:
                _flog("[FIX-SPSA-PARENT-HASH] %s shrink failed: %s"
                      % (_sh_attr, _sh_e))
        for _dq_attr in ("dl_1",):
            _dq_eng = getattr(ctx, _dq_attr, None)
            if _dq_eng is None or not getattr(_dq_eng, "_alive", False):
                continue
            try:
                _dq_eng.quit()
                _flog("[FIX-SPSA-PARENT-DL-QUIESCE] %s quit "
                      "(DirectML/VRAM+host RAM released; "
                      "auto-revive at next real go)" % _dq_attr)
            except Exception as _dq_e:
                _flog("[FIX-SPSA-PARENT-DL-QUIESCE] %s quit failed: %s"
                      % (_dq_attr, _dq_e))
        if not _spsa_wsl_health_reset():
            _wsl_abort_msg = (
                "[SPSA] 中止: WSL が利用不能 (wedge) — WSL bridge の nnue が"
                "起動できず全ワーカー死亡が確定するため。管理者 PowerShell で "
                "Restart-Service WSLService を実行するか、OS 再起動後に再実行"
                "してください。")
            _flog(_wsl_abort_msg)
            print("info string " + _wsl_abort_msg, flush=True)
            return
        if not _ensure_prereqs("spsa", _spsa_args):
            _flog("[SPSA] 前提工程 (DLP/Setup) 失敗 — SPSA を開始しない")
            return
        _saved = sys.argv[:]
        _state_path = os.path.join(_BASE_DIR, "spsa_state.txt")
        _argv = [sys.argv[0], "--spsa", "--run"]
        if os.path.exists(_state_path):
            _argv += ["--resume", _state_path]
            _flog("[SPSA] auto-resuming from %s" % _state_path)
        sys.argv = _argv
        try:
            _spsa_cli()
        except SystemExit:
            pass
        except Exception as e:
            _flog("[SPSA] tuning error: %s" % e)
        finally:
            sys.argv = _saved
    t = _spawn('spsa-tuner', _run, start_now=False)
    t.start()


