def _wdl_regress_endpoints_core(points, fit_offset: bool):
    pts = []
    for it in points:
        if len(it) >= 4:
            p, sl, a, w = float(it[0]), float(it[1]), float(it[2]), float(it[3])
        else:
            p, sl, a, w = float(it[0]), float(it[1]), float(it[2]), 1.0
        if w > 0.0:
            pts.append((p, sl, a, w))
    n = len(pts)
    if n == 0:
        return None
    if n == 1:
        p, sl, a, _w = pts[0]
        off = (a / p) if (fit_offset and p > 1e-9) else 0.0
        return max(1e-6, sl), max(1e-6, sl), off
    W = sum(w for _, _, _, w in pts)
    pbar = sum(w * p for p, _, _, w in pts) / W
    sbar = sum(w * sl for _, sl, _, w in pts) / W
    sxx = sum(w * (p - pbar) ** 2 for p, _, _, w in pts)
    sxy = sum(w * (p - pbar) * (sl - sbar) for p, sl, _, w in pts)
    if sxx < 1e-18:
        m, b = 0.0, sbar
    else:
        m = sxy / sxx
        b = sbar - m * pbar
    early = max(1e-6, b)
    late = max(1e-6, m + b)
    if fit_offset:
        denom = sum(w * p * p for p, _, _, w in pts)
        offset = (sum(w * p * a for p, _, a, w in pts) / denom
                  if denom > 1e-12 else 0.0)
    else:
        offset = 0.0
    return early, late, offset


def _wdl_fit_cli(args):
    kv = {}
    for a in args:
        if "=" in a:
            k, _, v = a.partition("=")
            kv[k.strip()] = v.strip()
    base = _BASE_DIR
    path = kv.get("stats") or os.path.join(base, "stats.txt")
    n_bands = max(2, int(kv.get("bands", "4")))
    game_phase_split = float(kv.get("game_phase_split", "0.5"))
    min_n = int(kv.get("min_n", "50"))
    fit_offset = _norm_str(kv.get("fit_offset", "1")) not in ("0", "false", "no")
    out = kv.get("out") or os.path.join(base, "wdl_fit.txt")

    _GAME_PHASE_MAX = 1.5

    def _band_index(game_phase):
        g = float(game_phase)
        if n_bands == 2:
            return (0 if g < game_phase_split else 1)
        idx = int(g / (_GAME_PHASE_MAX / n_bands))
        if idx < 0:
            idx = 0
        elif idx > n_bands - 1:
            idx = n_bands - 1
        return idx

    records, n_games, _vc = _tuner_load_records(path)
    _OUTCOME = {"win": 1.0, "lose": 0.0, "draw": 0.5, "rep_draw": 0.5,
                "sennichite": 0.5}
    _FAM = {"dl": "dl_top_score", "nnue": "nnue_score_cp"}
    _ANCHOR = {"dl": 0.0049, "nnue": 0.004}
    buckets = {}
    _prog_sum = {}
    _n_used = 0
    for rec in records:
        o = _OUTCOME.get(_norm_str(rec.get("_game_result", "")))
        if o is None:
            continue
        game_phase = rec.get("game_phase")
        if game_phase is None:
            continue
        bi = _band_index(game_phase)
        prog = _clamp01(float(game_phase))
        _matched = False
        for fam, fld in _FAM.items():
            cp = rec.get(fld)
            if cp is None:
                continue
            buckets.setdefault((fam, bi), []).append((float(cp), o))
            _ps = _prog_sum.setdefault((fam, bi), [0.0, 0])
            _ps[0] += prog
            _ps[1] += 1
            _matched = True
        if _matched:
            _n_used += 1

    def _fit_wr(pairs, anchor):
        if len(pairs) < min_n:
            return None

        def _nll(s, a):
            t = 0.0
            for cp, o in pairs:
                z = s * (cp - a)
                if z > 60.0:
                    lp, l1 = 0.0, -z
                elif z < -60.0:
                    lp, l1 = z, 0.0
                else:
                    lp = -math.log1p(math.exp(-z))
                    l1 = -math.log1p(math.exp(z))
                t -= o * lp + (1.0 - o) * l1
            return t

        s = anchor
        a = 0.0
        cur = _nll(s, a)
        for _ in range(100):
            g_s = g_a = h_ss = h_aa = h_sa = 0.0
            for cp, o in pairs:
                z = s * (cp - a)
                if z > 60.0:
                    p = 1.0
                elif z < -60.0:
                    p = 0.0
                else:
                    p = 1.0 / (1.0 + math.exp(-z))
                r = o - p
                w = p * (1.0 - p)
                d = cp - a
                g_s += d * r
                h_ss += w * d * d
                if fit_offset:
                    g_a += (-s) * r
                    h_aa += w * s * s
                    h_sa += w * (-s) * d
            if not fit_offset:
                if h_ss < 1e-12:
                    break
                ds = g_s / (h_ss + 1e-12)
                da = 0.0
            else:
                h_ss_r = h_ss + 1e-9
                h_aa_r = h_aa + 1e-9
                det = h_ss_r * h_aa_r - h_sa * h_sa
                if abs(det) < 1e-18:
                    break
                ds = (h_aa_r * g_s - h_sa * g_a) / det
                da = (-h_sa * g_s + h_ss_r * g_a) / det
            t = 1.0
            improved = False
            for _bt in range(30):
                ns = s + t * ds
                na = a + t * da
                if ns < 1e-6:
                    ns = 1e-6
                if na > 2000.0:
                    na = 2000.0
                elif na < -2000.0:
                    na = -2000.0
                nv = _nll(ns, na)
                if nv <= cur + 1e-12:
                    s, a, cur = ns, na, nv
                    improved = True
                    break
                t *= 0.5
            if not improved:
                break
            if abs(t * ds) < 1e-10 and abs(t * da) < 1e-9:
                break
        return s, a

    def _regress_endpoints(points):
        return _wdl_regress_endpoints_core(points, fit_offset)

    print(f"[wdl fit] {path}: games={n_games} used_moves={_n_used} "
          f"bands={n_bands} min_n={min_n} fit_offset={int(fit_offset)}"
          + (f" game_phase_split={game_phase_split}" if n_bands == 2 else ""), flush=True)
    lines = []
    for fam, KEY in (("dl", "DL"), ("nnue", "NNUE")):
        pts = []
        for bi in range(n_bands):
            pairs = buckets.get((fam, bi), [])
            res = _fit_wr(pairs, _ANCHOR[fam])
            if res is None:
                print(f"  {fam:4s} band{bi}: n={len(pairs):6d} "
                      f"slope=n/a (sample不足 <{min_n})", flush=True)
                continue
            sl, a = res
            _ps = _prog_sum.get((fam, bi), [0.0, 0])
            prog = (_ps[0] / _ps[1]) if _ps[1] > 0 else 0.0
            pts.append((prog, sl, a, len(pairs)))
            print(f"  {fam:4s} band{bi}: n={len(pairs):6d} prog={prog:.3f} "
                  f"slope={round(sl, 6)} a={round(a, 1)}", flush=True)
        reg = _regress_endpoints(pts)
        if reg is None:
            print(f"  {fam:4s} → 端点回帰不能 (有効バンド 0)。", flush=True)
            continue
        early, late, offset = reg
        print(f"  {fam:4s} → Early={round(early, 6)} Late={round(late, 6)} "
              f"Offset={round(offset, 1)} (有効バンド {len(pts)})", flush=True)
        lines.append(f"Council_WR_Scale_{KEY}_Early {round(early, 6)}")
        lines.append(f"Council_WR_Scale_{KEY}_Late {round(late, 6)}")
        if fit_offset:
            lines.append(f"Council_WR_Offset_{KEY} {round(offset, 1)}")

    if lines:
        try:
            with open(out, "w", encoding="utf-8") as f:
                f.write("# [SF-WDL] wdl fit 結果 (cp→winrate の GP 依存 slope + 中心 offset)。\n")
                f.write("# setup_config.txt / config.txt に設定するか SPSA 起点に使う。\n")
                f.write("\n".join(lines) + "\n")
            print(f"[wdl fit] {len(lines)} 行を {out} へ出力。"
                  " setup_config.txt/config.txt へ反映 (または SPSA 起点に)。", flush=True)
        except OSError as e:
            print(f"[wdl fit] 出力失敗: {e}", flush=True)
    else:
        print("[wdl fit] 有効データ不足 — stats.txt に win/lose/draw 結果 + "
              "dl_top_score/nnue_score_cp/game_phase が必要。", flush=True)



_FLIP_PIECES = ["歩", "香", "桂", "銀", "金", "角", "飛", "玉",
                "と", "杏", "圭", "全", "馬", "龍"]
_FLIP_FONT_NAME = "PyfamateFlip"


def _flip_find_cjk_font():
    import glob
    cands = []
    if sys.platform.startswith("win"):
        d = os.path.join(os.environ.get("WINDIR", r"C:\Windows"), "Fonts")
        cands = [os.path.join(d, n) for n in
                 ("meiryo.ttc", "YuGothM.ttc", "YuGothR.ttc", "msgothic.ttc",
                  "BIZ-UDGothicR.ttc", "msmincho.ttc")]
    else:
        import subprocess as _sp
        try:
            r = _sp.run(["fc-match", "-f", "%{file}", ":lang=ja"],
                        capture_output=True, text=True, timeout=5,
                        stdin=_sp.DEVNULL)
            if r.returncode == 0 and r.stdout.strip():
                cands.append(r.stdout.strip())
        except Exception as _e:
            _flog(f"[ignored] _flip_find_cjk_font: {_e!r}")
        _names = ("NotoSansCJK", "NotoSerifCJK", "NotoSansJP", "SourceHanSans",
                  "SourceHanSerif", "ipag", "ipaexg", "ipam", "ipaexm",
                  "TakaoGothic", "VL-Gothic", "DroidSansJapanese", "Hiragino")
        for base in ("/usr/share/fonts", "/usr/local/share/fonts",
                     os.path.expanduser("~/.local/share/fonts"), os.path.expanduser("~/.fonts"),
                     "/Library/Fonts", "/System/Library/Fonts"):
            if not os.path.isdir(base):
                continue
            for ext in ("ttf", "ttc", "otf"):
                for p in glob.glob(os.path.join(base, "**", "*." + ext), recursive=True):
                    if any(nm.lower() in os.path.basename(p).lower() for nm in _names):
                        cands.append(p)
    from fontTools.ttLib import TTFont
    def _scan(paths):
        for p in paths:
            if not os.path.exists(p):
                continue
            for idx in range(4):
                try:
                    cm = TTFont(p, fontNumber=idx).getBestCmap()
                except Exception:
                    break
                if all(ord(ch) in cm for ch in _FLIP_PIECES):
                    return (p, idx)
        return None
    hit = _scan(cands)
    if hit:
        return hit
    if sys.platform.startswith("win") or not _auto_install_ok():
        return None
    hit = _auto_install_cjk_font()
    return hit


def _auto_install_cjk_font():
    import shutil, subprocess as _sp
    _flog("[AUTO-FONT] CJK フォント未検出 — 自動インストールを試行")
    _installed = False
    _pkg_cmds = []
    if shutil.which("apt-get"):
        _pkg_cmds = [["sudo", "-n", "apt-get", "install", "-y", "fonts-noto-cjk"]]
    elif shutil.which("dnf"):
        _pkg_cmds = [["sudo", "-n", "dnf", "install", "-y", "google-noto-sans-cjk-fonts"]]
    elif shutil.which("pacman"):
        _pkg_cmds = [["sudo", "-n", "pacman", "-S", "--noconfirm", "noto-fonts-cjk"]]
    elif shutil.which("zypper"):
        _pkg_cmds = [["sudo", "-n", "zypper", "install", "-y", "noto-sans-cjk-fonts"]]
    elif shutil.which("brew"):
        _pkg_cmds = [["brew", "install", "--cask", "font-noto-sans-cjk"]]
    for cmd in _pkg_cmds:
        try:
            _flog(f"[AUTO-FONT] running: {' '.join(cmd)}")
            r = _sp.run(cmd, capture_output=True, timeout=300,
                        stdin=_sp.DEVNULL)
            if r.returncode == 0:
                _flog("[AUTO-FONT] パッケージインストール成功")
                _installed = True
                break
            _flog(f"[AUTO-FONT] package install failed (rc={r.returncode}): "
                  f"{(r.stderr or b'')[:200]}")
        except Exception as e:
            _flog(f"[AUTO-FONT] package install exception: {e!r}")
    if not _installed:
        _installed = _auto_install_cjk_font_user_local()
    if _installed:
        try:
            _sp.run(["fc-cache", "-f"], capture_output=True, timeout=30,
                    stdin=_sp.DEVNULL)
        except Exception as _e:
            _flog(f"[ignored] _auto_install_cjk_font: {_e!r}")
    return _rescan_cjk_fonts()


def _auto_install_cjk_font_user_local():
    import urllib.request, zipfile, io
    _dest = os.path.join(os.path.expanduser("~"), ".local", "share", "fonts")
    os.makedirs(_dest, exist_ok=True)
    _urls = [
        ("https://moji.or.jp/wp-content/ipafont/IPAexfont/IPAexfont00401.zip",
         "ipaexg.ttf"),
        ("https://moji.or.jp/wp-content/ipafont/IPAfont/IPAfont00303.zip",
         "ipag.ttf"),
    ]
    for url, target_name in _urls:
        try:
            _flog(f"[AUTO-FONT] user-local DL: {url}")
            req = urllib.request.Request(url, headers={"User-Agent": "Pyfamate/1.0"})
            with urllib.request.urlopen(req, timeout=60) as resp:
                data = resp.read()
            with zipfile.ZipFile(io.BytesIO(data)) as zf:
                for name in zf.namelist():
                    if name.lower().endswith((".ttf", ".otf")):
                        out_path = os.path.join(_dest, os.path.basename(name))
                        with open(out_path, "wb") as f:
                            f.write(zf.read(name))
                        _flog(f"[AUTO-FONT] extracted: {out_path}")
            _flog("[AUTO-FONT] user-local install 成功")
            return True
        except Exception as e:
            _flog(f"[AUTO-FONT] user-local DL failed: {e!r}")
    return False


def _rescan_cjk_fonts():
    import glob
    from fontTools.ttLib import TTFont
    _names = ("NotoSansCJK", "NotoSerifCJK", "NotoSansJP", "SourceHanSans",
              "SourceHanSerif", "ipag", "ipaexg", "ipam", "ipaexm",
              "TakaoGothic", "VL-Gothic")
    cands = []
    for base in ("/usr/share/fonts", "/usr/local/share/fonts",
                 os.path.expanduser("~/.local/share/fonts"),
                 os.path.expanduser("~/.fonts")):
        if not os.path.isdir(base):
            continue
        for ext in ("ttf", "ttc", "otf"):
            for p in glob.glob(os.path.join(base, "**", "*." + ext), recursive=True):
                if any(nm.lower() in os.path.basename(p).lower() for nm in _names):
                    cands.append(p)
    for p in cands:
        if not os.path.exists(p):
            continue
        for idx in range(4):
            try:
                cm = TTFont(p, fontNumber=idx).getBestCmap()
            except Exception:
                break
            if all(ord(ch) in cm for ch in _FLIP_PIECES):
                _flog(f"[AUTO-FONT] found: {p} (index {idx})")
                return (p, idx)
    _flog("[AUTO-FONT] インストール後もフォント未検出")
    return None


def _flip_build_font(out_path, mode="plain", ks_path=None):
    import math
    from fontTools.ttLib import TTFont
    from fontTools.fontBuilder import FontBuilder
    from fontTools.pens.ttGlyphPen import TTGlyphPen
    from fontTools.pens.transformPen import TransformPen
    from fontTools.pens.recordingPen import DecomposingRecordingPen
    from fontTools.pens.boundsPen import BoundsPen
    from fontTools.misc.transform import Transform

    found = _flip_find_cjk_font()
    if not found:
        raise RuntimeError("システム CJK フォント未検出 (漢数字/な/し の反転生成に必要)")
    sysf = TTFont(found[0], fontNumber=found[1])
    sgs = sysf.getGlyphSet(); scmap = sysf.getBestCmap(); smtx = sysf["hmtx"].metrics
    upm = sysf["head"].unitsPerEm; asc = sysf["hhea"].ascent; desc = sysf["hhea"].descent
    glyphs = {".notdef": TTGlyphPen(None).glyph()}
    order = [".notdef"]; metrics = {".notdef": (upm, 0)}; charmap = {}

    def _bb(fn):
        bp = BoundsPen(None); fn(bp); return bp.bounds or (0, 0, 0, 0)

    def _emit(name, cp, gs_src, glyphname, adv, rotate, scale=1.0):
        rec = DecomposingRecordingPen(gs_src); gs_src[glyphname].draw(rec)
        base = Transform().scale(scale)
        sb = _bb(lambda p: rec.replay(TransformPen(p, base)))
        if rotate:
            cx, cy = (sb[0] + sb[2]) / 2.0, (sb[1] + sb[3]) / 2.0
            t = Transform().translate(cx, cy).rotate(math.pi).translate(-cx, -cy).scale(scale)
        else:
            t = base
        pen = TTGlyphPen(None); rec.replay(TransformPen(pen, t))
        lsb = int(_bb(lambda p: rec.replay(TransformPen(p, t)))[0])
        glyphs[name] = pen.glyph(); order.append(name)
        metrics[name] = (int(round(adv * scale)), lsb); charmap[cp] = name

    if mode == "ks":
        if not ks_path:
            raise ValueError("ks モードは ks_path (KsShogiPieces.ttf) が必要")
        ksf = TTFont(ks_path); kgs = ksf.getGlyphSet(); kcmap = ksf.getBestCmap(); kmtx = ksf["hmtx"].metrics
        ksc = upm / float(ksf["head"].unitsPerEm)
        gl = ['i', 'h', 'g', 'f', 'e', 'd', 'c', 'a', 'y', 'x', 'w', 'v', 't', 's']
        gu = ['I', 'H', 'G', 'F', 'E', 'D', 'C', 'A', 'Y', 'X', 'W', 'V', 'T', 'S']
        for i in range(14):
            if ord(gl[i]) not in kcmap:
                raise ValueError("指定フォントに K's の駒グリフが無い — 正しい KsShogiPieces.ttf を")
            gn = kcmap[ord(gl[i])]; un = kcmap[ord(gu[i])]
            _emit("g%02d" % i, 0xE000 + i, kgs, gn, kmtx[gn][0], False, ksc)
            _emit("s%02d" % i, 0xE010 + i, kgs, un, kmtx[un][0], False, ksc)
    else:
        for i, ch in enumerate(_FLIP_PIECES):
            gn = scmap[ord(ch)]; adv = smtx[gn][0]
            _emit("g%02d" % i, 0xE000 + i, sgs, gn, adv, True)
            _emit("s%02d" % i, 0xE010 + i, sgs, gn, adv, False)
    for i, ch in enumerate(_FLIP_EXTRA):
        if ord(ch) not in scmap:
            continue
        gn = scmap[ord(ch)]
        _emit("x%02d" % i, 0xE020 + i, sgs, gn, smtx[gn][0], True)

    fb = FontBuilder(upm, isTTF=True)
    fb.setupGlyphOrder(order)
    fb.setupCharacterMap(charmap)
    fb.setupGlyf(glyphs)
    fb.setupHorizontalMetrics(metrics)
    fb.setupHorizontalHeader(ascent=asc, descent=desc)
    fb.setupNameTable({"familyName": _FLIP_FONT_NAME, "styleName": "Regular"})
    fb.setupOS2(sTypoAscender=asc, sTypoDescender=desc, usWinAscent=asc, usWinDescent=-desc)
    fb.setupPost()
    fb.save(out_path)


def _flip_install_font(ttf_path):
    import shutil
    fname = os.path.basename(ttf_path)
    if sys.platform.startswith("win"):
        _la = os.environ.get("LOCALAPPDATA", "")
        if not _la:
            return ("LOCALAPPDATA 未設定 — フォント自動インストール不可。"
                    "%s を手動で Fonts に配置してください。" % ttf_path)
        dest_dir = os.path.join(_la, "Microsoft", "Windows", "Fonts")
        os.makedirs(dest_dir, exist_ok=True)
        dest = os.path.join(dest_dir, fname)
        shutil.copyfile(ttf_path, dest)
        try:
            import winreg
            k = winreg.CreateKey(winreg.HKEY_CURRENT_USER,
                                 r"SOFTWARE\Microsoft\Windows NT\CurrentVersion\Fonts")
            winreg.SetValueEx(k, "%s (TrueType)" % _FLIP_FONT_NAME, 0, winreg.REG_SZ, dest)
            winreg.CloseKey(k)
        except Exception as e:
            return "コピー済 (%s) だがレジストリ登録失敗: %s — 手動インストールを。" % (dest, e)
        return "ユーザー単位インストール済: %s (フォント名 %s)" % (dest, _FLIP_FONT_NAME)
    dest_dir = os.path.join(os.path.expanduser("~"), ".local", "share", "fonts")
    if sys.platform == "darwin":
        dest_dir = os.path.join(os.path.expanduser("~"), "Library", "Fonts")
    os.makedirs(dest_dir, exist_ok=True)
    dest = os.path.join(dest_dir, fname)
    shutil.copyfile(ttf_path, dest)
    import subprocess
    subprocess.run(["fc-cache", "-f", dest_dir], capture_output=True, timeout=30)
    if sys.platform == "darwin":
        return ("インストール済: %s — 端末のフォントを %s に手動設定してください "
                "(mac は自動適用不可)。" % (dest, _FLIP_FONT_NAME))
    return "インストール済: %s / %s" % (dest, _flip_setup_fontconfig_fallback())


_FLIP_FC_CONF_NAME = "99-pyfamate-flip.conf"


def _flip_setup_fontconfig_fallback():
    conf_dir = os.path.join(
        os.environ.get("XDG_CONFIG_HOME") or os.path.expanduser("~/.config"),
        "fontconfig", "conf.d")
    conf = os.path.join(conf_dir, _FLIP_FC_CONF_NAME)
    xml = (
        '<?xml version="1.0"?>\n'
        '<!DOCTYPE fontconfig SYSTEM "fonts.dtd">\n'
        '<!-- Pyfamate flip-font: PUA (U+E000..) 反転駒グリフのフォールバック。\n'
        '     このファイルを削除すれば完全に無効化されます。 -->\n'
        '<fontconfig>\n'
        '  <match target="pattern">\n'
        '    <edit name="family" mode="append_last" binding="weak">\n'
        '      <string>%s</string>\n'
        '    </edit>\n'
        '  </match>\n'
        '</fontconfig>\n' % _FLIP_FONT_NAME)
    try:
        if os.path.exists(conf) and open(conf, encoding="utf-8").read() == xml:
            return "fontconfig フォールバック登録済 (%s) — 端末フォント変更不要。" % conf
        os.makedirs(conf_dir, exist_ok=True)
        open(conf, "w", encoding="utf-8").write(xml)
        import subprocess
        subprocess.run(["fc-cache", "-f"], capture_output=True, timeout=30)
        return ("fontconfig フォールバック登録: %s "
                "(端末フォント変更不要・新しい端末ウィンドウから反映)。" % conf)
    except Exception as e:
        return ("fontconfig 登録失敗 (非致命): %s — 端末フォントを %s に手動設定を。"
                % (e, _FLIP_FONT_NAME))


def _flip_set_user_env_live_flip_font():
    if os.name != "nt":
        return
    import winreg
    k = winreg.OpenKey(winreg.HKEY_CURRENT_USER, "Environment", 0, winreg.KEY_SET_VALUE)
    try:
        winreg.SetValueEx(k, "LIVE_FLIP_FONT", 0, winreg.REG_SZ, "1")
    finally:
        winreg.CloseKey(k)
    import ctypes
    from ctypes import wintypes
    HWND_BROADCAST = 0xFFFF
    WM_SETTINGCHANGE = 0x001A
    SMTO_ABORTIFHUNG = 0x0002
    res = wintypes.DWORD()
    ctypes.windll.user32.SendMessageTimeoutW(
        HWND_BROADCAST, WM_SETTINGCHANGE, 0,
        ctypes.c_wchar_p("Environment"),
        SMTO_ABORTIFHUNG, 1000, ctypes.byref(res))


def _flip_register_console_face():
    if os.name != "nt":
        return
    import winreg
    for _title in ("engine.py", "engine.exe", "Pyfamate"):
        _path = r"Console\%s" % _title
        try:
            k = winreg.CreateKey(winreg.HKEY_CURRENT_USER, _path)
        except Exception:
            continue
        try:
            winreg.SetValueEx(k, "FaceName", 0, winreg.REG_SZ, _FLIP_FONT_NAME)
            winreg.SetValueEx(k, "FontFamily", 0, winreg.REG_DWORD, 54)
            winreg.SetValueEx(k, "FontWeight", 0, winreg.REG_DWORD, 400)
        finally:
            winreg.CloseKey(k)
    import ctypes
    ctypes.windll.kernel32.SetConsoleTitleW("engine.py")


def _flip_strip_jsonc(text):
    out = []
    i, n = 0, len(text)
    in_str = False
    escape = False
    while i < n:
        c = text[i]
        if in_str:
            out.append(c)
            if escape:
                escape = False
            elif c == "\\":
                escape = True
            elif c == '"':
                in_str = False
            i += 1
            continue
        if c == '"':
            in_str = True
            out.append(c)
            i += 1
            continue
        if c == "/" and i + 1 < n and text[i + 1] == "/":
            j = text.find("\n", i)
            i = n if j == -1 else j
            continue
        if c == "/" and i + 1 < n and text[i + 1] == "*":
            j = text.find("*/", i + 2)
            i = n if j == -1 else j + 2
            continue
        out.append(c)
        i += 1
    cleaned = "".join(out)
    cleaned = re.sub(r",(\s*[}\]])", r"\1", cleaned)
    return cleaned


def _flip_setup_windows_terminal(engine_dir):
    import json

    _preserve_comments = os.environ.get(
        "PYFAMATE_WT_PRESERVE_COMMENTS", "").strip().lower() in ("1", "true", "yes")

    la = os.environ.get("LOCALAPPDATA", "")
    cands = [os.path.join(la, r"Packages\Microsoft.WindowsTerminal_8wekyb3d8bbwe\LocalState\settings.json"),
             os.path.join(la, r"Packages\Microsoft.WindowsTerminalPreview_8wekyb3d8bbwe\LocalState\settings.json"),
             os.path.join(la, r"Microsoft\Windows Terminal\settings.json")]
    path = next((p for p in cands if os.path.exists(p)), None)
    if not path:
        path = next((p for p in cands if os.path.isdir(os.path.dirname(p))),
                     os.path.join(la, r"Microsoft\Windows Terminal\settings.json"))
        os.makedirs(os.path.dirname(path), exist_ok=True)
        _seed = {"$schema": "https://aka.ms/terminal-profiles-schema",
                 "profiles": {"defaults": {"font": {"face": _FLIP_FONT_NAME}}, "list": []}}
        open(path, "w", encoding="utf-8").write(json.dumps(_seed, ensure_ascii=False, indent=4))
        raw = open(path, encoding="utf-8").read()
        _sentinel = os.path.join(os.path.dirname(os.path.abspath(__file__)),
                                 "_fontcheck", "wt_defaults_patched")
        os.makedirs(os.path.dirname(_sentinel), exist_ok=True)
        open(_sentinel, "w", encoding="utf-8").write("done\n")
        _msgs = ["WT settings.json 新規作成 (font.face=%s): %s" % (_FLIP_FONT_NAME, path)]
    elif _preserve_comments:
        return ("WT settings.json は既存 (PYFAMATE_WT_PRESERVE_COMMENTS=1 のため"
                "コメント消失を避けて書き換えをスキップしました。手動で "
                'profiles.defaults.font.face="%s" を設定してください: %s'
                % (_FLIP_FONT_NAME, path))
    else:
        raw = open(path, encoding="utf-8-sig").read()
        _msgs = []

    _sentinel = os.path.join(os.path.dirname(os.path.abspath(__file__)),
                             "_fontcheck", "wt_defaults_patched")
    _defaults_ok = False
    if '"profiles"' in raw:
        try:
            _ck_clean = _flip_strip_jsonc(raw)
            _ck_doc = json.loads(_ck_clean)
            _ck_prof = _ck_doc.get("profiles", {})
            if isinstance(_ck_prof, dict):
                _ck_face = _ck_prof.get("defaults", {}).get("font", {}).get("face")
                _defaults_ok = (_ck_face == _FLIP_FONT_NAME)
        except Exception as _e:
            _flog(f"[ignored] _flip_setup_windows_terminal: {_e!r}")
    if not _defaults_ok and ('"profiles"' in raw):
        _clean = ""
        try:
            _clean = _flip_strip_jsonc(raw)
            doc = json.loads(_clean)
            prof = doc.setdefault("profiles", {})
            if isinstance(prof, dict):
                dflt = prof.setdefault("defaults", {})
                font = dflt.setdefault("font", {})
                if font.get("face") != _FLIP_FONT_NAME:
                    font["face"] = _FLIP_FONT_NAME
                    new_text = json.dumps(doc, ensure_ascii=False, indent=4)
                    open(path + ".pyfamate.defaults.bak", "w", encoding="utf-8").write(raw)
                    open(path, "w", encoding="utf-8").write(new_text)
                    raw = new_text
                    os.makedirs(os.path.dirname(_sentinel), exist_ok=True)
                    open(_sentinel, "w", encoding="utf-8").write("done\n")
                    _msgs.append("WT profiles.defaults.font.face=%s 上書き完了 "
                                 "(backup: settings.json.pyfamate.defaults.bak)" % _FLIP_FONT_NAME)
        except json.JSONDecodeError as e:
            _ctx_lo = max(0, e.pos - 40)
            _ctx_hi = min(len(_clean), e.pos + 40)
            _flog(f"[flip-auto] WT defaults JSON parse 失敗詳細: {e} "
                  f"周辺テキスト={_clean[_ctx_lo:_ctx_hi]!r}")
            _msgs.append("WT defaults 上書き失敗 (非致命): %s" % e)
        except Exception as e:
            _msgs.append("WT defaults 上書き失敗 (非致命): %s" % e)

    _wt_pid = os.environ.get("WT_PROFILE_ID", "").strip().lower()
    if _wt_pid:
        try:
            _ap_clean = _flip_strip_jsonc(raw)
            _ap_doc = json.loads(_ap_clean)
            _ap_list = _ap_doc.get("profiles", {}).get("list", [])
            _ap_hit = next((p for p in _ap_list
                            if isinstance(p, dict)
                            and str(p.get("guid", "")).lower() == _wt_pid), None)
            if _ap_hit is not None:
                _ap_face = _ap_hit.get("font", {}).get("face") \
                           if isinstance(_ap_hit.get("font"), dict) else None
                if _ap_face and _ap_face != _FLIP_FONT_NAME:
                    _ap_hit.setdefault("font", {})["face"] = _FLIP_FONT_NAME
                    new_text = json.dumps(_ap_doc, ensure_ascii=False, indent=4)
                    open(path + ".pyfamate.activeprofile.bak",
                         "w", encoding="utf-8").write(raw)
                    open(path, "w", encoding="utf-8").write(new_text)
                    raw = new_text
                    _msgs.append("WT 現在プロファイル (%s, name=%s) の font.face を "
                                 "%s → %s に上書き (backup: "
                                 "settings.json.pyfamate.activeprofile.bak)"
                                 % (_wt_pid, _ap_hit.get("name", "?"),
                                    _ap_face, _FLIP_FONT_NAME))
        except Exception as e:
            _msgs.append("WT 現在プロファイル上書き失敗 (非致命): %s" % e)

    if "Pyfamate (flip)" in raw:
        _msgs.append("WT プロファイル「Pyfamate (flip)」既存 (スキップ)")
    else:
        _clean2 = ""
        try:
            _clean2 = _flip_strip_jsonc(raw)
            doc2 = json.loads(_clean2)
            prof2 = doc2.setdefault("profiles", {})
            if isinstance(prof2, dict):
                lst = prof2.setdefault("list", [])
                if isinstance(lst, list):
                    prof_obj = {
                        "name": "Pyfamate (flip)",
                        "guid": "{e1d2c3b4-a5f6-4789-9abc-def012345678}",
                        "font": {"face": _FLIP_FONT_NAME},
                        "startingDirectory": engine_dir,
                        "commandline": 'powershell.exe -NoExit -Command '
                                       '"$env:LIVE_FLIP_FONT=1"',
                    }
                    lst.insert(0, prof_obj)
                    new_text = json.dumps(doc2, ensure_ascii=False, indent=4)
                    open(path + ".pyfamate.bak", "w", encoding="utf-8").write(raw)
                    open(path, "w", encoding="utf-8").write(new_text)
                    raw = new_text
                    _msgs.append("WT プロファイル「Pyfamate (flip)」追加")
                else:
                    _msgs.append("profiles.list が配列でないため追加スキップ")
            else:
                _msgs.append("profiles が想定外の型のため追加スキップ")
        except json.JSONDecodeError as e:
            _ctx_lo = max(0, e.pos - 40)
            _ctx_hi = min(len(_clean2), e.pos + 40)
            _flog(f"[flip-auto] WT プロファイル追加 JSON parse 失敗詳細: {e} "
                  f"周辺テキスト={_clean2[_ctx_lo:_ctx_hi]!r}")
            _msgs.append("WT プロファイル追加で JSON 検証失敗 (変更せず): %s" % e)
        except Exception as e:
            _msgs.append("WT プロファイル追加で JSON 検証失敗 (変更せず): %s" % e)

    return " / ".join(_msgs) if _msgs else "WT 変更なし"


def _flip_setup_cli(args):
    kv = {}; flags = set(); it = iter(args)
    for a in it:
        if a.startswith("--"):
            k = a[2:]
            if k in ("no-install", "no-terminal", "check"):
                flags.add(k)
            else:
                kv[k] = next(it, "")
    if "check" in flags:
        _sr_configure_render(force=True)
        _w = {(hex(ord(c)) if ord(c) >= 0xE000 else c): v
              for c, v in _SR_MEASURED_W.items()}
        print("[check] 実測幅: %s" % (_w or "(測定不能: 非TTY か DSR 未対応端末)"), flush=True)
        print("[check] flip=%s %s" % (_sr_flip_font_active(), _SR_PROBE_NOTE or "OK"),
              flush=True)
        print("0123456789" * 3, flush=True)
        print("".join(_sr_cell(p) for p in ("p", "l", "n", "s", "g", "b", "r", "k")),
              flush=True)
        print("".join(_sr_cell(p) for p in ("P", "L", "N", "S", "G", "B", "R", "K")),
              flush=True)
        print("▲▽■□──  ← 各行が定規と桁一致し、駒が上下反転して見えれば正常", flush=True)
        return
    mode = kv.get("mode", "plain")
    engine_dir = os.path.dirname(os.path.abspath(__file__))
    out = kv.get("out") or os.path.join(engine_dir, "_fontcheck", _FLIP_FONT_NAME + ".ttf")
    os.makedirs(os.path.dirname(out) or ".", exist_ok=True)
    try:
        import fontTools
    except ImportError:
        print("[flip] fontTools が必要です: pip install fonttools", flush=True); return
    if mode == "ks":
        ks = kv.get("ks-font", "")
        if not ks or not os.path.exists(ks):
            print("[flip] --ks-font に KsShogiPieces.ttf のパスを指定してください "
                  "(K's は再配布不可・各自入手 https://ksbookshelf.com/FD/KsShogiPieces.zip)", flush=True); return
        _flip_build_font(out, mode="ks", ks_path=ks)
        print("[flip] K's タイル版を生成: %s" % out, flush=True)
    else:
        found = _flip_find_cjk_font()
        if not found:
            print("[flip] システムの CJK フォントが見つかりません "
                  "(Noto Sans CJK / IPAGothic 等を入れてください)。", flush=True); return
        base, idx = found
        print("[flip] base CJK font: %s (index %d)" % (base, idx), flush=True)
        _flip_build_font(out, mode="plain")
        print("[flip] 素の漢字反転版を生成: %s" % out, flush=True)
    if "no-install" not in flags:
        print("[flip] " + _flip_install_font(out), flush=True)
    if sys.platform.startswith("win") and "no-terminal" not in flags:
        print("[flip] " + _flip_setup_windows_terminal(engine_dir), flush=True)
    print("[flip] 完了 (先手=正立/後手=反転)。Windows は WT/conhost へ、Linux は "
          "fontconfig フォールバックで自動適用 (新しい端末ウィンドウから)。mac のみ端末"
          "フォントを %s に手動設定。反映確認は `flip-font --check`。有効/無効は起動時の"
          "端末実測で自動判定 (LIVE_FLIP_FONT=0 で強制OFF / LIVE_FLIP_FONT_FORCE=1 で"
          "強制ON)。" % _FLIP_FONT_NAME, flush=True)



def _ensure_lint_tools():
    for _mod, _pkg in (("mypy", "mypy==1.11.*"), ("ruff.__main__", "ruff")):
        try:
            __import__(_mod)
        except ImportError:
            if _auto_install_ok():
                _pip_install([_pkg])
            else:
                print(f"[lint] {_pkg} が見つかりません (PYFAMATE_NO_AUTO_INSTALL=1)")
                return False
    return True


def _lint_cli(rest):
    _me = os.path.abspath(__file__)
    _base = os.path.dirname(_me)
    _baseline_path = os.path.join(_base, "lint_baseline.json")

    if not _ensure_lint_tools():
        sys.exit(1)

    import subprocess as _sp

    print("[lint] ruff check …")
    _ruff_rc = _sp.call([sys.executable, "-m", "ruff", "check",
                         "--select", "F821,F811,F841", _me])
    if _ruff_rc != 0:
        print(f"[lint] ruff: {_ruff_rc} error(s)")

    print("[lint] mypy check …")
    _mypy_args = [
        sys.executable, "-m", "mypy", _me,
        "--python-version", "3.11",
        "--check-untyped-defs",
        "--ignore-missing-imports",
        "--allow-redefinition",
        "--cache-dir", os.path.join(_base, ".mypy_cache"),
        "--enable-error-code", "used-before-def",
        "--enable-error-code", "possibly-undefined",
        "--disable-error-code", "assignment",
        "--disable-error-code", "arg-type",
        "--disable-error-code", "union-attr",
        "--disable-error-code", "index",
        "--disable-error-code", "operator",
        "--disable-error-code", "var-annotated",
        "--no-error-summary",
    ]
    _mypy_proc = _sp.run(_mypy_args, capture_output=True, text=True)
    _mypy_lines = [ln for ln in (_mypy_proc.stdout or "").strip().splitlines()
                   if ln.strip() and ": error" in ln]

    _code_counts = {}
    for _ln in _mypy_lines:
        _ec = "unknown"
        if "  [" in _ln and _ln.rstrip().endswith("]"):
            _ec = _ln.rstrip().rsplit("[", 1)[1].rstrip("]")
        _code_counts[_ec] = _code_counts.get(_ec, 0) + 1

    _baseline = {}
    if os.path.isfile(_baseline_path):
        try:
            with open(_baseline_path, encoding="utf-8") as _f:
                _baseline = json.loads(_f.read())
        except Exception as _e:
            _flog(f"[ignored] _lint_cli: {_e!r}")

    _regressed = False
    for _c, _n in _code_counts.items():
        _b = _baseline.get(_c, 0)
        if _n > _b:
            print(f"[lint] REGRESSION: [{_c}] {_b}→{_n} (+{_n - _b})")
            _regressed = True

    _updated = False
    for _c, _n in list(_code_counts.items()):
        if _n < _baseline.get(_c, _n + 1):
            _updated = True
    for _c in list(_baseline):
        if _c not in _code_counts:
            _updated = True

    if _updated or not _baseline:
        try:
            with open(_baseline_path, "w", encoding="utf-8") as _f:
                _f.write(json.dumps(_code_counts, indent=2, sort_keys=True) + "\n")
            print(f"[lint] baseline 更新: {_baseline_path}")
        except Exception as _e:
            print(f"[lint] baseline 書き込み失敗: {_e}")

    _total = sum(_code_counts.values())
    print(f"[lint] mypy: {_total} error(s) "
          + " ".join(f"[{c}]={n}" for c, n in sorted(_code_counts.items())))
    if _ruff_rc != 0:
        print("[lint] ruff: FAIL")
    if _regressed:
        print("[lint] baseline 超過: FAIL")
        sys.exit(1)
    if _ruff_rc != 0:
        sys.exit(1)
    print("[lint] OK")



_KIF_PIECE = {"P": "歩", "L": "香", "N": "桂", "S": "銀", "G": "金",
              "B": "角", "R": "飛", "K": "玉",
              "+P": "と", "+L": "成香", "+N": "成桂", "+S": "成銀",
              "+B": "馬", "+R": "龍"}
_KIF_COL = "０１２３４５６７８９"
_KIF_ROW = "〇一二三四五六七八九"

_KIF_REASON_END = {
    "resign": "投了", "win_declare": "入玉宣言", "sennichite": "千日手",
    "perpetual_check": "千日手", "flag_fall": "切れ負け",
    "game_timeout": "切れ負け", "jishogi": "持将棋",
    "move_limit": "持将棋", "illegal": "反則負け", "adjudication": "投了",
}
_CSA_REASON_SYM = {
    "resign": "%TORYO", "win_declare": "%KACHI", "sennichite": "%SENNICHITE",
    "perpetual_check": "%SENNICHITE", "flag_fall": "%TIME_UP",
    "game_timeout": "%TIME_UP", "jishogi": "%JISHOGI",
    "move_limit": "%JISHOGI", "illegal": "%ILLEGAL_MOVE",
    "adjudication": "%TORYO",
}


def _kif_move_str(board, usi):
    if "*" in usi:
        piece_ch = usi[0]
        to_col = int(usi[2])
        to_row = int(usi[3])
        pname = _KIF_PIECE.get(piece_ch, piece_ch)
        return "%s%s%s打" % (_KIF_COL[to_col], _KIF_ROW[to_row], pname)
    from_col = int(usi[0])
    from_row = int(usi[1])
    to_col = int(usi[2])
    to_row = int(usi[3])
    promote = len(usi) > 4 and usi[4] == "+"
    pc = board.board.get((from_col, from_row), "")
    pname = _KIF_PIECE.get(pc, pc)
    origin = "(%d%d)" % (from_col, from_row)
    promo_s = "成" if promote else ""
    return "%s%s%s%s%s" % (_KIF_COL[to_col], _KIF_ROW[to_row], pname, promo_s, origin)


def _kifconv_cli(rest):
    if not rest:
        print("usage: Pyfamate.py kifconv <in.sfen> [format=kif|csa] [out=<dir>]")
        return
    in_path = rest[0]
    fmt = "kif"
    out_dir = os.path.dirname(in_path) or "."
    for a in rest[1:]:
        if a.startswith("format="):
            fmt = a.split("=", 1)[1].lower()
        elif a.startswith("out="):
            out_dir = a.split("=", 1)[1]
    stem = os.path.splitext(os.path.basename(in_path))[0]
    try:
        with open(in_path, encoding="utf-8") as f:
            lines = f.readlines()
    except OSError as e:
        print("error: %s" % e)
        return
    n_ok = 0
    n_skip = 0
    for idx, raw_line in enumerate(lines):
        raw_line = raw_line.strip()
        if not raw_line or raw_line.startswith("#"):
            continue
        parsed = _game_phase_fit_parse_kif_line(raw_line)
        if parsed is None:
            n_skip += 1
            continue
        origin, mvs_raw, terminal = parsed
        toks = raw_line.split()
        reason = None
        result_tok = None
        for t in reversed(toks):
            if t in _SFEN_KIFU_RESULTS:
                result_tok = t
            elif t in _SFEN_KIFU_REASONS and reason is None:
                reason = t
            else:
                break
        if origin != "startpos":
            print("warning: line %d: non-startpos origin — skipped" % (idx + 1))
            n_skip += 1
            continue
        try:
            board = ShogiBoard()
            out_path = os.path.join(out_dir, "%s_%04d.%s" % (stem, idx + 1, fmt))
            if fmt == "csa":
                csa_lines = ["'CSA encoding=UTF-8", "V2.2",
                             "N+sente", "N-gote", "PI", "+"]
                for m in mvs_raw:
                    csa_m = board.usi_to_csa(m)
                    if csa_m:
                        csa_lines.append(csa_m)
                    board.apply_usi(m)
                end_sym = _CSA_REASON_SYM.get(reason, "%TORYO")
                csa_lines.append(end_sym)
                if reason or result_tok:
                    csa_lines.append("'result=%s reason=%s" % (result_tok or "", reason or ""))
                with open(out_path, "w", encoding="utf-8") as w:
                    w.write("\n".join(csa_lines) + "\n")
            else:
                kif_lines = ["手合割：平手", "先手：sente", "後手：gote",
                             "手数----指手---------消費時間--"]
                for mi, m in enumerate(mvs_raw):
                    disp = _kif_move_str(board, m)
                    kif_lines.append("%4d %s" % (mi + 1, disp))
                    board.apply_usi(m)
                end_str = _KIF_REASON_END.get(reason, "投了")
                kif_lines.append("%4d %s" % (len(mvs_raw) + 1, end_str))
                if result_tok == "sente_win":
                    footer = "まで%d手で先手の勝ち" % len(mvs_raw)
                elif result_tok == "gote_win":
                    footer = "まで%d手で後手の勝ち" % len(mvs_raw)
                elif result_tok == "draw":
                    footer = "まで%d手で%s" % (len(mvs_raw), end_str)
                else:
                    footer = "まで%d手で中断" % len(mvs_raw)
                kif_lines.append(footer)
                with open(out_path, "w", encoding="utf-8") as w:
                    w.write("\n".join(kif_lines) + "\n")
            n_ok += 1
        except Exception as e:
            print("warning: line %d: conversion failed (%s) — skipped" % (idx + 1, e))
            n_skip += 1
    print("[kifconv] %d converted, %d skipped -> %s" % (n_ok, n_skip, out_dir))


def _selftest_render(rest=None):
    del rest
    _pos = "startpos"
    _base = {"nnue_bestmove": "7g7f", "dl_top_move": "2g2f", "council_winner": "2g2f",
             "nnue_score_cp": 30, "dl_used": True, "game_phase": 0.4}
    _stale = {"council_wr_nnue": 0.6, "council_wr_dl": 0.55, "council_wr_dl2": 0.5,
              "dl_2_top_move": "6g6f", "dl_2_invoked": True,
              "council_stale_withdraw": True, "endgame_veto_applied": True,
              "endgame_veto_dl_move": "5g5f", "endgame_veto_src": "dl_1",
              "ctx.endgame_mode": True}
    cases = {
        "council": dict(_base),
        "arbiter_full": dict(_base, source="council", council_source="sv_arbiter",
                             arb_p_pairwise=0.71, arb_tier="trunk", arb_abstained=False,
                             arb_tau_eff=0.64, arb_q_nnue=0.55, arb_q_dl=0.71),
        "arbiter_scalar": dict(_base, council_source="sv_arbiter", arb_p_pairwise=0.58,
                               arb_tier="scalar", arb_abstained=True, arb_tau_eff=0.62),
        "arbiter_min": dict(_base, arb_p_pairwise=0.5),
        "book": {"source": "book", "council_winner": "7g7f"},
        "ponderhit": dict(_base, handler="ponderhit"),
        "stale_keys": dict(_base, **_stale),
        "selfplay_stale": dict(_base, source="selfplay", **_stale, _orig_source="light_council"),
    }
    _fail = 0
    for name, rec in cases.items():
        try:
            out = _sr_render_think(rec, _pos)
            ok = isinstance(out, str) and len(out) > 0
            print("[selftest-render] %-16s %s (%d chars)"
                  % (name, "OK" if ok else "EMPTY", len(out) if isinstance(out, str) else -1))
        except Exception as e:
            ok = False
            print("[selftest-render] %-16s EXCEPTION %r" % (name, e))
        if not ok:
            _fail += 1
    if "裁定" not in _sr_render_think(cases["arbiter_full"], _pos):
        print("[selftest-render] arbiter_full: '裁定' 行が描画されていない"); _fail += 1
    if "裁定" in _sr_render_think(cases["council"], _pos):
        print("[selftest-render] council: 誤って '裁定' 行が出た"); _fail += 1
    _stale_out = _sr_render_think(cases["stale_keys"], _pos)
    for _lbl in ("DL₂", "DL₃", "簡易合議", "合議疲弊"):
        if _lbl in _stale_out:
            print("[selftest-render] stale_keys: 撤去した表示 '%s' が復活した" % _lbl); _fail += 1
    _sfp_out = _sr_render_think(cases["selfplay_stale"], _pos)
    if "簡易合議" in _sfp_out:
        print("[selftest-render] selfplay_stale: 撤去した '簡易合議' が復活した"); _fail += 1
    try:
        _end_out = _sr_render_think(cases["council"], _pos, mode="endgame")
        if not (isinstance(_end_out, str) and _end_out):
            print("[selftest-render] mode=endgame: 描画が空/例外"); _fail += 1
    except Exception as e:
        print("[selftest-render] mode=endgame: EXCEPTION %r" % e); _fail += 1
    if _fail:
        print("[SELFTEST-RENDER] FAIL — %d 件" % _fail); sys.exit(1)
    print("[SELFTEST-RENDER] OK — 全 source で例外なく描画・裁定行の presence-gate 正常 + 3声panel regression clean")
    sys.exit(0)


def _selftest_cfg_drift(rest=None):
    del rest
    try:
        _bare  = EngineConfig()
        _canon = EngineConfig.from_cfg(dict(_CONFIG_DEFAULTS))
    except Exception as e:
        print(f"[SELFTEST-CFG] FATAL: EngineConfig 生成に失敗: {e!r}", file=sys.stderr)
        sys.exit(2)

    drift = [(f.name, getattr(_bare, f.name), getattr(_canon, f.name))
             for f in dataclasses.fields(EngineConfig)
             if getattr(_bare, f.name) != getattr(_canon, f.name)]

    if not drift:
        print("[SELFTEST-CFG] OK — B(bare) == canon(A via from_cfg) 全フィールド一致")
        sys.exit(0)

    print(f"[SELFTEST-CFG] FAIL — B(bare) vs canon(A) 不一致 {len(drift)} 件:", file=sys.stderr)
    for name, bv, cv in drift:
        print(f"  B[{name}]={bv!r}  canon={cv!r}", file=sys.stderr)
    sys.exit(1)


_CONNECTIVITY_BASELINE = {
    'unused_module_functions': 21,
    'unused_module_constants': 8,
    'unused_function_arguments': 72,
    'write_only_attributes': 23,
}


def _selftest_connectivity(rest=None):
    del rest
    import ast as _ast
    from collections import Counter as _Counter
    try:
        with open(__file__, encoding='utf-8') as _fh:
            _src = _fh.read()
        _tree = _ast.parse(_src)
    except Exception as _e:
        print(f"[SELFTEST-CONN] FATAL: 自ファイル読取/parse 失敗: {_e!r}", file=sys.stderr)
        sys.exit(2)

    _name_refs = _Counter()
    _attr_reads = _Counter()
    _attr_writes = _Counter()

    class _Scan(_ast.NodeVisitor):
        def visit_Name(self, node):
            if isinstance(node.ctx, _ast.Load):
                _name_refs[node.id] += 1
            self.generic_visit(node)
        def visit_Attribute(self, node):
            if isinstance(node.ctx, _ast.Load):
                _attr_reads[node.attr] += 1
            elif isinstance(node.ctx, _ast.Store):
                _attr_writes[node.attr] += 1
            self.generic_visit(node)

    _Scan().visit(_tree)

    _name_str_refs = _Counter()
    for _m in re.finditer(r'''['"]([A-Za-z_][A-Za-z0-9_]*)['"]''', _src):
        _name_str_refs[_m.group(1)] += 1

    _EXCLUDE_FUNCS = {'main', '_csa_main', '__main__'}

    _unused_funcs = []
    for _node in _tree.body:
        if isinstance(_node, _ast.FunctionDef):
            _n = _node.name
            if _n in _EXCLUDE_FUNCS:
                continue
            if _n.startswith('__') and _n.endswith('__'):
                continue
            if _name_refs.get(_n, 0) == 0 and _name_str_refs.get(_n, 0) == 0:
                _unused_funcs.append((_node.lineno, _n))

    _unused_consts = []
    for _node in _tree.body:
        _tgts = []
        if isinstance(_node, _ast.Assign):
            _tgts = [t for t in _node.targets if isinstance(t, _ast.Name)]
        elif isinstance(_node, _ast.AnnAssign) and isinstance(_node.target, _ast.Name):
            _tgts = [_node.target]
        for _tgt in _tgts:
            _n = _tgt.id
            if not (_n.startswith('_') or _n.isupper()):
                continue
            if _n.startswith('__') and _n.endswith('__'):
                continue
            if _name_refs.get(_n, 0) == 0 and _name_str_refs.get(_n, 0) == 0:
                _unused_consts.append((_tgt.lineno, _n))

    _unused_args = []
    for _n in _ast.walk(_tree):
        if isinstance(_n, (_ast.FunctionDef, _ast.AsyncFunctionDef)):
            _body_names = set()
            for _sub in _ast.walk(_n):
                if isinstance(_sub, _ast.Name) and isinstance(_sub.ctx, _ast.Load):
                    _body_names.add(_sub.id)
            for _a in _n.args.args:
                if _a.arg in ('self', 'cls'):
                    continue
                if _a.arg not in _body_names:
                    _unused_args.append((_n.lineno, f"{_n.name}({_a.arg})"))

    _write_only = []
    for _attr, _wcount in _attr_writes.items():
        if _attr.startswith('__') and _attr.endswith('__'):
            continue
        if _attr_reads.get(_attr, 0) > 0:
            continue
        if _name_str_refs.get(_attr, 0) > 0:
            continue
        _write_only.append((_attr, _wcount))
    _write_only.sort(key=lambda x: -x[1])

    _counts = {
        'unused_module_functions': len(_unused_funcs),
        'unused_module_constants': len(_unused_consts),
        'unused_function_arguments': len(_unused_args),
        'write_only_attributes': len(_write_only),
    }
    _samples = {
        'unused_module_functions': _unused_funcs,
        'unused_module_constants': _unused_consts,
        'unused_function_arguments': _unused_args,
        'write_only_attributes': _write_only,
    }

    _ratchet_fail = False
    _ratchet_loose = []
    print('[SELFTEST-CONN] AST connectivity scan:')
    for _cat, _cur in _counts.items():
        _base = _CONNECTIVITY_BASELINE.get(_cat, _cur)
        _mark = 'OK'
        if _cur > _base:
            _mark = f'REGRESSION (+{_cur - _base})'
            _ratchet_fail = True
        elif _cur < _base:
            _mark = f'improved (-{_base - _cur}, consider ratchet update)'
            _ratchet_loose.append(_cat)
        print(f'  {_cat:32s}  current={_cur:4d}  baseline={_base:4d}  {_mark}')

    if _ratchet_fail:
        print('[SELFTEST-CONN] FAIL — 増加したカテゴリの先頭:', file=sys.stderr)
        for _cat, _cur in _counts.items():
            _base = _CONNECTIVITY_BASELINE.get(_cat, _cur)
            if _cur > _base:
                print(f'  [{_cat}] +{_cur - _base}:', file=sys.stderr)
                for _lineno_or_name, _detail in _samples[_cat][:8]:
                    print(f'    L{_lineno_or_name}  {_detail}' if isinstance(_lineno_or_name, int)
                          else f'    {_lineno_or_name} writes={_detail}', file=sys.stderr)
        sys.exit(1)

    if _ratchet_loose:
        print(f'[SELFTEST-CONN] 改善検出: {", ".join(_ratchet_loose)} — _CONNECTIVITY_BASELINE を締められます')
    print('[SELFTEST-CONN] OK — 全カテゴリ baseline 以内')
    sys.exit(0)



def _teach_parse_args(args):
    opts = {
        "bin": None, "kif_dir": None,
        "iters": 3000, "lr": 0.02, "positions": 200000,
        "pairs": 400000, "wr_pairs": 0.25, "s_weight": 1.0, "l2": 1e-3,
        "device": None, "save": None,
    }
    _FLOATS = {"--lr": "lr", "--wr-pairs": "wr_pairs",
               "--s-weight": "s_weight", "--l2": "l2"}
    _INTS = {"--iters": "iters", "--positions": "positions", "--pairs": "pairs"}
    _STRS = {"--bin": "bin", "--kif-dir": "kif_dir",
             "--device": "device", "--save": "save"}
    i = 0
    while i < len(args):
        a = args[i]
        if a in _STRS and i + 1 < len(args):
            opts[_STRS[a]] = args[i + 1]; i += 2; continue
        if a in _INTS and i + 1 < len(args):
            try: opts[_INTS[a]] = int(args[i + 1])
            except ValueError: pass
            i += 2; continue
        if a in _FLOATS and i + 1 < len(args):
            try: opts[_FLOATS[a]] = float(args[i + 1])
            except ValueError: pass
            i += 2; continue
        i += 1
    return opts


def _teach_iter_bin_files(path):
    if not path:
        return []
    if os.path.isfile(path):
        return [path]
    if os.path.isdir(path):
        out = []
        for _root, _dirs, _files in os.walk(path):
            for _fn in _files:
                if _fn.lower().endswith(".bin"):
                    out.append(os.path.join(_root, _fn))
        out.sort()
        return out
    return []


_TEACH_HAND_CAPS = (18, 4, 4, 4, 4, 2, 2)


def _teach_gp_counts(sb):
    cells = sb.cells
    h0, h1 = sb.hand[0], sb.hand[1]
    hand = [h0[_i] + h1[_i] for _i in range(7)]
    camp = [0] * 13
    promo = 0
    k0c = k0r = k1c = k1r = -1
    pcs = []
    pcs_a = pcs.append
    for idx in range(81):
        pid = cells[idx]
        if pid == 0:
            continue
        pm1 = pid - 1
        pi = pm1 % 14
        owner = pm1 // 14
        r_ = idx // 9
        c_ = idx % 9
        if pi == 7:
            if owner == 0:
                k0c = c_; k0r = r_
            else:
                k1c = c_; k1r = r_
            continue
        if pi >= 8:
            promo += 1
        rank = r_ + 1
        if (owner == 0 and rank <= 3) or (owner == 1 and rank >= 7):
            camp[pi if pi < 7 else pi - 1] += 1
        pcs_a((c_, r_, owner))
    king = 0.0
    for _kc, _kr, _owner, _entry, _ahead in (
            (k0c, k0r, 0, _GAME_PHASE_KING_SENTE_ROW, -1),
            (k1c, k1r, 1, _GAME_PHASE_KING_GOTE_ROW, 1)):
        if _kr < 0:
            continue
        _rank = _kr + 1
        raw = (_entry - _rank) if _ahead < 0 else (_rank - _entry)
        if raw < 0:
            continue
        sup = 0
        for cc, cr, po in pcs:
            if po != _owner:
                continue
            if max(abs(cc - _kc), abs(cr - _kr)) <= 2 and (
                    cr <= _kr + 1 if _ahead < 0 else cr >= _kr - 1):
                sup += 1
        if sup > 3:
            sup = 3
        king += (raw + 0.5) * (0.25 + 0.25 * sup)
    ring1 = 0
    for cc, cr, po in pcs:
        if po == 0 and k0r >= 0:
            if max(abs(cc - k0c), abs(cr - k0r)) == 1:
                ring1 += 1
        elif po == 1 and k1r >= 0:
            if max(abs(cc - k1c), abs(cr - k1r)) == 1:
                ring1 += 1
    return hand, camp, promo, king, 16 - ring1


def _teach_collect(bin_paths, max_positions):
    import numpy as _np
    H = []; C = []; P = []; K = []; E = []; PLY = []; SC = []
    rej = {"decode": 0, "hand_cap": 0, "promo": 0, "ply": 0, "score": 0}
    _sb = SvBoard()
    n = 0
    for _p in bin_paths:
        if n >= max_positions:
            break
        try:
            _f = open(_p, "rb")
        except OSError as _oe:
            _flog(f"[teach] open error: {_p!r}: {_oe!r}")
            continue
        try:
            while n < max_positions:
                _raw = _f.read(_PSV_RECORD_SIZE)
                if len(_raw) < _PSV_RECORD_SIZE:
                    break
                _data32, _score, _move16, _ply, _result, _ = _struct.unpack(_PSV_FMT, _raw)
                if abs(_score) >= 32767:
                    rej["score"] += 1; continue
                if _ply < 0 or _ply > 512:
                    rej["ply"] += 1; continue
                _sb.cells = [0] * 81
                _sb.hand = [[0] * 7, [0] * 7]
                _sb.side = 0
                try:
                    _fast_decode_psfen_into(_data32, _sb)
                except Exception:
                    rej["decode"] += 1; continue
                _capng = False
                for _side_h in _sb.hand:
                    for _i in range(7):
                        if _side_h[_i] > _TEACH_HAND_CAPS[_i]:
                            _capng = True; break
                    if _capng:
                        break
                if _capng:
                    rej["hand_cap"] += 1; continue
                _h, _c, _pr, _k, _e = _teach_gp_counts(_sb)
                if _pr > 26:
                    rej["promo"] += 1; continue
                H.append(_h); C.append(_c); P.append(_pr); K.append(_k)
                E.append(_e); PLY.append(_ply); SC.append(_score)
                n += 1
        finally:
            try: _f.close()
            except OSError: pass
    if not SC:
        return None, rej
    feats = {
        "hand":  _np.asarray(H,   dtype=_np.float32),
        "camp":  _np.asarray(C,   dtype=_np.float32),
        "promo": _np.asarray(P,   dtype=_np.float32),
        "king":  _np.asarray(K,   dtype=_np.float32),
        "expo":  _np.asarray(E,   dtype=_np.float32),
        "ply":   _np.asarray(PLY, dtype=_np.float32),
        "score": _np.asarray(SC,  dtype=_np.float32),
    }
    return feats, rej


def _teach_resolve_ply(feats, view):
    import numpy as _np
    ply = feats["ply"].copy()
    unknown = ply <= 0.0
    if not bool(unknown.any()):
        return ply
    hv0 = _np.asarray(_gp_hand_vals, dtype=_np.float32)
    cv0 = _np.asarray(_gp_camp_vals, dtype=_np.float32)
    for _i in _np.nonzero(unknown)[0]:
        _wh = float(feats["hand"][_i] @ hv0)
        _wc = float(feats["camp"][_i] @ cv0)
        _gp0 = _calc_state_phase(_wh, float(feats["promo"][_i]), _wc,
                                 float(feats["king"][_i]),
                                 float(feats["expo"][_i]), cfg=view, ply=0)
        ply[_i] = _estimate_ply_from_state(_gp0)
    return ply


def _teach_build_pairs(feats, ply, opts, rng):
    import numpy as _np
    N = len(ply)
    max_pairs = max(0, int(opts["pairs"]))
    idx_sorted = _np.argsort(ply, kind="stable")
    ply_pairs = []
    if max_pairs > 0 and N >= 2:
        want = max_pairs
        ii = rng.integers(0, N, size=want * 2)
        jj = rng.integers(0, N, size=want * 2)
        d = ply[jj] - ply[ii]
        ok = d >= 40.0
        ply_pairs = _np.stack([ii[ok], jj[ok]], axis=1)[:max_pairs]
    wr_pairs = []
    if opts["wr_pairs"] > 0.0 and N >= 2:
        sc = feats["score"]
        finite = _np.abs(sc) < 30000.0
        band = (ply // 10).astype(_np.int64)
        order = _np.lexsort((_np.abs(sc), band))
        want = max_pairs // 2 if max_pairs > 0 else 100000
        ii = rng.integers(0, N, size=want * 4)
        jj = rng.integers(0, N, size=want * 4)
        ok = (finite[ii] & finite[jj]
              & (_np.abs(ply[ii] - ply[jj]) <= 10.0)
              & ((_np.abs(sc[jj]) - _np.abs(sc[ii])) >= 800.0))
        wr_pairs = _np.stack([ii[ok], jj[ok]], axis=1)[:want]
        _ = order, idx_sorted
    import numpy as _np2
    if len(ply_pairs) == 0:
        ply_pairs = _np2.zeros((0, 2), dtype=_np2.int64)
    if len(wr_pairs) == 0:
        wr_pairs = _np2.zeros((0, 2), dtype=_np2.int64)
    return ply_pairs.astype(_np2.int64), wr_pairs.astype(_np2.int64)


def _teach_fit(_torch, feats, opts):
    import numpy as _np
    view = _game_phase_param_view()
    ply = _teach_resolve_ply(feats, view)
    rng = _np.random.default_rng(20260715)
    pp, wp = _teach_build_pairs(feats, ply, opts, rng)
    _dev = opts["device"]
    if _dev is None:
        try:
            _dev = "cuda" if _torch.cuda.is_available() else "cpu"
        except Exception:
            _dev = "cpu"
    dev = _torch.device(_dev)
    T = lambda a: _torch.from_numpy(_np.ascontiguousarray(a)).to(dev)
    Ht, Ct = T(feats["hand"]), T(feats["camp"])
    Pt, Kt, Et = T(feats["promo"]), T(feats["king"]), T(feats["expo"])
    PLYt = T(ply.astype(_np.float32))
    ppt, wpt = T(pp), T(wp)
    wh, wp_, wc = view.game_phase_w_hand, view.game_phase_w_promo, view.game_phase_w_camp
    wk, wply, we = view.game_phase_w_king, view.game_phase_w_ply, view.game_phase_w_exposure
    hr, pr, cr = view.game_phase_hand_ref, view.game_phase_promo_ref, view.game_phase_camp_ref
    kr, plyr, er = view.game_phase_king_ref, view.game_phase_ply_ref, view.game_phase_exposure_ref
    scale = view.game_phase_scale
    onset, full = (view.game_phase_nyugyoku_king_onset,
                   view.game_phase_nyugyoku_king_full)
    ply_on = bool(getattr(view, "game_phase_ply_enable", True))
    bonus = 0.5 * _torch.clamp((Kt - onset) / max(1e-9, full - onset), 0.0, 1.0)
    const_S = (wp_ * Pt / pr + wk * Kt / kr + we * Et / er
               + (wply * PLYt / plyr if ply_on else 0.0))
    hv0 = _torch.tensor(list(_gp_hand_vals), dtype=_torch.float32, device=dev)
    cv0 = _torch.tensor(list(_gp_camp_vals), dtype=_torch.float32, device=dev)
    sp = _torch.nn.functional.softplus
    def sp_inv(t):
        return _torch.log(_torch.expm1(_torch.clamp(t, min=1e-4)))
    raw_h = sp_inv(hv0[1:]).clone().requires_grad_(True)
    raw_c = sp_inv(cv0).clone().requires_grad_(True)
    one = _torch.ones(1, dtype=_torch.float32, device=dev)
    def tables():
        return _torch.cat([one, sp(raw_h)]), sp(raw_c)
    def S_of(hv, cv):
        return const_S + wh * (Ht @ hv) / hr + wc * (Ct @ cv) / cr
    def GP_of(S):
        return 1.0 - _torch.exp(-S / scale) + bonus
    def hinge_stats(S, GP, idx):
        if idx.shape[0] == 0:
            z = _torch.zeros((), device=dev)
            return z, z, 0.0
        i, j = idx[:, 0], idx[:, 1]
        h_gp = _torch.clamp(GP[i] - GP[j], min=0.0)
        h_s = _torch.clamp((S[i] - S[j]) / scale, min=0.0)
        viol = float((h_gp > 0).float().mean())
        return h_gp.mean(), h_s.mean(), viol
    def total_loss(hv, cv, sub_pp, sub_wp):
        S = S_of(hv, cv); GP = GP_of(S)
        g1, s1, _ = hinge_stats(S, GP, sub_pp)
        g2, s2, _ = hinge_stats(S, GP, sub_wp)
        l2 = ((hv - hv0) ** 2).sum() + ((cv - cv0) ** 2).sum()
        return (g1 + opts["s_weight"] * s1
                + opts["wr_pairs"] * (g2 + opts["s_weight"] * s2)
                + opts["l2"] * l2)
    with _torch.no_grad():
        hv_i, cv_i = tables()
        S0 = S_of(hv_i, cv_i); GP0 = GP_of(S0)
        _, _, v_ply0 = hinge_stats(S0, GP0, ppt)
        _, _, v_wr0 = hinge_stats(S0, GP0, wpt)
    opt = _torch.optim.Adam([raw_h, raw_c], lr=opts["lr"])
    iters = max(1, int(opts["iters"]))
    BS = 65536
    gen = _torch.Generator(device="cpu").manual_seed(20260715)
    def batch(idx):
        if idx.shape[0] <= BS:
            return idx
        sel = _torch.randint(0, idx.shape[0], (BS,), generator=gen).to(dev)
        return idx[sel]
    last = float("nan")
    for it in range(iters):
        hv, cv = tables()
        loss = total_loss(hv, cv, batch(ppt), batch(wpt))
        opt.zero_grad(); loss.backward(); opt.step()
        last = float(loss.detach())
        if it == 0 or (it + 1) % max(1, iters // 10) == 0:
            print(f"[teach] iter {it + 1}/{iters}  loss={last:.6f}", flush=True)
    with _torch.no_grad():
        hv, cv = tables()
        S1 = S_of(hv, cv); GP1 = GP_of(S1)
        _, _, v_ply1 = hinge_stats(S1, GP1, ppt)
        _, _, v_wr1 = hinge_stats(S1, GP1, wpt)
        cov_h = []; cov_c = []
        if ppt.shape[0] > 0:
            i, j = ppt[:, 0], ppt[:, 1]
            for t in range(7):
                cov_h.append(float((Ht[i, t] != Ht[j, t]).float().mean()))
            for t in range(13):
                cov_c.append(float((Ct[i, t] != Ct[j, t]).float().mean()))
        sens = []
        for t in range(13):
            cvp = cv.clone(); cvp[t] = cvp[t] + 0.5
            Sx = S_of(hv, cvp); GPx = GP_of(Sx)
            _, _, vx = hinge_stats(Sx, GPx, ppt)
            sens.append(round(vx - v_ply1, 6))
    stats = {
        "n_positions": int(Ht.shape[0]),
        "n_ply_pairs": int(ppt.shape[0]), "n_wr_pairs": int(wpt.shape[0]),
        "viol_ply_init": round(v_ply0, 6), "viol_ply_final": round(v_ply1, 6),
        "viol_wr_init": round(v_wr0, 6), "viol_wr_final": round(v_wr1, 6),
        "coverage_hand": [round(x, 4) for x in cov_h],
        "coverage_camp": [round(x, 4) for x in cov_c],
        "cv_sensitivity_plus0.5": sens,
        "s_weight": opts["s_weight"], "wr_weight": opts["wr_pairs"],
        "l2": opts["l2"], "final_loss": last,
    }
    print(f"[teach] done. ply-pair viol {v_ply0:.4f}→{v_ply1:.4f}  "
          f"wr-pair viol {v_wr0:.4f}→{v_wr1:.4f}", flush=True)
    if v_ply1 >= v_ply0 and v_wr1 >= v_wr0:
        print("[teach] 警告: ペア違反率が改善していない — 学習結果に意味が無い"
              " (データ量/被覆を _teach_stats で確認)", flush=True)
    return hv.cpu().tolist(), cv.cpu().tolist(), stats


def _teach_write_result(hand_vals, camp_vals, save_path, stats=None):
    import json as _json
    _out = {}
    _hnames = ["FU", "KY", "KE", "GI", "KI", "KA", "HI"]
    _cnames = ["FU", "KY", "KE", "GI", "KI", "KA", "HI",
               "TO", "NY", "NK", "NG", "UM", "RY"]
    for _i, _nm in enumerate(_hnames):
        _out[f"GP_Hand_Val_{_nm}"] = round(float(hand_vals[_i]), 6)
    for _i, _nm in enumerate(_cnames):
        _out[f"GP_Camp_Val_{_nm}"] = round(float(camp_vals[_i]), 6)
    if stats:
        _out["_teach_stats"] = dict(stats)
    _target = save_path or os.path.join(_BASE_DIR, "gp_fit_result.json")
    try:
        with open(_target, "w", encoding="utf-8") as _f:
            _json.dump(_out, _f, ensure_ascii=False, indent=2)
        print(f"[teach] saved: {_target}", flush=True)
        _flog(f"[teach] saved: {_target}")
    except OSError as _oe:
        print(f"[teach] save error: {_target}: {_oe!r}", flush=True)


def _teach_ensure_torch():
    try:
        import ctypes.util as _cu
    except ImportError as _ce:
        _flog(f"[teach] ctypes.util 先行 import 失敗 (無視): {_ce!r}")
    try:
        import torch as _t
        return _t
    except ImportError as _ie:
        _flog(f"[teach] torch import 失敗: {_ie!r}")
    if not _auto_install_ok():
        print("[teach] torch が無く PYFAMATE_NO_AUTO_INSTALL=1 のため導入も"
              "しません — スキップ", flush=True)
        return None
    import shutil as _sh
    _target = ([sys.executable] if not _IS_FROZEN
               else (_ensure_system_python() or []))
    _pcmd = _pip_cmd(_target) if _target else None
    if _pcmd:
        try:
            if _sh.which("nvidia-smi"):
                _flog("[teach] torch (CUDA cu126) を導入中… "
                      "(進捗: diagnosis.txt [teach-torch-install])")
                _run_pip_logged(_pcmd + ["torch", "--index-url",
                                         "https://download.pytorch.org/whl/cu126"],
                                timeout=3600, tag="teach-torch-install")
            else:
                _pip_install(["torch"])
        except Exception as _e:
            _flog(f"[teach] torch 導入失敗: {_e!r}")
    try:
        import torch as _t
        return _t
    except ImportError as _ie2:
        print(f"[teach] torch 導入に失敗 — スキップ ({_ie2!r})", flush=True)
        return None


def _gp_pieces_fit_step(extra):
    _opts = _teach_parse_args(list(extra))
    if _opts["bin"] is None and _opts["kif_dir"] is None:
        if os.path.exists(_TEACHER_DEFAULT_PSV_DIR):
            _opts["bin"] = _TEACHER_DEFAULT_PSV_DIR
        else:
            print(f"[fit][gp_pieces] データ未指定かつ既定教師パス "
                  f"{_TEACHER_DEFAULT_PSV_DIR} が無い — スキップ "
                  "(例: teach --bin teacher.bin)", flush=True)
            return 0
    if _opts["kif_dir"] is not None and _opts["bin"] is None:
        print("[fit][gp_pieces] --kif-dir 単独指定は本工程では未対応 "
              "(packed-sfen .bin を --bin で指定) — スキップ", flush=True)
        return 0
    _bin_paths = _teach_iter_bin_files(_opts["bin"])
    if not _bin_paths:
        print(f"[fit][gp_pieces] .bin ファイルが見つからない: {_opts['bin']!r} "
              "— スキップ", flush=True)
        return 0
    _torch = _teach_ensure_torch()
    if _torch is None:
        return 0
    _flog(f"[gp_pieces] teach-v3: bins={len(_bin_paths)} "
          f"positions={_opts['positions']} iters={_opts['iters']} "
          f"lr={_opts['lr']} pairs={_opts['pairs']}")
    print(f"[teach] loading up to {_opts['positions']} positions from "
          f"{len(_bin_paths)} file(s) …", flush=True)
    _feats, _rej = _teach_collect(_bin_paths, _opts["positions"])
    if _feats is None:
        print(f"[fit][gp_pieces] 有効な教師局面が無い (reject={_rej}) — "
              "スキップ", flush=True)
        return 0
    _n_rej = sum(_rej.values())
    print(f"[teach] collected {len(_feats['score'])} positions "
          f"(rejected {_n_rej}: {_rej}) — building pairs & fitting "
          f"(iters={_opts['iters']}, lr={_opts['lr']})", flush=True)
    _hand, _camp, _stats = _teach_fit(_torch, _feats, _opts)
    _stats["rejects"] = _rej
    _teach_write_result(_hand, _camp, _opts["save"], _stats)
    return 0


def _teach_cli(args):
    rc = _gp_pieces_fit_step(list(args))
    print(f"[teach] rc={rc}", flush=True)




def _arb_iter_jsonl(path):
    if not os.path.isfile(path):
        return
    with open(path, "r", encoding="utf-8") as fh:
        for ln in fh:
            ln = ln.strip()
            if not ln:
                continue
            try:
                yield json.loads(ln)
            except Exception:
                continue


def _arb_shared_and_cands(sample):
    scal = {"gp": sample.get("gp", 0.0), "eff_s": sample.get("eff_s", 0.0),
            "rem_ms": sample.get("rem_ms", 0.0), "move_count": sample.get("move_count", 0.0),
            "nnue_depth": 0, "nnue_nodes": 0}
    for c in sample.get("cands", []):
        if c.get("source") == "nnue":
            scal["nnue_depth"] = c.get("depth") or 0
            scal["nnue_nodes"] = c.get("nodes") or 0
    shared = SvArbiter._shared_features(scal)
    cands = [ArbCand(move=c.get("move"), source=c.get("source", "nnue"),
                     pv=c.get("pv"), cp=c.get("cp"), depth=c.get("depth"),
                     nodes=c.get("nodes")) for c in sample.get("cands", [])]
    return shared, cands


def _arb_pair_np(np_, shared, cand_s_list, i, j, q=None, pi=None, use_t=False):
    v = list(shared) + list(cand_s_list[i]) + list(cand_s_list[j])
    if use_t:
        v += [(q or {}).get(i, 0.5), (q or {}).get(j, 0.5),
              (pi or {}).get(i, 0.0), (pi or {}).get(j, 0.0)]
    return np_.asarray(v, dtype="float32")


def _arb_boards_for_sample(sample, pv_cap):
    root = _svboard_from_position_cmd(sample.get("sfen") or "startpos")
    if root is None:
        return None
    per = []
    for ci, c in enumerate(sample.get("cands", [])):
        try:
            b1 = root.clone(); b1.apply_usi(c.get("move"))
        except Exception:
            return None
        bl, applied = None, 0
        pv = _arb_pv_list(c.get("pv"))
        if pv:
            bl = b1.clone()
            for mv in pv[:pv_cap]:
                try:
                    bl.apply_usi(mv); applied += 1
                except Exception:
                    break
            if applied == 0:
                bl = None
        per.append((ci, b1, bl, applied))
    return root, per


def sv_arbiter_train_main(rest):
    import argparse
    import torch
    import torch.nn as nn
    ap = argparse.ArgumentParser(prog="arbiter-train")
    ap.add_argument("--data", default=os.path.join(_BASE_DIR, "arbiter_labeled.jsonl"))
    ap.add_argument("--base", default=os.path.join(_svonnx_here(), "model.infer.pt"),
                    help="トランク凍結初期値 (vision checkpoint)")
    ap.add_argument("--out", default=os.path.join(_svonnx_here(), "arbiter"))
    ap.add_argument("--epochs", type=int, default=8)
    ap.add_argument("--lr", type=float, default=1e-3)
    ap.add_argument("--pv-cap", type=int, default=12)
    ap.add_argument("--ch", type=int, default=64)
    ap.add_argument("--blocks", type=int, default=5)
    ap.add_argument("--val-frac", type=float, default=0.1)
    ap.add_argument("--batch", type=int, default=0,
                    help="勾配蓄積バッチ (0=auto: VRAM>=8GB→32, else 16)")
    a = ap.parse_args(rest)
    dev = "cuda" if torch.cuda.is_available() else "cpu"
    _np = _arb_ensure_np()
    _grad_accum = a.batch
    if _grad_accum <= 0:
        try:
            _vram_gb = torch.cuda.get_device_properties(0).total_mem / (1 << 30) if dev == "cuda" else 0
        except Exception:
            _vram_gb = 0
        _grad_accum = 32 if _vram_gb >= 8 else 16
    _amp = (dev == "cuda")
    if _amp:
        torch.backends.cudnn.benchmark = True
        try:
            torch.backends.cuda.matmul.allow_tf32 = True
            torch.backends.cudnn.allow_tf32 = True
        except AttributeError:
            pass
    try:
        _scaler = torch.amp.GradScaler("cuda", enabled=_amp)
    except (AttributeError, TypeError):
        _scaler = torch.cuda.amp.GradScaler(enabled=_amp)

    rows = [r for r in _arb_iter_jsonl(a.data) if r.get("y") is not None
            and len(r.get("cands", [])) >= 2]
    if not rows:
        print("[arbiter-train] 教師 0 行 — %s を先に生成 (arbiter-label)" % a.data); return
    def _gkey(r):
        return r.get("game_id") or (r.get("pos_hash") or "")[:4]
    keys = sorted({_gkey(r) for r in rows})
    n_val = max(1, int(len(keys) * a.val_frac))
    val_keys = set(keys[:n_val])
    tr = [r for r in rows if _gkey(r) not in val_keys]
    va = [r for r in rows if _gkey(r) in val_keys]
    print("[arbiter-train] train=%d val=%d (games=%d, val_games=%d) batch=%d"
          % (len(tr), len(va), len(keys), len(val_keys), _grad_accum))

    trunk = _sv_build_model(ch=a.ch, blocks=a.blocks, ver=3, in_ch=sv_N_PLANES, arb=True)
    if os.path.isfile(a.base):
        try:
            _ck = torch.load(a.base, map_location="cpu", weights_only=False)
            _sd = (_ck.get("ema") or _ck.get("model") or _ck) if isinstance(_ck, dict) else _ck
            trunk.load_state_dict(_sd, strict=False)
            print("[arbiter-train] base trunk loaded: %s" % a.base)
        except Exception as e:
            print("[arbiter-train] base load 失敗 (ランダム初期化で継続): %r" % e)
    trunk = trunk.to(dev)

    def _mlp(din):
        return nn.Sequential(nn.Linear(din, 64), nn.ReLU(True),
                             nn.Linear(64, 64), nn.ReLU(True), nn.Linear(64, 1))
    head_s = _mlp(14).to(dev)
    head_t = _mlp(18).to(dev)
    _pgroups = [{"params": trunk.parameters(), "lr": a.lr / 10.0},
                {"params": list(head_s.parameters()) + list(head_t.parameters()), "lr": a.lr}]
    try:
        opt = torch.optim.AdamW(_pgroups, weight_decay=1e-4, fused=_amp)
    except (TypeError, RuntimeError):
        opt = torch.optim.AdamW(_pgroups, weight_decay=1e-4)

    def _pair_logit(head, shared, cand_s, i, j, q, pi, use_t):
        fi = torch.tensor(_arb_pair_np(_np, shared, cand_s, i, j, q, pi, use_t), device=dev)
        fj = torch.tensor(_arb_pair_np(_np, shared, cand_s, j, i, q, pi, use_t), device=dev)
        return 0.5 * (head(fi) - head(fj)).squeeze(-1)

    def _trunk_qpi(sample):
        bl = _arb_boards_for_sample(sample, a.pv_cap)
        if bl is None:
            return None
        root, per = bl
        boards = [root] + [x[1] for x in per] + [x[2] for x in per if x[2] is not None]
        planes = torch.tensor(sv_encode_planes(
            [b.cells for b in boards], [b.hand[0] + b.hand[1] for b in boards],
            [b.side for b in boards]), device=dev)
        with torch.autocast("cuda", dtype=torch.float16, enabled=_amp):
            f = trunk.body(trunk.stem(planes))
            val = trunk.value_head(trunk.value_conv(f).flatten(1)).squeeze(1)
            mv = trunk.move_head(f).flatten(2).permute(0, 2, 1).reshape(planes.shape[0], -1)
            dr = trunk.drop_head(f).flatten(2).reshape(planes.shape[0], -1)
            pol_logits = torch.cat([mv, dr], dim=1)
        val = val.float(); pol_logits = pol_logits.float()
        pol = torch.softmax(pol_logits, dim=1)
        root_side = int(root.side)

        def _our(k):
            v = torch.sigmoid(val[k])
            if int(boards[k].side) == 1:
                v = 1.0 - v
            if root_side == 1:
                v = 1.0 - v
            return v
        idx = 1
        q, pi, s1v = {}, {}, {}
        sl_ptr = 1 + len(per)
        for (ci, b1, bl2, applied) in per:
            v1 = _our(idx); idx += 1
            s1v[ci] = v1
            if bl2 is not None:
                vL = _our(sl_ptr); sl_ptr += 1
                lam = 0.5 * min(1.0, applied / 8.0)
                q[ci] = float(((1.0 - lam) * v1 + lam * vL).item())
            else:
                q[ci] = float(v1.item())
            try:
                lab = sv_usi_to_label(sample["cands"][ci]["move"])
                pi[ci] = float(pol[0, lab].item()) if 0 <= lab < pol.shape[1] else 0.0
            except Exception:
                pi[ci] = 0.0
        return q, pi, s1v, pol_logits

    def _run(rows_, train=True):
        agree_s = agree_t = tot = 0
        loss_sum = 0.0
        if train:
            opt.zero_grad()
        for _si, r in enumerate(rows_):
            shared, cands = _arb_shared_and_cands(r)
            cand_s = [SvArbiter._cand_scalars(c) for c in cands]
            y = int(r["y"]); w = float(r.get("w", 0.1))
            i, j = 0, 1
            yt = torch.tensor(1.0 if y == i else 0.0, device=dev)
            ls = _pair_logit(head_s, shared, cand_s, i, j, None, None, False)
            L_rank_s = w * nn.functional.binary_cross_entropy_with_logits(ls, yt)
            qp = _trunk_qpi(r)
            L = L_rank_s
            if qp is not None:
                q, pi, s1v, pol_logits = qp
                lt = _pair_logit(head_t, shared, cand_s, i, j, q, pi, True)
                L_rank_t = w * nn.functional.binary_cross_entropy_with_logits(lt, yt)
                L_val = torch.tensor(0.0, device=dev)
                wr = r.get("wr")
                if isinstance(wr, (list, tuple)) and len(wr) >= 2:
                    for ci in (i, j):
                        if ci < len(wr) and wr[ci] is not None and ci in s1v:
                            L_val = L_val + (s1v[ci] - float(wr[ci])) ** 2
                L_pol = torch.tensor(0.0, device=dev)
                try:
                    lab = sv_usi_to_label(cands[y].move)
                    L_pol = -torch.log_softmax(pol_logits, dim=1)[0, lab]
                except Exception:
                    pass
                L = 1.0 * (L_rank_s + L_rank_t) + 0.5 * L_val + 0.25 * L_pol
                agree_t += int((lt.item() > 0) == (y == i))
            agree_s += int((ls.item() > 0) == (y == i))
            tot += 1
            loss_sum += float(L.item())
            if train:
                _scaler.scale(L / _grad_accum).backward()
                if (_si + 1) % _grad_accum == 0:
                    _scaler.step(opt)
                    _scaler.update()
                    opt.zero_grad()
        if train and len(rows_) % _grad_accum != 0:
            _scaler.step(opt)
            _scaler.update()
        return (agree_s / max(1, tot), agree_t / max(1, tot), loss_sum / max(1, tot))

    import time as _time
    for ep in range(a.epochs):
        _ep0 = _time.perf_counter()
        trunk.train(); head_s.train(); head_t.train()
        tr_s, tr_t, tl = _run(tr, train=True)
        _sps = len(tr) / max(1e-9, _time.perf_counter() - _ep0)
        trunk.eval(); head_s.eval(); head_t.eval()
        with torch.no_grad():
            va_s, va_t, vl = _run(va, train=False)
        print("[arbiter-train] ep%d train_loss=%.4f (%.0f samples/s%s) | "
              "val agree S=%.3f T=%.3f Δ(trunk)=%+.3f"
              % (ep, tl, _sps, " amp" if _amp else "", va_s, va_t, va_t - va_s), flush=True)

    def _dump(head, prefix, npz):
        i = 0
        for m in head:
            if isinstance(m, nn.Linear):
                npz["%s_W%d" % (prefix, i)] = m.weight.detach().cpu().numpy().T.astype("float32")
                npz["%s_b%d" % (prefix, i)] = m.bias.detach().cpu().numpy().astype("float32")
                i += 1
    npz = {}
    _dump(head_s, "s", npz); _dump(head_t, "t", npz)
    _tmp = a.out + "_head.tmp"
    _np.savez(_tmp, **npz)
    os.replace(_tmp + ".npz", os.path.join(_svonnx_here(), "arbiter_head.npz"))
    d = {"model": trunk.state_dict(),
         "arch": {"ch": a.ch, "blocks": a.blocks, "ver": 3, "in_ch": sv_N_PLANES, "arb": True}}
    torch.save(d, a.out + ".pt.tmp"); os.replace(a.out + ".pt.tmp", a.out + ".pt")
    try:
        _svonnx_export_ckpt(a.out + ".pt", out=os.path.join(_svonnx_here(), "arbiter.onnx"),
                            verify=True, arbiter=True)
        print("[arbiter-train] arbiter.onnx + arbiter_head.npz 出力完了")
    except Exception as e:
        print("[arbiter-train] onnx export 失敗: %r" % e)


def sv_arbiter_tau_main(rest):
    import argparse
    ap = argparse.ArgumentParser(prog="arbiter-tau")
    ap.add_argument("--data", default=os.path.join(_BASE_DIR, "arbiter_labeled.jsonl"))
    a = ap.parse_args(rest)
    arb = _sv_arbiter_get()
    if not arb.load():
        print("[arbiter-tau] arbiter_head.npz 不在 — arbiter-train を先に"); return
    _np = arb._np
    rows = [r for r in _arb_iter_jsonl(a.data) if r.get("y") is not None
            and len(r.get("cands", [])) >= 2]
    if not rows:
        print("[arbiter-tau] 教師 0 行"); return
    samples = []
    for r in rows:
        shared, cands = _arb_shared_and_cands(r)
        cs = [SvArbiter._cand_scalars(c) for c in cands]
        dl_i = next((k for k, c in enumerate(cands) if c.source == "dl1"), 1)
        nn_i = next((k for k, c in enumerate(cands) if c.source == "nnue"), 0)
        lij = 0.5 * (arb._mlp_forward(arb._head_s, arb._pair_vec(shared, cs[dl_i], cs[nn_i], dl_i, nn_i, {}, {}, False))
                     - arb._mlp_forward(arb._head_s, arb._pair_vec(shared, cs[nn_i], cs[dl_i], nn_i, dl_i, {}, {}, False)))
        p_dl = 1.0 / (1.0 + _np.exp(-max(-60.0, min(60.0, lij))))
        samples.append((float(p_dl), int(r["y"] == dl_i), float(r.get("w", 0.1))))
    best_tau, best_regret = 0.62, 1e18
    for t in [x / 100.0 for x in range(40, 96)]:
        regret = 0.0
        for p_dl, dl_correct, w in samples:
            override = p_dl > t
            if override and not dl_correct:
                regret += w
            elif (not override) and dl_correct:
                regret += w
        if regret < best_regret:
            best_regret, best_tau = regret, t
    print("[arbiter-tau] best Override_Tau=%.2f (regret=%.3f, N=%d)"
          % (best_tau, best_regret, len(samples)))
    with open(os.path.join(_svonnx_here(), "arbiter_tau.json"), "w", encoding="utf-8") as w:
        json.dump({"Arbiter_Override_Tau": best_tau, "regret": best_regret,
                   "n": len(samples)}, w)


def sv_arbiter_eval_main(rest):
    import argparse
    ap = argparse.ArgumentParser(prog="arbiter-eval")
    ap.add_argument("--data", default=os.path.join(_BASE_DIR, "arbiter_labeled.jsonl"))
    a = ap.parse_args(rest)
    arb = _sv_arbiter_get()
    if not arb.load():
        print("[arbiter-eval] arbiter_head.npz 不在"); return
    rows = [r for r in _arb_iter_jsonl(a.data) if r.get("y") is not None
            and len(r.get("cands", [])) >= 2]
    n = agree = dl_correct_disputed = disputed = 0
    for r in rows:
        shared, cands = _arb_shared_and_cands(r)
        cs = [SvArbiter._cand_scalars(c) for c in cands]
        y = int(r["y"])
        lij = 0.5 * (arb._mlp_forward(arb._head_s, arb._pair_vec(shared, cs[0], cs[1], 0, 1, {}, {}, False))
                     - arb._mlp_forward(arb._head_s, arb._pair_vec(shared, cs[1], cs[0], 1, 0, {}, {}, False)))
        pred = 0 if lij > 0 else 1
        agree += int(pred == y); n += 1
        if r.get("bucket") == "D":
            disputed += 1
            dl_i = next((k for k, c in enumerate(cands) if c.source == "dl1"), 1)
            dl_correct_disputed += int(y == dl_i)
    print("[arbiter-eval] N=%d  Tier-S一致率=%.3f  disputed=%d  P(DL正解|disputed)=%.3f"
          % (n, agree / max(1, n), disputed, dl_correct_disputed / max(1, disputed)))


class _ArbUsi:
    def __init__(self, exe, options=None, cwd=None, env=None):
        _env = None
        if env:
            _env = dict(os.environ)
            _env.update({str(_k): str(_v) for _k, _v in env.items()})
        self.p = subprocess.Popen([exe], cwd=cwd or (os.path.dirname(exe) or None),
                                  stdin=subprocess.PIPE, stdout=subprocess.PIPE,
                                  stderr=subprocess.DEVNULL, text=True, bufsize=1,
                                  env=_env)
        self._send("usi"); self._wait("usiok")
        for k, v in (options or {}).items():
            self._send("setoption name %s value %s" % (k, v))
        self._send("isready"); self._wait("readyok")

    def _send(self, s):
        self.p.stdin.write(s + "\n"); self.p.stdin.flush()

    def _wait(self, tok):
        while True:
            ln = self.p.stdout.readline()
            if not ln:
                raise RuntimeError("engine EOF")
            if ln.strip().startswith(tok):
                return ln.strip()

    def _read_bestmove(self):
        score, pv = None, []
        while True:
            ln = self.p.stdout.readline()
            if not ln:
                raise RuntimeError("engine EOF")
            ln = ln.strip()
            if ln.startswith("info") and " score cp " in ln:
                try:
                    toks = ln.split()
                    score = int(toks[toks.index("cp") + 1])
                    if "pv" in toks:
                        pv = toks[toks.index("pv") + 1:]
                except Exception:
                    pass
            elif ln.startswith("bestmove"):
                return ln.split()[1], score, pv

    def analyse(self, position_cmd, nodes=None, movetime_ms=None):
        self._send(position_cmd if position_cmd.startswith("position") else "position " + position_cmd)
        if movetime_ms is not None:
            self._send("go movetime %d" % int(movetime_ms))
        else:
            self._send("go nodes %d" % int(nodes))
        return self._read_bestmove()


    def close(self):
        try:
            self._send("quit"); self.p.wait(timeout=5)
        except Exception:
            try:
                self.p.kill()
            except Exception:
                pass


def _arb_analyse_pair(nn, dl, pos, nn_ms, dl_ms):
    import threading
    res = {}

    def _go(tag, eng, ms):
        try:
            res[tag] = eng.analyse(pos, movetime_ms=ms)
        except Exception as e:
            res[tag] = e
    t1 = threading.Thread(target=_go, args=("nn", nn, nn_ms), daemon=True)
    t2 = threading.Thread(target=_go, args=("dl", dl, dl_ms), daemon=True)
    t1.start(); t2.start(); t1.join(); t2.join()
    for tag in ("nn", "dl"):
        if isinstance(res.get(tag), Exception):
            raise res[tag]
    return res["nn"], res["dl"]


_ARB_PAIR_MIN_NN_THREADS = 32


def _arb_pairs_auto():
    _gpus = max(1, _sys_gpu_count())
    _cores = max(1, _cpu_count_effective())
    _by_cpu = max(1, _cores // _ARB_PAIR_MIN_NN_THREADS)
    return max(1, min(_gpus, _by_cpu))


def _arb_dl_opts_single_gpu(base):
    _num_re = re.compile(r"^(DNN_Model|DNN_Batch_Size|UCT_Threads)(\d+)$")
    out = {}
    for k, v in base.items():
        if k == "Max_GPU":
            continue
        _m = _num_re.match(k)
        if _m and _m.group(2) != "1":
            continue
        out[k] = v
    return out


def _arb_nn_opts_share(base, n_pairs):
    if n_pairs <= 1:
        return dict(base)
    out = dict(base)
    for _k, _floor in (("Threads", _ARB_PAIR_MIN_NN_THREADS), ("USI_Hash", 64)):
        if _k in out:
            try:
                out[_k] = str(max(_floor, int(out[_k]) // n_pairs))
            except Exception:
                pass
    return out


def _arb_engine_paths():
    def _abs(p):
        if not p:
            return None
        p = str(p).strip().strip('"')
        if not os.path.isabs(p):
            p = os.path.join(_BASE_DIR, p)
        return p if os.path.isfile(p) else None
    nn_exe = _abs(globals().get("nnue_1_PATH") or _cfg.get("nnue_1_Path"))
    dl_exe = _abs(globals().get("DL_1_PATH") or _cfg.get("DL_1_Path"))
    return nn_exe, dl_exe


def sv_arbiter_synth_main(rest):
    import argparse
    ap = argparse.ArgumentParser(prog="arbiter-synth")
    ap.add_argument("--sfens", default="",
                    help="互角局面集 txt またはそれを含むフォルダ "
                         "(既定: start_sfens_ply32.txt / start_sfens_ply24.txt)")
    ap.add_argument("--nnue-movetime-ms", type=int, default=500)
    ap.add_argument("--dl-movetime-ms", type=int, default=500)
    ap.add_argument("--out", default=_ARBITER_SAMPLES_PATH)
    ap.add_argument("--max-positions", type=int, default=0, help="0=全局面 (固定 seed 抽出)")
    a = ap.parse_args(rest)
    srcs = []
    if a.sfens:
        if os.path.isdir(a.sfens):
            srcs = sorted(glob.glob(os.path.join(a.sfens, "*.txt")))
        elif os.path.isfile(a.sfens):
            srcs = [a.sfens]
    else:
        for fn in ("start_sfens_ply32.txt", "start_sfens_ply24.txt"):
            for root in (_BASE_DIR, os.getcwd()):
                p = os.path.join(root, fn)
                if os.path.isfile(p) and p not in srcs:
                    srcs.append(p)
                    break
    if not srcs:
        print("[arbiter-synth] 互角局面集が見つかりません — start_sfens_ply32.txt / "
              "start_sfens_ply24.txt を %s に置いてください" % _BASE_DIR)
        return
    plist, psrc = [], []
    for sp_ in srcs:
        try:
            with open(sp_, "r", encoding="utf-8", errors="ignore") as fh:
                for ln in fh:
                    ln = ln.strip()
                    if not ln or ln.startswith("#"):
                        continue
                    if ln.startswith("position "):
                        plist.append(ln)
                    elif ln.startswith("sfen ") or ln.startswith("startpos"):
                        plist.append("position " + ln)
                    else:
                        plist.append("position sfen " + ln)
                    psrc.append(os.path.basename(sp_))
        except OSError as _oe:
            print("[arbiter-synth] 読込失敗 %s: %r" % (sp_, _oe))
    if not plist:
        print("[arbiter-synth] 互角局面集に局面がありません: %s" % ", ".join(srcs))
        return
    if a.max_positions and len(plist) > a.max_positions:
        _rng = random.Random(0)
        _pairs = list(zip(plist, psrc))
        _rng.shuffle(_pairs)
        _pairs = _pairs[:a.max_positions]
        plist = [x[0] for x in _pairs]
        psrc = [x[1] for x in _pairs]
    nn_exe, dl_exe = _arb_engine_paths()
    if not (nn_exe and dl_exe and os.path.isfile(nn_exe) and os.path.isfile(dl_exe)):
        print("[arbiter-synth] NNUE/DL エンジン exe 未解決 (cfg NNUE_1_Path/DL_1_Path) — 中止"); return
    _nn_opts = dict(_nnue_1_opts)
    _nn_opts.update({"USI_Ponder": "false", "Stochastic_Ponder": "false"})
    _dl_opts = dict(_dl_1_opts)
    _dl_opts["USI_Ponder"] = "false"
    nn = _ArbUsi(nn_exe, options=_nn_opts)
    dl = _ArbUsi(dl_exe, options=_dl_opts)
    eff_grid = [1.0, 3.0, 8.0]
    n_emit = 0
    try:
        import time as _time
        print("[arbiter-synth] 互角局面集 %d 局面 (%s)" % (len(plist), ", ".join(
            os.path.basename(s) for s in srcs)), flush=True)
        print("[arbiter-synth] oracle: nnue=%s (%d ms) / dl=%s (%d ms)"
              % (nn_exe, a.nnue_movetime_ms, dl_exe, a.dl_movetime_ms), flush=True)
        _t0 = _time.perf_counter()
        _beat = _t0
        for pi, pos in enumerate(plist):
            _now = _time.perf_counter()
            if _now - _beat >= 30.0:
                _rate = (pi + 1) / max(1e-9, _now - _t0)
                _eta = (len(plist) - pi) / max(1e-9, _rate)
                _msg = ("[arbiter-synth] %d/%d 局面 %d サンプル (%.2f 局面/s, 残り目安 %.0f 分)"
                        % (pi + 1, len(plist), n_emit, _rate, _eta / 60.0))
                print(_msg, flush=True)
                _flog(_msg)
                _beat = _now
            try:
                (nmv, ncp, npv), (dmv, dcp, dpv) = _arb_analyse_pair(
                    nn, dl, pos, a.nnue_movetime_ms, a.dl_movetime_ms)
            except Exception as e:
                _flog("[arbiter-synth] analyse: %r" % e); continue
            if not nmv or not dmv or nmv == dmv:
                continue
            _gid = psrc[pi] + "/" + _pos_hash8(pos)
            for eff in eff_grid:
                rec = {"sfen": pos, "pos_hash": _pos_hash8(pos),
                       "game_id": _gid,
                       "cands": [{"move": nmv, "source": "nnue", "pv": npv, "cp": ncp},
                                 {"move": dmv, "source": "dl1", "pv": dpv, "cp": dcp}],
                       "gp": None, "eff_s": eff, "rem_ms": None,
                       "move_count": None, "ply": None}
                _atomic_append(a.out, json.dumps(rec, ensure_ascii=False, default=str) + "\n",
                               lock=_arbiter_sample_lock, fsync=False, os_write=True)
                n_emit += 1
    finally:
        nn.close(); dl.close()
    print("[arbiter-synth] 完了: %d 局面 → %d 不一致サンプル → %s"
          % (len(plist), n_emit, a.out))


def _arb_list_kif(root):
    out = []
    for dp, _dn, fn in os.walk(root):
        for f in fn:
            if f.lower().endswith((".kif", ".kifu", ".csa", ".sfen")):
                out.append(os.path.join(dp, f))
    return out


def _arb_kif_positions(fpath):
    try:
        with open(fpath, "rb") as fh:
            raw = fh.read()
    except OSError:
        return
    text = None
    for enc in ("utf-8-sig", "cp932", "euc-jp"):
        try:
            text = raw.decode(enc)
            break
        except UnicodeDecodeError:
            continue
    if text is None:
        return
    ext = os.path.splitext(fpath)[1].lower()
    if ext not in (".csa", ".kif", ".kifu"):
        for line in text.splitlines():
            line = line.strip()
            if line.startswith(("position ", "startpos", "sfen ")):
                toks = line.split()
                if "moves" in toks:
                    base = " ".join(toks[:toks.index("moves") + 1])
                    mvs = toks[toks.index("moves") + 1:]
                    for k in range(len(mvs) + 1):
                        yield (("position " if not line.startswith("position") else "")
                               + base + " " + " ".join(mvs[:k]))
                else:
                    yield ("position " if not line.startswith("position") else "") + line
        return
    try:
        if ext == ".csa":
            b0, mvs, _w = sv_parse_csa(text)
        else:
            b0, mvs, _w = sv_parse_kif(text)
    except Exception as _pe:
        _flog("[arbiter-synth] parse skip %s: %r" % (os.path.basename(fpath), _pe))
        return
    if not mvs:
        return
    base = "position sfen " + _svboard_to_sfen(b0) + " moves "
    for k in range(8, len(mvs) + 1):
        yield base + " ".join(mvs[:k])


def sv_arbiter_label_main(rest):
    import argparse
    ap = argparse.ArgumentParser(prog="arbiter-label")
    ap.add_argument("--data", default=_ARBITER_SAMPLES_PATH)
    ap.add_argument("--out", default=os.path.join(_BASE_DIR, "arbiter_labeled.jsonl"))
    ap.add_argument("--oracle-movetime-ms", type=int, default=15000)
    ap.add_argument("--dl-movetime-ms", type=int, default=5000)
    ap.add_argument("--budget-min", type=int, default=0,
                    help="総時間予算[分]。到達で停止し次回 resume (0=無制限)")
    ap.add_argument("--limit", type=int, default=0)
    ap.add_argument("--pairs", type=int, default=0,
                    help="NNUE/DL ワーカーペア数。0=auto (min(GPU数, cores/%d))、"
                         "1=従来動作" % _ARB_PAIR_MIN_NN_THREADS)
    a = ap.parse_args(rest)
    nn_exe, dl_exe = _arb_engine_paths()
    if not (nn_exe and dl_exe and os.path.isfile(nn_exe) and os.path.isfile(dl_exe)):
        print("[arbiter-label] エンジン exe 未解決 — 中止"); return
    _pairs = a.pairs if a.pairs > 0 else _arb_pairs_auto()
    _pairs = max(1, _pairs)
    _nn_opts = _arb_nn_opts_share(_nnue_1_opts, _pairs)
    _nn_opts.update({"USI_Ponder": "false", "Stochastic_Ponder": "false"})
    _dl_opts = dict(_dl_1_opts)
    _dl_opts["USI_Ponder"] = "false"
    if _pairs > 1:
        _dl_opts = _arb_dl_opts_single_gpu(_dl_opts)
        print("[arbiter-label] ワーカーペア %d (GPU=%d cores=%d) — "
              "DL は 1 ペア 1 GPU 固定 / NNUE Threads=%s Hash=%s に分割"
              % (_pairs, _sys_gpu_count(), _cpu_count_effective(),
                 _nn_opts.get("Threads", "?"), _nn_opts.get("USI_Hash", "?")),
              flush=True)
    import time as _time
    _seen = set()
    for _lr in _arb_iter_jsonl(a.out):
        _lk = (_lr.get("pos_hash"), _lr.get("eff_s"))
        if _lk[0]:
            _seen.add(_lk)
    _total = sum(1 for _ in _arb_iter_jsonl(a.data))
    if _seen:
        print("[arbiter-label] resume: 既ラベル %d 件 skip / 全 %d 件" % (len(_seen), _total),
              flush=True)
    _t0 = _time.time()
    _beat = _t0
    n_g = n_d = 0

    def _argmax(xs):
        best, bi = -1.0, None
        for k, x in enumerate(xs):
            if x is not None and x > best:
                best, bi = x, k
        return bi

    _src = _arb_iter_jsonl(a.data)
    _src_lock = threading.Lock()
    _w_lock = threading.Lock()
    _stop = threading.Event()
    _idx_ct = [0]

    def _next_row():
        with _src_lock:
            if _stop.is_set():
                return None
            if a.limit and _idx_ct[0] >= a.limit:
                return None
            if a.budget_min and (_time.time() - _t0) >= a.budget_min * 60.0:
                if not _stop.is_set():
                    _stop.set()
                    print("[arbiter-label] 時間予算 %d 分に到達 (%d 件処理) — 残り %d 件は"
                          "次回 resume" % (a.budget_min, n_g + n_d,
                                           max(0, _total - len(_seen) - n_g - n_d)), flush=True)
                return None
            try:
                r = next(_src)
            except StopIteration:
                return None
            i = _idx_ct[0]
            _idx_ct[0] += 1
            return i, r

    def _worker(nn, dl, w):
        nonlocal n_g, n_d, _beat
        while True:
            _got = _next_row()
            if _got is None:
                return
            idx, r = _got
            _lk = (r.get("pos_hash"), r.get("eff_s"))
            if _lk[0] and _lk in _seen:
                continue
            with _w_lock:
                if _time.time() - _beat >= 30.0:
                    _done = n_g + n_d
                    _rate = _done / max(1e-9, _time.time() - _t0)
                    _rest = max(0, _total - len(_seen) - _done)
                    print("[arbiter-label] %d 件処理 (G=%d D=%d, %.1f 件/分, 残り %d 件 ≈ %.1f 時間)"
                          % (_done, n_g, n_d, _rate * 60.0, _rest,
                             _rest / max(1e-9, _rate) / 3600.0), flush=True)
                    _beat = _time.time()
            cands = r.get("cands", [])
            if len(cands) < 2:
                continue
            base = _svboard_from_position_cmd(r.get("sfen") or "startpos")
            if base is None:
                continue
            wr_nn, wr_dl = [], []
            for c in cands:
                try:
                    b = base.clone(); b.apply_usi(c["move"])
                except Exception:
                    wr_nn.append(None); wr_dl.append(None); continue
                pcmd = "position sfen " + b.to_sfen()
                try:
                    (_, cp_n, _), (_, cp_d, _) = _arb_analyse_pair(
                        nn, dl, pcmd, a.oracle_movetime_ms, a.dl_movetime_ms)
                except Exception:
                    cp_n = cp_d = None
                wr_nn.append(1.0 - _cp_to_winrate(cp_n, _SR_WR_SLOPE) if cp_n is not None else None)
                wr_dl.append(1.0 - _cp_to_winrate(cp_d, _SR_WR_SLOPE) if cp_d is not None else None)
            y_nn, y_dl = _argmax(wr_nn), _argmax(wr_dl)
            if y_nn is None or y_dl is None:
                continue
            if y_nn == y_dl:
                bucket, y = "G", y_nn
                dwr = abs((wr_nn[y] or 0.5) - (wr_nn[1 - y] or 0.5))
                if dwr < 0.02:
                    continue
                wgt = max(0.02, min(0.20, dwr))
                _inc = "G"
            else:
                bucket, y, wgt = "D", y_dl, 0.15; _inc = "D"
            out = dict(r, y=int(y), w=float(wgt), bucket=bucket, wr=wr_nn)
            _line = json.dumps(out, ensure_ascii=False, default=str) + "\n"
            with _w_lock:
                w.write(_line); w.flush()
                if _inc == "G":
                    n_g += 1
                else:
                    n_d += 1
                if (n_g + n_d) % 200 == 0:
                    print("[arbiter-label] %d 局面 (G=%d D=%d)"
                          % (n_g + n_d, n_g, n_d), flush=True)

    _engs = []
    try:
        with open(a.out, "a", encoding="utf-8") as w:
            for _pi in range(_pairs):
                _env = {"CUDA_VISIBLE_DEVICES": str(_pi)} if _pairs > 1 else None
                _nn_i = _ArbUsi(nn_exe, options=_nn_opts)
                _dl_i = _ArbUsi(dl_exe, options=_dl_opts, env=_env)
                _engs += [_nn_i, _dl_i]
                if _pairs == 1:
                    _worker(_nn_i, _dl_i, w)
            if _pairs > 1:
                _ths = [threading.Thread(target=_worker,
                                         args=(_engs[2 * i], _engs[2 * i + 1], w),
                                         daemon=True, name="arblabel/%d" % i)
                        for i in range(_pairs)]
                for _t in _ths:
                    _t.start()
                for _t in _ths:
                    _t.join()
    finally:
        for _e in _engs:
            try:
                _e.close()
            except Exception:
                pass
    print("[arbiter-label] 完了: G=%d D=%d → %s" % (n_g, n_d, a.out))


def sv_arbiter_mine_main(rest):
    import argparse
    ap = argparse.ArgumentParser(prog="arbiter-mine")
    ap.add_argument("--stats", default=_STATS_PATH)
    ap.add_argument("--out", default=_ARBITER_SAMPLES_PATH)
    a = ap.parse_args(rest)
    n = 0
    for r in _arb_iter_jsonl(a.stats):
        nt, dt = r.get("nnue_bestmove") or r.get("nnue_top"), r.get("dl_top_move") or r.get("dl_top")
        pos = r.get("sfen") or r.get("position")
        if nt and dt and nt != dt and pos:
            rec = {"sfen": pos, "pos_hash": _pos_hash8(pos), "game_id": r.get("game_id"),
                   "cands": [{"move": nt, "source": "nnue", "cp": r.get("nnue_score_cp")},
                             {"move": dt, "source": "dl1", "cp": r.get("dl_top_score")}],
                   "gp": r.get("game_phase"), "eff_s": r.get("eff_s"),
                   "move_count": r.get("move_count"), "ply": r.get("move_count")}
            _atomic_append(a.out, json.dumps(rec, ensure_ascii=False, default=str) + "\n",
                           lock=_arbiter_sample_lock, fsync=False, os_write=True)
            n += 1
    print("[arbiter-mine] %d 不一致局面を stats.txt から採取 → %s" % (n, a.out))


def sv_arbiter_playout_main(rest):
    import argparse
    ap = argparse.ArgumentParser(prog="arbiter-playout")
    ap.add_argument("--data", default=os.path.join(_BASE_DIR, "arbiter_labeled.jsonl"))
    ap.add_argument("--out", default=os.path.join(_BASE_DIR, "arbiter_labeled_D.jsonl"))
    ap.add_argument("--k", type=int, default=8)
    ap.add_argument("--nodes", type=int, default=20000)
    a = ap.parse_args(rest)
    nn_exe, dl_exe = _arb_engine_paths()
    if not (nn_exe and dl_exe):
        print("[arbiter-playout] エンジン未解決 — 中止"); return
    disputed = [r for r in _arb_iter_jsonl(a.data) if r.get("bucket") == "D"]
    print("[arbiter-playout] 係争 %d 局面を playout (K=%d, nodes=%d/手) — 実装は engine 対局"
          " ループへ接続 (run later)。フレーム/契約は確定。" % (len(disputed), a.k, a.nodes))


def sv_arbiter_collect_main(rest):
    import argparse
    ap = argparse.ArgumentParser(prog="arbiter-collect")
    ap.add_argument("--data", default=_ARBITER_SAMPLES_PATH)
    ap.add_argument("--out", default=os.path.join(_BASE_DIR, "arbiter_dagger.jsonl"))
    ap.add_argument("--top", type=int, default=5000)
    a = ap.parse_args(rest)
    arb = _sv_arbiter_get()
    if not arb.load():
        print("[arbiter-collect] arbiter_head.npz 不在"); return
    _np = arb._np
    scored = []
    for r in _arb_iter_jsonl(a.data):
        cands = r.get("cands", [])
        if len(cands) < 2:
            continue
        shared, cs_cands = _arb_shared_and_cands(r)
        cs = [SvArbiter._cand_scalars(c) for c in cs_cands]
        lij = 0.5 * (arb._mlp_forward(arb._head_s, arb._pair_vec(shared, cs[0], cs[1], 0, 1, {}, {}, False))
                     - arb._mlp_forward(arb._head_s, arb._pair_vec(shared, cs[1], cs[0], 1, 0, {}, {}, False)))
        p = 1.0 / (1.0 + _np.exp(-max(-60.0, min(60.0, lij))))
        ent = -(p * _np.log(p + 1e-9) + (1 - p) * _np.log(1 - p + 1e-9))
        scored.append((float(ent), r))
    scored.sort(key=lambda x: x[0], reverse=True)
    with open(a.out, "w", encoding="utf-8") as w:
        for _e, r in scored[:a.top]:
            w.write(json.dumps(r, ensure_ascii=False, default=str) + "\n")
    print("[arbiter-collect] 高エントロピー上位 %d 局面 → %s (DAgger 再ラベル対象)"
          % (min(a.top, len(scored)), a.out))


