if __name__ == "__main__":
    _mp.freeze_support()
    sys.excepthook = _excepthook_to_diagnosis
    try:
        _args = sys.argv[1:]
        _cli_handler = _CLI_DISPATCH.get(_args[0]) if _args else None
        if _cli_handler is not None:
            _cli_handler(_args[1:])
        else:
            main()
    except Exception as _fatal_exc:
        if _is_pipe_lost_exc(_fatal_exc):
            _flog(f"[PIPE-LOST] stdio pipe closed by peer: {_fatal_exc!r}")
        else:
            _flog("FATAL in main():\n" + _safe_format_exc().strip())
        raise
